// ============================================================================
// DATABASE UPGRADE CHECK — Run migrations when the plugin version changes
// ============================================================================

/**
 * Check if the database needs updating after a plugin file update.
 *
 * WHY: The activation hook only fires once — when the plugin is first activated.
 *      When we push a new version via SCP (or auto-update), the activation hook
 *      does NOT re-run. So if we added new tables or seeded new data in a later
 *      version, sites that were already running the plugin would never get them.
 *
 *      This check runs on every admin page load (cheap — just comparing two
 *      strings). If the stored db version doesn't match the current plugin
 *      version, we re-run the table creation and seeding. dbDelta() is safe
 *      to run repeatedly — it only makes changes where the schema differs.
 */
add_action( 'admin_init', function () {
    $stored_version = get_option( 'societypress_db_version', '0' );

    if ( $stored_version !== SOCIETYPRESS_VERSION ) {
        sp_create_tables();
        sp_maybe_seed_default_tiers();
        sp_maybe_seed_event_categories();
        sp_maybe_create_newsletter_category();
        sp_maybe_seed_resource_categories();
        sp_maybe_seed_library_categories();
        sp_maybe_seed_document_categories();

        // Backfill phonetic codes for any surnames added before this feature existed
        sp_maybe_backfill_surname_phonetics();

        // WHY: Without saving the new version, the upgrade check fires on every admin
        // page load, re-running dbDelta on 43 tables and all seeding functions. This was
        // a silent performance killer — every admin request did full schema reconciliation.
        update_option( 'societypress_db_version', SOCIETYPRESS_VERSION );
    }
});

// ============================================================================
// MIGRATION: Add role_type column to sp_volunteer_roles for existing installs
//
// WHY: The role_type column distinguishes officers, committee assignments, and
//      general volunteers in the same table. Sites that were running before this
//      column existed won't have it — dbDelta sometimes fails to add columns to
//      existing tables, so we do an explicit check-and-add here. The check
//      (SHOW COLUMNS) is cheap and only runs once per admin page load; the ALTER
//      only fires if the column is genuinely missing. Existing rows default to
//      'volunteer' so they continue to appear on the Volunteer Roster page.
// ============================================================================
add_action( 'admin_init', function () {
    global $wpdb;
    $table = $wpdb->prefix . 'sp_volunteer_roles';

    // Bail early if the table doesn't exist yet (fresh install — sp_create_tables
    // will handle it via the CREATE TABLE statement that already includes role_type).
    if ( $wpdb->get_var( "SHOW TABLES LIKE '{$table}'" ) !== $table ) {
        return;
    }

    $col = $wpdb->get_results( "SHOW COLUMNS FROM {$table} LIKE 'role_type'" );
    if ( empty( $col ) ) {
        $wpdb->query( "ALTER TABLE {$table} ADD COLUMN role_type VARCHAR(20) NOT NULL DEFAULT 'volunteer' AFTER committee" );
        $wpdb->query( "ALTER TABLE {$table} ADD KEY role_type (role_type)" );
    }
} );


// ============================================================================
// MIGRATION: Add external event columns to sp_events for existing installs
//
// WHY: External events (manual URLs and iCal imports) need four new columns in
//      sp_events. dbDelta sometimes fails to add columns to existing tables, so
//      we do an explicit check-and-add. The check (SHOW COLUMNS) is cheap —
//      the ALTER only fires if the columns are genuinely missing.
// ============================================================================
add_action( 'admin_init', function () {
    global $wpdb;
    $table = $wpdb->prefix . 'sp_events';

    // Bail early if the table doesn't exist yet (fresh install — sp_create_tables
    // will handle it via the CREATE TABLE statement that already includes these columns).
    if ( $wpdb->get_var( "SHOW TABLES LIKE '{$table}'" ) !== $table ) {
        return;
    }

    // external_url — holds the URL for manual external events and iCal imports
    $col = $wpdb->get_results( "SHOW COLUMNS FROM {$table} LIKE 'external_url'" );
    if ( empty( $col ) ) {
        $wpdb->query( "ALTER TABLE {$table} ADD COLUMN external_url VARCHAR(500) NULL AFTER recurrence_end_date" );
    }

    // external_source — 'manual' for hand-entered URLs, 'ical_feed' for imported events
    $col = $wpdb->get_results( "SHOW COLUMNS FROM {$table} LIKE 'external_source'" );
    if ( empty( $col ) ) {
        $wpdb->query( "ALTER TABLE {$table} ADD COLUMN external_source VARCHAR(20) NULL DEFAULT NULL AFTER external_url" );
        $wpdb->query( "ALTER TABLE {$table} ADD KEY external_source (external_source)" );
    }

    // external_uid — the UID from the iCal VEVENT, used for deduplication on sync
    $col = $wpdb->get_results( "SHOW COLUMNS FROM {$table} LIKE 'external_uid'" );
    if ( empty( $col ) ) {
        $wpdb->query( "ALTER TABLE {$table} ADD COLUMN external_uid VARCHAR(255) NULL DEFAULT NULL AFTER external_source" );
        $wpdb->query( "ALTER TABLE {$table} ADD KEY external_uid (external_uid)" );
    }

    // feed_id — FK to sp_ical_feeds, links imported events to their source feed
    $col = $wpdb->get_results( "SHOW COLUMNS FROM {$table} LIKE 'feed_id'" );
    if ( empty( $col ) ) {
        $wpdb->query( "ALTER TABLE {$table} ADD COLUMN feed_id BIGINT(20) UNSIGNED NULL DEFAULT NULL AFTER external_uid" );
        $wpdb->query( "ALTER TABLE {$table} ADD KEY feed_id (feed_id)" );
    }
} );


// ============================================================================
// DEACTIVATION — Clean up cron jobs on plugin deactivation
// ============================================================================

register_deactivation_hook( __FILE__, function () {
    // Clean up scheduled cron jobs so they don't fire on a plugin that
    // isn't loaded anymore. Settings and data are preserved — this only
    // removes the timer, not the data.
    wp_clear_scheduled_hook( 'sp_renewal_reminder_cron' );
    wp_clear_scheduled_hook( 'sp_email_log_cleanup_cron' );
    wp_clear_scheduled_hook( 'sp_ical_feed_sync_cron' );
});

// ============================================================================
// ENCRYPTION UTILITIES
// ============================================================================
//
// WHY: SocietyPress stores sensitive data in the database — Stripe API keys,
//      SMTP credentials, etc. These should never be stored in plaintext.
//      We use PHP's sodium extension (built into PHP 7.2+) for authenticated
//      encryption. The encryption key is derived from WordPress's AUTH_KEY
//      and SECURE_AUTH_KEY constants (defined in wp-config.php), so each
//      site has a unique key without requiring any extra configuration.
//
// USAGE:
//   $encrypted = sp_encrypt( 'sk_live_abc123' );     // Store this in DB
//   $plaintext = sp_decrypt( $encrypted );            // Retrieve original
//   sp_setting_encrypt( 'stripe_secret_key', $key );  // Encrypt + save setting
//   $key = sp_setting_decrypt( 'stripe_secret_key' ); // Retrieve + decrypt setting
//
// SECURITY NOTES:
//   - Uses XChaCha20-Poly1305 (sodium) — authenticated encryption, tamper-proof
//   - Each encryption generates a unique random nonce — same plaintext produces
//     different ciphertext every time
//   - If AUTH_KEY changes (wp-config.php replaced), encrypted data becomes
//     unrecoverable. This is acceptable — it's the same risk as WordPress
//     session cookies, and it means a database dump alone can't reveal secrets.

/**
 * Derive a 32-byte encryption key from WordPress's secret keys.
 *
 * WHY: We don't want to ask the admin to configure a separate encryption key.
 *      WordPress already has strong secret keys in wp-config.php — we derive
 *      our encryption key from those. Using hash('sha256', ...) produces a
 *      consistent 32-byte key suitable for sodium.
 *
 * @return string 32-byte binary key.
 */
function sp_get_encryption_key(): string {
    // Combine two WordPress secrets so that knowing just one isn't enough.
    // AUTH_KEY and SECURE_AUTH_KEY are defined in wp-config.php and are
    // unique per installation (WordPress generates them during setup).
    $material = ( defined( 'AUTH_KEY' ) ? AUTH_KEY : 'sp-fallback-auth' )
              . ( defined( 'SECURE_AUTH_KEY' ) ? SECURE_AUTH_KEY : 'sp-fallback-secure' );

    return hash( 'sha256', $material, true ); // 32 bytes, binary
}

/**
 * Encrypt a string using sodium (XChaCha20-Poly1305).
 *
 * WHY: This is the go-to authenticated encryption in libsodium. It's fast,
 *      safe, and nonce-misuse-resistant (24-byte nonce = astronomically low
 *      collision probability even with random nonces).
 *
 * @param string $plaintext The data to encrypt.
 * @return string Base64-encoded ciphertext (nonce + ciphertext).
 *                Returns empty string if encryption fails.
 */
function sp_encrypt( string $plaintext ): string {
    if ( $plaintext === '' ) {
        return '';
    }

    // sodium must be available (it is on PHP 7.2+ / 8.x)
    if ( ! function_exists( 'sodium_crypto_secretbox' ) ) {
        // Fallback: return the plaintext base64-encoded with a prefix so
        // sp_decrypt() knows it wasn't actually encrypted. This should
        // never happen on PHP 8.3, but better than crashing.
        return 'noenc:' . base64_encode( $plaintext );
    }

    $key   = sp_get_encryption_key();
    $nonce = random_bytes( SODIUM_CRYPTO_SECRETBOX_NONCEBYTES ); // 24 bytes

    $ciphertext = sodium_crypto_secretbox( $plaintext, $nonce, $key );

    // Prepend the nonce to the ciphertext so we can extract it on decrypt.
    // Base64-encode the whole thing for safe storage in wp_options / DB columns.
    return base64_encode( $nonce . $ciphertext );
}

/**
 * Decrypt a string that was encrypted with sp_encrypt().
 *
 * @param string $encrypted Base64-encoded string from sp_encrypt().
 * @return string|false The original plaintext, or false if decryption fails
 *                      (tampered data, wrong key, etc.).
 */
function sp_decrypt( string $encrypted ) {
    if ( $encrypted === '' ) {
        return '';
    }

    // Handle the "noenc:" fallback prefix
    if ( strpos( $encrypted, 'noenc:' ) === 0 ) {
        return base64_decode( substr( $encrypted, 6 ) );
    }

    if ( ! function_exists( 'sodium_crypto_secretbox_open' ) ) {
        return false;
    }

    $decoded = base64_decode( $encrypted, true );
    if ( $decoded === false ) {
        return false;
    }

    $key        = sp_get_encryption_key();
    $nonce_len  = SODIUM_CRYPTO_SECRETBOX_NONCEBYTES; // 24

    if ( strlen( $decoded ) < $nonce_len ) {
        return false;
    }

    $nonce      = substr( $decoded, 0, $nonce_len );
    $ciphertext = substr( $decoded, $nonce_len );

    $plaintext = sodium_crypto_secretbox_open( $ciphertext, $nonce, $key );

    // sodium_crypto_secretbox_open returns false if the MAC check fails
    // (data was tampered with, or the key is wrong).
    return $plaintext;
}

/**
 * Encrypt a value and store it in the SocietyPress settings array.
 *
 * WHY: Convenience wrapper. Instead of:
 *        $s = get_option('societypress_settings', []);
 *        $s['stripe_secret_key'] = sp_encrypt($key);
 *        update_option('societypress_settings', $s);
 *      Just call:
 *        sp_setting_encrypt('stripe_secret_key', $key);
 *
 * @param string $key     The settings key (e.g., 'stripe_secret_key').
 * @param string $value   The plaintext value to encrypt and store.
 */
function sp_setting_encrypt( string $key, string $value ): void {
    $settings = get_option( 'societypress_settings', [] );
    $settings[ $key ] = sp_encrypt( $value );
    update_option( 'societypress_settings', $settings );
}

/**
 * Retrieve and decrypt a value from the SocietyPress settings array.
 *
 * @param string $key     The settings key (e.g., 'stripe_secret_key').
 * @return string|false   The decrypted value, or false if not found or decryption fails.
 */
function sp_setting_decrypt( string $key ) {
    $settings = get_option( 'societypress_settings', [] );
    if ( ! isset( $settings[ $key ] ) || $settings[ $key ] === '' ) {
        return '';
    }
    return sp_decrypt( $settings[ $key ] );
}

// ============================================================================
// CONTACT FIELD ENCRYPTION — Encrypt sensitive member data at rest
// ============================================================================
//
// WHY: GDPR and data protection best practices call for encrypting personally
//      identifiable information at rest. If the database is ever compromised
//      (SQL injection, backup leak, hosting breach), encrypted fields are
//      unreadable without the AUTH_KEY from wp-config.php.
//
// WHICH FIELDS: We encrypt fields that are NEVER used in SQL WHERE/LIKE/ORDER BY:
//   - cell, work_phone, alt_phone, fax (phone numbers beyond primary)
//   - address_1, address_2 (street addresses)
//   - seasonal_address_1 (seasonal street address)
//
// NOT ENCRYPTED (used in directory search/sort): phone, city, state,
//   postal_code, country, alt_email. Encrypting these would break search
//   and sorting functionality.
//
// HOW: sp_member_encrypt_fields() runs before every DB write to sp_members.
//      sp_member_decrypt_row() runs after every DB read from sp_members.
//      Both are no-ops for empty/null values. Decryption gracefully handles
//      plaintext data (pre-migration) so the transition is non-destructive.
// ============================================================================

/**
 * Fields in sp_members that are encrypted at rest.
 *
 * WHY as a function not a constant: Functions are available immediately at any
 *     point in the PHP execution, even before the class/constant is fully loaded.
 *     Also allows easy extension in the future.
 *
 * @return string[] Column names to encrypt/decrypt.
 */
function sp_encrypted_member_fields(): array {
    return [ 'cell', 'work_phone', 'alt_phone', 'fax', 'address_1', 'address_2', 'seasonal_address_1' ];
}

/**
 * Encrypt sensitive fields in a member data array before DB write.
 *
 * WHY: Called before $wpdb->insert() and $wpdb->update() on sp_members.
 *      Modifies the array in-place — fields listed in sp_encrypted_member_fields()
 *      get replaced with their encrypted (base64) values. Empty/null values
 *      are left alone.
 *
 * @param array $data Associative array of column => value pairs (modified in-place).
 */
function sp_member_encrypt_fields( array &$data ): void {
    foreach ( sp_encrypted_member_fields() as $field ) {
        if ( isset( $data[ $field ] ) && $data[ $field ] !== null && $data[ $field ] !== '' ) {
            $data[ $field ] = sp_encrypt( (string) $data[ $field ] );
        }
    }
}

/**
 * Decrypt sensitive fields on a member row after DB read.
 *
 * WHY: Called after $wpdb->get_row() / get_results() when reading from sp_members.
 *      Handles both object and array rows. Gracefully falls back to the raw value
 *      if decryption fails (e.g., plaintext data from before encryption was enabled).
 *      This means migration is non-destructive — unencrypted data still works.
 *
 * @param object|array|null $row A single member row from the database.
 * @return object|array|null The same row with encrypted fields decrypted.
 */
function sp_member_decrypt_row( $row ) {
    if ( ! $row ) {
        return $row;
    }

    $fields = sp_encrypted_member_fields();

    if ( is_object( $row ) ) {
        foreach ( $fields as $field ) {
            if ( isset( $row->$field ) && $row->$field !== null && $row->$field !== '' ) {
                $decrypted = sp_decrypt( $row->$field );
                // If decryption fails (returns false), the data is probably still
                // plaintext from before migration. Leave it as-is.
                if ( $decrypted !== false ) {
                    $row->$field = $decrypted;
                }
            }
        }
    } elseif ( is_array( $row ) ) {
        foreach ( $fields as $field ) {
            if ( isset( $row[ $field ] ) && $row[ $field ] !== null && $row[ $field ] !== '' ) {
                $decrypted = sp_decrypt( $row[ $field ] );
                if ( $decrypted !== false ) {
                    $row[ $field ] = $decrypted;
                }
            }
        }
    }

    return $row;
}

/**
 * Decrypt sensitive fields on an array of member rows.
 *
 * WHY: Convenience wrapper for get_results() which returns multiple rows.
 *
 * @param array $rows Array of member row objects.
 * @return array The same array with encrypted fields decrypted on each row.
 */
function sp_member_decrypt_rows( array $rows ): array {
    foreach ( $rows as &$row ) {
        $row = sp_member_decrypt_row( $row );
    }
    return $rows;
}

/**
 * One-time migration: encrypt existing plaintext contact data.
 *
 * WHY: When this feature is first deployed, all existing member contact data
 *      is stored in plaintext. This function reads each member row, encrypts
 *      the target fields, and writes them back. It runs once on plugin
 *      activation (checked via a version flag in options) and skips rows
 *      that are already encrypted (sp_decrypt succeeds, meaning it's either
 *      encrypted or very short plaintext that coincidentally base64-decodes).
 *
 * SAFETY: Even if this runs twice, sp_encrypt() produces different ciphertext
 *         each time (random nonce), but sp_decrypt_row() handles the already-
 *         encrypted case gracefully — it decrypts first, then re-encrypts.
 */
function sp_maybe_migrate_encrypt_contacts(): void {
    // Only run once — flag stored in options
    if ( get_option( 'sp_contacts_encrypted' ) ) {
        return;
    }

    global $wpdb;
    $table  = $wpdb->prefix . 'sp_members';
    $fields = sp_encrypted_member_fields();

    // Process in batches to avoid memory issues on large member tables
    $batch_size = 100;
    $offset     = 0;

    // Build a SELECT that only fetches the fields we need
    $select_cols = 'user_id, ' . implode( ', ', $fields );

    while ( true ) {
        $rows = $wpdb->get_results( $wpdb->prepare(
            "SELECT {$select_cols} FROM {$table} LIMIT %d OFFSET %d",
            $batch_size, $offset
        ) );

        if ( empty( $rows ) ) {
            break;
        }

        foreach ( $rows as $row ) {
            $updates = [];
            foreach ( $fields as $field ) {
                $val = $row->$field ?? '';
                if ( $val === '' || $val === null ) {
                    continue;
                }

                // Check if already encrypted — try to decrypt it.
                // If decryption succeeds AND the result differs from the stored value,
                // it's already encrypted. Skip it.
                $test = sp_decrypt( $val );
                if ( $test !== false && $test !== $val ) {
                    // Already encrypted — skip this field
                    continue;
                }

                // It's plaintext — encrypt it
                $updates[ $field ] = sp_encrypt( $val );
            }

            if ( ! empty( $updates ) ) {
                $wpdb->update( $table, $updates, [ 'user_id' => $row->user_id ] );
            }
        }

        $offset += $batch_size;
    }

    update_option( 'sp_contacts_encrypted', 1, true );
}


// ============================================================================
// CURRENCY FORMATTING
//
// WHY: The plugin hardcoded '$' throughout finances, tiers, payments, store,
//      and donations. Non-US societies need €, £, ¥, etc. This function reads
//      from settings so Harold configures it once (Settings → Organization)
//      and every monetary display respects it.
// ============================================================================

/**
 * Format a monetary amount with the configured currency symbol and position.
 *
 * WHY: Centralizes all currency display so societies outside the US can use
 *      their own symbol (€, £, ¥, etc.) and position (before or after the
 *      amount). Harold sets this once in Settings → Organization and every
 *      monetary value in admin, frontend, and emails picks it up.
 *
 * @param float|string $amount The numeric amount.
 * @param bool         $html   Whether to wrap in a <span> for styling (default false).
 * @return string Formatted amount like "$25.00" or "25.00 €".
 */
function sp_format_currency( $amount, bool $html = false ): string {
    $settings = get_option( 'societypress_settings', [] );
    $symbol   = $settings['currency_symbol'] ?? '$';
    $position = $settings['currency_position'] ?? 'before';
    $formatted = number_format( (float) $amount, 2 );

    if ( $position === 'after' ) {
        $result = $formatted . $symbol;
    } else {
        $result = $symbol . $formatted;
    }

    return $html ? '<span class="sp-currency">' . esc_html( $result ) . '</span>' : $result;
}

/**
 * Get just the configured currency symbol.
 *
 * WHY: JavaScript code needs the raw symbol and position to format amounts
 *      client-side. This avoids duplicating the settings lookup everywhere.
 *
 * @return string The currency symbol (e.g., '$', '€', '£').
 */
function sp_get_currency_symbol(): string {
    $settings = get_option( 'societypress_settings', [] );
    return $settings['currency_symbol'] ?? '$';
}

/**
 * Get the configured currency position.
 *
 * WHY: JavaScript code needs to know whether the symbol goes before or after
 *      the amount. Paired with sp_get_currency_symbol() for client-side use.
 *
 * @return string 'before' or 'after'.
 */
function sp_get_currency_position(): string {
    $settings = get_option( 'societypress_settings', [] );
    return $settings['currency_position'] ?? 'before';
}


