/**
 * Replace the entire WordPress admin sidebar with a single SocietyPress menu.
 *
 * WHY: WordPress's default admin has 12+ menu items designed for bloggers
 *      and developers. Our users are running genealogical society websites.
 *      We hide WordPress entirely and present SocietyPress as "the application."
 *
 *      All items are registered flat under one 'societypress' parent. JavaScript
 *      (injected via admin_head below) reorganises the flat submenu into grouped
 *      flyout panels so it LOOKS like three levels even though WordPress only
 *      supports two.
 *
 * WHAT THE USER SEES:
 *
 *   SocietyPress
 *   ├── Members          → All Members, Add New, Import
 *   ├── Events           (placeholder)
 *   ├── Governance       (placeholder)
 *   ├── Library          (standalone, placeholder)
 *   ├── Finances         (standalone, placeholder)
 *   ├── Appearance       → Pages, Media
 *   └── Settings         → Settings
 */
add_action( 'admin_menu', function () {
    global $wpdb;

    // ---- SocietyPress = Dashboard (parent menu) ----
    // Clicking "SocietyPress" in the sidebar takes the user straight to their
    // dashboard. Position 2 puts it at the very top of the sidebar.
    // WHY sp_access_admin: Non-admin SP staff (Treasurer, Librarian, etc.)
    // need to see this top-level menu. The user_has_cap filter grants
    // sp_access_admin to anyone with at least one access area. WordPress
    // admins (manage_options) get it automatically.
    add_menu_page(
        'SocietyPress',
        'SocietyPress',
        'sp_access_admin',
        'societypress',
        'sp_render_dashboard_page',
        'dashicons-groups',
        2
    );

    // WordPress automatically creates a submenu entry that duplicates the parent.
    // We nuke it in admin_head after the entire menu is built.
    add_action( 'admin_head', function () {
        global $submenu;
        if ( isset( $submenu['societypress'] ) ) {
            foreach ( $submenu['societypress'] as $key => $item ) {
                if ( $item[2] === 'societypress' ) {
                    unset( $submenu['societypress'][ $key ] );
                    break;
                }
            }
        }
    } );

    // -----------------------------------------------------------------
    // MEMBERS GROUP — All Members, Add New (hidden), Import
    // WHY: Members is the core of what a society does. These flat items
    //      get grouped into a "Members" flyout by the JS below.
