add_action( 'admin_menu', function () {
    global $menu, $submenu;

    $cap_map = sp_get_menu_capability_map();

    // Remap the top-level menu's capability (belt & suspenders — we already
    // set it to sp_access_admin in add_menu_page, but future-proofing).
    if ( isset( $menu ) && is_array( $menu ) ) {
        foreach ( $menu as &$item ) {
            if ( ( $item[2] ?? '' ) === 'societypress' && isset( $cap_map['societypress'] ) ) {
                $item[1] = $cap_map['societypress'];
                break;
            }
        }
        unset( $item );
    }

    // Remap all SocietyPress submenu items
    if ( isset( $submenu['societypress'] ) ) {
        foreach ( $submenu['societypress'] as &$item ) {
            $slug = $item[2] ?? '';
            if ( isset( $cap_map[ $slug ] ) ) {
                $item[1] = $cap_map[ $slug ];
            }
        }
        unset( $item );
    }

    // Also remap hidden pages (null or '' parent — stored in $submenu[''])
    $hidden_parents = [ '', null ];
    foreach ( $hidden_parents as $parent ) {
        $parent_key = (string) $parent;
        if ( ! isset( $submenu[ $parent_key ] ) ) continue;
        foreach ( $submenu[ $parent_key ] as &$item ) {
            $slug = $item[2] ?? '';
            if ( isset( $cap_map[ $slug ] ) ) {
                $item[1] = $cap_map[ $slug ];
            }
        }
        unset( $item );
    }

}, 998 ); // Priority 998 = after all menus registered (999) but before module filter (1000)


// ============================================================================
// MODULE-BASED MENU FILTERING — Hide admin menus for disabled modules
//
// WHY: Rather than wrapping each add_submenu_page() call in a module check
//      (which would be fragile and scatter conditional logic across 100+ lines),
//      we let all menus register normally, then remove the ones belonging to
//      disabled modules in a single pass. This is cleaner and means enabling
//      a module later "just works" — the menus reappear automatically.
// ============================================================================
add_action( 'admin_menu', function () {
    $all_modules = sp_get_modules();

    foreach ( $all_modules as $slug => $module ) {
        if ( sp_module_enabled( $slug ) ) continue;

        // Remove all menu items for this disabled module
        foreach ( $module['menu_slugs'] as $menu_slug ) {
            remove_submenu_page( 'societypress', $menu_slug );
        }
    }
}, 1000 ); // Priority 1000 = after all menus are registered AND after WP cleanup


// ============================================================================
// ADMIN BAR (TOOLBAR) — Replace default items with SocietyPress
// ============================================================================

/**
 * Clean up the WordPress admin bar so it only shows SocietyPress.
 *
 * WHY: When viewing the site while logged in, WordPress shows a toolbar at
 *      the top with "Dashboard", "Plugins", "Themes", "Widgets", "Menus"
 *      under the site name dropdown. Harold doesn't need any of that — he
 *      should only see "SocietyPress" which takes him straight to the admin.
 *      We remove all default items and add our own.
 */
add_action( 'admin_bar_menu', function ( $wp_admin_bar ) {

    // Remove the default site-name dropdown children
    // (Dashboard, Themes, Customize, Widgets, Menus, Plugins)
    $wp_admin_bar->remove_node( 'dashboard' );
    $wp_admin_bar->remove_node( 'themes' );
    $wp_admin_bar->remove_node( 'customize' );
    $wp_admin_bar->remove_node( 'widgets' );
    $wp_admin_bar->remove_node( 'menus' );

    // Remove Plugins (only shows for admins, but we still don't want it)
    // The node ID varies — could be 'plugins' or embedded in appearance
    $wp_admin_bar->remove_node( 'plugins' );

    // Add SocietyPress as the only item under the site name
    $wp_admin_bar->add_node( [
        'parent' => 'site-name',
        'id'     => 'sp-admin',
        'title'  => 'SocietyPress',
        'href'   => admin_url( 'admin.php?page=societypress' ),
    ] );

}, 999 ); // Late priority to run after WP adds its default nodes


// ============================================================================
// WP-NATIVE PAGES LIST — Show all pages (no pagination)
// ============================================================================
//
// WHY: WordPress's native edit.php?post_type=page screen defaults to 20 items
//      per page. Most societies have under 50 pages, so paginating is just an
//      annoyance. This filter forces the per-page count to 999 so Harold sees
//      all pages on one screen without needing to click through pages.
// ============================================================================

add_filter( 'edit_page_per_page', function () {
    return 999;
} );


// ============================================================================
// ADMIN FOOTER — Remove WordPress branding
// ============================================================================
//
// WHY: "Thank you for creating with WordPress" and "Version 6.9.1" in the
//      footer are confusing noise for a non-technical admin. Harold doesn't
//      need to know what WordPress is or what version he's running. Replace
//      with our own branding so the entire admin feels like SocietyPress.
// ============================================================================

// Left side: "Thank you for creating with WordPress" → SocietyPress branding
add_filter( 'admin_footer_text', function () {
    /* translators: %s: product name (SocietyPress) */
    return '<span id="footer-thankyou">' . sprintf( esc_html__( 'Powered by %s', 'societypress' ), '<strong>SocietyPress</strong>' ) . '</span>';
});

// Right side: "Version 6.9.1" → SocietyPress version
add_filter( 'update_footer', function () {
    return 'SocietyPress ' . SOCIETYPRESS_VERSION;
}, 11 ); // Priority 11 = override WordPress's default (priority 10)

// ============================================================================
// SVG UPLOAD SUPPORT
// ============================================================================
//
// WHY: WordPress blocks SVG uploads by default because SVGs can contain
//      embedded JavaScript (XSS vector). On a multi-user site that's a real
//      concern — but SocietyPress sites have a single admin (Harold), so the
//      risk is essentially zero. Society logos are frequently SVGs, and Harold
//      needs to upload them through the Media Library / Customizer without
//      hitting a "file type not permitted" wall.
//
//      Locked to manage_options so only full admins can upload SVGs — if a
//      site ever adds editor/author roles, they won't get this ability.
// ============================================================================

add_filter( 'upload_mimes', function ( $mimes ) {
    if ( current_user_can( 'manage_options' ) ) {
        $mimes['svg']  = 'image/svg+xml';
        $mimes['svgz'] = 'image/svg+xml';
    }
    return $mimes;
} );

// WHY: WordPress 4.7.1+ runs a "real MIME type" check using fileinfo/getimagesize.
//      SVGs fail this check because they're XML, not a binary image format.
//      This filter tells WordPress "yes, this SVG is what it claims to be"
//      so the upload doesn't get rejected after the MIME type whitelist passes.
add_filter( 'wp_check_filetype_and_ext', function ( $data, $file, $filename, $mimes ) {
    if ( ! current_user_can( 'manage_options' ) ) {
        return $data;
    }

    $ext = strtolower( pathinfo( $filename, PATHINFO_EXTENSION ) );
    if ( $ext === 'svg' || $ext === 'svgz' ) {
        $data['ext']  = $ext;
        $data['type'] = 'image/svg+xml';
    }

    return $data;
}, 10, 4 );


// ============================================================================
// FONT FAMILY HELPERS
// ============================================================================
//
// WHY: The font-name-to-CSS-font-family mapping was duplicated in three places:
//      the Design System CSS vars output, the login page styles, and the login
//      acknowledgment modal. A single canonical source prevents drift and makes
//      adding new fonts a one-line change.
// ============================================================================

/**
 * Get the full font-name → CSS font-family map.
 *
 * WHY: Every place that converts a stored font key (e.g. 'georgia') into a
 *      CSS font-family string should call this instead of maintaining its
 *      own copy of the map. One map, one place to update.
 *
 * @return array<string, string> Font key => CSS font-family value.
 */
function sp_get_font_family_options(): array {
    return [
        'system'       => "-apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, Oxygen, Ubuntu, Cantarell, sans-serif",
        'inter'        => '"Inter", sans-serif',
        'georgia'      => "Georgia, 'Times New Roman', serif",
        'palatino'     => "'Palatino Linotype', 'Book Antiqua', Palatino, serif",
        'garamond'     => "'EB Garamond', Georgia, serif",
        'merriweather' => "Merriweather, Georgia, serif",
        'lora'         => "Lora, Georgia, serif",
        'roboto'       => "Roboto, -apple-system, BlinkMacSystemFont, sans-serif",
        'open-sans'    => "'Open Sans', -apple-system, BlinkMacSystemFont, sans-serif",
        'source-sans'  => "'Source Sans 3', -apple-system, BlinkMacSystemFont, sans-serif",
        'nunito'       => "Nunito, -apple-system, BlinkMacSystemFont, sans-serif",
        'lato'         => '"Lato", sans-serif',
    ];
}

/**
 * Look up the CSS font-family string for a given font key.
 *
 * WHY: Callers that just need the CSS value for one font shouldn't have to
 *      grab the full map, look up the key, and handle the fallback themselves.
 *      This does all three in one call.
 *
 * @param string|null $font_key Font key (e.g. 'georgia'). Null = use the
 *                              design_font_body setting, falling back to 'system'.
 * @return string CSS font-family value.
 */
function sp_get_font_family_css( ?string $font_key = null ): string {
    $map = sp_get_font_family_options();
    if ( $font_key === null ) {
        $settings = get_option( 'societypress_settings', [] );
        $font_key = $settings['design_font_body'] ?? 'system';
    }
    return $map[ $font_key ] ?? $map['system'];
}


// ============================================================================
// MEMBER STATUS HELPERS
// ============================================================================
//
// WHY: The list of valid member statuses was duplicated across the members list
//      table filter, the member edit form dropdown, and the import mapper. A
//      single canonical source prevents drift and ensures every dropdown/filter
//      shows the same options.
// ============================================================================

/**
 * Get the canonical list of member statuses with translated labels.
 *
 * WHY: Every place that builds a status dropdown, validates a status value, or
 *      displays a status label should call this instead of maintaining its own
 *      copy. One list, one place to update.
 *
 * @return array<string, string> Status key => Translated label.
 */
function sp_get_member_statuses(): array {
    return [
        'active'   => __( 'Active', 'societypress' ),
        'expired'  => __( 'Expired', 'societypress' ),
        'lapsed'   => __( 'Lapsed', 'societypress' ),
        'grace'    => __( 'Grace Period', 'societypress' ),
        'pending'  => __( 'Pending', 'societypress' ),
        'inactive' => __( 'Inactive', 'societypress' ),
        'deceased' => __( 'Deceased', 'societypress' ),
    ];
}


/**
 * Compute phonetic codes for a surname.
 *
 * WHY: Genealogists constantly deal with surname spelling variations across
 * census records, immigration documents, and family branches. Soundex is the
 * classic algorithm (used on US Census records since 1880). Metaphone is more
 * accurate for non-Anglo names common in Texas genealogy (Garcia/Garza,
 * Mueller/Muller). Storing both lets us offer "sounds like" matching that
 * connects members researching the same family under different spellings.
 *
 * @param string $surname The surname to encode.
 * @return array { soundex: string, metaphone: string }
 */
function sp_surname_phonetic_codes( string $surname ): array {
    return [
        'soundex'   => soundex( $surname ),
        'metaphone' => metaphone( $surname ),
    ];
}

/**
 * Backfill phonetic codes for all existing surnames that don't have them.
 *
 * WHY: Surnames added before this feature was built have NULL soundex/metaphone
 * columns. This runs once on upgrade (via the admin_init version check) and
 * fills them in. It's idempotent — only touches rows with NULL codes.
 */
function sp_maybe_backfill_surname_phonetics(): void {
    global $wpdb;
    $table = $wpdb->prefix . 'sp_member_surnames';

    $rows = $wpdb->get_results(
        "SELECT id, surname FROM {$table} WHERE soundex_code IS NULL OR metaphone_code IS NULL"
    );

    foreach ( $rows as $row ) {
        $wpdb->update( $table, [
            'soundex_code'   => soundex( $row->surname ),
            'metaphone_code' => metaphone( $row->surname ),
        ], [ 'id' => $row->id ] );
    }
}


// ============================================================================
// FRONTEND: DESIGN SYSTEM — CSS CUSTOM PROPERTIES
// ============================================================================
//
// WHY THIS IS IN THE PLUGIN, NOT THE THEME:
//      These CSS custom properties are the bridge between the Design settings
//      (stored in the plugin's societypress_settings option) and the theme's
//      stylesheet (which references --sp-color-primary, --sp-font-body, etc.).
//      The plugin owns the data, so the plugin should output it. This way,
//      ANY theme (parent or child) can use these variables without needing
//      its own copy of this logic.
//
// WHY priority 1: Must load in <head> before the theme stylesheet so the
//      variables are defined before anything tries to use them.

add_action( 'wp_head', function () {

    $settings = get_option( 'societypress_settings', [] );

    // --- Color defaults (match the theme's original hardcoded values) ---
    $primary       = $settings['design_color_primary']      ?? '#1e3a5f';
    $primary_hover = $settings['design_color_primary_hover'] ?? '#2c5282';
    $accent        = $settings['design_color_accent']        ?? '#667eea';
    $header_bg     = $settings['design_color_header_bg']     ?? '#1e3a5f';
    $header_text   = $settings['design_color_header_text']   ?? '#ffffff';
    $footer_bg     = $settings['design_color_footer_bg']     ?? '#1e3a5f';
    $footer_text   = $settings['design_color_footer_text']   ?? '#ffffff';

    // Use the canonical font map — no more inline duplicates
    $font_map = sp_get_font_family_options();

    $body_key    = $settings['design_font_body']    ?? 'system';
    $heading_key = $settings['design_font_heading']  ?? 'inherit';
    $font_body   = $font_map[ $body_key ] ?? $font_map['system'];
    $font_heading = ( $heading_key === 'inherit' ) ? 'inherit' : ( $font_map[ $heading_key ] ?? 'inherit' );

    $size_map = [ 'compact' => '16px', 'comfortable' => '18px', 'large' => '20px' ];
    $font_size = $size_map[ $settings['design_font_size'] ?? 'comfortable' ] ?? '18px';

    $scale_map = [ 'small' => '0.85', 'normal' => '1', 'large' => '1.15' ];
    $font_scale = $scale_map[ $settings['design_heading_scale'] ?? 'normal' ] ?? '1';

    $width_key = $settings['design_content_width'] ?? 'standard';
    if ( $width_key === 'custom' ) {
        $content_width = max( 600, min( 2000, (int) ( $settings['design_content_width_px'] ?? 1100 ) ) ) . 'px';
    } else {
        $width_map = [ 'narrow' => '900px', 'standard' => '1100px', 'wide' => '1400px' ];
        $content_width = $width_map[ $width_key ] ?? '1100px';
    }

    $header_height = (int) ( $settings['design_header_height'] ?? 0 );

    echo '<style id="sp-design-vars">
:root {
    --sp-color-primary: ' . esc_attr( $primary ) . ';
    --sp-color-primary-hover: ' . esc_attr( $primary_hover ) . ';
    --sp-color-accent: ' . esc_attr( $accent ) . ';
    --sp-color-header-bg: ' . esc_attr( $header_bg ) . ';
    --sp-color-header-text: ' . esc_attr( $header_text ) . ';
    --sp-color-footer-bg: ' . esc_attr( $footer_bg ) . ';
    --sp-color-footer-text: ' . esc_attr( $footer_text ) . ';
    --sp-font-body: ' . $font_body . ';
    --sp-font-heading: ' . $font_heading . ';
    --sp-font-size-base: ' . esc_attr( $font_size ) . ';
    --sp-font-scale: ' . esc_attr( $font_scale ) . ';
    --sp-content-width: ' . esc_attr( $content_width ) . ';
}
' . ( $header_height ? '.site-header .header-inner { height: ' . $header_height . 'px; align-items: center; }
body { padding-top: ' . ( $header_height + 3 ) . 'px; }' : '' ) . '
</style>' . "\n";

}, 1 );


// ============================================================================
// FRONTEND: GOOGLE FONTS LOADER
// ============================================================================

add_action( 'wp_head', function () {
    $settings = get_option( 'societypress_settings', [] );
    $google_fonts = [
        'garamond'     => 'EB+Garamond:wght@400;500;600;700',
        'merriweather' => 'Merriweather:wght@400;700',
        'lora'         => 'Lora:wght@400;500;600;700',
        'roboto'       => 'Roboto:wght@400;500;700',
        'open-sans'    => 'Open+Sans:wght@400;500;600;700',
        'source-sans'  => 'Source+Sans+3:wght@400;500;600;700',
        'nunito'       => 'Nunito:wght@400;500;600;700',
    ];
    $body_key    = $settings['design_font_body']    ?? 'system';
    $heading_key = $settings['design_font_heading']  ?? 'inherit';
    $families = [];
    if ( isset( $google_fonts[ $body_key ] ) ) $families[] = $google_fonts[ $body_key ];
    if ( $heading_key !== 'inherit' && $heading_key !== $body_key && isset( $google_fonts[ $heading_key ] ) ) {
        $families[] = $google_fonts[ $heading_key ];
    }
    if ( empty( $families ) ) return;
    echo '<link rel="preconnect" href="https://fonts.googleapis.com">' . "\n";
    echo '<link rel="preconnect" href="https://fonts.gstatic.com" crossorigin>' . "\n";
    echo '<link href="https://fonts.googleapis.com/css2?family=' . implode( '&family=', $families ) . '&display=swap" rel="stylesheet">' . "\n";
}, 0 );


// ============================================================================
// FRONTEND: GOOGLE ANALYTICS
// ============================================================================
//
// WHY: Most societies want page view tracking for grant applications, board
//      reports, or general curiosity. Rather than requiring a separate plugin,
//      we output the official gtag.js snippet when a GA4 Measurement ID is
//      configured in Settings → Website. Admin traffic can be excluded so
//      Harold's own browsing doesn't skew the numbers.

add_action( 'wp_head', function () {

    // Don't output analytics on admin pages — only the public-facing site.
    if ( is_admin() ) {
        return;
    }

    $settings = get_option( 'societypress_settings', [] );
    $ga_id    = $settings['analytics_google_id'] ?? '';

    // No measurement ID configured — nothing to output.
    if ( empty( $ga_id ) ) {
        return;
    }

    // If "exclude admins" is on and the current user is an administrator,
    // skip the tracking snippet entirely. This is more reliable than GA
    // filters because it never sends the hit in the first place.
    if ( ! empty( $settings['analytics_exclude_admins'] ) && current_user_can( 'manage_options' ) ) {
        return;
    }

    // Output the standard Google Analytics 4 (gtag.js) snippet.
    // WHY async: Google recommends async loading so the script doesn't
    // block page rendering. The dataLayer push pattern is Google's
    // official integration method for GA4.
    $escaped_id = esc_attr( $ga_id );
    echo "<!-- SocietyPress: Google Analytics -->\n";
    echo '<script async src="https://www.googletagmanager.com/gtag/js?id=' . $escaped_id . '"></script>' . "\n";
    echo "<script>\n";
    echo "window.dataLayer = window.dataLayer || [];\n";
    echo "function gtag(){dataLayer.push(arguments);}\n";
    echo "gtag('js', new Date());\n";
    echo "gtag('config', '" . $escaped_id . "');\n";
    echo "</script>\n";

}, 5 );


// ============================================================================
// FRONTEND: ADMIN BAR TOGGLE + LOAD DASHICONS
// ============================================================================

// WHY: The admin bar is handy during development but Harold doesn't need it.
// Controlled by Settings → Website → "Admin Toolbar" checkbox.
// When off (default), the bar is hidden on the frontend for everyone.
add_filter( 'show_admin_bar', function ( $show ) {
    $sp = get_option( 'societypress_settings', [] );
    if ( empty( $sp['website_show_admin_bar'] ) ) {
        return false;
    }
    return $show;
} );

// WHY: Dashicons are only needed for logged-in users (admin bar, My Account
//      icons). Loading them for anonymous visitors wastes ~46KB of CSS + font.
add_action( 'wp_enqueue_scripts', function () {
    if ( is_user_logged_in() ) {
        wp_enqueue_style( 'dashicons' );
    }
} );


// ============================================================================
// MY ACCOUNT — URL Helper
// ============================================================================

function sp_get_my_account_url() {
    static $url = null;
    if ( $url !== null ) return $url;
    $pages = get_pages([ 'meta_key' => '_wp_page_template', 'meta_value' => 'page-my-account.php', 'number' => 1 ]);
    $url = ! empty( $pages ) ? get_permalink( $pages[0]->ID ) : home_url( '/' );
    return $url;
}


// ============================================================================
// MEMBER RECORD — Helper
// ============================================================================

function sp_user_has_member_record( $user_id ) {

    global $wpdb;
    return (bool) $wpdb->get_var(
        $wpdb->prepare( "SELECT COUNT(*) FROM {$wpdb->prefix}sp_members WHERE user_id = %d", $user_id )
    );
}


// ============================================================================
// EMAIL OBFUSCATION — Hide email addresses from scrapers on the frontend
// ============================================================================
//
// WHY: Bots crawl pages looking for mailto: links and plaintext email addresses.
//      Instead of rendering emails directly, we split each address at the "@",
//      base64-encode both halves, and store them in data attributes on a <span>.
//      A small JS snippet (injected via wp_footer) assembles the real address
//      and creates a clickable mailto: link on page load. Since almost no email
//      harvester executes JavaScript, this blocks the vast majority of scrapers
//      while keeping emails fully functional for real visitors.
//
// USAGE: Anywhere you'd normally echo an email on the frontend, call:
//        echo sp_obfuscate_email( $email_address );
//
//        The JS assembler runs automatically on every frontend page.

/**
 * Returns an obfuscated <span> that JS will convert to a mailto: link.
 *
 * Falls back to an empty string for invalid/empty emails so callers
 * don't need to guard against nulls.
 */
function sp_obfuscate_email( string $email ): string {
    if ( ! $email || ! is_email( $email ) ) {
        return '';
    }

    $parts = explode( '@', $email, 2 );

    return sprintf(
        '<span class="sp-eml" data-u="%s" data-d="%s"></span>',
        esc_attr( base64_encode( $parts[0] ) ),
        esc_attr( base64_encode( $parts[1] ) )
    );
}

/**
 * Frontend JS: assembles obfuscated email spans into real mailto: links.
 *
 * WHY wp_footer: The script runs after all page content has rendered, so
 * every .sp-eml span — including those injected by AJAX callbacks that
 * write HTML before the footer — will be picked up. We also expose a
 * global spAssembleEmails() so dynamically-built HTML (like the member
 * detail modal) can trigger assembly on demand.
 */
add_action( 'wp_footer', function () {
    // Only run on the frontend, never in wp-admin
    if ( is_admin() ) {
        return;
    }
    ?>
    <script>
    (function(){
        /**
         * Find every .sp-eml span in the given root (or the whole document),
         * decode the two base64 halves, and replace the span with a real
         * <a href="mailto:..."> link.
         */
        function spAssembleEmails(root) {
            (root || document).querySelectorAll('.sp-eml').forEach(function(el) {
                try {
                    var u = atob(el.getAttribute('data-u') || '');
                    var d = atob(el.getAttribute('data-d') || '');
                    if (!u || !d) return;
                    var addr = u + '@' + d;
                    var a = document.createElement('a');
                    a.href = 'mailto:' + addr;
                    a.textContent = addr;
                    el.parentNode.replaceChild(a, el);
                } catch(e) {
                    // Malformed base64 — leave the span as-is
                }
            });
        }
        // Run once on page load for all server-rendered emails
        spAssembleEmails();
        // Expose globally so AJAX-built HTML can call it after insertion
        window.spAssembleEmails = spAssembleEmails;
    })();
    </script>
    <?php
}, 99 ); // Priority 99: run after other wp_footer scripts so all spans exist


