            line-height: 1.7;
            color: #333;
            margin: 0 0 14px;
        }

        .sp-acknowledge-modal .sp-acknowledge-btn {
            display: block;
            width: 100%;
            margin-top: 24px;
            padding: 12px;
            background: <?php echo esc_attr( $primary ); ?>;
            color: #fff;
            border: none;
            border-radius: 6px;
            font-size: 1rem;
            font-weight: 600;
            cursor: pointer;
            transition: background 0.2s;
        }

        .sp-acknowledge-modal .sp-acknowledge-btn:hover {
            background: <?php echo esc_attr( $primary_hover ); ?>;
        }
    </style>
    <?php
} );

/**
 * Add the pre-login privacy notice above the login form.
 *
 * WHY: The society's policy requires members to read the acceptable-use
 *      notice before logging in. This filter adds it above the form on
 *      the standard login action only (not on password reset, etc.).
 */
add_filter( 'login_message', function ( $message ) {
    // Only show on the main login form, not on password reset or registration
    $action = isset( $_GET['action'] ) ? $_GET['action'] : 'login';
    if ( $action !== 'login' ) {
        return $message;
    }

    $settings = get_option( 'societypress_settings', [] );
    $org_email = $settings['organization_email'] ?? '';

    $notice  = '<div class="sp-login-notice">';
    $notice .= '<h2>Important Notice</h2>';
    $notice .= '<p>This information is for members only; please do not share your ID and password with non-members. Names and contact information are provided to assist members in collaborating on society projects and in genealogical research. The use of this information for commercial, political, personal, or religious purposes is strictly forbidden. It would show a lack of respect for the privacy of our members and would reduce their willingness to share contact data. Any violation will be considered a serious offense and will have consequences.</p>';
    $notice .= '<p>Just as you would not share your private family conversations or your family financial matters with the general public, please do not share our financial reports, board meeting notes, etc. with non-members. In an effort to keep our members well informed, we are exceptionally open with this data within our membership. However, it is not intended for public dissemination.</p>';

    if ( $org_email ) {
        $notice .= '<p>' . esc_html__( 'If you have any membership questions, please contact the Membership Chair at ', 'societypress' ) . sp_obfuscate_email( $org_email ) . '.</p>';
    } else {
        $notice .= '<p>' . esc_html__( 'If you have any membership questions, please contact the Membership Chair.', 'societypress' ) . '</p>';
    }

    $notice .= '</div>';

    return $notice . $message;
} );

/**
 * Change the "Username or Email Address" label to "Login Name".
 * Also add help text below the form.
 *
 * WHY: "Username or Email Address" is WordPress jargon. Society members
 *      know their "login name" — that's what they were given. We also add
 *      help text explaining what to do if they've forgotten their credentials.
 *      Injected via login_footer because WordPress doesn't have a filter
 *      for individual form field labels — we use JavaScript to swap it.
 */
add_action( 'login_footer', function () {
    $action = isset( $_GET['action'] ) ? $_GET['action'] : 'login';
    if ( $action !== 'login' ) {
        return;
    }
    ?>
    <div class="sp-login-help" id="sp-login-help" style="display:none;">
        <strong>Login Problem?</strong><br>
        Click the "Lost your password?" link above if you have forgotten your
        password. Enter your login name or email address and password reset
        instructions will be sent to the email address associated with your
        membership profile.
    </div>
    <script>
        (function() {
            // Move the help text inside #login so it centers with everything else
            var help = document.getElementById('sp-login-help');
            var login = document.getElementById('login');
            if (help && login) {
                login.appendChild(help);
                help.style.display = '';
            }

            // WHY: WordPress hardcodes "Username or Email Address" as the label.
            //      There's no PHP filter for it, so we swap it client-side.
            var label = document.querySelector('label[for="user_login"]');
            if (label) {
                var firstText = label.childNodes[0];
                if (firstText && firstText.nodeType === 3) {
                    firstText.textContent = 'Login Name';
                }
            }

            // WHY: WordPress blocks paste on the password field, which breaks
            //      password managers like BitWarden. Remove all paste-blocking
            //      event handlers so members can paste their passwords normally.
            var passField = document.getElementById('user_pass');
            if (passField) {
                passField.onpaste = null;
                passField.addEventListener('paste', function(e) { e.stopImmediatePropagation(); }, true);
            }
        })();
    </script>
    <?php
} );

/**
 * Point the login header link to the site home (instead of wordpress.org).
 *
 * WHY: The default login page links the logo to wordpress.org. We've hidden
 *      the logo, but if it somehow shows, it should link home — not to WP.
 */
add_filter( 'login_headerurl', function () {
    return home_url( '/' );
} );

add_filter( 'login_headertext', function () {
    $settings = get_option( 'societypress_settings', [] );
    return $settings['organization_name'] ?? get_bloginfo( 'name' );
} );


// ============================================================================
// POST-LOGIN ACKNOWLEDGMENT — Full privacy notice after successful login
// ============================================================================
//
// WHY: Society leadership requires members to see and acknowledge the full
//      acceptable-use policy after every login. This is more detailed than
//      the pre-login notice and includes specific legal consequences. A
//      transient flag is set at login time; on the first admin page load,
//      a blocking modal is shown. The member must click "I Understand" to
//      dismiss it. The flag is cleared so it won't show again until the
//      next login.

/**
 * Set a transient flag when a user successfully logs in.
 *
 * WHY: We need to know "this user just logged in and hasn't acknowledged
 *      the notice yet." A transient with a short TTL (1 hour) works well —
 *      if they close the browser and come back, they're already past the
 *      WordPress session check anyway and would need to log in again.
 */
add_action( 'wp_login', function ( $user_login, $user ) {
    set_transient( 'sp_login_ack_' . $user->ID, 1, HOUR_IN_SECONDS );
}, 10, 2 );

/**
 * AJAX handler to dismiss the acknowledgment.
 *
 * WHY: When the member clicks "I Understand," JavaScript fires an AJAX
 *      request to delete the transient. This way the modal doesn't show
 *      on subsequent page loads within the same session.
 */
add_action( 'wp_ajax_sp_dismiss_login_ack', function () {
    $user_id = get_current_user_id();
    if ( $user_id ) {
        delete_transient( 'sp_login_ack_' . $user_id );
    }
    wp_send_json_success();
} );

/**
 * Show the post-login acknowledgment modal on admin pages.
 *
 * WHY: This hooks into admin_footer so the modal HTML is injected at the
 *      bottom of the page. It only renders if the transient flag exists
 *      (meaning the user just logged in and hasn't acknowledged yet).
 *      The modal is a full-screen overlay that blocks all interaction
 *      until the member clicks "I Understand."
 */
add_action( 'admin_footer', function () {
    $user_id = get_current_user_id();
    if ( ! $user_id ) return;

    // Check if this user just logged in and hasn't acknowledged yet
    $needs_ack = get_transient( 'sp_login_ack_' . $user_id );
    if ( ! $needs_ack ) return;

    $settings  = get_option( 'societypress_settings', [] );
    $primary   = $settings['design_color_primary'] ?? '#1e3a5f';
    $primary_hover = $settings['design_color_primary_hover'] ?? '#2c5282';

    // Use the canonical font map instead of a local duplicate
    $font_family = sp_get_font_family_css( $settings['design_font_body'] ?? null );
    ?>
    <div class="sp-acknowledge-overlay" id="sp-login-ack-overlay">
        <div class="sp-acknowledge-modal">
            <h2>Important Notice</h2>
            <p>This information is for members only; please do not share your ID and password with non-members or other members. Each member in good standing has been provided their own individual ID and password. Names and contact information are provided to assist members in collaborating on society projects and in genealogical research. The use of this information for commercial, political, personal, or religious purposes is strictly forbidden. It would show a lack of respect for the privacy of our dedicated members and would reduce their willingness to share contact data. Any violation will be considered a serious offense and will have legal consequences. Appropriate action will be taken immediately upon violation of this policy and will result in immediate loss of membership, in addition to legal consequences.</p>
            <p>Just as you would not share your private family conversations or your family financial matters with the general public, please do not share our financial reports, board meeting notes, etc. with non-members. In an effort to keep our members well informed, we are open with this data within our membership. However, it is not intended for public dissemination for any reason. Individuals who violate the confidential nature of this information will be dealt with by the Board of Directors and appropriate action will be taken, including immediate loss of membership.</p>
            <?php
            // WHY: The contact email was hardcoded to President@upstream-society.org. Every society
            // needs their own email here, so we pull from the org_email setting instead.
            $sp_ack_settings = get_option( 'societypress_settings', [] );
            $sp_ack_email    = $sp_ack_settings['org_email'] ?? '';
            ?>
            <p><?php echo esc_html__( 'If you have any questions, please contact us at ', 'societypress' ); ?><?php echo $sp_ack_email ? sp_obfuscate_email( $sp_ack_email ) : ''; ?>.</p>
            <button type="button" class="sp-acknowledge-btn" id="sp-login-ack-btn">I Understand</button>
        </div>
    </div>
    <style>
        .sp-acknowledge-overlay {
            position: fixed;
            top: 0; left: 0; right: 0; bottom: 0;
            background: rgba(0,0,0,0.6);
            z-index: 999999;
            display: flex;
            align-items: center;
            justify-content: center;
        }
        .sp-acknowledge-modal {
            background: #fff;
            border-radius: 12px;
            max-width: 640px;
            width: 90%;
            max-height: 85vh;
            overflow-y: auto;
            padding: 32px 36px;
            box-shadow: 0 8px 40px rgba(0,0,0,0.3);
            font-family: <?php echo $font_family; ?>;
        }
        .sp-acknowledge-modal h2 {
            font-size: 1.3rem;
            font-weight: 700;
            color: <?php echo esc_attr( $primary ); ?>;
            margin: 0 0 20px;
        }
        .sp-acknowledge-modal p {
            font-size: 0.9rem;
            line-height: 1.7;
            color: #333;
            margin: 0 0 14px;
        }
        .sp-acknowledge-modal a {
            color: <?php echo esc_attr( $primary ); ?>;
        }
        .sp-acknowledge-btn {
            display: block;
            width: 100%;
            margin-top: 24px;
            padding: 12px;
            background: <?php echo esc_attr( $primary ); ?>;
            color: #fff;
            border: none;
            border-radius: 6px;
            font-size: 1rem;
            font-weight: 600;
            cursor: pointer;
            transition: background 0.2s;
        }
        .sp-acknowledge-btn:hover {
            background: <?php echo esc_attr( $primary_hover ); ?>;
        }
    </style>
    <script>
        // WHY: When the member clicks "I Understand," we dismiss the modal
        //      and fire an AJAX request to clear the transient so it won't
        //      show on the next page load. The modal removal is instant —
        //      we don't wait for the AJAX response.
        document.getElementById('sp-login-ack-btn').addEventListener('click', function() {
            document.getElementById('sp-login-ack-overlay').remove();
            var xhr = new XMLHttpRequest();
            xhr.open('POST', ajaxurl, true);
            xhr.setRequestHeader('Content-Type', 'application/x-www-form-urlencoded');
            xhr.send('action=sp_dismiss_login_ack&_ajax_nonce=<?php echo wp_create_nonce( 'sp_dismiss_login_ack' ); ?>');
        });
    </script>
    <?php
} );


// ============================================================================
// REUSABLE CONFIRMATION MODAL — Replaces browser confirm() dialogs
// ============================================================================

/**
 * Output a styled, accessible confirmation modal on every admin page.
 *
 * WHY: Browser confirm() dialogs are ugly, unstylable, and vary wildly
 *      between browsers. For destructive actions like deleting members,
 *      we need a modal that (a) looks professional, (b) clearly labels
 *      what will happen, (c) focuses the CANCEL button by default so
 *      destructive actions require a deliberate move to "Confirm," and
 *      (d) traps focus for keyboard-only users (accessibility).
 *
 *      The modal exposes a global `spConfirm()` function that returns a
 *      Promise, making it a drop-in replacement for confirm():
 *
 *        spConfirm('Delete Member', 'This is permanent.', 'Delete', 'Cancel')
 *          .then(function(ok) { if (!ok) return; // proceed });
 *
 *      An optional 5th parameter `{ danger: true }` styles the confirm
 *      button red for destructive actions.
 *
 * UX issue #9: Replace browser confirm() dialogs with styled modals.
 */
add_action( 'admin_footer', function () {
    // Only render on SocietyPress admin pages — no need to pollute
    // every single WP admin page with modal HTML.
    $screen = get_current_screen();
    if ( ! $screen ) return;

    // Check if we're on a SocietyPress page (page slug starts with 'sp-')
    // or the WP page editor (where our builder lives).
    $is_sp_page = (
        isset( $_GET['page'] ) && str_starts_with( $_GET['page'], 'sp-' )
    ) || $screen->id === 'page' || $screen->id === 'dashboard';

    if ( ! $is_sp_page ) return;

    // Default button labels — passed through i18n so translators can
    // localize them. Individual calls to spConfirm() can override these.
    $default_confirm = esc_js( __( 'Confirm', 'societypress' ) );
    $default_cancel  = esc_js( __( 'Cancel', 'societypress' ) );
    ?>
    <!-- Reusable confirmation modal (UX issue #9) -->
    <div id="sp-confirm-modal" role="dialog" aria-modal="true" aria-labelledby="sp-confirm-title" style="display:none;">
        <div class="sp-confirm-overlay"></div>
        <div class="sp-confirm-box">
            <h3 id="sp-confirm-title"></h3>
            <p id="sp-confirm-message"></p>
            <div class="sp-confirm-actions">
                <button type="button" class="button sp-confirm-cancel"><?php echo esc_html__( 'Cancel', 'societypress' ); ?></button>
                <button type="button" class="button button-primary sp-confirm-ok"><?php echo esc_html__( 'Confirm', 'societypress' ); ?></button>
            </div>
        </div>
    </div>
    <style>
        /* ---- Confirmation modal overlay ---- */
        #sp-confirm-modal {
            position: fixed;
            inset: 0;
            z-index: 100100; /* Above WP modals (100000) and admin bar (99999) */
            display: flex;
            align-items: center;
            justify-content: center;
        }
        .sp-confirm-overlay {
            position: absolute;
            inset: 0;
            background: rgba(0, 0, 0, 0.5);
        }
        .sp-confirm-box {
            position: relative;
            background: #fff;
            padding: 24px 28px;
            border-radius: 8px;
            max-width: 480px;
            width: 90%;
            box-shadow: 0 8px 32px rgba(0, 0, 0, 0.3);
        }
        #sp-confirm-title {
            margin: 0 0 12px;
            font-size: 16px;
            font-weight: 600;
            color: #1d2327;
        }
        #sp-confirm-message {
            margin: 0 0 20px;
            color: #50575e;
            font-size: 14px;
            line-height: 1.5;
            /* WHY: preserve \n line breaks in messages (e.g. multi-line
               warnings about deleting all members) */
            white-space: pre-line;
        }
        .sp-confirm-actions {
            display: flex;
            justify-content: flex-end;
            gap: 8px;
        }
        /* Danger variant — red confirm button for destructive actions */
        .sp-confirm-ok.sp-confirm-danger {
            background: #d63638;
            border-color: #d63638;
            color: #fff;
        }
        .sp-confirm-ok.sp-confirm-danger:hover,
        .sp-confirm-ok.sp-confirm-danger:focus {
            background: #b32d2e;
            border-color: #b32d2e;
        }
    </style>
    <script>
    /**
     * Global confirmation modal — returns a Promise that resolves to
     * true (confirmed) or false (cancelled).
     *
     * @param {string} title         - Modal heading text
     * @param {string} message       - Body text (supports \n for line breaks)
     * @param {string} confirmLabel  - Text for the confirm button
     * @param {string} cancelLabel   - Text for the cancel button
     * @param {object} opts          - Options: { danger: true } styles the confirm button red
     * @returns {Promise<boolean>}
     */
    window.spConfirm = function(title, message, confirmLabel, cancelLabel, opts) {
        // Defaults — uses the i18n labels baked into the PHP output above
        confirmLabel = confirmLabel || '<?php echo $default_confirm; ?>';
        cancelLabel  = cancelLabel  || '<?php echo $default_cancel; ?>';
        opts         = opts || {};

        return new Promise(function(resolve) {
            var modal      = document.getElementById('sp-confirm-modal');
            var overlay    = modal.querySelector('.sp-confirm-overlay');
            var titleEl    = document.getElementById('sp-confirm-title');
            var messageEl  = document.getElementById('sp-confirm-message');
            var okBtn      = modal.querySelector('.sp-confirm-ok');
            var cancelBtn  = modal.querySelector('.sp-confirm-cancel');

            // Remember what was focused before so we can restore it afterward
            var previousFocus = document.activeElement;

            // Set content
            titleEl.textContent   = title;
            messageEl.textContent = message;
            okBtn.textContent     = confirmLabel;
            cancelBtn.textContent = cancelLabel;

            // Danger mode — red confirm button for destructive actions
            if (opts.danger) {
                okBtn.classList.add('sp-confirm-danger');
            } else {
                okBtn.classList.remove('sp-confirm-danger');
            }

            // Show the modal
            modal.style.display = 'flex';

            // Focus the cancel button by default — the safe choice.
            // WHY: For destructive actions, making the user actively
            //      move to the confirm button is an important safety net.
            cancelBtn.focus();

            // ---- Cleanup function (runs once on any resolution) ----
            function cleanup() {
                modal.style.display = 'none';
                okBtn.removeEventListener('click', onOk);
                cancelBtn.removeEventListener('click', onCancel);
                overlay.removeEventListener('click', onCancel);
                document.removeEventListener('keydown', onKeydown);

                // Restore focus to the element that triggered the modal
                if (previousFocus && previousFocus.focus) {
                    previousFocus.focus();
                }
            }

            function onOk() {
                cleanup();
                resolve(true);
            }

            function onCancel() {
                cleanup();
                resolve(false);
            }

            // ---- Keyboard handling ----
            function onKeydown(e) {
                // Escape key closes the modal (same as Cancel)
                if (e.key === 'Escape') {
                    e.preventDefault();
                    onCancel();
                    return;
                }

                // Tab key — trap focus within the modal (cycle between
                // the two buttons). This is required for accessibility:
                // screen reader users must not be able to tab behind the
                // overlay to interact with the page beneath.
                if (e.key === 'Tab') {
                    // Only two focusable elements: cancelBtn and okBtn
                    if (e.shiftKey) {
                        // Shift+Tab: if on cancel, wrap to ok
                        if (document.activeElement === cancelBtn) {
                            e.preventDefault();
                            okBtn.focus();
                        }
                    } else {
                        // Tab: if on ok, wrap to cancel
                        if (document.activeElement === okBtn) {
                            e.preventDefault();
                            cancelBtn.focus();
                        }
                    }
                }
            }

            // Attach listeners
            okBtn.addEventListener('click', onOk);
            cancelBtn.addEventListener('click', onCancel);
            overlay.addEventListener('click', onCancel);
            document.addEventListener('keydown', onKeydown);
        });
    };
    </script>
    <?php
}, 5 ); // Priority 5 — render early so spConfirm is available to later admin_footer scripts


// ============================================================================
// ADMIN BAR CLEANUP — Remove WordPress branding and irrelevant links
// ============================================================================

/**
 * Clean up the admin toolbar (the bar across the top of every page).
 *
 * WHY: The default toolbar has a WordPress logo, links to Comments, and
 *      shortcuts to create Posts and Users — all things we've hidden from
 *      the sidebar. Leaving them in the toolbar would be confusing and
 *      inconsistent. We keep the essentials: site name (to visit the site),
 *      the + New button (for Pages and Media only), and the user menu
 *      (to log out or edit profile).
 */
add_action( 'wp_before_admin_bar_render', function () {
    global $wp_admin_bar;

    $wp_admin_bar->remove_node( 'wp-logo' );    // WordPress logo + "About WordPress"
    $wp_admin_bar->remove_node( 'comments' );    // Comments shortcut
    $wp_admin_bar->remove_node( 'new-post' );    // + New → Post
    $wp_admin_bar->remove_node( 'new-user' );    // + New → User
    $wp_admin_bar->remove_node( 'updates' );     // Updates notification badge

    // NOTE: WordPress already adds a "Log Out" link (id: 'logout') to the
    // user-actions group. A previous version of this code added a duplicate
    // 'sp-logout' node because we thought the default was removed — it wasn't.
    // No need to add anything here; the built-in logout link is sufficient.
});


// ============================================================================
// DASHBOARD WIDGET CLEANUP
// ============================================================================

/**
 * Remove default dashboard widgets that don't apply to SocietyPress.
 *
 * WHY: Even though we redirect away from the WordPress dashboard, these
 *      widgets can sometimes flash briefly during the redirect. Removing
 *      them is belt-and-suspenders — makes sure nothing confusing appears
 *      even if the redirect is slow.
 */
