            <!-- JavaScript: toggle individual vs organization fields -->
            <script>
            (function() {
                // WHY: When "Organization" is selected, we hide all the individual-specific
                //      name fields (prefix, first, preferred, middle, last, maiden, suffix,
                //      DOB, gender) and show the organization name field instead. When
                //      "Individual" is selected (default), we reverse that. The fields are
                //      hidden/shown via display:none so they don't submit empty values that
                //      would clear existing data — but the hidden fields still exist in the
                //      DOM and retain their values if the user switches back.
                var radios = document.querySelectorAll('input[name="member_type"]');
                var orgWrap = document.getElementById('sp-org-name-wrap');
                var personalSection = document.getElementById('sp-personal-section');

                function toggleType() {
                    var isOrg = document.querySelector('input[name="member_type"]:checked').value === 'organization';
                    orgWrap.style.display = isOrg ? '' : 'none';
                    if (personalSection) {
                        personalSection.style.display = isOrg ? 'none' : '';
                    }
                    // Toggle the required attribute on first/last name vs org name
                    var firstName = document.getElementById('sp-first-name');
                    var lastName = document.getElementById('sp-last-name');
                    var orgName = document.getElementById('sp-org-name');
                    if (firstName) firstName.required = !isOrg;
                    if (lastName) lastName.required = !isOrg;
                    if (orgName) orgName.required = isOrg;
                }

                radios.forEach(function(r) {
                    r.addEventListener('change', toggleType);
                });

                // Run once on load to set initial state
                toggleType();
            })();
            </script>

