                        <?php
                        // --- Country dropdown ---
                        // WHY: Country comes before State so JavaScript can swap
                        //      the State field between a dropdown (US/CA) and
                        //      freetext (everywhere else). ISO 2-letter codes
                        //      are the storage format.
                        $country_val = $member->country ?? 'US';
                        // Normalize legacy 3-letter codes that may exist in older data
                        $legacy_map = array(
                            'USA' => 'US', 'CAN' => 'CA', 'GBR' => 'GB', 'AUS' => 'AU',
                            'DEU' => 'DE', 'FRA' => 'FR', 'MEX' => 'MX', 'NZL' => 'NZ',
                            'IRL' => 'IE', 'ITA' => 'IT', 'ESP' => 'ES', 'BRA' => 'BR',
                        );
                        if ( isset( $legacy_map[ strtoupper( $country_val ) ] ) ) {
                            $country_val = $legacy_map[ strtoupper( $country_val ) ];
                        }
                        // Countries most likely for genealogical societies, US first
                        $countries = array(
                            'US' => 'United States',
                            'CA' => 'Canada',
                            'GB' => 'United Kingdom',
                            'AU' => 'Australia',
                            'NZ' => 'New Zealand',
                            'IE' => 'Ireland',
                            'DE' => 'Germany',
                            'FR' => 'France',
                            'IT' => 'Italy',
                            'ES' => 'Spain',
                            'MX' => 'Mexico',
                            'BR' => 'Brazil',
                            'NL' => 'Netherlands',
                            'SE' => 'Sweden',
                            'NO' => 'Norway',
                            'DK' => 'Denmark',
                            'FI' => 'Finland',
                            'PL' => 'Poland',
                            'CZ' => 'Czech Republic',
                            'AT' => 'Austria',
                            'CH' => 'Switzerland',
                            'PT' => 'Portugal',
                            'ZA' => 'South Africa',
                            'JP' => 'Japan',
                            'OTHER' => '— Other (type below) —',
                        );
