// ============================================================================
// IMPORT MEMBERS
// ============================================================================

/**
 * Handle the CSV import form submission.
 *
 * WHY: Societies migrating from EasyNetSites need a one-click import.
 *      This processes the combined CSV export (all 86 columns in one file)
 *      OR individual Member Records / Membership Plans / Membership Records
 *      files. It auto-detects the format from the header row.
 *
 * WHAT IT DOES:
 *   1. Parses the CSV (handles multi-line quoted fields like admin notes)
 *   2. Creates membership tiers that don't already exist
 *   3. Creates WordPress user accounts (without sending welcome emails)
 *   4. Inserts sp_members rows with all mapped fields
 *   5. Inserts sp_member_payments for the most recent payment
 *   6. Imports admin notes as sp_member_notes entries
 *   7. Returns a summary of what was imported
 */
function sp_process_import( string $file_path = '', array $field_map = [] ): array {
    global $wpdb;
    $prefix = $wpdb->prefix . 'sp_';

    // Suppress ALL user notification emails during bulk import.
    // WHY: wp_insert_user() fires the 'user_register' action, which WordPress
    //      hooks into to send "New User" and "Welcome" emails. Creating 400
    //      users in a loop would fire 400+ emails, hammering the mail server
    //      and confusing members who aren't expecting a welcome email from a
    //      site they didn't sign up for. The society can send a proper welcome
    //      announcement later. We unhook both the admin and user notifications.
    remove_action( 'register_new_user', 'wp_send_new_user_notifications' );
    remove_action( 'edit_user_created_user', 'wp_send_new_user_notifications' );
    add_filter( 'wp_send_new_user_notification_to_admin', '__return_false' );
    add_filter( 'wp_send_new_user_notification_to_user', '__return_false' );

    $results = [
        'imported'  => 0,
        'skipped'   => 0,
        'errors'    => [],
        'tiers_created' => [],
    ];

    // Accept either a pre-saved temp file (from the two-step preview flow)
    // or fall back to the direct upload (for any future single-step usage).
    if ( ! empty( $file_path ) && file_exists( $file_path ) ) {
        $file = $file_path;
    } elseif ( ! empty( $_FILES['import_file']['tmp_name'] ) ) {
        $file = $_FILES['import_file']['tmp_name'];
    } else {
        $results['errors'][] = 'No file was uploaded.';
        return $results;
    }

    // Parse the entire CSV into an array of associative arrays.
    // WHY: PHP's built-in fgetcsv() handles quoted fields with embedded
    //      newlines correctly, which is critical because EasyNetSites puts
    //      multi-line renewal notes inside quoted fields.
    $handle = fopen( $file, 'r' );
    if ( ! $handle ) {
        $results['errors'][] = 'Could not open the uploaded file.';
        return $results;
    }

    // Read the header row to get column names
    $headers = fgetcsv( $handle );
    if ( ! $headers ) {
        fclose( $handle );
        $results['errors'][] = 'The file appears to be empty.';
        return $results;
    }

    // Trim any BOM or whitespace from headers
    $headers = array_map( function( $h ) {
        return trim( $h, "\xEF\xBB\xBF \t\n\r" );
    }, $headers );

    // Build a lookup: header name → column index
    $col = array_flip( $headers );

    // ================================================================
    // Build the field mapping — target_key → CSV column name
    //
    // WHY: The admin may have rearranged the field mapping in the preview
    //      step, assigning CSV columns to different SocietyPress fields
    //      than the auto-detection suggested. The $field_map parameter
    //      is: csv_column_name → target_key (e.g. 'First Name' → 'first_name').
    //      We invert it to: target_key → csv_column_name so we can look
    //      up "which CSV column holds the first name?" easily.
    //
    //      If no field map was provided (backwards compatibility), we
    //      build one from the hardcoded EasyNetSites auto-detection so
    //      the function still works exactly as before.
    // ================================================================

    // Default EasyNetSites auto-detection map: CSV column → target key.
    // WHY: This is the original hardcoded mapping. When the admin doesn't
    //      customize the dropdowns (or for old callers that don't pass a map),
    //      this ensures the import works out of the box with EasyNetSites exports.
    $default_auto_map = [
        'First Name'                => 'first_name',
        'Last Name'                 => 'last_name',
        'Name Prefix'               => 'prefix',
        'PreferredName'             => 'preferred_name',
        'Middle Name'               => 'middle_name',
        'Maiden Name'               => 'maiden_name',
        'Name Suffix'               => 'suffix',
        'Email'                     => 'email',
        'Member Active'             => 'status',
        'Deceased'                  => 'deceased',
        'Member Join Date'          => 'join_date',
        'Expiration Date'           => 'expiration_date',
        'Birth Year'                => 'birth_year',
        'Birth Month'               => 'birth_month',
        'Birth Day'                 => 'birth_day',
        'Address 1'                 => 'address_1',
        'Address 2'                 => 'address_2',
        'City'                      => 'city',
        'State / Province'          => 'state',
        'Postal Code'               => 'postal_code',
        'Country'                   => 'country',
        'Telephone'                 => 'phone',
        'Cell Phone'                => 'cell',
        'Website'                   => 'website',
        'Alternate Address 1'       => 'seasonal_address',
        'Alt. City'                 => 'seasonal_city',
        'Alt. State / Province'     => 'seasonal_state',
        'Alt. Postal Code'          => 'seasonal_postal_code',
        'Al. Country'               => 'seasonal_country',
        'Use Seasonal Address'      => 'seasonal_flag',
        'Use Alt. Info Month Begin' => 'seasonal_month_begin',
        'Alt. Contact Day Begin'    => 'seasonal_day_begin',
        'Use Alt. Info Month End'   => 'seasonal_month_end',
        'Alt. Contact Day End'      => 'seasonal_day_end',
        'Quarterly'                 => 'pref_print',
        'General Email'             => 'pref_general_email',
        'Event Email'               => 'pref_event_email',
        'Newsletter Email'          => 'pref_newsletter',
        'Surname Inquiry'           => 'pref_surname',
        'Mbr. List - Show Name'     => 'dir_show_name',
        'Mbr. List - Show Address'  => 'dir_show_address',
        'Mbr. List - Show Phone'    => 'dir_show_phone',
        'Mbr. List - Show Email'    => 'dir_show_email',
        'Mbr. List - Show Photo'    => 'dir_show_photo',
        'Membership Plan'           => 'tier',
        'Membership Number'         => 'member_number',
        'Amount Paid'               => 'payment_amount',
        'Date Paid'                 => 'payment_date',
        'Payment Type'              => 'payment_method',
        'Donation'                  => 'payment_donation',
        'Comment'                   => 'payment_note',
        'Administrative Notes'      => 'admin_notes',
        // These EasyNetSites columns now have proper database columns.
        // WHY: Originally stored as meta key/value pairs, but these are
        //      real member attributes that deserve first-class columns for
        //      searching, sorting, and display in the admin UI.
        'Gender'                    => 'gender',
        'Volunteering?'             => 'volunteer',
        'Joint Member'              => 'joint_member',
        'Email of Joint'            => 'joint_email',
        'Phone of Joint'            => 'joint_phone',
        'Your Skills'               => 'skills',
        'Your Interests'            => 'interests',
        'Your Education'            => 'education',
        'Business Phone'            => 'work_phone',
        'Fax'                       => 'fax',
        'Address Label Name'        => 'label_name',
        'Login'                     => 'login',
        // WHY: "File Name" in the EasyNetSites export contains the organization
        //      name for institutional members (libraries, societies). We map it
        //      to organization_name so the import detects and creates org records.
        'File Name'                 => 'organization_name',
        // Remaining ENS columns — stored as custom meta so nothing is lost.
        // Most are empty or uniform, but they're here if we ever need them.
        'Contact'                   => '__meta',
        'UseMaiden'                 => '__meta',
        // 'Deceased' intentionally omitted — already mapped to 'deceased'
        // field above (line ~7988) for status logic. Duplicate keys in PHP
        // arrays silently overwrite, which broke the status mapping.
        'Image Filename'            => '__meta',
        'Toll Free Phone'           => '__meta',
        'International Phone'       => '__meta',
        'Preferred Phone'           => '__meta',
        'Alt. Address 2'            => '__meta',
        'Alt. Phone'                => '__meta',
        'Alt. International Phone'  => '__meta',
        'Alt. Preferred Phone'      => '__meta',
        'Alt. Email'                => '__meta',
        'Membership Type'           => '__meta',
        'Max Members'               => '__meta',
        'Mail Publication'          => '__meta',
        'Mail Publications'         => '__meta',
        'Acct. Primary'             => '__meta',
        'Membership Tie ID'         => '__meta',
        'Login Count'               => '__meta',
        'Last Login Date'           => '__meta',
        'Last Updated By'           => '__meta',
        'Last Updated Date'         => '__meta',
        'ENS Member Record ID'      => '__meta',
    ];

    // Use the admin's custom mapping, or fall back to auto-detection
    if ( empty( $field_map ) ) {
        // Build field_map from headers using auto-detection defaults
        foreach ( $headers as $header ) {
            if ( isset( $default_auto_map[ $header ] ) ) {
                $field_map[ $header ] = $default_auto_map[ $header ];
            } else {
                // Unknown column — store as custom meta so no data is lost
                $field_map[ $header ] = '__meta';
            }
        }
    }

    // Invert the field map: target_key → CSV column name.
    // Also collect columns marked as custom meta or skip.
    $target_to_csv = [];  // target_key → CSV column name (e.g. 'first_name' → 'First Name')
    $meta_columns  = [];  // CSV columns the admin chose to store as custom fields
    $skip_columns  = [];  // CSV columns the admin chose to ignore entirely
    foreach ( $field_map as $csv_col => $target ) {
        if ( $target === '__skip' ) {
            $skip_columns[] = $csv_col;
        } elseif ( $target === '__meta' ) {
            $meta_columns[] = $csv_col;
        } else {
            $target_to_csv[ $target ] = $csv_col;
        }
    }

    // Detect format — check if tier and payment fields are mapped
    // WHY: "Combined" exports include membership plan + payment data alongside
    //      member data. If the admin mapped tier and payment columns, we know
    //      to process those. If not, we just import member records.
    $has_tier    = isset( $target_to_csv['tier'] );
    $has_payment = isset( $target_to_csv['payment_amount'] );

    // Verify that the minimum required fields are mapped.
    // WHY: We need EITHER first+last name (individual) OR organization_name (org).
    //      If neither is mapped, we can't identify anyone in the CSV.
    $has_name_fields = isset( $target_to_csv['first_name'] ) && isset( $target_to_csv['last_name'] );
    $has_org_field   = isset( $target_to_csv['organization_name'] );
    if ( ! $has_name_fields && ! $has_org_field ) {
        fclose( $handle );
        $results['errors'][] = 'No columns are mapped to "First Name" and "Last Name" or "Organization Name." '
                             . 'Please go back and assign those fields in the mapping.';
        return $results;
    }

    // ================================================================
    // Helper: safely get a column value from a row by TARGET KEY.
    //
    // WHY: The admin's field mapping tells us which CSV column holds
    //      each piece of data. This helper looks up the CSV column
    //      name for a given target key, then fetches the value from
    //      that column in the current row. Returns empty string if
    //      the field wasn't mapped or the column doesn't exist.
    // ================================================================
    $get = function( array $row, string $target_key ) use ( $col, $target_to_csv ) {
        if ( ! isset( $target_to_csv[ $target_key ] ) ) return '';
        $csv_col = $target_to_csv[ $target_key ];
        if ( ! isset( $col[ $csv_col ] ) ) return '';
        return trim( $row[ $col[ $csv_col ] ] ?? '' );
    };

    // Helper: get a raw value by CSV column name (for meta and direct access).
    // WHY: Some lookups need the original CSV column name rather than a target
    //      key — specifically when processing custom meta fields and unknown columns.
    $get_raw = function( array $row, string $csv_col_name ) use ( $col ) {
        if ( ! isset( $col[ $csv_col_name ] ) ) return '';
        return trim( $row[ $col[ $csv_col_name ] ] ?? '' );
    };

    // ================================================================
    // Helper: convert EasyNetSites date (MM/DD/YYYY) to MySQL (YYYY-MM-DD)
    // ================================================================
    $parse_date = function( string $date_str ): string {
        if ( empty( $date_str ) ) return '';
        // Handle both MM/DD/YYYY and YYYY-MM-DD formats
        $dt = date_create( $date_str );
        if ( ! $dt ) return '';
        return $dt->format( 'Y-m-d' );
    };

    // ================================================================
    // Helper: convert Yes/No to 1/0
    // ================================================================
    $yes_no = function( string $val ): int {
        return ( strtolower( trim( $val ) ) === 'yes' || strtolower( trim( $val ) ) === 'y' ) ? 1 : 0;
    };

    // ================================================================
    // Helper: normalize country to ISO 2-letter code
    // ================================================================
    $normalize_country = function( string $val ): string {
        $val = strtoupper( trim( $val ) );
        if ( empty( $val ) ) return 'US'; // Default for US-based societies
        $map = [
            'USA' => 'US', 'US' => 'US', 'UNITED STATES' => 'US',
            'CAN' => 'CA', 'CA' => 'CA', 'CANADA' => 'CA',
            'GBR' => 'GB', 'GB' => 'GB', 'UK' => 'GB', 'UNITED KINGDOM' => 'GB',
            'AUS' => 'AU', 'AU' => 'AU', 'AUSTRALIA' => 'AU',
            'DEU' => 'DE', 'DE' => 'DE', 'GERMANY' => 'DE',
            'FRA' => 'FR', 'FR' => 'FR', 'FRANCE' => 'FR',
            'MEX' => 'MX', 'MX' => 'MX', 'MEXICO' => 'MX',
            'NZL' => 'NZ', 'NZ' => 'NZ', 'NEW ZEALAND' => 'NZ',
            'IRL' => 'IE', 'IE' => 'IE', 'IRELAND' => 'IE',
        ];
        return $map[ $val ] ?? $val;
    };

    // ================================================================
    // Helper: strip phone to digits only for clean storage
    // ================================================================
    $clean_phone = function( string $val ): string {
        $val = trim( $val );
        if ( empty( $val ) ) return '';
        // Leave international numbers alone
        if ( $val[0] === '+' ) return $val;
        return preg_replace( '/\D/', '', $val );
    };

    // ================================================================
    // Pre-load existing tier names → IDs so we don't create duplicates
    // ================================================================
    $tier_map = [];
    $existing_tiers = $wpdb->get_results(
        "SELECT id, name FROM {$prefix}membership_tiers"
    );
    foreach ( $existing_tiers as $t ) {
        $tier_map[ strtolower( $t->name ) ] = (int) $t->id;
    }

    // Keep track of the next sort_order for new tiers
    $max_sort = (int) $wpdb->get_var(
        "SELECT MAX(sort_order) FROM {$prefix}membership_tiers"
    );

    // ================================================================
    // Pre-load existing members for duplicate detection (email + name).
    // WHY: A duplicate email does NOT mean a duplicate record. Married
    //      couples and parents often share one email address. We only
    //      consider it a true duplicate if the email AND name are similar.
    //      Keyed by lowercase email → array of {user_id, first, last}.
    // ================================================================
    $existing_members = [];
    $existing_rows = $wpdb->get_results(
        "SELECT m.user_id, m.first_name, m.last_name, u.user_email
         FROM {$prefix}members m
         JOIN {$wpdb->users} u ON u.ID = m.user_id"
    );
    foreach ( $existing_rows as $er ) {
        $key = strtolower( $er->user_email );
        if ( ! isset( $existing_members[ $key ] ) ) {
            $existing_members[ $key ] = [];
        }
        $existing_members[ $key ][] = [
            'user_id' => (int) $er->user_id,
            'first'   => strtolower( trim( $er->first_name ) ),
            'last'    => strtolower( trim( $er->last_name ) ),
        ];
    }

    // ================================================================
    // Helper: check if a name matches any existing member under the
    //         same email. "Similar" means identical last name AND first
    //         name is either identical or one contains the other (catches
    //         "Bob" vs "Robert", "Liz" vs "Elizabeth" won't match, but
    //         that's safer than a false-positive skip).
    // ================================================================
    $is_name_similar = function( string $first, string $last, array $records ): bool {
        $fn = strtolower( trim( $first ) );
        $ln = strtolower( trim( $last ) );
        foreach ( $records as $rec ) {
            if ( $rec['last'] !== $ln ) continue;
            if ( $rec['first'] === $fn )                    return true;
            // WHY: The substring check catches "Bob" matching "Robert" won't work,
            //      but it DOES catch "Jo" matching "John" — which is a false positive.
            //      Requiring at least 4 characters for substring matching prevents
            //      short names like "Jo" from accidentally matching "John De La Garza".
            if ( strlen( $fn ) >= 4 && str_contains( $rec['first'], $fn ) ) return true;
            if ( strlen( $rec['first'] ) >= 4 && str_contains( $fn, $rec['first'] ) ) return true;
        }
        return false;
    };

    // ================================================================
    // Process each row
    // ================================================================
    $row_num = 1; // Header was row 1, data starts at row 2
    while ( ( $row = fgetcsv( $handle ) ) !== false ) {
        $row_num++;

        // Skip rows that don't have enough columns (malformed)
        if ( count( $row ) < 10 ) {
            continue;
        }

        $first_name = sanitize_text_field( $get( $row, 'first_name' ) );
        $last_name  = sanitize_text_field( $get( $row, 'last_name' ) );
        $email      = sanitize_email( $get( $row, 'email' ) );

        // Detect organizational members — no first/last name but has an org name.
        // WHY: The the society CSV has 29 institutional members (libraries, societies)
        //      whose names only exist in the "File Name" column. Instead of skipping
        //      these rows, we detect them as organizational members and store the
        //      organization name from either the explicit organization_name mapping
        //      or from the "File Name" column (which is mapped to __meta by default).
        $org_name    = sanitize_text_field( $get( $row, 'organization_name' ) );
        $member_type = 'individual';

        if ( empty( $first_name ) && empty( $last_name ) ) {
            // Try the organization_name mapping first, then fall back to File Name
            if ( empty( $org_name ) ) {
                $org_name = sanitize_text_field( $get_raw( $row, 'File Name' ) );
            }
            if ( ! empty( $org_name ) ) {
                // This is an organizational member
                $member_type = 'organization';
                // WHY: first_name and last_name are NOT NULL columns. For orgs we
                //      store the org name there too so sorts and searches still work.
                $first_name = $org_name;
                $last_name  = $org_name;
            } else {
                // Truly blank — no name at all, skip with an explanation
                $results['skipped']++;
                $results['errors'][] = "Row {$row_num}: Skipped — no first name, last name, or organization name found.";
                continue;
            }
        } elseif ( ! empty( $org_name ) ) {
            // Has both individual name fields AND an org name — treat as org
            $member_type = 'organization';
        }

        // Skip only if this email + name combination already exists.
        // WHY: Same email ≠ same person. Married couples share addresses.
        //      We compare names under that email — if the last name matches
        //      and the first name is identical or one contains the other,
        //      it's a true duplicate. Otherwise it's a family member who
        //      happens to share an inbox.
        if ( ! empty( $email ) && isset( $existing_members[ strtolower( $email ) ] ) ) {
            if ( $is_name_similar( $first_name, $last_name, $existing_members[ strtolower( $email ) ] ) ) {
                $results['skipped']++;
                $results['errors'][] = "Row {$row_num}: Skipped {$first_name} {$last_name} — already exists (same email and similar name).";
                continue;
            }
        }

        // ==============================================================
        // Resolve or create the membership tier
        // ==============================================================
        $tier_id = null;
        if ( $has_tier ) {
            $plan_name = sanitize_text_field( $get( $row, 'tier' ) );
            if ( ! empty( $plan_name ) ) {
                $key = strtolower( $plan_name );
                if ( isset( $tier_map[ $key ] ) ) {
                    $tier_id = $tier_map[ $key ];
                } else {
                    // Create the tier.
                    // WHY: If the CSV has a membership plan name we haven't seen
                    //      before, we auto-create it with $0 pricing. The admin
                    //      can set actual dues amounts later.
                    $max_sort++;
                    $wpdb->insert( $prefix . 'membership_tiers', [
                        'name'       => $plan_name,
                        'price'      => 0.00, // We don't know the price from the export
                        'sort_order' => $max_sort,
                        'active'     => 1,
                    ]);
                    $tier_id = (int) $wpdb->insert_id;
                    $tier_map[ $key ] = $tier_id;
                    $results['tiers_created'][] = $plan_name;
                }
            }
        }

        // ==============================================================
        // Build date of birth from separate Year/Month/Day columns
        // ==============================================================
        $dob = '';
        $birth_year  = $get( $row, 'birth_year' );
        $birth_month = $get( $row, 'birth_month' );
        $birth_day   = $get( $row, 'birth_day' );
        if ( ! empty( $birth_year ) && (int) $birth_year > 0 ) {
            $dob = sprintf(
                '%04d-%02d-%02d',
                (int) $birth_year,
                max( 1, (int) $birth_month ),
                max( 1, (int) $birth_day )
            );
        }

        // ==============================================================
        // Parse dates
        // ==============================================================
        $join_date      = $parse_date( $get( $row, 'join_date' ) );
        $expiration_date = $parse_date( $get( $row, 'expiration_date' ) );

        if ( empty( $join_date ) ) {
            $join_date = current_time( 'Y-m-d' );
        }

        // ==============================================================
        // Determine member status
        // ==============================================================
        $active_val = strtolower( $get( $row, 'status' ) );
        $deceased   = strtolower( $get( $row, 'deceased' ) );
        if ( $deceased === 'yes' ) {
            $status = 'inactive';
        } elseif ( $active_val === 'yes' || $active_val === 'y' ) {
            $status = 'active';
        } else {
            $status = 'lapsed';
        }

        // ==============================================================
        // Seasonal address fields
        // ==============================================================
        $seasonal = $yes_no( $get( $row, 'seasonal_flag' ) );
        $seasonal_from = '';
        $seasonal_to   = '';
        if ( $seasonal ) {
            // Seasonal months may be stored as full names or numbers
            $month_begin = $get( $row, 'seasonal_month_begin' );
            $month_end   = $get( $row, 'seasonal_month_end' );
            // Convert month name to number if needed
            if ( ! empty( $month_begin ) && ! is_numeric( $month_begin ) ) {
                $dt = date_create( "1 {$month_begin} 2000" );
                $month_begin = $dt ? $dt->format( 'n' ) : '';
            }
            if ( ! empty( $month_end ) && ! is_numeric( $month_end ) ) {
                $dt = date_create( "1 {$month_end} 2000" );
                $month_end = $dt ? $dt->format( 'n' ) : '';
            }
            $day_begin = $get( $row, 'seasonal_day_begin' ) ?: '1';
            $day_end   = $get( $row, 'seasonal_day_end' ) ?: '1';
            if ( ! empty( $month_begin ) ) {
                $seasonal_from = sprintf( '%02d-%02d', (int) $month_begin, (int) $day_begin );
            }
            if ( ! empty( $month_end ) ) {
                $seasonal_to = sprintf( '%02d-%02d', (int) $month_end, (int) $day_end );
            }
        }

        // ==============================================================
        // Create WordPress user account
        //
        // WHY the complexity: WordPress requires unique email addresses
        //      per user. But married couples (Joint memberships) often
        //      share one email. When we encounter a shared email for a
        //      DIFFERENT person, we create their WP user with a +suffix
        //      alias (e.g. bob.jane+sp2@gmail.com). Most mail servers
        //      deliver +suffix addresses to the base inbox, so the family
        //      still receives any emails WordPress sends. Notification
        //      emails are suppressed during import regardless.
        //
        //      If the CSV has a Login column mapped, we use that as the
        //      user_login (WordPress username). Otherwise we default to
        //      the email address as the username. Either way, WordPress
        //      requires user_login to be unique — if it's taken, we
        //      append a numeric suffix to make it unique.
        // ==============================================================

        // Use the imported login if available, otherwise fall back to email
        $imported_login = sanitize_user( $get( $row, 'login' ), true );

        if ( ! empty( $email ) ) {
            $existing_user = get_user_by( 'email', $email );
            if ( $existing_user ) {
                // A WP user already has this email. Check if that user is
                // already an sp_member with a similar name (true duplicate).
                $already = $wpdb->get_row( $wpdb->prepare(
                    "SELECT first_name, last_name FROM {$prefix}members WHERE user_id = %d",
                    $existing_user->ID
                ) );
                if ( $already && $is_name_similar( $first_name, $last_name, [ [
                    'first' => strtolower( $already->first_name ),
                    'last'  => strtolower( $already->last_name ),
                ] ] ) ) {
                    // Same person, already imported — skip
                    $results['skipped']++;
                    $results['errors'][] = "Row {$row_num}: Skipped {$first_name} {$last_name} — already imported.";
                    continue;
                }

                // Different person sharing the same email (spouse, parent, etc.).
                // Create a new WP user with a +suffix alias so WordPress
                // accepts it as unique. Mail still delivers to the same inbox.
                $parts  = explode( '@', $email );
                $suffix = 2;
                do {
                    $unique_email = $parts[0] . '+sp' . $suffix . '@' . $parts[1];
                    $suffix++;
                } while ( get_user_by( 'email', $unique_email ) );

                // For shared-email users, prefer imported login, then email alias
                $use_login = ! empty( $imported_login ) ? $imported_login : $unique_email;
                // Ensure login is unique — append number if taken
                if ( username_exists( $use_login ) ) {
                    $base = $use_login;
                    $n = 2;
                    do {
                        $use_login = $base . $n;
                        $n++;
                    } while ( username_exists( $use_login ) );
                }

                // WHY: Org members display their organization name everywhere, while
                //      individuals display "First Last". This affects the WP profile.
                $import_display = ( $member_type === 'organization' && ! empty( $org_name ) )
                    ? $org_name : trim( $first_name . ' ' . $last_name );

                $random_pass = wp_generate_password( 16, true, true );
                $user_id = wp_insert_user( [
                    'user_login'   => $use_login,
                    'user_email'   => $unique_email,
                    'user_pass'    => $random_pass,
                    'first_name'   => $first_name,
                    'last_name'    => $last_name,
                    'display_name' => $import_display,
                    'role'         => 'subscriber',
                ] );

                if ( is_wp_error( $user_id ) ) {
                    $results['errors'][] = "Row {$row_num}: Could not create user for {$import_display} — "
                                         . $user_id->get_error_message();
                    $results['skipped']++;
                    continue;
                }
            } else {
                // Email not yet in WordPress — create fresh user.
                // Prefer imported login, fall back to email as username.
                $use_login = ! empty( $imported_login ) ? $imported_login : $email;
                // Ensure login is unique
                if ( username_exists( $use_login ) ) {
                    $base = $use_login;
                    $n = 2;
                    do {
                        $use_login = $base . $n;
                        $n++;
                    } while ( username_exists( $use_login ) );
                }

                $import_display = ( $member_type === 'organization' && ! empty( $org_name ) )
                    ? $org_name : trim( $first_name . ' ' . $last_name );

                $random_pass = wp_generate_password( 16, true, true );
                $user_id = wp_insert_user( [
                    'user_login'   => $use_login,
                    'user_email'   => $email,
                    'user_pass'    => $random_pass,
                    'first_name'   => $first_name,
                    'last_name'    => $last_name,
                    'display_name' => $import_display,
                    'role'         => 'subscriber',
                ] );

                if ( is_wp_error( $user_id ) ) {
                    $results['errors'][] = "Row {$row_num}: Could not create user for {$import_display} — "
                                         . $user_id->get_error_message();
                    $results['skipped']++;
                    continue;
                }
            }
        } else {
            // No email — use imported login if available, otherwise generate
            // a placeholder. Every sp_members row needs a user_id (PRIMARY KEY).
            // Members without email get a placeholder login they'll never use,
            // but their data is preserved for the directory.
            if ( ! empty( $imported_login ) && ! username_exists( $imported_login ) ) {
                $login = $imported_login;
            } else {
                // WHY: For org members, use the org name in the placeholder login
                //      instead of the duplicated first_last (which would be the org
                //      name twice). sanitize_title makes it URL-safe.
                $login_base = ( $member_type === 'organization' && ! empty( $org_name ) )
                    ? sanitize_title( $org_name )
                    : sanitize_title( $last_name . '_' . $first_name );
                $login = 'sp_' . $login_base . '_' . wp_rand( 100, 999 );
            }

            $import_display = ( $member_type === 'organization' && ! empty( $org_name ) )
                ? $org_name : trim( $first_name . ' ' . $last_name );

            $random_pass = wp_generate_password( 16, true, true );
            $user_id = wp_insert_user( [
                'user_login'   => $login,
                'user_email'   => $login . '@placeholder.invalid',
                'user_pass'    => $random_pass,
                'first_name'   => $first_name,
                'last_name'    => $last_name,
                'display_name' => $import_display,
                'role'         => 'subscriber',
            ] );

            if ( is_wp_error( $user_id ) ) {
                $results['errors'][] = "Row {$row_num}: Could not create user for {$import_display} (no email) — "
                                     . $user_id->get_error_message();
                $results['skipped']++;
                continue;
            }
        }

        // ==============================================================
        // Insert the sp_members row
        // ==============================================================
        $member_data = [
            'user_id'               => $user_id,
            'member_type'           => $member_type,
            'organization_name'     => ( $member_type === 'organization' ) ? $org_name : null,
            'member_number'         => sanitize_text_field( $get( $row, 'member_number' ) ) ?: null,
            'status'                => $status,
            'tier_id'               => $tier_id,
            'prefix'                => sanitize_text_field( $get( $row, 'prefix' ) ) ?: null,
            'first_name'            => $first_name,
            'preferred_name'        => sanitize_text_field( $get( $row, 'preferred_name' ) ) ?: null,
            'middle_name'           => sanitize_text_field( $get( $row, 'middle_name' ) ) ?: null,
            'last_name'             => $last_name,
            'maiden_name'           => sanitize_text_field( $get( $row, 'maiden_name' ) ) ?: null,
            'suffix'                => sanitize_text_field( $get( $row, 'suffix' ) ) ?: null,
            'date_of_birth'         => $dob ?: null,
            'gender'                => sanitize_text_field( $get( $row, 'gender' ) ) ?: null,
            'deceased'              => ( $deceased === 'yes' ) ? 1 : 0,
            'join_date'             => $join_date,
            'expiration_date'       => $expiration_date ?: null,
            'address_1'             => sanitize_text_field( $get( $row, 'address_1' ) ) ?: null,
            'address_2'             => sanitize_text_field( $get( $row, 'address_2' ) ) ?: null,
            'city'                  => sanitize_text_field( $get( $row, 'city' ) ) ?: null,
            'state'                 => sanitize_text_field( $get( $row, 'state' ) ) ?: null,
            'postal_code'           => sanitize_text_field( $get( $row, 'postal_code' ) ) ?: null,
            'country'               => $normalize_country( $get( $row, 'country' ) ),
            'phone'                 => $clean_phone( $get( $row, 'phone' ) ),
            'cell'                  => $clean_phone( $get( $row, 'cell' ) ),
            'work_phone'            => $clean_phone( $get( $row, 'work_phone' ) ),
            'fax'                   => $clean_phone( $get( $row, 'fax' ) ),
            'website'               => esc_url_raw( $get( $row, 'website' ) ) ?: null,
            'seasonal'              => $seasonal,
            'seasonal_from'         => $seasonal_from ?: null,
            'seasonal_to'           => $seasonal_to ?: null,
            'seasonal_address_1'    => sanitize_text_field( $get( $row, 'seasonal_address' ) ) ?: null,
            'seasonal_city'         => sanitize_text_field( $get( $row, 'seasonal_city' ) ) ?: null,
            'seasonal_state'        => sanitize_text_field( $get( $row, 'seasonal_state' ) ) ?: null,
            'seasonal_postal_code'  => sanitize_text_field( $get( $row, 'seasonal_postal_code' ) ) ?: null,
            'seasonal_country'      => $normalize_country( $get( $row, 'seasonal_country' ) ),
            'lifetime'              => 0, // Will be set from tier if applicable
            'volunteer'             => $yes_no( $get( $row, 'volunteer' ) ),
            'joint_member'          => $yes_no( $get( $row, 'joint_member' ) ),
            'joint_email'           => sanitize_email( $get( $row, 'joint_email' ) ) ?: null,
            'joint_phone'           => $clean_phone( $get( $row, 'joint_phone' ) ),
            'skills'                => sanitize_text_field( $get( $row, 'skills' ) ) ?: null,
            'interests'             => sanitize_text_field( $get( $row, 'interests' ) ) ?: null,
            'education'             => sanitize_text_field( $get( $row, 'education' ) ) ?: null,
            'label_name'            => sanitize_text_field( $get( $row, 'label_name' ) ) ?: null,
            'login_username'        => $imported_login ?: null,
            'receive_print'         => $yes_no( $get( $row, 'pref_print' ) ),
            'pref_email_notices'    => $yes_no( $get( $row, 'pref_general_email' ) ),
            'pref_email_events'     => $yes_no( $get( $row, 'pref_event_email' ) ),
            'pref_email_newsletters'=> $yes_no( $get( $row, 'pref_newsletter' ) ),
            'pref_email_surnames'   => $yes_no( $get( $row, 'pref_surname' ) ),
            'dir_show_name'         => $yes_no( $get( $row, 'dir_show_name' ) ),
            'dir_show_address'      => $yes_no( $get( $row, 'dir_show_address' ) ),
            'dir_show_phone'        => $yes_no( $get( $row, 'dir_show_phone' ) ),
            'dir_show_email'        => $yes_no( $get( $row, 'dir_show_email' ) ),
            'dir_show_website'      => 1, // Default to visible — most exports don't have this field
            'dir_show_photo'        => $yes_no( $get( $row, 'dir_show_photo' ) ),
        ];

        // Encrypt sensitive contact fields before writing to DB
        sp_member_encrypt_fields( $member_data );
        $inserted = $wpdb->insert( $prefix . 'members', $member_data );
        if ( ! $inserted ) {
            $results['errors'][] = "Row {$row_num}: Database error inserting {$first_name} {$last_name}. MySQL: {$wpdb->last_error}";
            $results['skipped']++;
            continue;
        }

        // Track for duplicate detection within the same import batch.
        // WHY: If the CSV has the same person twice (data entry error),
        //      we catch it on the second pass through the loop.
        if ( ! empty( $email ) ) {
            $key = strtolower( $email );
            if ( ! isset( $existing_members[ $key ] ) ) {
                $existing_members[ $key ] = [];
            }
            $existing_members[ $key ][] = [
                'user_id' => $user_id,
                'first'   => strtolower( $first_name ),
                'last'    => strtolower( $last_name ),
            ];
        }

        // ==============================================================
        // Insert payment record (if payment data exists)
        // ==============================================================
        if ( $has_payment ) {
            $amount_paid = $get( $row, 'payment_amount' );
            $date_paid   = $parse_date( $get( $row, 'payment_date' ) );
            $donation    = $get( $row, 'payment_donation' );

            if ( ! empty( $amount_paid ) && (float) $amount_paid > 0 && ! empty( $date_paid ) ) {
                // WHY recorded_by is null: CSV imports are system actions, not manual entries.
                // Showing the importer's name on every record is misleading — null means
                // "imported" while a user ID means "manually recorded by that person."
                $wpdb->insert( $prefix . 'member_payments', [
                    'user_id'     => $user_id,
                    'amount'      => (float) $amount_paid,
                    'type'        => 'dues',
                    'method'      => sanitize_text_field( $get( $row, 'payment_method' ) ) ?: null,
                    'date'        => $date_paid,
                    'note'        => sanitize_text_field( $get( $row, 'payment_note' ) ) ?: null,
                    'recorded_by' => null,
                ]);
            }

            // If there's a donation amount, insert a separate payment record
            if ( ! empty( $donation ) && (float) $donation > 0 && ! empty( $date_paid ) ) {
                $wpdb->insert( $prefix . 'member_payments', [
                    'user_id'     => $user_id,
                    'amount'      => (float) $donation,
                    'type'        => 'donation',
                    'method'      => sanitize_text_field( $get( $row, 'payment_method' ) ) ?: null,
                    'date'        => $date_paid,
                    'note'        => 'Imported from previous system',
                    'recorded_by' => null,
                ]);
            }
        }

        // ==============================================================
        // Import admin notes (multi-line renewal history)
        // ==============================================================
        $admin_notes = trim( $get( $row, 'admin_notes' ) );
        if ( ! empty( $admin_notes ) ) {
            $wpdb->insert( $prefix . 'member_notes', [
                'user_id'   => $user_id,
                'content'   => sanitize_textarea_field( $admin_notes ),
                'author_id' => get_current_user_id(),
            ]);
        }

        // ==============================================================
        // Import custom meta fields
        //
        // WHY: The admin chose "Store as custom field" for these CSV
        //      columns in the field mapping step. Every society has
        //      different data — gender, volunteering status, joint
        //      member info, legacy system IDs, etc. Rather than adding
        //      a database column for every possible field, we store
        //      them in the flexible sp_member_meta key/value table.
        //      The meta key is a sanitized version of the CSV column
        //      name so it stays readable in the database.
        // ==============================================================
        foreach ( $meta_columns as $csv_col ) {
            $val = trim( $get_raw( $row, $csv_col ) );
            if ( $val !== '' ) {
                $meta_key = sanitize_key( str_replace( ' ', '_', strtolower( $csv_col ) ) );
                if ( ! empty( $meta_key ) ) {
                    $wpdb->insert( $prefix . 'member_meta', [
                        'user_id'    => $user_id,
                        'meta_key'   => $meta_key,
                        'meta_value' => sanitize_text_field( $val ),
                    ]);
                }
            }
        }

        $results['imported']++;
    }

    fclose( $handle );

    // Restore email notifications now that bulk import is done.
    // WHY: We only wanted to suppress during the import loop. Any future
    //      user creation (like an admin manually adding a member) should
    //      still trigger the normal WordPress notification flow.
    add_action( 'register_new_user', 'wp_send_new_user_notifications' );
    add_action( 'edit_user_created_user', 'wp_send_new_user_notifications', 10, 2 );
    remove_filter( 'wp_send_new_user_notification_to_admin', '__return_false' );
    remove_filter( 'wp_send_new_user_notification_to_user', '__return_false' );

    return $results;
}


/**
 * Render the Import page — a two-step process:
 *
 * STEP 1 (Upload): User picks a CSV file and clicks "Upload & Preview."
 *         We parse the headers, show a field-mapping table so the user can
 *         verify everything lines up, display a preview of the first 5 rows,
 *         and save the file to a temp location for Step 2.
 *
 * STEP 2 (Import): User reviews the mapping and clicks "Run Import."
 *         We read the temp file, process all rows, show results.
 *
 * WHY two steps: Harold should never blindly trust a CSV. Showing the mapping
 *     lets him confirm that "First Name" actually maps to first_name, that the
 *     file has the right columns, and that the preview data looks sane. It also
 *     catches the case where someone uploads the wrong file entirely.
 */
function sp_render_import_page(): void {
    if ( ! current_user_can( 'manage_options' ) ) {
        wp_die( esc_html__( 'You do not have permission to access this page.', 'societypress' ) );
    }

    $results  = null;
    $preview  = null;

    // ------------------------------------------------------------------
    // STEP 2: Run the actual import from the temp file
    // ------------------------------------------------------------------
    if ( isset( $_POST['sp_import_action'] ) && $_POST['sp_import_action'] === 'run_import' ) {
        check_admin_referer( 'sp_import_members' );

        // The temp file basename was stored in a hidden field from Step 1.
        // WHY basename only: We never expose full server paths in HTML. Reconstruct
        //      the full path here and validate it's inside our temp directory.
        $token = sanitize_file_name( $_POST['sp_import_temp_file'] ?? '' );
        $upload_dir = wp_upload_dir();
        $temp_dir   = $upload_dir['basedir'] . '/sp-import-temp/';
        $temp_file  = realpath( $temp_dir . $token );
        if ( ! $temp_file || strpos( $temp_file, realpath( $temp_dir ) ) !== 0 ) {
            $temp_file = '';
        }

        // Parse the field mapping — the admin's chosen assignment for each CSV column.
        // WHY: The admin reviewed the mapping dropdowns and may have reassigned,
        //      skipped, or changed columns before clicking "Run Import." The array
        //      is: csv_column_name → target_key (e.g. 'First Name' → 'first_name',
        //      'Gender' → '__meta', 'File Name' → '__skip').
        $raw_map = isset( $_POST['sp_field_map'] ) && is_array( $_POST['sp_field_map'] )
                 ? $_POST['sp_field_map']
                 : [];
        $import_field_map = [];
        foreach ( $raw_map as $csv_col => $target ) {
            $import_field_map[ sanitize_text_field( $csv_col ) ] = sanitize_text_field( $target );
        }

        if ( ! empty( $temp_file ) && file_exists( $temp_file ) ) {
            $results = sp_process_import( $temp_file, $import_field_map );
            // Clean up the temp file after import
            wp_delete_file( $temp_file );
        } else {
            $results = [
                'imported' => 0, 'skipped' => 0,
                'errors'   => [ __( 'The uploaded file has expired. Please upload again.', 'societypress' ) ],
                'tiers_created' => [],
            ];
        }
    }

    // ------------------------------------------------------------------
    // STEP 1: Upload CSV and show preview / field mapping
    // ------------------------------------------------------------------
    if ( isset( $_POST['sp_import_action'] ) && $_POST['sp_import_action'] === 'preview' ) {
        check_admin_referer( 'sp_import_members' );

        if ( ! empty( $_FILES['import_file']['tmp_name'] ) ) {
            // Move the upload to a temp file that persists between requests.
            // WHY: PHP deletes the upload temp file when the request ends.
            //      We need it to survive until Step 2. Store it in the WP
            //      uploads directory with a unique name.
            $upload_dir = wp_upload_dir();
            $temp_dir   = $upload_dir['basedir'] . '/sp-import-temp';
            if ( ! is_dir( $temp_dir ) ) {
                wp_mkdir_p( $temp_dir );
                // Block direct access to temp CSV files
                file_put_contents( $temp_dir . '/.htaccess', 'Deny from all' );
            }

            $temp_file = $temp_dir . '/import-' . wp_generate_password( 12, false ) . '.csv';
            move_uploaded_file( $_FILES['import_file']['tmp_name'], $temp_file );

            // Parse the header row and first few data rows for preview
            $handle  = fopen( $temp_file, 'r' );
            $headers = fgetcsv( $handle );

            if ( $headers ) {
                // Strip BOM and whitespace from headers
                $headers = array_map( function( $h ) {
                    return trim( $h, "\xEF\xBB\xBF \t\n\r" );
                }, $headers );

                // Count total rows (for the summary)
                $row_count = 0;
                $sample_rows = [];
                while ( ( $row = fgetcsv( $handle ) ) !== false ) {
                    $row_count++;
                    if ( count( $sample_rows ) < 5 ) {
                        $sample_rows[] = $row;
                    }
                }

                $preview = [
                    'headers'     => $headers,
                    'sample_rows' => $sample_rows,
                    'row_count'   => $row_count,
                    'temp_file'   => $temp_file,
                ];
            } else {
                wp_delete_file( $temp_file );
            }
            fclose( $handle );
        }
    }

    // ------------------------------------------------------------------
    // Define the field mapping — CSV column name → SocietyPress description.
    // This is the canonical list of columns we know how to import. Anything
    // in the CSV that's NOT in this map gets shown as "Ignored."
    // ------------------------------------------------------------------
    $field_map = [
        'File Name'             => 'Organization Name',
        'First Name'            => 'First Name',
        'Last Name'             => 'Last Name',
        'Name Prefix'           => 'Prefix (Mr., Mrs., Dr.)',
        'PreferredName'         => 'Preferred / Nickname',
        'Middle Name'           => 'Middle Name',
        'Maiden Name'           => 'Maiden Name',
        'Name Suffix'           => 'Suffix (Jr., III)',
        'Email'                 => 'Email Address',
        'Login'                 => 'Login / Username',
        'Member Active'         => 'Status (active / lapsed)',
        'Deceased'              => 'Status (marks as inactive)',
        'Member Join Date'      => 'Join Date',
        'Expiration Date'       => 'Expiration Date',
        'Birth Year'            => 'Date of Birth (year)',
        'Birth Month'           => 'Date of Birth (month)',
        'Birth Day'             => 'Date of Birth (day)',
        'Address 1'             => 'Address Line 1',
        'Address 2'             => 'Address Line 2',
        'City'                  => 'City',
        'State / Province'      => 'State / Province',
        'Postal Code'           => 'Postal Code',
        'Country'               => 'Country',
        'Telephone'             => 'Phone',
        'Cell Phone'            => 'Cell Phone',
        'Website'               => 'Website',
        'Alternate Address 1'   => 'Seasonal Address',
        'Alt. City'             => 'Seasonal City',
        'Alt. State / Province' => 'Seasonal State',
        'Alt. Postal Code'      => 'Seasonal Postal Code',
        'Al. Country'           => 'Seasonal Country',
        'Use Seasonal Address'  => 'Has Seasonal Address (yes/no)',
        'Use Alt. Info Month Begin' => 'Seasonal Start Month',
        'Alt. Contact Day Begin'    => 'Seasonal Start Day',
        'Use Alt. Info Month End'   => 'Seasonal End Month',
        'Alt. Contact Day End'      => 'Seasonal End Day',
        'Gender'                => 'Gender',
        'Volunteering?'         => 'Volunteering',
        'Joint Member'          => 'Joint Member (yes/no)',
        'Email of Joint'        => 'Joint Member Email',
        'Phone of Joint'        => 'Joint Member Phone',
        'Your Skills'           => 'Skills',
        'Your Interests'        => 'Interests',
        'Your Education'        => 'Education',
        'Business Phone'        => 'Business / Work Phone',
        'Fax'                   => 'Fax',
        'Address Label Name'    => 'Mailing Label Name',
        'Login'                 => 'Login / Username',
        'Quarterly'             => 'Receives Print Newsletter',
        'General Email'         => 'Pref: General Emails',
        'Event Email'           => 'Pref: Event Emails',
        'Newsletter Email'      => 'Pref: Newsletter Emails',
        'Surname Inquiry'       => 'Pref: Surname Inquiries',
        'Mbr. List - Show Name'    => 'Directory: Show Name',
        'Mbr. List - Show Address' => 'Directory: Show Address',
        'Mbr. List - Show Phone'   => 'Directory: Show Phone',
        'Mbr. List - Show Email'   => 'Directory: Show Email',
        'Mbr. List - Show Photo'   => 'Directory: Show Photo',
        'Membership Plan'       => 'Membership Plan / Tier',
        'Membership Number'     => 'Member Number',
        'Amount Paid'           => 'Payment: Amount',
        'Date Paid'             => 'Payment: Date',
        'Payment Type'          => 'Payment: Method',
        'Donation'              => 'Payment: Donation Amount',
        'Comment'               => 'Payment: Note',
        'Administrative Notes'  => 'Admin Notes',
    ];

    ?>
    <div class="wrap">
        <h1><?php esc_html_e( 'Import Members', 'societypress' ); ?></h1>

        <?php
        // ---- Gate: admin must have a member record before importing ----
        // WHY: The admin should add themselves as the first member before importing
        // everyone else. This ensures they have a member record linked to their WP
        // account, which is needed for My Account, directory, and other member features.
        // Without this, the admin is invisible in their own system.
        if ( ! sp_user_has_member_record( get_current_user_id() ) ) :
            $add_self_url = admin_url( 'admin.php?page=sp-member-edit&link_to_self=1' );
        ?>
            <div class="notice notice-warning" style="padding: 16px; border-left-color: #C9973A;">
                <h3 style="margin: 0 0 8px;"><?php esc_html_e( 'Add yourself first', 'societypress' ); ?></h3>
                <p style="margin: 0 0 12px;">
                    <?php esc_html_e( 'Before importing members, you need to add yourself as the first member of your society. This links your administrator account to a member record so you appear in the directory, can use My Account, and are included in reports.', 'societypress' ); ?>
                </p>
                <a href="<?php echo esc_url( $add_self_url ); ?>" class="button button-primary">
                    <?php esc_html_e( 'Add Yourself as a Member', 'societypress' ); ?>
                </a>
            </div>
        <?php return; endif; ?>

        <?php // ============================================================ ?>
        <?php // RESULTS — shown after Step 2 completes                        ?>
        <?php // ============================================================ ?>
        <?php if ( $results ) : ?>
            <?php if ( $results['imported'] > 0 ) : ?>
                <div class="notice notice-success is-dismissible">
                    <p><strong><?php
                        /* translators: %d: number of members imported */
                        printf( esc_html__( '%d members imported successfully.', 'societypress' ), (int) $results['imported'] );
                    ?></strong></p>
                </div>
            <?php endif; ?>

            <?php if ( ! empty( $results['tiers_created'] ) ) : ?>
                <div class="notice notice-info is-dismissible">
                    <p><?php
                        /* translators: %s: comma-separated list of membership plan names */
                        printf( esc_html__( 'Created membership plans: %s', 'societypress' ), '<strong>' . esc_html( implode( ', ', array_unique( $results['tiers_created'] ) ) ) . '</strong>' );
                    ?></p>
                    <p><?php
                        printf(
                            /* translators: %s: link to Members admin page */
                            esc_html__( 'These were imported with $0 pricing — update them under %s to set the correct dues amounts.', 'societypress' ),
                            '<a href="' . esc_url( admin_url( 'admin.php?page=sp-members' ) ) . '">' . esc_html__( 'Members', 'societypress' ) . '</a>'
                        );
                    ?></p>
                </div>
            <?php endif; ?>

            <?php if ( $results['skipped'] > 0 ) : ?>
                <div class="notice notice-warning is-dismissible">
                    <p><?php
                        /* translators: %d: number of rows skipped */
                        printf( esc_html__( '%d rows skipped (duplicates or errors).', 'societypress' ), (int) $results['skipped'] );
                    ?></p>
                </div>
            <?php endif; ?>

            <?php if ( ! empty( $results['errors'] ) ) : ?>
                <div class="notice notice-error">
                    <p><strong><?php esc_html_e( 'Details:', 'societypress' ); ?></strong></p>
                    <ul style="margin: 0 0 10px 20px; list-style: disc;">
                        <?php foreach ( array_slice( $results['errors'], 0, 50 ) as $err ) : ?>
                            <li><?php echo esc_html( $err ); ?></li>
                        <?php endforeach; ?>
                        <?php if ( count( $results['errors'] ) > 50 ) : ?>
                            <li>...and <?php echo count( $results['errors'] ) - 50; ?> more.</li>
                        <?php endif; ?>
                    </ul>
                </div>
            <?php endif; ?>
        <?php endif; ?>

        <?php // ============================================================ ?>
        <?php // STEP 1 RESULTS — Field mapping preview + confirmation button  ?>
        <?php // ============================================================ ?>
        <?php if ( $preview ) : ?>
            <div style="max-width: 900px; background: #fff; border: 1px solid #c3c4c7; border-radius: 4px; margin-top: 20px; padding: 0;">
                <h2 style="margin: 0; padding: 12px 20px; border-bottom: 1px solid #c3c4c7; font-size: 14px; font-weight: 600; background: #f6f7f7;">
                    <?php esc_html_e( 'Review Field Mapping', 'societypress' ); ?>
                </h2>
                <div style="padding: 20px;">
                    <p style="margin-top: 0;">
                        Found <strong><?php echo (int) $preview['row_count']; ?> rows</strong> and
                        <strong><?php echo count( $preview['headers'] ); ?> columns</strong> in your file.
                        Review the mapping below to make sure everything looks right.
                    </p>

                    <?php
                    // Build the list of all possible target fields for the dropdown.
                    // WHY: The admin might need to reassign a CSV column to a different
                    //      SocietyPress field if the auto-detection got it wrong, or if
                    //      their export uses different column names than EasyNetSites.
                    //
                    //      Grouped by category so the dropdown is scannable. The key is
                    //      what gets submitted; the label is what the admin sees.
                    $target_fields = [
                        'Name' => [
                            'first_name'        => 'First Name',
                            'last_name'         => 'Last Name',
                            'organization_name' => 'Organization Name',
                            'prefix'          => 'Prefix (Mr., Mrs., Dr.)',
                            'preferred_name'  => 'Preferred / Nickname',
                            'middle_name'     => 'Middle Name',
                            'maiden_name'     => 'Maiden Name',
                            'suffix'          => 'Suffix (Jr., III)',
                        ],
                        'Membership' => [
                            'email'           => 'Email Address',
                            'login'           => 'Login / Username',
                            'status'          => 'Status (active / lapsed)',
                            'deceased'        => 'Deceased Flag',
                            'join_date'       => 'Join Date',
                            'expiration_date' => 'Expiration Date',
                            'tier'            => 'Membership Plan / Tier',
                            'member_number'   => 'Member Number',
                        ],
                        'Contact' => [
                            'phone'           => 'Phone',
                            'cell'            => 'Cell Phone',
                            'work_phone'      => 'Business / Work Phone',
                            'fax'             => 'Fax',
                            'website'         => 'Website',
                        ],
                        'Address' => [
                            'address_1'       => 'Address Line 1',
                            'address_2'       => 'Address Line 2',
                            'city'            => 'City',
                            'state'           => 'State / Province',
                            'postal_code'     => 'Postal Code',
                            'country'         => 'Country',
                        ],
                        'Birth Date' => [
                            'birth_year'      => 'Date of Birth (year)',
                            'birth_month'     => 'Date of Birth (month)',
                            'birth_day'       => 'Date of Birth (day)',
                        ],
                        'Seasonal Address' => [
                            'seasonal_flag'        => 'Has Seasonal Address (yes/no)',
                            'seasonal_address'     => 'Seasonal Address',
                            'seasonal_city'        => 'Seasonal City',
                            'seasonal_state'       => 'Seasonal State',
                            'seasonal_postal_code' => 'Seasonal Postal Code',
                            'seasonal_country'     => 'Seasonal Country',
                            'seasonal_month_begin' => 'Seasonal Start Month',
                            'seasonal_day_begin'   => 'Seasonal Start Day',
                            'seasonal_month_end'   => 'Seasonal End Month',
                            'seasonal_day_end'     => 'Seasonal End Day',
                        ],
                        'Preferences' => [
                            'pref_print'         => 'Receives Print Newsletter',
                            'pref_general_email' => 'Pref: General Emails',
                            'pref_event_email'   => 'Pref: Event Emails',
                            'pref_newsletter'    => 'Pref: Newsletter Emails',
                            'pref_surname'       => 'Pref: Surname Inquiries',
                        ],
                        'Directory Visibility' => [
                            'dir_show_name'    => 'Directory: Show Name',
                            'dir_show_address' => 'Directory: Show Address',
                            'dir_show_phone'   => 'Directory: Show Phone',
                            'dir_show_email'   => 'Directory: Show Email',
                            'dir_show_photo'   => 'Directory: Show Photo',
                        ],
                        'Payment' => [
                            'payment_amount'   => 'Payment: Amount',
                            'payment_date'     => 'Payment: Date',
                            'payment_method'   => 'Payment: Method',
                            'payment_donation' => 'Payment: Donation Amount',
                            'payment_note'     => 'Payment: Note',
                        ],
                        'Personal' => [
                            'gender'           => 'Gender',
                            'volunteer'        => 'Volunteering',
                            'skills'           => 'Skills',
                            'interests'        => 'Interests',
                            'education'        => 'Education',
                            'label_name'       => 'Mailing Label Name',
                            'login'            => 'Login / Username',
                        ],
                        'Joint / Household' => [
                            'joint_member'     => 'Joint Member (yes/no)',
                            'joint_email'      => 'Joint Member Email',
                            'joint_phone'      => 'Joint Member Phone',
                        ],
                        'Other' => [
                            'admin_notes'      => 'Admin Notes',
                        ],
                    ];

                    // Reverse lookup: SocietyPress label → target key.
                    // WHY: The $field_map uses CSV column names as keys and SP labels
                    //      as values. We need to find the target key from the label so
                    //      we can pre-select the correct dropdown option.
                    $label_to_key = [];
                    foreach ( $target_fields as $group => $fields ) {
                        foreach ( $fields as $key => $label ) {
                            $label_to_key[ $label ] = $key;
                        }
                    }
                    ?>

                    <!-- Single form wrapping both the mapping dropdowns and the confirm button.
                         WHY: The field mapping dropdowns (<select name="sp_field_map[...]">)
                         need to be inside the same <form> as the "Run Import" submit button.
                         Otherwise the admin's mapping choices won't be sent with the POST
                         when they click import. -->
                    <form method="post" id="sp-import-confirm-form">
                        <?php wp_nonce_field( 'sp_import_members' ); ?>
                        <input type="hidden" name="sp_import_action" value="run_import">
                        <input type="hidden" name="sp_import_temp_file"
                               value="<?php echo esc_attr( basename( $preview['temp_file'] ) ); ?>">

                    <!-- Field mapping table -->
                    <table class="widefat striped" style="margin-top: 16px;">
                        <thead>
                            <tr>
                                <th style="width: 30%;"><?php esc_html_e( 'CSV Column', 'societypress' ); ?></th>
                                <th style="width: 40%;"><?php esc_html_e( 'Maps To', 'societypress' ); ?></th>
                                <th style="width: 30%;"><?php esc_html_e( 'Sample Value', 'societypress' ); ?></th>
                            </tr>
                        </thead>
                        <tbody>
                            <?php
                            $first_data_row = $preview['sample_rows'][0] ?? [];
                            foreach ( $preview['headers'] as $idx => $header ) :
                                $mapped_label = $field_map[ $header ] ?? null;
                                $mapped_key   = $mapped_label ? ( $label_to_key[ $mapped_label ] ?? '' ) : '';

                                // Decide what should be pre-selected for this column:
                                // - If auto-detection found a matching target key → use it
                                // - If the column is known (in $field_map) but doesn't map
                                //   to a specific target → store as custom field (__meta)
                                // - If the column is completely unknown → also store as
                                //   custom field so no data from the import is lost
                                if ( ! empty( $mapped_key ) ) {
                                    $selected_value = $mapped_key;
                                } else {
                                    $selected_value = '__meta';
                                }

                                $sample = isset( $first_data_row[ $idx ] ) ? trim( $first_data_row[ $idx ] ) : '';
                                if ( strlen( $sample ) > 60 ) {
                                    $sample = substr( $sample, 0, 57 ) . '...';
                                }
                            ?>
                                <tr class="sp-import-field-row">
                                    <td><code><?php echo esc_html( $header ); ?></code></td>
                                    <td>
                                        <select name="sp_field_map[<?php echo esc_attr( $header ); ?>]"
                                                class="sp-field-map-select"
                                                style="width: 100%; max-width: 320px;">
                                            <option value="__skip"
                                                <?php selected( $selected_value, '__skip' ); ?>>
                                                &#10005; Skip — do not import
                                            </option>
                                            <option value="__meta"
                                                <?php selected( $selected_value, '__meta' ); ?>>
                                                &#128190; Store as custom field
                                            </option>
                                            <?php foreach ( $target_fields as $group => $fields ) : ?>
                                                <optgroup label="<?php echo esc_attr( $group ); ?>">
                                                    <?php foreach ( $fields as $key => $label ) : ?>
                                                        <option value="<?php echo esc_attr( $key ); ?>"
                                                            <?php selected( $selected_value, $key ); ?>>
                                                            <?php echo esc_html( $label ); ?>
                                                        </option>
                                                    <?php endforeach; ?>
                                                </optgroup>
                                            <?php endforeach; ?>
                                        </select>
                                    </td>
                                    <td style="color: #666; font-size: 13px;">
                                        <?php echo esc_html( $sample ); ?>
                                    </td>
                                </tr>
                            <?php endforeach; ?>
                        </tbody>
                    </table>

                    <script>
                    // WHY: When a field is set to "Skip," dim the row so the admin
                    //      can see at a glance what's being excluded.
                    (function() {
                        var selects = document.querySelectorAll('.sp-field-map-select');
                        selects.forEach(function(sel) {
                            sel.addEventListener('change', function() {
                                var row = this.closest('tr');
                                if (this.value === '__skip') {
                                    row.style.opacity = '0.4';
                                } else {
                                    row.style.opacity = '';
                                }
                            });
                            // Apply initial state
                            if (sel.value === '__skip') {
                                sel.closest('tr').style.opacity = '0.4';
                            }
                        });
                    })();
                    </script>

                    <!-- Data preview -->
                    <h3 style="margin-top: 24px;">Data Preview (first <?php echo count( $preview['sample_rows'] ); ?> rows)</h3>
                    <div style="overflow-x: auto; margin-top: 8px; border: 1px solid #c3c4c7; border-radius: 3px;">
                        <table class="widefat striped" style="min-width: 800px; font-size: 12px;">
                            <thead>
                                <tr>
                                    <?php
                                    // Only show columns that auto-detected to a specific
                                    // target field (not meta and not skip) in the preview.
                                    // WHY: The full 86-column CSV would be unreadable.
                                    //      We show only the key columns: names, email,
                                    //      dates, address, etc. — the ones the admin most
                                    //      needs to verify are correct.
                                    $preview_cols = [];
                                    foreach ( $preview['headers'] as $idx => $header ) {
                                        $lbl = $field_map[ $header ] ?? null;
                                        $key = $lbl ? ( $label_to_key[ $lbl ] ?? '' ) : '';
                                        if ( ! empty( $key ) ) {
                                            $preview_cols[ $idx ] = $header;
                                        }
                                    }
                                    foreach ( $preview_cols as $header ) : ?>
                                        <th style="white-space: nowrap; font-size: 11px;"><?php echo esc_html( $header ); ?></th>
                                    <?php endforeach; ?>
                                </tr>
                            </thead>
                            <tbody>
                                <?php foreach ( $preview['sample_rows'] as $row ) : ?>
                                    <tr>
                                        <?php foreach ( $preview_cols as $idx => $header ) :
                                            $val = isset( $row[ $idx ] ) ? trim( $row[ $idx ] ) : '';
                                            if ( strlen( $val ) > 40 ) $val = substr( $val, 0, 37 ) . '...';
                                        ?>
                                            <td style="white-space: nowrap;"><?php echo esc_html( $val ); ?></td>
                                        <?php endforeach; ?>
                                    </tr>
                                <?php endforeach; ?>
                            </tbody>
                        </table>
                    </div>

                    <!-- Confirm import button — inside the same form as the mapping dropdowns -->
                    <div style="margin-top: 24px; padding: 16px; background: #f0f6fc; border-left: 4px solid #2271b1; border-radius: 0 3px 3px 0;">
                            <p style="margin: 0 0 12px 0;">
                                <?php /* translators: %d: number of members to import */ ?>
                                <strong><?php printf( esc_html__( 'Ready to import %d members?', 'societypress' ), (int) $preview['row_count'] ); ?></strong><br>
                                <?php esc_html_e( 'This will create login accounts for each member (no welcome emails are sent). Duplicates are automatically skipped.', 'societypress' ); ?>
                            </p>

                            <?php submit_button( 'Run Import', 'primary', 'sp_import_submit', false ); ?>
                            <a href="<?php echo esc_url( admin_url( 'admin.php?page=sp-import' ) ); ?>"
                               class="button" style="margin-left: 8px;"><?php esc_html_e( 'Cancel', 'societypress' ); ?></a>
                    </div>
                    </form>
                </div>
            </div>

        <?php // ============================================================ ?>
        <?php // STEP 1 FORM — Upload CSV file                                ?>
        <?php // ============================================================ ?>
        <?php else : ?>

            <?php
            // WHY: If the admin just added themselves and this is a fresh install with only
            // 1 member, show a welcome message acknowledging that step and encouraging
            // the import. This makes the onboarding flow feel intentional, not accidental.
            global $wpdb;
            $sp_member_count = (int) $wpdb->get_var( "SELECT COUNT(*) FROM {$wpdb->prefix}sp_members" );
            if ( $sp_member_count <= 1 ) : ?>
                <div class="notice notice-success" style="padding: 16px; border-left-color: #00a32a; margin-top: 20px;">
                    <h3 style="margin: 0 0 8px;">&#10003; <?php esc_html_e( "You're all set!", 'societypress' ); ?></h3>
                    <p style="margin: 0 0 8px;">
                        <?php esc_html_e( "Now you can import your society's existing membership data. Upload a CSV export from your current system — SocietyPress will map the columns automatically.", 'societypress' ); ?>
                    </p>
                    <?php
                    // WHY: Only show the sample data link if load-sample-data.php exists
                    // in the web root. Real installs won't have it — only the demo site does.
                    if ( file_exists( ABSPATH . 'load-sample-data.php' ) ) : ?>
                    <p style="margin: 0; font-size: 13px; color: #6B7280;">
                        <?php
                        printf(
                            /* translators: %s: link to sample data */
                            __( 'Just exploring? %s to see what a populated society looks like. You can clear it anytime.', 'societypress' ),
                            '<a href="' . esc_url( home_url( '/load-sample-data.php' ) ) . '">' . esc_html__( 'Load 2,500 sample members', 'societypress' ) . '</a>'
                        );
                        ?>
                    </p>
                    <?php endif; ?>
                </div>
            <?php endif; ?>

            <div style="max-width: 700px; background: #fff; border: 1px solid #c3c4c7; border-radius: 4px; margin-top: 20px; padding: 0;">
                <h2 style="margin: 0; padding: 12px 20px; border-bottom: 1px solid #c3c4c7; font-size: 14px; font-weight: 600; background: #f6f7f7;"><?php esc_html_e( 'Import Members', 'societypress' ); ?></h2>
                <div style="padding: 20px;">
                    <p style="margin-top: 0;">
                        <?php esc_html_e( 'Upload a membership export CSV to import all members, membership plans, payment records, and admin notes.', 'societypress' ); ?>
                    </p>

                    <h3 style="margin-top: 20px;"><?php esc_html_e( 'How to prepare your import file:', 'societypress' ); ?></h3>
                    <ol>
                        <li><?php esc_html_e( 'Export your membership data from your current system as CSV', 'societypress' ); ?></li>
                        <li><?php echo wp_kses( __( 'Make sure the export includes <strong>all fields</strong>', 'societypress' ), [ 'strong' => [] ] ); ?></li>
                        <li><?php esc_html_e( 'Upload the CSV file below', 'societypress' ); ?></li>
                    </ol>

                    <form method="post" enctype="multipart/form-data" style="margin-top: 20px;">
                        <?php wp_nonce_field( 'sp_import_members' ); ?>
                        <input type="hidden" name="sp_import_action" value="preview">

                        <div style="margin-bottom: 16px;">
                            <label for="sp-import-file" style="display: block; font-weight: 600; margin-bottom: 6px;">
                                <?php esc_html_e( 'CSV File', 'societypress' ); ?>
                            </label>
                            <input type="file" name="import_file" id="sp-import-file"
                                   accept=".csv,.txt" required>
                            <p class="description" style="margin-top: 6px;">
                                <?php esc_html_e( 'Accepts CSV format. Compatible with most membership platform exports.', 'societypress' ); ?>
                            </p>
                        </div>

                        <p style="margin-top: 20px;">
                            <?php submit_button( 'Upload &amp; Preview', 'primary', 'sp_import_submit', false ); ?>
                        </p>
                    </form>
                </div>
            </div>
        <?php endif; ?>

        <!-- Processing overlay — hidden until the import confirmation form is submitted.
             WHY: Importing hundreds of members takes a while (creating WP users,
             inserting rows, etc.). Without visual feedback Harold WILL close
             the tab thinking it crashed. This overlay locks the page and shows
             a spinner so he knows it's working. Only triggers on the Step 2
             form (the confirmation), not the Step 1 upload. -->
        <div id="sp-import-overlay" style="display:none; position:fixed; inset:0; background:rgba(255,255,255,0.92); z-index:999999; justify-content:center; align-items:center;">
            <div style="text-align:center; padding:40px;">
                <div style="display:inline-block; width:40px; height:40px; border:4px solid #c3c4c7; border-top-color:#2271b1; border-radius:50%; animation:sp-spin 0.8s linear infinite;"></div>
                <h2 style="margin-top:20px; font-size:18px; color:#1d2327;"><?php echo esc_html__( 'Importing Members…', 'societypress' ); ?></h2>
                <p style="color:#50575e; margin-top:8px; font-size:14px;">
                    This may take a minute or two for large lists.<br>
                    Please don't close or refresh this page.
                </p>
            </div>
        </div>
        <style>
            @keyframes sp-spin { to { transform: rotate(360deg); } }
        </style>
        <script>
            /* Show the processing overlay only when the Step 2 confirmation
               form is submitted (not the Step 1 upload form).
               WHY: The upload/preview step is fast — no spinner needed. The
               actual import is slow — spinner essential. We target the specific
               form by its ID. */
            (function() {
                var form = document.getElementById('sp-import-confirm-form');
                if ( ! form ) return;
                form.addEventListener('submit', function() {
                    var overlay = document.getElementById('sp-import-overlay');
                    if ( overlay ) {
                        overlay.style.display = 'flex';
                    }
                    var btn = form.querySelector('input[name="sp_import_submit"]');
                    if ( btn ) {
                        btn.disabled = true;
                        btn.value = 'Importing\u2026';
                    }
                });
            })();
        </script>
    </div>
    <?php
}


// ============================================================================
// EXPORT — CSV download handler (admin_init) + page renderer
//
// WHY: Societies need to get their data OUT as easily as they put it IN.
//      Board treasurers want a spreadsheet for dues tracking, secretaries
//      want mailing labels, webmasters want backups. The export handler
//      runs on admin_init (before any HTML output) because CSV download
//      requires sending HTTP headers immediately.
// ============================================================================

/**
 * Handle CSV download request.
 *
 * WHY: wp_redirect() and header() calls must happen before WordPress sends
 *      any output. That's why this is on admin_init, not inside the page
 *      callback. When the user clicks "Download CSV", the form POSTs with
 *      sp_export_action=download. We intercept it here, query the database,
 *      stream the CSV, and exit before WordPress renders anything.
 */
add_action( 'admin_init', function () {

    // Only fire when the export form is submitted
    if ( empty( $_POST['sp_export_action'] ) || $_POST['sp_export_action'] !== 'download' ) {
        return;
    }

    // Security: verify nonce and capability
    if ( ! check_admin_referer( 'sp_export_members' ) ) {
        wp_die( esc_html__( 'Security check failed.', 'societypress' ) );
    }
    if ( ! current_user_can( 'manage_options' ) ) {
        wp_die( 'You do not have permission to export members.' );
    }

    global $wpdb;
    $prefix = $wpdb->prefix . 'sp_';

    // ----------------------------------------------------------------
    // Build the WHERE clause from filter selections
    // ----------------------------------------------------------------
    $where  = [];
    $values = [];

    // Status filter
    $status = sanitize_text_field( $_POST['sp_export_status'] ?? '' );
    if ( ! empty( $status ) && $status !== 'all' ) {
        $where[]  = 'm.status = %s';
        $values[] = $status;
    }

    // Tier filter
    $tier_id = absint( $_POST['sp_export_tier'] ?? 0 );
    if ( $tier_id > 0 ) {
        $where[]  = 'm.tier_id = %d';
        $values[] = $tier_id;
    }

    // Join date range
    $join_from = sanitize_text_field( $_POST['sp_export_join_from'] ?? '' );
    $join_to   = sanitize_text_field( $_POST['sp_export_join_to'] ?? '' );
    if ( ! empty( $join_from ) ) {
        $where[]  = 'm.join_date >= %s';
        $values[] = $join_from;
    }
    if ( ! empty( $join_to ) ) {
        $where[]  = 'm.join_date <= %s';
        $values[] = $join_to;
    }

    // Expiration date range
    $exp_from = sanitize_text_field( $_POST['sp_export_exp_from'] ?? '' );
    $exp_to   = sanitize_text_field( $_POST['sp_export_exp_to'] ?? '' );
    if ( ! empty( $exp_from ) ) {
        $where[]  = 'm.expiration_date >= %s';
        $values[] = $exp_from;
    }
    if ( ! empty( $exp_to ) ) {
        $where[]  = 'm.expiration_date <= %s';
        $values[] = $exp_to;
    }

    $where_sql = '';
    if ( ! empty( $where ) ) {
        $where_sql = 'WHERE ' . implode( ' AND ', $where );
    }

    // ----------------------------------------------------------------
    // Query members with tier name and email from wp_users
    //
    // WHY: Email lives on wp_users, not sp_members. Tier name lives on
    //      sp_membership_tiers. We join both so the CSV has everything
    //      a society admin would expect in a single flat export.
    // ----------------------------------------------------------------
    $sql = "SELECT
                m.*,
                u.user_email AS email,
                t.name AS tier_name
            FROM {$prefix}members m
            LEFT JOIN {$wpdb->users} u ON u.ID = m.user_id
            LEFT JOIN {$prefix}membership_tiers t ON t.id = m.tier_id
            {$where_sql}
            ORDER BY m.last_name ASC, m.first_name ASC";

    if ( ! empty( $values ) ) {
        $sql = $wpdb->prepare( $sql, $values );
    }

    $members = $wpdb->get_results( $sql );
    // Decrypt sensitive contact/address fields that are encrypted at rest.
    // WHY: The CSV export needs plaintext values — an encrypted blob is useless
    // to Harold when he prints a mailing list or phone directory.
    $members = sp_member_decrypt_rows( $members );

    // ----------------------------------------------------------------
    // Which columns did the user select?
    // ----------------------------------------------------------------
    $selected = $_POST['sp_export_fields'] ?? [];
    if ( empty( $selected ) || ! is_array( $selected ) ) {
        // If nothing selected, export everything
        $selected = array_keys( sp_get_export_columns() );
    }

    $columns = sp_get_export_columns();

    // ----------------------------------------------------------------
    // Stream the CSV
    //
    // WHY: We open php://output as a file handle and use fputcsv() to
    //      properly escape commas, quotes, and newlines in field values.
    //      No temp file needed — it streams directly to the browser.
    // ----------------------------------------------------------------
    $filename = 'members-export-' . current_time( 'Y-m-d' ) . '.csv';

    // Clean any buffered output so headers aren't corrupted
    if ( ob_get_level() ) {
        ob_end_clean();
    }

    header( 'Content-Type: text/csv; charset=utf-8' );
    header( 'Content-Disposition: attachment; filename="' . $filename . '"' );
    header( 'Pragma: no-cache' );
    header( 'Expires: 0' );

    $output = fopen( 'php://output', 'w' );

    // UTF-8 BOM so Excel opens it correctly
    // WHY: Without the BOM, Excel assumes ANSI encoding and mangles
    //      accented characters (common in genealogy — Müller, García, etc.)
    fwrite( $output, "\xEF\xBB\xBF" );

    // Header row — only selected columns
    $header = [];
    foreach ( $selected as $key ) {
        if ( isset( $columns[ $key ] ) ) {
            $header[] = $columns[ $key ]['label'];
        }
    }
    fputcsv( $output, $header );

    // ----------------------------------------------------------------
    // Bulk-load all member meta and attach to each member object
    //
    // WHY: The meta value getters expect $member->_meta['key']. Rather
    //      than running a query per member per meta column (N*M queries),
    //      we load ALL meta in one query and index it by user_id. This
    //      is the same pattern WordPress core uses for wp_cache_get_multiple.
    // ----------------------------------------------------------------
    $has_meta_cols = false;
    foreach ( $selected as $key ) {
        if ( str_starts_with( $key, 'meta:' ) ) {
            $has_meta_cols = true;
            break;
        }
    }

    if ( $has_meta_cols && ! empty( $members ) ) {
        $user_ids = array_map( fn( $m ) => $m->user_id, $members );
        $id_placeholders = implode( ',', array_fill( 0, count( $user_ids ), '%d' ) );
        $all_meta = $wpdb->get_results(
            $wpdb->prepare(
                "SELECT user_id, meta_key, meta_value
                 FROM {$prefix}member_meta
                 WHERE user_id IN ({$id_placeholders})",
                $user_ids
            )
        );

        // Index by user_id for fast lookup
        $meta_by_user = [];
        foreach ( $all_meta as $meta_row ) {
            $meta_by_user[ $meta_row->user_id ][ $meta_row->meta_key ] = $meta_row->meta_value;
        }

        // Attach to each member object
        foreach ( $members as $member ) {
            $member->_meta = $meta_by_user[ $member->user_id ] ?? [];
        }
    } else {
        // No meta columns selected — still set empty array so closures don't error
        foreach ( $members as $member ) {
            $member->_meta = [];
        }
    }

    // Data rows
    foreach ( $members as $member ) {
        $row = [];
        foreach ( $selected as $key ) {
            if ( ! isset( $columns[ $key ] ) ) continue;
            $getter = $columns[ $key ]['value'];
            $row[]  = $getter( $member );
        }
        fputcsv( $output, $row );
    }

    fclose( $output );
    exit;
});


/**
 * Define all exportable columns — fixed schema columns plus any dynamic
 * meta keys that exist in the database.
 *
 * WHY: The fixed columns come from sp_members (the schema we control).
 *      The dynamic columns come from sp_member_meta (whatever a society
 *      imported or created). This means the export page automatically
 *      shows checkboxes for fields we never anticipated — skills,
 *      interests, education, joint member info, or whatever a future
 *      society decides to track. Zero code changes needed.
 *
 * @return array  Keyed by column slug. Each entry has 'label' (string for
 *                the CSV header and checkbox) and 'value' (closure that
 *                takes a member row object and returns the cell value).
 *                Dynamic meta columns use 'meta:keyname' as the slug.
 */
function sp_get_export_columns(): array {
    $columns = [
        // ---- Member Type ----
        'member_type'    => [
            'label' => 'Member Type',
            'value' => fn( $m ) => ucfirst( $m->member_type ?? 'individual' ),
        ],
        'organization_name' => [
            'label' => 'Organization Name',
            'value' => fn( $m ) => $m->organization_name ?? '',
        ],

        // ---- Identity ----
        'member_number'  => [
            'label' => 'Member Number',
            'value' => fn( $m ) => $m->member_number ?? '',
        ],
        'prefix'         => [
            'label' => 'Prefix',
            'value' => fn( $m ) => $m->prefix ?? '',
        ],
        'first_name'     => [
            'label' => 'First Name',
            'value' => fn( $m ) => $m->first_name ?? '',
        ],
        'preferred_name' => [
            'label' => 'Preferred Name',
            'value' => fn( $m ) => $m->preferred_name ?? '',
        ],
        'middle_name'    => [
            'label' => 'Middle Name',
            'value' => fn( $m ) => $m->middle_name ?? '',
        ],
        'last_name'      => [
            'label' => 'Last Name',
            'value' => fn( $m ) => $m->last_name ?? '',
        ],
        'maiden_name'    => [
            'label' => 'Maiden Name',
            'value' => fn( $m ) => $m->maiden_name ?? '',
        ],
        'suffix'         => [
            'label' => 'Suffix',
            'value' => fn( $m ) => $m->suffix ?? '',
        ],
        'date_of_birth'  => [
            'label' => 'Date of Birth',
            'value' => fn( $m ) => $m->date_of_birth ?? '',
        ],

        // ---- Membership ----
        'status'         => [
            'label' => 'Status',
            'value' => fn( $m ) => ucfirst( $m->status ?? '' ),
        ],
        'tier_name'      => [
            'label' => 'Membership Type',
            'value' => fn( $m ) => $m->tier_name ?? '',
        ],
        'join_date'      => [
            'label' => 'Join Date',
            'value' => fn( $m ) => $m->join_date ?? '',
        ],
        'expiration_date' => [
            'label' => 'Expiration Date',
            'value' => fn( $m ) => $m->expiration_date ?? '',
        ],

        // ---- Contact ----
        'email'          => [
            'label' => 'Email',
            'value' => fn( $m ) => $m->email ?? '',
        ],
        'phone'          => [
            'label' => 'Phone',
            'value' => fn( $m ) => $m->phone ?? '',
        ],
        'cell'           => [
            'label' => 'Cell Phone',
            'value' => fn( $m ) => $m->cell ?? '',
        ],
        'website'        => [
            'label' => 'Website',
            'value' => fn( $m ) => $m->website ?? '',
        ],

        // ---- Address ----
        'address_1'      => [
            'label' => 'Address 1',
            'value' => fn( $m ) => $m->address_1 ?? '',
        ],
        'address_2'      => [
            'label' => 'Address 2',
            'value' => fn( $m ) => $m->address_2 ?? '',
        ],
        'city'           => [
            'label' => 'City',
            'value' => fn( $m ) => $m->city ?? '',
        ],
        'state'          => [
            'label' => 'State / Province',
            'value' => fn( $m ) => $m->state ?? '',
        ],
        'postal_code'    => [
            'label' => 'Postal Code',
            'value' => fn( $m ) => $m->postal_code ?? '',
        ],
        'country'        => [
            'label' => 'Country',
            'value' => fn( $m ) => $m->country ?? '',
        ],

        // ---- Seasonal Address ----
        'seasonal'       => [
            'label' => 'Has Seasonal Address',
            'value' => fn( $m ) => ( $m->seasonal ?? 0 ) ? 'Yes' : 'No',
        ],
        'seasonal_from'  => [
            'label' => 'Seasonal From',
            'value' => fn( $m ) => $m->seasonal_from ?? '',
        ],
        'seasonal_to'    => [
            'label' => 'Seasonal To',
            'value' => fn( $m ) => $m->seasonal_to ?? '',
        ],
        'seasonal_address_1' => [
            'label' => 'Seasonal Address',
            'value' => fn( $m ) => $m->seasonal_address_1 ?? '',
        ],
        'seasonal_city'  => [
            'label' => 'Seasonal City',
            'value' => fn( $m ) => $m->seasonal_city ?? '',
        ],
        'seasonal_state' => [
            'label' => 'Seasonal State',
            'value' => fn( $m ) => $m->seasonal_state ?? '',
        ],
        'seasonal_postal_code' => [
            'label' => 'Seasonal Postal Code',
            'value' => fn( $m ) => $m->seasonal_postal_code ?? '',
        ],
        'seasonal_country' => [
            'label' => 'Seasonal Country',
            'value' => fn( $m ) => $m->seasonal_country ?? '',
        ],

        // ---- Preferences ----
        'receive_print'  => [
            'label' => 'Receives Print',
            'value' => fn( $m ) => ( $m->receive_print ?? 0 ) ? 'Yes' : 'No',
        ],
        'pref_email_notices' => [
            'label' => 'Pref: General Emails',
            'value' => fn( $m ) => ( $m->pref_email_notices ?? 1 ) ? 'Yes' : 'No',
        ],
        'pref_email_events' => [
            'label' => 'Pref: Event Emails',
            'value' => fn( $m ) => ( $m->pref_email_events ?? 1 ) ? 'Yes' : 'No',
        ],
        'pref_email_newsletters' => [
            'label' => 'Pref: Newsletter Emails',
            'value' => fn( $m ) => ( $m->pref_email_newsletters ?? 1 ) ? 'Yes' : 'No',
        ],
        'pref_email_surnames' => [
            'label' => 'Pref: Surname Emails',
            'value' => fn( $m ) => ( $m->pref_email_surnames ?? 1 ) ? 'Yes' : 'No',
        ],

        // ---- Directory Visibility ----
        'dir_show_name'  => [
            'label' => 'Directory: Show Name',
            'value' => fn( $m ) => ( $m->dir_show_name ?? 1 ) ? 'Yes' : 'No',
        ],
        'dir_show_address' => [
            'label' => 'Directory: Show Address',
            'value' => fn( $m ) => ( $m->dir_show_address ?? 1 ) ? 'Yes' : 'No',
        ],
        'dir_show_phone' => [
            'label' => 'Directory: Show Phone',
            'value' => fn( $m ) => ( $m->dir_show_phone ?? 1 ) ? 'Yes' : 'No',
        ],
        'dir_show_email' => [
            'label' => 'Directory: Show Email',
            'value' => fn( $m ) => ( $m->dir_show_email ?? 1 ) ? 'Yes' : 'No',
        ],
        'dir_show_website' => [
            'label' => 'Directory: Show Website',
            'value' => fn( $m ) => ( $m->dir_show_website ?? 1 ) ? 'Yes' : 'No',
        ],
        'dir_show_photo' => [
            'label' => 'Directory: Show Photo',
            'value' => fn( $m ) => ( $m->dir_show_photo ?? 0 ) ? 'Yes' : 'No',
        ],
    ];

    // ----------------------------------------------------------------
    // Dynamic meta columns — pulled straight from the database
    //
    // WHY: Whatever a society imported or created as member meta shows
    //      up here automatically. No code changes, no config files.
    //      The meta_key becomes the column slug (prefixed with "meta:")
    //      and we generate a human-readable label from the key name.
    // ----------------------------------------------------------------
    global $wpdb;
    $prefix = $wpdb->prefix . 'sp_';

    $meta_keys = $wpdb->get_col(
        "SELECT DISTINCT meta_key FROM {$prefix}member_meta ORDER BY meta_key ASC"
    );

    // Convert meta_key slugs to human-readable labels
    // e.g. "joint_member" → "Joint Member", "skills" → "Skills"
    foreach ( $meta_keys as $mk ) {
        $label = ucwords( str_replace( [ '_', '-' ], ' ', $mk ) );
        // Prefix legacy keys for clarity
        if ( str_starts_with( $mk, 'legacy_' ) ) {
            $label = str_replace( 'Legacy ', 'Legacy: ', $label );
        }

        $columns[ 'meta:' . $mk ] = [
            'label' => $label,
            // WHY: The value getter receives the member object, but meta
            //      is stored separately. We attach all meta to the member
            //      object as ->_meta['key'] in the download handler before
            //      this closure runs. That way we query meta once in bulk
            //      instead of once per member per column.
            'value' => fn( $m ) => $m->_meta[ $mk ] ?? '',
        ];
    }

    return $columns;
}


/**
 * AJAX handler: return a filtered member count so the export page can
 * update the "X members match your filters" number in real time.
 *
 * WHY: Harold changes the Status dropdown to "Active" and immediately
 *      sees "247 members match your filters" instead of the total 356.
 *      No page reload, no guessing. He knows exactly what the CSV will
 *      contain before he clicks Download.
 */
add_action( 'wp_ajax_sp_export_count', function () {
    check_ajax_referer( 'sp_export_count' );

    if ( ! current_user_can( 'manage_options' ) ) {
        wp_send_json_error( __( 'Unauthorized', 'societypress' ), 403 );
    }

    global $wpdb;
    $prefix = $wpdb->prefix . 'sp_';

    $where  = [];
    $values = [];

    $status = sanitize_text_field( $_POST['status'] ?? '' );
    if ( ! empty( $status ) && $status !== 'all' ) {
        $where[]  = 'status = %s';
        $values[] = $status;
    }

    $tier_id = absint( $_POST['tier'] ?? 0 );
    if ( $tier_id > 0 ) {
        $where[]  = 'tier_id = %d';
        $values[] = $tier_id;
    }

    $join_from = sanitize_text_field( $_POST['join_from'] ?? '' );
    $join_to   = sanitize_text_field( $_POST['join_to'] ?? '' );
    if ( ! empty( $join_from ) ) {
        $where[]  = 'join_date >= %s';
        $values[] = $join_from;
    }
    if ( ! empty( $join_to ) ) {
        $where[]  = 'join_date <= %s';
        $values[] = $join_to;
    }

    $exp_from = sanitize_text_field( $_POST['exp_from'] ?? '' );
    $exp_to   = sanitize_text_field( $_POST['exp_to'] ?? '' );
    if ( ! empty( $exp_from ) ) {
        $where[]  = 'expiration_date >= %s';
        $values[] = $exp_from;
    }
    if ( ! empty( $exp_to ) ) {
        $where[]  = 'expiration_date <= %s';
        $values[] = $exp_to;
    }

    $where_sql = '';
    if ( ! empty( $where ) ) {
        $where_sql = 'WHERE ' . implode( ' AND ', $where );
    }

    $sql = "SELECT COUNT(*) FROM {$prefix}members {$where_sql}";
    if ( ! empty( $values ) ) {
        $sql = $wpdb->prepare( $sql, $values );
    }

    $count = (int) $wpdb->get_var( $sql );
    wp_send_json_success( [ 'count' => number_format( $count ) ] );
});


/**
 * Render the Export Members admin page.
 *
 * WHY: Societies need to export their data for all kinds of reasons —
 *      mailing labels, treasurer reports, board presentations, backups,
 *      or migrating somewhere else (hopefully not). This page lets them
 *      filter by status/tier/date range and pick exactly which columns
 *      they want. Big friendly "Download CSV" button at the bottom.
 */
function sp_render_export_page(): void {
    global $wpdb;
    $prefix = $wpdb->prefix . 'sp_';

    // Get tier list for the filter dropdown
    $tiers = $wpdb->get_results(
        "SELECT id, name FROM {$prefix}membership_tiers ORDER BY sort_order ASC, name ASC"
    );

    // Get member count for the summary
    $total_members = (int) $wpdb->get_var( "SELECT COUNT(*) FROM {$prefix}members" );

    // All exportable columns
    $columns = sp_get_export_columns();

    // Group columns for the checkbox UI
    $groups = [
        'Identity'           => [ 'member_type', 'organization_name', 'member_number',
                                  'prefix', 'first_name', 'preferred_name',
                                  'middle_name', 'last_name', 'maiden_name', 'suffix',
                                  'date_of_birth' ],
        'Membership'         => [ 'status', 'tier_name', 'join_date', 'expiration_date' ],
        'Contact'            => [ 'email', 'phone', 'cell', 'website' ],
        'Address'            => [ 'address_1', 'address_2', 'city', 'state', 'postal_code',
                                  'country' ],
        'Seasonal Address'   => [ 'seasonal', 'seasonal_from', 'seasonal_to',
                                  'seasonal_address_1', 'seasonal_city', 'seasonal_state',
                                  'seasonal_postal_code', 'seasonal_country' ],
        'Preferences'        => [ 'receive_print', 'pref_email_notices', 'pref_email_events',
                                  'pref_email_newsletters', 'pref_email_surnames' ],
        'Directory Visibility' => [ 'dir_show_name', 'dir_show_address', 'dir_show_phone',
                                    'dir_show_email', 'dir_show_website', 'dir_show_photo' ],
    ];

    // Dynamically add any meta columns that exist in the database.
    // WHY: Whatever a society imported or created shows up automatically
    //      as checkboxes — no code changes, no config. If there are no
    //      meta keys yet, the group simply doesn't appear.
    $meta_col_keys = array_filter(
        array_keys( $columns ),
        fn( $k ) => str_starts_with( $k, 'meta:' )
    );
    if ( ! empty( $meta_col_keys ) ) {
        // Split into "useful" vs "legacy" groups so Harold isn't
        // overwhelmed by import artifacts he doesn't care about
        $custom_keys = [];
        $legacy_keys = [];
        foreach ( $meta_col_keys as $k ) {
            $raw_key = substr( $k, 5 ); // strip "meta:" prefix
            if ( str_starts_with( $raw_key, 'legacy_' ) ) {
                $legacy_keys[] = $k;
            } else {
                $custom_keys[] = $k;
            }
        }
        if ( ! empty( $custom_keys ) ) {
            $groups['Custom Fields'] = $custom_keys;
        }
        if ( ! empty( $legacy_keys ) ) {
            $groups['Legacy / Import Data'] = $legacy_keys;
        }
    }

    ?>
    <div class="wrap">
        <h1><?php esc_html_e( 'Export Members', 'societypress' ); ?></h1>

        <p style="font-size: 14px; color: #50575e; margin-bottom: 20px;">
            <strong id="sp-export-count"><?php echo esc_html( number_format( $total_members ) ); ?></strong> <?php esc_html_e( 'members match your filters. Adjust the filters below to narrow your export, or leave them blank to export everyone.', 'societypress' ); ?>
        </p>
        <?php // AJAX nonce for live count updates ?>
        <input type="hidden" id="sp-export-count-nonce"
               value="<?php echo esc_attr( wp_create_nonce( 'sp_export_count' ) ); ?>"
        >

        <form method="post">
            <?php wp_nonce_field( 'sp_export_members' ); ?>
            <input type="hidden" name="sp_export_action" value="download">

            <!-- ============================================================ -->
            <!-- FILTERS                                                       -->
            <!-- ============================================================ -->

            <div style="max-width: 800px; background: #fff; border: 1px solid #c3c4c7; border-radius: 4px; margin-bottom: 20px;">
                <h2 style="margin: 0; padding: 12px 20px; border-bottom: 1px solid #c3c4c7; font-size: 14px; font-weight: 600; background: #f6f7f7;">
                    <?php esc_html_e( 'Filters', 'societypress' ); ?>
                </h2>
                <div style="padding: 20px;">

                    <table class="form-table" role="presentation" style="margin: 0;">
                        <tr>
                            <th scope="row"><label for="sp-export-status"><?php esc_html_e( 'Status', 'societypress' ); ?></label></th>
                            <td>
                                <select name="sp_export_status" id="sp-export-status">
                                    <option value="all"><?php esc_html_e( 'All Statuses', 'societypress' ); ?></option>
                                    <option value="active"><?php esc_html_e( 'Active', 'societypress' ); ?></option>
                                    <option value="lapsed"><?php esc_html_e( 'Lapsed', 'societypress' ); ?></option>
                                    <option value="expired"><?php esc_html_e( 'Expired', 'societypress' ); ?></option>
                                    <option value="grace"><?php esc_html_e( 'Grace Period', 'societypress' ); ?></option>
                                    <option value="deceased"><?php esc_html_e( 'Deceased', 'societypress' ); ?></option>
                                    <option value="inactive"><?php esc_html_e( 'Inactive', 'societypress' ); ?></option>
                                </select>
                            </td>
                        </tr>
                        <tr>
                            <th scope="row"><label for="sp-export-tier"><?php esc_html_e( 'Membership Type', 'societypress' ); ?></label></th>
                            <td>
                                <select name="sp_export_tier" id="sp-export-tier">
                                    <option value="0"><?php esc_html_e( 'All Types', 'societypress' ); ?></option>
                                    <?php foreach ( $tiers as $tier ) : ?>
                                        <option value="<?php echo esc_attr( $tier->id ); ?>">
                                            <?php echo esc_html( $tier->name ); ?>
                                        </option>
                                    <?php endforeach; ?>
                                </select>
                            </td>
                        </tr>
                        <tr>
                            <th scope="row"><?php esc_html_e( 'Join Date Range', 'societypress' ); ?></th>
                            <td>
                                <input type="date" name="sp_export_join_from" style="width: 160px;">
                                <span style="padding: 0 8px; color: #50575e;"><?php esc_html_e( 'to', 'societypress' ); ?></span>
                                <input type="date" name="sp_export_join_to" style="width: 160px;">
                            </td>
                        </tr>
                        <tr>
                            <th scope="row"><?php esc_html_e( 'Expiration Date Range', 'societypress' ); ?></th>
                            <td>
                                <input type="date" name="sp_export_exp_from" style="width: 160px;">
                                <span style="padding: 0 8px; color: #50575e;"><?php esc_html_e( 'to', 'societypress' ); ?></span>
                                <input type="date" name="sp_export_exp_to" style="width: 160px;">
                            </td>
                        </tr>
                    </table>

                </div>
            </div>

            <!-- ============================================================ -->
            <!-- COLUMN SELECTION                                              -->
            <!-- ============================================================ -->

            <div style="max-width: 800px; background: #fff; border: 1px solid #c3c4c7; border-radius: 4px; margin-bottom: 20px;">
                <h2 style="margin: 0; padding: 12px 20px; border-bottom: 1px solid #c3c4c7; font-size: 14px; font-weight: 600; background: #f6f7f7;">
                    <?php esc_html_e( 'Columns to Export', 'societypress' ); ?>
                    <span style="font-weight: 400; color: #50575e; font-size: 12px; margin-left: 8px;">
                        <?php esc_html_e( 'Leave all unchecked to export everything.', 'societypress' ); ?>
                    </span>
                </h2>
                <div style="padding: 20px;">

                    <!-- Select All / None toggle -->
                    <p style="margin-top: 0; margin-bottom: 16px;">
                        <a href="#" id="sp-export-select-all" style="text-decoration: none;"><?php esc_html_e( 'Select All', 'societypress' ); ?></a>
                        &nbsp;|&nbsp;
                        <a href="#" id="sp-export-select-none" style="text-decoration: none;"><?php esc_html_e( 'Select None', 'societypress' ); ?></a>
                    </p>

                    <?php foreach ( $groups as $group_label => $group_keys ) : ?>
                        <fieldset style="margin-bottom: 16px; padding: 0; border: none;">
                            <legend style="font-weight: 600; font-size: 13px; margin-bottom: 6px; color: #1d2327;">
                                <?php echo esc_html( $group_label ); ?>
                            </legend>
                            <div style="display: flex; flex-wrap: wrap; gap: 4px 20px;">
                                <?php foreach ( $group_keys as $key ) :
                                    if ( ! isset( $columns[ $key ] ) ) continue;
                                ?>
                                    <label style="display: flex; align-items: center; gap: 4px; font-size: 13px; min-width: 180px; cursor: pointer;">
                                        <input type="checkbox" name="sp_export_fields[]"
                                               value="<?php echo esc_attr( $key ); ?>"
                                               class="sp-export-col-cb">
                                        <?php echo esc_html( $columns[ $key ]['label'] ); ?>
                                    </label>
                                <?php endforeach; ?>
                            </div>
                        </fieldset>
                    <?php endforeach; ?>

                </div>
            </div>

            <!-- ============================================================ -->
            <!-- SUBMIT                                                        -->
            <!-- ============================================================ -->

            <p>
                <?php submit_button( 'Download CSV', 'primary', 'sp_export_submit', false ); ?>
            </p>

        </form>

        <!-- Select All / Select None + Live Filter Count JS -->
        <script>
        (function() {
            var checkboxes = document.querySelectorAll('.sp-export-col-cb');

            document.getElementById('sp-export-select-all').addEventListener('click', function(e) {
                e.preventDefault();
                checkboxes.forEach(function(cb) { cb.checked = true; });
            });

            document.getElementById('sp-export-select-none').addEventListener('click', function(e) {
                e.preventDefault();
                checkboxes.forEach(function(cb) { cb.checked = false; });
            });

            // ============================================================
            // Live filter count — updates "X members match" when any
            // filter dropdown or date field changes.
            //
            // WHY: Immediate feedback. Harold picks "Active" from the
            //      status dropdown and instantly sees the number shrink.
            //      No guessing, no wasted exports of the wrong data set.
            // ============================================================
            var countEl   = document.getElementById('sp-export-count');
            var nonceEl   = document.getElementById('sp-export-count-nonce');
            var statusEl  = document.getElementById('sp-export-status');
            var tierEl    = document.getElementById('sp-export-tier');
            var joinFrom  = document.querySelector('input[name="sp_export_join_from"]');
            var joinTo    = document.querySelector('input[name="sp_export_join_to"]');
            var expFrom   = document.querySelector('input[name="sp_export_exp_from"]');
            var expTo     = document.querySelector('input[name="sp_export_exp_to"]');

            var debounceTimer = null;

            function updateCount() {
                // Debounce so rapid changes don't spam the server
                clearTimeout(debounceTimer);
                debounceTimer = setTimeout(function() {
                    var data = new FormData();
                    data.append('action', 'sp_export_count');
                    data.append('_ajax_nonce', nonceEl.value);
                    data.append('status', statusEl.value);
                    data.append('tier', tierEl.value);
                    data.append('join_from', joinFrom.value);
                    data.append('join_to', joinTo.value);
                    data.append('exp_from', expFrom.value);
                    data.append('exp_to', expTo.value);

                    countEl.style.opacity = '0.5';

                    fetch(ajaxurl, { method: 'POST', body: data })
                        .then(function(r) { return r.json(); })
                        .then(function(resp) {
                            if (resp.success) {
                                countEl.textContent = resp.data.count;
                            }
                            countEl.style.opacity = '1';
                        })
                        .catch(function() {
                            countEl.style.opacity = '1';
                        });
                }, 300);
            }

            // Listen on all filter inputs
            [statusEl, tierEl, joinFrom, joinTo, expFrom, expTo].forEach(function(el) {
                if (el) el.addEventListener('change', updateCount);
            });
        })();
        </script>
    </div>
    <?php
}


// ============================================================================
// SETTINGS REGISTRATION (WordPress Settings API)
// ============================================================================

/**
 * Register all settings — both SocietyPress-specific and WordPress core
 * settings that we've absorbed into our consolidated Settings page.
 *
 * WHY: Instead of scattering settings across six WordPress pages (General,
 *      Writing, Reading, Discussion, Media, Permalinks), we put everything
 *      the user needs into one clean page. WordPress core options like
 *      blogname and timezone_string are registered in our settings group
 *      so they save through the same form submission.
 *
 * HOW IT WORKS:
 *      WordPress's Settings API uses register_setting() to whitelist option
 *      names for a given settings group. When the form submits to options.php,
 *      WordPress checks that each submitted option is registered in the
 *      specified group before saving it. By registering WordPress core
 *      options (blogname, etc.) in our group, they save seamlessly alongside
 *      our custom societypress_settings option.
 */
add_action( 'admin_init', function () {

    // ====================================================================
    // SETTINGS REGISTRATION — One group per page.
    //
    // WHY separate groups: Each settings page has its own <form> that
    //      posts to options.php. WordPress only saves options that are
    //      registered under the group in the form's settings_fields().
    //      If we kept everything under one group and the Website page
    //      submitted without any societypress_settings[] fields, the
    //      sanitize callback would receive an empty array and wipe out
    //      all Organization/Membership/etc. data. Separate groups =
    //      each page only touches the options it displays.
    // ====================================================================

    // ---- WEBSITE page — WordPress core options only ----
    register_setting( 'societypress_settings_group', 'blogname',
        [ 'sanitize_callback' => 'sanitize_text_field' ] );

    register_setting( 'societypress_settings_group', 'blogdescription',
        [ 'sanitize_callback' => 'sanitize_text_field' ] );

    register_setting( 'societypress_settings_group', 'admin_email',
        [ 'sanitize_callback' => 'sanitize_email' ] );

    register_setting( 'societypress_settings_group', 'timezone_string',
        [ 'sanitize_callback' => 'sanitize_text_field' ] );

    register_setting( 'societypress_settings_group', 'date_format',
        [ 'sanitize_callback' => 'sanitize_text_field' ] );

    register_setting( 'societypress_settings_group', 'time_format',
        [ 'sanitize_callback' => 'sanitize_text_field' ] );

    register_setting( 'societypress_settings_group', 'show_on_front',
        [ 'sanitize_callback' => 'sanitize_text_field' ] );

    register_setting( 'societypress_settings_group', 'page_on_front',
        [ 'sanitize_callback' => 'absint' ] );

    register_setting( 'societypress_settings_group', 'blog_public',
        [ 'sanitize_callback' => 'absint' ] );

    // ---- WEBSITE page also has SP settings (login requirement, admin bar) ----
    register_setting(
        'societypress_settings_group',
        'societypress_settings',
        [
            'type'              => 'array',
            'sanitize_callback' => 'sp_sanitize_settings',
        ]
    );

    // ---- ORGANIZATION page — saves to societypress_settings array ----
    register_setting(
        'sp-settings-org',
        'societypress_settings',
        [
            'type'              => 'array',
            'sanitize_callback' => 'sp_sanitize_settings',
        ]
    );

    // ---- MEMBERSHIP page — saves to societypress_settings array ----
    register_setting(
        'sp-settings-membership',
        'societypress_settings',
        [
            'type'              => 'array',
            'sanitize_callback' => 'sp_sanitize_settings',
        ]
    );

    // ---- DIRECTORY page — saves to societypress_settings array ----
    register_setting(
        'sp-settings-directory',
        'societypress_settings',
        [
            'type'              => 'array',
            'sanitize_callback' => 'sp_sanitize_settings',
        ]
    );

    // ---- EVENTS page — saves to societypress_settings array ----
    register_setting(
        'sp-settings-events',
        'societypress_settings',
        [
            'type'              => 'array',
            'sanitize_callback' => 'sp_sanitize_settings',
        ]
    );

    // ---- PRIVACY page — just the privacy policy page picker ----
    register_setting( 'sp-settings-privacy', 'wp_page_for_privacy_policy',
        [ 'sanitize_callback' => 'absint' ] );

    // ---- DESIGN page — saves to societypress_settings array ----
    register_setting(
        'sp-settings-design',
        'societypress_settings',
        [
            'type'              => 'array',
            'sanitize_callback' => 'sp_sanitize_settings',
        ]
    );


    // ====================================================================
    // SECTION: Your Website
    // ====================================================================

    add_settings_section(
        'sp_website_section',
        __( 'Your Website', 'societypress' ),
        function () {
            echo '<p>' . esc_html__( 'Basic settings for your website.', 'societypress' ) . '</p>';
        },
        'sp-settings-website'
    );

    // --- Site Title ---
    add_settings_field(
        'blogname',
        __( 'Site Title', 'societypress' ),
        function () {
            printf(
                '<input type="text" name="blogname" value="%s" class="regular-text">',
                esc_attr( get_option( 'blogname', '' ) )
            );
            echo '<p class="description">' . esc_html__( 'The name of your website, shown in the browser tab and site header.', 'societypress' ) . '</p>';
        },
        'sp-settings-website',
        'sp_website_section'
    );

    // --- Tagline ---
    add_settings_field(
        'blogdescription',
        __( 'Tagline', 'societypress' ),
        function () {
            printf(
                '<input type="text" name="blogdescription" value="%s" class="regular-text">',
                esc_attr( get_option( 'blogdescription', '' ) )
            );
            echo '<p class="description">' . esc_html__( 'A short phrase describing your organization (appears below the site title).', 'societypress' ) . '</p>';
        },
        'sp-settings-website',
        'sp_website_section'
    );

    // --- Admin Email ---
    add_settings_field(
        'admin_email',
        __( 'Admin Email', 'societypress' ),
        function () {
            printf(
                '<input type="email" name="admin_email" value="%s" class="regular-text">',
                esc_attr( get_option( 'admin_email', '' ) )
            );
            echo '<p class="description">' . esc_html__( 'Password resets and system notifications are sent to this address.', 'societypress' ) . '</p>';
        },
        'sp-settings-website',
        'sp_website_section'
    );

    // --- Timezone ---
    // WHY: WordPress's built-in wp_timezone_choice() dumps every city on
    //      Earth into the dropdown — hundreds of entries grouped by continent.
    //      That's overwhelming for a non-technical user who just wants to
    //      pick their timezone. We replace it with a clean list of 38 UTC
    //      offsets, each paired with one recognizable city, covering the
    //      entire world. No one needs to know the difference between
    //      America/Chicago and America/Indiana/Knox.
    add_settings_field(
        'timezone_string',
        __( 'Timezone', 'societypress' ),
        function () {
            $current_tz = get_option( 'timezone_string', '' );

            // Every UTC offset that exists, paired with one well-known city.
            // The PHP timezone identifier is what WordPress actually stores.
            $timezones = [
                'Etc/GMT+12'         => 'UTC−12:00 — Baker Island',
                'Pacific/Pago_Pago'  => 'UTC−11:00 — Pago Pago',
                'Pacific/Honolulu'   => 'UTC−10:00 — Honolulu',
                'Pacific/Marquesas'  => 'UTC−09:30 — Marquesas Islands',
                'America/Anchorage'  => 'UTC−09:00 — Anchorage',
                'America/Los_Angeles'=> 'UTC−08:00 — Los Angeles',
                'America/Denver'     => 'UTC−07:00 — Denver',
                'America/Chicago'    => 'UTC−06:00 — Chicago, ND',
                'America/New_York'   => 'UTC−05:00 — New York',
                'America/Santiago'   => 'UTC−04:00 — Santiago',
                'America/St_Johns'   => 'UTC−03:30 — St. John\'s',
                'America/Sao_Paulo'  => 'UTC−03:00 — São Paulo',
                'America/Noronha'    => 'UTC−02:00 — Fernando de Noronha',
                'Atlantic/Cape_Verde'=> 'UTC−01:00 — Praia',
                'Europe/London'      => 'UTC±00:00 — London',
                'Europe/Paris'       => 'UTC+01:00 — Paris',
                'Africa/Cairo'       => 'UTC+02:00 — Cairo',
                'Europe/Moscow'      => 'UTC+03:00 — Moscow',
                'Asia/Tehran'        => 'UTC+03:30 — Tehran',
                'Asia/Dubai'         => 'UTC+04:00 — Dubai',
                'Asia/Kabul'         => 'UTC+04:30 — Kabul',
                'Asia/Karachi'       => 'UTC+05:00 — Karachi',
                'Asia/Kolkata'       => 'UTC+05:30 — Mumbai',
                'Asia/Kathmandu'     => 'UTC+05:45 — Kathmandu',
                'Asia/Dhaka'         => 'UTC+06:00 — Dhaka',
                'Asia/Yangon'        => 'UTC+06:30 — Yangon',
                'Asia/Bangkok'       => 'UTC+07:00 — Bangkok',
                'Asia/Shanghai'      => 'UTC+08:00 — Beijing',
                'Australia/Eucla'    => 'UTC+08:45 — Eucla',
                'Asia/Tokyo'         => 'UTC+09:00 — Tokyo',
                'Australia/Adelaide' => 'UTC+09:30 — Adelaide',
                'Australia/Sydney'   => 'UTC+10:00 — Sydney',
                'Australia/Lord_Howe'=> 'UTC+10:30 — Lord Howe Island',
                'Pacific/Noumea'     => 'UTC+11:00 — Nouméa',
                'Pacific/Auckland'   => 'UTC+12:00 — Auckland',
                'Pacific/Chatham'    => 'UTC+12:45 — Chatham Islands',
                'Pacific/Apia'       => 'UTC+13:00 — Apia',
                'Pacific/Kiritimati' => 'UTC+14:00 — Kiritimati',
            ];

            echo '<select name="timezone_string">';

            // Default empty option if nothing is set yet
            if ( empty( $current_tz ) ) {
                echo '<option value="">' . esc_html__( '— Select your timezone —', 'societypress' ) . '</option>';
            }

            foreach ( $timezones as $tz_id => $label ) {
                printf(
                    '<option value="%s" %s>%s</option>',
                    esc_attr( $tz_id ),
                    selected( $current_tz, $tz_id, false ),
                    esc_html( $label )
                );
            }

            echo '</select>';
            echo '<p class="description">' . esc_html__( 'Choose the timezone where your organization is located.', 'societypress' ) . '</p>';
        },
        'sp-settings-website',
        'sp_website_section'
    );

    // --- Date Format ---
    // WHY: We show live examples using Harold's actual current date (in his
    //      configured timezone) so the preview matches reality. No more
    //      guessing what "F j, Y" means — he sees today's date formatted
    //      each way and picks the one that looks right.
    add_settings_field(
        'date_format',
        __( 'Date Format', 'societypress' ),
        function () {
            $current = get_option( 'date_format', 'F j, Y' );

            // Each format paired with a human-friendly description.
            // wp_date() automatically uses the site's configured timezone,
            // so Harold sees HIS current date, not the server's.
            $formats = [
                'l, F jS, Y' => 'Full day name',      // Thursday, February 12th, 2026
                'F j, Y'     => 'Month and day',       // February 12, 2026
                'M j, Y'     => 'Short month',         // Feb 12, 2026
                'm/d/Y'      => 'US numeric',          // 02/12/2026
                'd/m/Y'      => 'International numeric',// 12/02/2026
                'Y-m-d'      => 'ISO standard',        // 2026-02-12
            ];

            foreach ( $formats as $format => $hint ) {
                // wp_date() respects the site timezone — shows Harold's local date
                $example = wp_date( $format );
                printf(
                    '<label style="display: block; margin-bottom: 6px;">'
                    . '<input type="radio" name="date_format" value="%s" %s> '
                    . '<span>%s</span>'
                    . '</label>',
                    esc_attr( $format ),
                    checked( $current, $format, false ),
                    esc_html( $example )
                );
            }
        },
        'sp-settings-website',
        'sp_website_section'
    );

    // --- Time Format ---
    // WHY: Same approach as date — live examples using Harold's current
    //      time in his timezone. The "with timezone" option (g:i A T) shows
    //      the abbreviation (CST, EST, etc.) so readers know at a glance
    //      which timezone events and dates refer to.
    add_settings_field(
        'time_format',
        __( 'Time Format', 'societypress' ),
        function () {
            $current = get_option( 'time_format', 'g:i A' );

            $formats = [
                'g:i A'   => '12-hour',               // 1:30 PM
                'g:i A T' => '12-hour with timezone',  // 1:30 PM CST
                'H:i'     => '24-hour',                // 13:30
            ];

            foreach ( $formats as $format => $hint ) {
                // wp_date() respects the site timezone — shows Harold's local time
                $example = wp_date( $format );
                printf(
                    '<label style="display: block; margin-bottom: 6px;">'
                    . '<input type="radio" name="time_format" value="%s" %s> '
                    . '<span>%s</span>'
                    . '</label>',
                    esc_attr( $format ),
                    checked( $current, $format, false ),
                    esc_html( $example )
                );
            }
        },
        'sp-settings-website',
        'sp_website_section'
    );

    // --- Homepage ---
    add_settings_field(
        'page_on_front',
        __( 'Homepage', 'societypress' ),
        function () {
            $page_on_front = get_option( 'page_on_front', 0 );

            // We always use a static page for the homepage, not "latest posts."
            // A society website isn't a blog — the front page should be a
            // designed welcome page, not a reverse-chronological post feed.
            echo '<input type="hidden" name="show_on_front" value="page">';

            // wp_dropdown_pages() outputs nothing if there are no published
            // pages — which leaves Harold staring at a bare description with
            // no dropdown. We check for that and show a helpful message instead.
            // WHY not get_pages(['number'=>1]): The 'number' param in get_pages()
            // doesn't reliably limit results in all WP versions. A direct count
            // query is fast and always works.
            global $wpdb;
            $pages_exist = (int) $wpdb->get_var( "SELECT COUNT(*) FROM $wpdb->posts WHERE post_type = 'page' AND post_status = 'publish'" );
            if ( $pages_exist > 0 ) {
                wp_dropdown_pages( [
                    'name'              => 'page_on_front',
                    'show_option_none'  => __( '— Select a page —', 'societypress' ),
                    'option_none_value' => '0',
                    'selected'          => $page_on_front,
                ] );
                echo '<p class="description">' . esc_html__( 'Choose which page visitors see when they go to your website\'s address.', 'societypress' ) . '</p>';
            } else {
                echo '<p class="description">'
                   . sprintf(
                       /* translators: %s: URL to create a new page */
                       __( 'No pages have been created yet. <a href="%s">Create your first page</a>, then come back here to set it as your homepage.', 'societypress' ),
                       esc_url( admin_url( 'post-new.php?post_type=page' ) )
                   )
                   . '</p>';
            }
        },
        'sp-settings-website',
        'sp_website_section'
    );

    // --- Search Engine Visibility ---
    add_settings_field(
        'blog_public',
        __( 'Search Engines', 'societypress' ),
        function () {
            $blog_public = get_option( 'blog_public', 1 );

            // Hidden field ensures blog_public=1 is submitted even when the
            // checkbox is unchecked. When checked, the checkbox value (0)
            // overrides the hidden field value (1).
            echo '<input type="hidden" name="blog_public" value="1">';
            printf(
                '<label><input type="checkbox" name="blog_public" value="0" %s> '
                . esc_html__( 'Discourage search engines from showing this site in results', 'societypress' ) . '</label>',
                checked( $blog_public, 0, false )
            );
            echo '<p class="description">' . esc_html__( 'Check this while you\'re still building your site. Uncheck it when you\'re ready for the world to find you.', 'societypress' ) . '</p>';
        },
        'sp-settings-website',
        'sp_website_section'
    );

