    );
}
add_action( 'admin_menu', 'sp_register_audit_log_menu', 99 );

/**
 * Render the Audit Log admin page.
 */
function sp_render_audit_log_page(): void {
    global $wpdb;
    $table = $wpdb->prefix . 'sp_audit_log';

    // Filters
    $filter_action = sanitize_text_field( $_GET['action_filter'] ?? '' );
    $filter_user   = (int) ( $_GET['user_filter'] ?? 0 );
    $search        = sanitize_text_field( $_GET['s'] ?? '' );
    $per_page      = 50;
    $paged         = max( 1, (int) ( $_GET['paged'] ?? 1 ) );
    $offset        = ( $paged - 1 ) * $per_page;

    $where = [ '1=1' ];
    $args  = [];

    if ( $filter_action ) {
        $where[] = 'a.action = %s';
        $args[]  = $filter_action;
    }
    if ( $filter_user ) {
        $where[] = 'a.user_id = %d';
        $args[]  = $filter_user;
    }
    if ( $search ) {
        $like    = '%' . $wpdb->esc_like( $search ) . '%';
        $where[] = '(a.description LIKE %s OR a.action LIKE %s)';
        $args[]  = $like;
        $args[]  = $like;
    }

    $where_sql = implode( ' AND ', $where );

    // Count total
    $count_sql = "SELECT COUNT(*) FROM {$table} a WHERE {$where_sql}";
    $total = $args
        ? (int) $wpdb->get_var( $wpdb->prepare( $count_sql, ...$args ) )
        : (int) $wpdb->get_var( $count_sql );
    $total_pages = ceil( $total / $per_page );

    // Get rows
    $rows_sql = "SELECT a.*, u.display_name AS user_name
                 FROM {$table} a
                 LEFT JOIN {$wpdb->users} u ON a.user_id = u.ID
                 WHERE {$where_sql}
                 ORDER BY a.created_at DESC
                 LIMIT %d OFFSET %d";
    $query_args = array_merge( $args, [ $per_page, $offset ] );
    $rows = $wpdb->get_results( $wpdb->prepare( $rows_sql, ...$query_args ) );

    // Distinct actions for filter dropdown
    $actions = $wpdb->get_col( "SELECT DISTINCT action FROM {$table} ORDER BY action" );

    ?>
    <div class="wrap sp-admin-wrap">
        <h1><?php esc_html_e( 'Audit Log', 'societypress' ); ?></h1>

        <style>
            .sp-audit-filters { background: #fff; border: 1px solid #c3c4c7; padding: 12px; margin: 12px 0; display: flex; gap: 8px; align-items: end; flex-wrap: wrap; }
            .sp-audit-filters label { font-size: 12px; display: block; margin-bottom: 2px; color: #646970; }
            .sp-audit-filters select,
            .sp-audit-filters input { padding: 4px 8px; }
            .sp-audit-action { display: inline-block; background: #f0f0f1; padding: 2px 8px; border-radius: 3px; font-size: 12px; font-family: monospace; }
            .sp-audit-obj { color: #646970; font-size: 12px; }
        </style>

        <form method="get" class="sp-audit-filters">
            <input type="hidden" name="page" value="sp-audit-log">
            <div>
                <label for="sp-af-action"><?php esc_html_e( 'Action', 'societypress' ); ?></label>
                <select name="action_filter" id="sp-af-action">
                    <option value="">All Actions</option>
                    <?php foreach ( $actions as $a ) : ?>
                        <option value="<?php echo esc_attr( $a ); ?>" <?php selected( $filter_action, $a ); ?>><?php echo esc_html( $a ); ?></option>
                    <?php endforeach; ?>
                </select>
            </div>
            <div>
                <label for="sp-af-search"><?php esc_html_e( 'Search', 'societypress' ); ?></label>
                <input type="search" name="s" id="sp-af-search" value="<?php echo esc_attr( $search ); ?>" placeholder="Description...">
            </div>
            <div>
                <button type="submit" class="button"><?php esc_html_e( 'Filter', 'societypress' ); ?></button>
                <?php if ( $filter_action || $filter_user || $search ) : ?>
                    <a href="<?php echo esc_url( admin_url( 'admin.php?page=sp-audit-log' ) ); ?>" class="button"><?php esc_html_e( 'Clear', 'societypress' ); ?></a>
                <?php endif; ?>
            </div>
        </form>

        <table class="widefat striped">
            <thead>
                <tr>
                    <th><?php esc_html_e( 'Date/Time', 'societypress' ); ?></th>
                    <th><?php esc_html_e( 'User', 'societypress' ); ?></th>
                    <th><?php esc_html_e( 'Action', 'societypress' ); ?></th>
                    <th><?php esc_html_e( 'Description', 'societypress' ); ?></th>
                    <th><?php esc_html_e( 'Object', 'societypress' ); ?></th>
                    <th><?php esc_html_e( 'IP', 'societypress' ); ?></th>
                </tr>
            </thead>
            <tbody>
                <?php if ( empty( $rows ) ) : ?>
                    <tr><td colspan="6" style="text-align: center; padding: 20px;"><?php esc_html_e( 'No log entries found.', 'societypress' ); ?></td></tr>
                <?php else : ?>
                    <?php foreach ( $rows as $row ) : ?>
                        <tr>
                            <!-- WHY: wp_date() respects the site's timezone setting; PHP date() uses server timezone. -->
                            <td style="white-space: nowrap;"><?php echo esc_html( wp_date( 'M j, Y g:i A', strtotime( $row->created_at ) ) ); ?></td>
                            <td><?php echo $row->user_name ? esc_html( $row->user_name ) : '<span style="color:#787c82;">System</span>'; ?></td>
                            <td><span class="sp-audit-action"><?php echo esc_html( $row->action ); ?></span></td>
                            <td><?php echo $row->description ? esc_html( $row->description ) : ''; ?></td>
                            <td class="sp-audit-obj">
                                <?php if ( $row->object_type ) : ?>
                                    <?php echo esc_html( $row->object_type ); ?>
                                    <?php if ( $row->object_id ) : ?>
                                        #<?php echo esc_html( $row->object_id ); ?>
                                    <?php endif; ?>
                                <?php endif; ?>
                            </td>
                            <td style="font-size: 12px; color: #787c82;"><?php echo $row->ip_address ? esc_html( $row->ip_address ) : ''; ?></td>
                        </tr>
                    <?php endforeach; ?>
                <?php endif; ?>
            </tbody>
        </table>

        <?php if ( $total_pages > 1 ) : ?>
            <div class="tablenav bottom">
                <div class="tablenav-pages">
                    <span class="displaying-num"><?php echo number_format( $total ); ?> entries</span>
                    <?php
                    echo paginate_links( [
                        'base'    => add_query_arg( 'paged', '%#%' ),
                        'format'  => '',
                        'current' => $paged,
                        'total'   => $total_pages,
                        'prev_text' => '&laquo;',
                        'next_text' => '&raquo;',
                    ] );
                    ?>
                </div>
            </div>
        <?php endif; ?>

        <p style="margin-top: 16px; color: #646970; font-size: 12px;">
            Log entries older than 1 year are automatically pruned.
            <?php echo number_format( $total ); ?> total entries.
        </p>
    </div>
    <?php
}

