                                    <?php /* translators: %s: version number */ ?>
                                    <?php printf( esc_html__( 'Update to %s', 'societypress' ), esc_html( $reg_version ) ); ?>
                                </button>
                            <?php endif; ?>

                            <?php
                            // Edit and Delete buttons for custom themes
