                                    <?php esc_html_e( 'Delete', 'societypress' ); ?>
                                </button>
                            <?php endif; ?>
                        </div>
                    </div>
                </div>
            <?php endforeach; ?>

            <!-- ============================================================ -->
            <!-- AVAILABLE (NOT INSTALLED) THEMES FROM REGISTRY               -->
