    <!-- ================================================================== -->
    <!-- DESIGN PAGE — COLOR PICKER INIT + LIVE PREVIEW ENGINE              -->
    <!-- ================================================================== -->
    <!-- WHY all of this is inline instead of a separate .js file:           -->
    <!-- Single-file plugin architecture. This script only loads on the      -->
    <!-- Design page (it's inside sp_render_settings_design_page), so        -->
    <!-- there's zero overhead on other admin pages or the frontend.         -->
    <script>
    (function() {
        // ---- Logo uploader ----
        // WHY deferred to window load: wp_enqueue_media() outputs its scripts
        // in the footer (wp_footer hook), which runs AFTER our inline <script>
        // in the page body. If we check for wp.media right now, it doesn't
        // exist yet and the handler silently never attaches. Deferring to
        // window 'load' guarantees all footer scripts have executed.
        window.addEventListener('load', function() {
            var logoBtn    = document.getElementById('sp-logo-upload-btn');
            var logoRemove = document.getElementById('sp-logo-remove-btn');
            var logoInput  = document.getElementById('sp-design-logo-id');
            var logoPreview = document.getElementById('sp-logo-preview');

            if (logoBtn && typeof wp !== 'undefined' && wp.media) {
                var logoFrame;

                logoBtn.addEventListener('click', function(e) {
                    e.preventDefault();

                    if (logoFrame) {
                        logoFrame.open();
                        return;
                    }

                    logoFrame = wp.media({
                        title:    'Select Logo',
                        button:   { text: 'Use as Logo' },
                        multiple: false
                    });

                    logoFrame.on('select', function() {
                        var attachment = logoFrame.state().get('selection').first().toJSON();
                        logoInput.value = attachment.id;
                        // Use medium size if available, otherwise full URL (SVGs only have full)
                        var url = (attachment.sizes && attachment.sizes.medium)
                                ? attachment.sizes.medium.url
                                : attachment.url;
                        logoPreview.innerHTML = '<img src="' + url + '" style="max-height: 80px; width: auto; background: #f0f0f0; padding: 8px; border-radius: 4px;">';
                        logoBtn.textContent = '<?php echo esc_js( __( 'Change Logo', 'societypress' ) ); ?>';
                        if (logoRemove) logoRemove.style.display = '';
                    });

                    logoFrame.open();
                });

                if (logoRemove) {
                    logoRemove.addEventListener('click', function(e) {
                        e.preventDefault();
                        logoInput.value = '0';
                        logoPreview.innerHTML = '';
                        logoBtn.textContent = '<?php echo esc_js( __( 'Upload Logo', 'societypress' ) ); ?>';
                        logoRemove.style.display = 'none';
                    });
                }
            }
        });

        // ---- Initialize WordPress color pickers ----
        // WHY: WordPress ships wp-color-picker (based on Iris) but we need
        // to initialize it ourselves. The 'change' and 'clear' callbacks
        // trigger preview updates whenever a color changes.
        if (typeof jQuery !== 'undefined' && jQuery.fn.wpColorPicker) {
            jQuery('.sp-color-picker').wpColorPicker({
                change: function() {
                    // Small delay because wpColorPicker fires 'change' before
                    // updating the input value. 50ms is enough for it to sync.
                    setTimeout(updatePreview, 50);
                },
                clear: function() {
                    setTimeout(updatePreview, 50);
                }
            });
        }

        // ---- Font family mapping (mirrors the PHP mapping in functions.php) ----
        // WHY duplicated here: The preview runs client-side and needs to know
        // what CSS font stack each key maps to. Keeping it in sync with the
        // PHP version is critical — if you add a font, add it in both places.
        var fontMap = {
            'system':       "-apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, Oxygen, Ubuntu, Cantarell, sans-serif",
            'georgia':      "Georgia, 'Times New Roman', serif",
            'palatino':     "'Palatino Linotype', 'Book Antiqua', Palatino, serif",
            'garamond':     "'EB Garamond', Georgia, serif",
            'merriweather': "Merriweather, Georgia, serif",
            'lora':         "Lora, Georgia, serif",
            'roboto':       "Roboto, -apple-system, BlinkMacSystemFont, sans-serif",
            'open-sans':    "'Open Sans', -apple-system, BlinkMacSystemFont, sans-serif",
            'source-sans':  "'Source Sans 3', -apple-system, BlinkMacSystemFont, sans-serif",
            'nunito':       "Nunito, -apple-system, BlinkMacSystemFont, sans-serif"
        };

        // Google Fonts that need loading via <link> tag (web-safe fonts don't)
        var googleFonts = {
            'garamond':     'EB+Garamond:wght@400;500;600;700',
            'merriweather': 'Merriweather:wght@400;700',
            'lora':         'Lora:wght@400;500;600;700',
            'roboto':       'Roboto:wght@400;500;700',
            'open-sans':    'Open+Sans:wght@400;500;600;700',
            'source-sans':  'Source+Sans+3:wght@400;500;600;700',
            'nunito':       'Nunito:wght@400;500;600;700'
        };

        // Size/scale/width mappings (mirrors PHP)
        var sizeMap  = { 'compact': '16px', 'comfortable': '18px', 'large': '20px' };
        var scaleMap = { 'small': '0.85', 'normal': '1', 'large': '1.15' };
        var widthMap = { 'narrow': '900px', 'standard': '1100px', 'wide': '1400px' };

        var iframe = document.getElementById('sp-design-preview');

        /**
         * Read all current design form values and inject a <style> block
         * into the preview iframe's <head> that overrides :root variables.
         *
         * WHY we override :root in the iframe: The iframe loads the real
         * homepage which already has the :root block from functions.php.
         * By injecting a second :root block with higher specificity (later
         * in the cascade), we override the saved values with the unsaved
         * form values. This gives Harold an instant preview without saving.
         */
        function updatePreview() {
            if (!iframe || !iframe.contentDocument) return;

            try {
                var doc = iframe.contentDocument;
                var head = doc.head || doc.getElementsByTagName('head')[0];
                if (!head) return;

                // Get color values — wpColorPicker stores the value in the
                // original input, which may be hidden. jQuery can read it.
                var primary      = getColorValue('sp-design-primary', '#1e3a5f');
                var primaryHover = getColorValue('sp-design-primary-hover', '#2c5282');
                var accent       = getColorValue('sp-design-accent', '#667eea');
                var headerBg     = getColorValue('sp-design-header-bg', '#1e3a5f');
                var headerText   = getColorValue('sp-design-header-text', '#ffffff');
                var footerBg     = getColorValue('sp-design-footer-bg', '#1e3a5f');
                var footerText   = getColorValue('sp-design-footer-text', '#ffffff');

                // Get select values
                var bodyFont     = document.getElementById('sp-design-font-body').value;
                var headingFont  = document.getElementById('sp-design-font-heading').value;
                var fontSize     = document.getElementById('sp-design-font-size').value;
                var headingScale = document.getElementById('sp-design-heading-scale').value;
                var contentWidth = document.getElementById('sp-design-content-width').value;

                // Resolve font family strings
                var bodyFontCSS    = fontMap[bodyFont] || fontMap['system'];
                var headingFontCSS = (headingFont === 'inherit') ? 'inherit' : (fontMap[headingFont] || 'inherit');

                // Build the override CSS
                var css = ':root {\n'
                    + '  --sp-color-primary: ' + primary + ';\n'
                    + '  --sp-color-primary-hover: ' + primaryHover + ';\n'
                    + '  --sp-color-accent: ' + accent + ';\n'
                    + '  --sp-color-header-bg: ' + headerBg + ';\n'
                    + '  --sp-color-header-text: ' + headerText + ';\n'
                    + '  --sp-color-footer-bg: ' + footerBg + ';\n'
                    + '  --sp-color-footer-text: ' + footerText + ';\n'
                    + '  --sp-font-body: ' + bodyFontCSS + ';\n'
                    + '  --sp-font-heading: ' + headingFontCSS + ';\n'
                    + '  --sp-font-size-base: ' + (sizeMap[fontSize] || '18px') + ';\n'
                    + '  --sp-font-scale: ' + (scaleMap[headingScale] || '1') + ';\n'
                    + '  --sp-content-width: ' + (contentWidth === 'custom'
                        ? (document.getElementById('sp-design-content-width-px').value || '1100') + 'px'
                        : (widthMap[contentWidth] || '1100px')) + ';\n'
                    + '}\n';

                // Remove any existing preview override style
                var existing = doc.getElementById('sp-design-preview-override');
                if (existing) existing.remove();

                // Inject the new override style
                var style = doc.createElement('style');
                style.id = 'sp-design-preview-override';
                style.textContent = css;
                head.appendChild(style);

                // Load Google Fonts in the iframe if needed
                loadGoogleFontsInIframe(doc, head, bodyFont, headingFont);

            } catch (e) {
                // Cross-origin errors are expected if the iframe hasn't loaded
                // yet or if the site is on a different domain. Silently ignore.
            }
        }

        /**
         * Get the current color value from a wpColorPicker input.
         * WHY: wpColorPicker hides the original input and creates its own
         * UI elements. We need to read the actual input value, which jQuery's
         * wpColorPicker keeps in sync.
         */
        function getColorValue(inputId, fallback) {
            var el = document.getElementById(inputId);
            if (!el) return fallback;
            return el.value || fallback;
        }

        /**
         * Load Google Fonts inside the preview iframe when a Google Font
         * is selected. We track which fonts are already loaded to avoid
         * duplicate <link> tags.
         */
        function loadGoogleFontsInIframe(doc, head, bodyKey, headingKey) {
            var families = [];
            if (googleFonts[bodyKey]) families.push(googleFonts[bodyKey]);
            if (headingKey !== 'inherit' && headingKey !== bodyKey && googleFonts[headingKey]) {
                families.push(googleFonts[headingKey]);
            }

            // Remove old Google Fonts link if any
            var oldLink = doc.getElementById('sp-preview-google-fonts');
            if (oldLink) oldLink.remove();

            if (families.length === 0) return;

            var link = doc.createElement('link');
            link.id = 'sp-preview-google-fonts';
            link.rel = 'stylesheet';
            link.href = 'https://fonts.googleapis.com/css2?family=' + families.join('&family=') + '&display=swap';
            head.appendChild(link);
        }

        // ---- Bind change/input events on all design controls ----
        // WHY both 'change' and 'input': 'change' fires when a select changes
        // or when the color picker closes. 'input' fires continuously as the
        // user drags the color picker slider, giving true real-time feedback.
        var controls = document.querySelectorAll('.sp-design-control');
        controls.forEach(function(ctrl) {
            ctrl.addEventListener('change', updatePreview);
            ctrl.addEventListener('input', updatePreview);
        });

        // ---- Device width toggle ----
        // WHY: Harold wants to see how the site looks on different screen sizes.
        // Instead of making him resize his browser, we resize the iframe container.
        var deviceBtns = document.querySelectorAll('.sp-preview-device');
        var previewContainer = document.getElementById('sp-preview-container');
        deviceBtns.forEach(function(btn) {
            btn.addEventListener('click', function() {
                deviceBtns.forEach(function(b) { b.classList.remove('sp-preview-device-active'); });
                this.classList.add('sp-preview-device-active');
                var width = this.getAttribute('data-width');
                if (previewContainer) {
                    previewContainer.style.maxWidth = width;
                    // Center the container when it's narrower than full width
                    previewContainer.style.margin = (width === '100%') ? '0' : '0 auto';
                }
            });
        });

        // ---- Active device button styling ----
        var styleTag = document.createElement('style');
        styleTag.textContent = '.sp-preview-device-active { background: #2271b1 !important; color: #fff !important; border-color: #2271b1 !important; }';
        document.head.appendChild(styleTag);

        // ---- Custom width row toggle ----
        // WHY: The Custom Width field should only show when "Custom" is selected
        // in the Content Width dropdown. No point confusing Harold with an extra
        // field when he's using a preset.
        var widthSelect  = document.getElementById('sp-design-content-width');
        var customRow    = document.getElementById('sp-custom-width-row');
        if (widthSelect && customRow) {
            widthSelect.addEventListener('change', function() {
                customRow.style.display = (this.value === 'custom') ? '' : 'none';
            });
        }

        // ---- Style presets ----
        // WHY: Clicking a preset card fills in all color + font fields at once,
        //      then triggers updatePreview() so the iframe reflects the new
        //      values immediately. Harold sees the result before he even saves.
        document.querySelectorAll('.sp-preset-card').forEach(function(card) {
            card.addEventListener('click', function() {
                var colors      = JSON.parse(this.getAttribute('data-colors'));
                var fontBody    = this.getAttribute('data-font-body');
                var fontHeading = this.getAttribute('data-font-heading');

                // Colors order: primary, primaryHover, accent, headerBg, headerText, footerBg, footerText
                var colorIds = [
                    'sp-design-primary', 'sp-design-primary-hover', 'sp-design-accent',
                    'sp-design-header-bg', 'sp-design-header-text',
                    'sp-design-footer-bg', 'sp-design-footer-text'
                ];

                for (var i = 0; i < colorIds.length; i++) {
                    var input = document.getElementById(colorIds[i]);
                    if (input) {
                        input.value = colors[i];
                        // If wpColorPicker is initialized, update it too
                        if (typeof jQuery !== 'undefined' && jQuery.fn.wpColorPicker) {
                            try { jQuery(input).wpColorPicker('color', colors[i]); } catch(e) {}
                        }
                    }
                }

                // Font selects
                var bodySelect = document.getElementById('sp-design-font-body');
                var headingSelect = document.getElementById('sp-design-font-heading');
                if (bodySelect)    bodySelect.value = fontBody;
                if (headingSelect) headingSelect.value = fontHeading;

                // Visual feedback: highlight the selected card
                document.querySelectorAll('.sp-preset-card').forEach(function(c) {
                    c.style.borderColor = '#ddd';
                    c.style.boxShadow = 'none';
                });
                this.style.borderColor = '#2271b1';
                this.style.boxShadow = '0 0 0 2px rgba(34, 113, 177, 0.3)';

                // Refresh the live preview
                updatePreview();
            });
        });

        // ---- Initial preview update after iframe loads ----
        if (iframe) {
            iframe.addEventListener('load', function() {
                updatePreview();
            });
        }
    })();
    </script>
    <?php
}


// ============================================================================
// MODULES TAB — SETTINGS PAGE
// ============================================================================
//
// WHY: After the initial wizard, admins need a place to enable/disable feature
//      modules without re-running the wizard. This settings page mirrors the
//      wizard Step 3 checklist but lives in the Settings flyout for quick access.
//      Toggling a module off hides its admin menu items, frontend page templates,
//      shortcodes, and cron jobs — no code is deleted, just gated.
//
// ============================================================================

function sp_render_settings_modules_page(): void {
    // ---- Handle form submission ----
    // WHY we handle save here instead of using register_setting: The module
    // toggle is stored in its own option (sp_enabled_modules), not inside the
    // societypress_settings array. Processing the POST ourselves keeps it
    // simple — one nonce check, one update_option call, done.
    if ( $_SERVER['REQUEST_METHOD'] === 'POST' && isset( $_POST['_sp_modules_nonce'] ) ) {
        if ( wp_verify_nonce( $_POST['_sp_modules_nonce'], 'sp_save_modules' ) && current_user_can( 'manage_options' ) ) {
            $all_module_slugs = array_keys( sp_get_modules() );
            $enabled = [];
            foreach ( $all_module_slugs as $slug ) {
                if ( ! empty( $_POST[ 'sp_module_' . $slug ] ) ) {
                    $enabled[] = $slug;
                }
            }
            update_option( 'sp_enabled_modules', $enabled );

            // Redirect to avoid form resubmission on refresh
            wp_safe_redirect( admin_url( 'admin.php?page=sp-settings-modules&saved=1' ) );
            exit;
        }
    }

    $modules = sp_get_modules();
    $enabled = sp_get_enabled_modules();
    ?>
    <div class="wrap">
        <h1><?php esc_html_e( 'Settings: Modules', 'societypress' ); ?></h1>

        <p style="max-width:700px; color:#646970; margin-bottom:24px;">
            <?php esc_html_e( 'Enable or disable feature modules for your society. Disabled modules are hidden from the admin menu and unavailable on the frontend. No data is deleted — re-enable a module anytime to restore it.', 'societypress' ); ?>
        </p>

        <?php if ( isset( $_GET['saved'] ) && $_GET['saved'] === '1' ) : ?>
            <div class="notice notice-success is-dismissible"><p><?php esc_html_e( 'Module settings saved.', 'societypress' ); ?></p></div>
        <?php endif; ?>

        <form method="post">
            <?php wp_nonce_field( 'sp_save_modules', '_sp_modules_nonce' ); ?>

            <style>
                .sp-modules-grid {
                    display: grid;
                    grid-template-columns: repeat(auto-fill, minmax(320px, 1fr));
                    gap: 16px;
                    margin-bottom: 24px;
                }
                .sp-module-card {
                    background: #fff;
                    border: 1px solid #ddd;
                    border-radius: 8px;
                    padding: 16px 20px;
                    display: flex;
                    align-items: flex-start;
                    gap: 14px;
                    transition: border-color 0.2s, box-shadow 0.2s;
                }
                .sp-module-card:hover {
                    border-color: #2271b1;
                }
                .sp-module-card.sp-module-enabled {
                    border-color: #2271b1;
                    box-shadow: 0 0 0 1px #2271b1;
                }
                .sp-module-card-icon {
                    font-size: 24px;
                    color: #646970;
                    flex-shrink: 0;
                    width: 30px;
                    text-align: center;
                    margin-top: 2px;
                }
                .sp-module-card.sp-module-enabled .sp-module-card-icon {
                    color: #2271b1;
                }
                .sp-module-card-body {
                    flex: 1;
                    min-width: 0;
                }
                .sp-module-card-header {
                    display: flex;
                    align-items: center;
                    justify-content: space-between;
                    margin-bottom: 6px;
                }
                .sp-module-card-name {
                    font-weight: 600;
                    font-size: 14px;
                    color: #1d2327;
                }
                /* Toggle switch styling — a friendlier alternative to a plain
                   checkbox. The hidden checkbox drives the state; the visual
                   slider is purely CSS. */
                .sp-toggle {
                    position: relative;
                    width: 40px;
                    height: 22px;
                    flex-shrink: 0;
                }
                .sp-toggle input {
                    opacity: 0;
                    width: 0;
                    height: 0;
                    position: absolute;
                }
                .sp-toggle-slider {
                    position: absolute;
                    cursor: pointer;
                    inset: 0;
                    background: #ccc;
                    border-radius: 22px;
                    transition: background 0.2s;
                }
                .sp-toggle-slider::before {
                    content: '';
                    position: absolute;
                    width: 16px;
                    height: 16px;
                    left: 3px;
                    bottom: 3px;
                    background: #fff;
                    border-radius: 50%;
                    transition: transform 0.2s;
                }
                .sp-toggle input:checked + .sp-toggle-slider {
                    background: #2271b1;
                }
                .sp-toggle input:checked + .sp-toggle-slider::before {
                    transform: translateX(18px);
                }
                .sp-toggle input:focus + .sp-toggle-slider {
                    box-shadow: 0 0 0 2px rgba(34, 113, 177, 0.4);
                }
                .sp-module-card-desc {
                    font-size: 12px;
                    color: #646970;
                    line-height: 1.5;
                }
            </style>

            <div class="sp-modules-grid">
                <?php foreach ( $modules as $slug => $mod ) :
                    $is_on = in_array( $slug, $enabled, true );
                ?>
                    <div class="sp-module-card <?php echo $is_on ? 'sp-module-enabled' : ''; ?>" id="sp-mod-card-<?php echo esc_attr( $slug ); ?>">
                        <span class="dashicons <?php echo esc_attr( $mod['icon'] ); ?> sp-module-card-icon"></span>
                        <div class="sp-module-card-body">
                            <div class="sp-module-card-header">
                                <span class="sp-module-card-name" id="sp-mod-name-<?php echo esc_attr( $slug ); ?>"><?php echo esc_html( $mod['name'] ); ?></span>
                                <label class="sp-toggle">
                                    <input type="checkbox"
                                           name="sp_module_<?php echo esc_attr( $slug ); ?>"
                                           value="1"
                                           aria-labelledby="sp-mod-name-<?php echo esc_attr( $slug ); ?>"
                                           <?php checked( $is_on ); ?>
                                           onchange="this.closest('.sp-module-card').classList.toggle('sp-module-enabled', this.checked);">
                                    <span class="sp-toggle-slider"></span>
                                </label>
                            </div>
                            <div class="sp-module-card-desc"><?php echo esc_html( $mod['description'] ); ?></div>
                        </div>
                    </div>
                <?php endforeach; ?>
            </div>

            <p style="font-size:12px; color:#646970; margin-bottom:20px;">
                <?php esc_html_e( 'Members & Finances are always available — they are core to every society.', 'societypress' ); ?>
            </p>

            <div style="display:flex; gap:12px; align-items:center;">
                <?php submit_button( __( 'Save Module Settings', 'societypress' ), 'primary', 'submit', false ); ?>
                <button type="button" class="button" onclick="document.querySelectorAll('.sp-module-card input[type=checkbox]').forEach(function(c){c.checked=true;c.closest('.sp-module-card').classList.add('sp-module-enabled')});">
                    <?php esc_html_e( 'Enable All', 'societypress' ); ?>
                </button>
                <button type="button" class="button" onclick="document.querySelectorAll('.sp-module-card input[type=checkbox]').forEach(function(c){c.checked=false;c.closest('.sp-module-card').classList.remove('sp-module-enabled')});">
                    <?php esc_html_e( 'Disable All', 'societypress' ); ?>
                </button>
            </div>
        </form>
    </div>
    <?php
}


// ============================================================================
// USER ACCESS — ASSIGN ROLES & PERMISSIONS TO NON-ADMIN USERS
// ============================================================================
//
// WHY: Harold needs to delegate admin tasks to board members and volunteers
//      without making them full WordPress administrators. This page shows all
//      WordPress users and lets Harold assign a role template (Treasurer,
//      Librarian, etc.) or customize individual access areas per user.
//
//      Non-admin users with access areas see a filtered SocietyPress admin —
//      only their assigned sections are visible. This is how the board
//      treasurer sees only Finances and Reports, while the librarian sees
//      only the Library Catalog.
// ============================================================================

/**
 * Render the User Access admin page.
 *
 * WHY: Central hub for managing who has access to what. Shows a table of
 *      all users (excluding plain members) with their current role template
 *      and access areas. Harold can edit each user's permissions inline.
 */
function sp_render_user_access_page(): void {
    global $wpdb;

    // Handle form submission — save access areas for a user
    if ( $_SERVER['REQUEST_METHOD'] === 'POST' && isset( $_POST['_sp_access_nonce'] ) ) {
        if ( wp_verify_nonce( $_POST['_sp_access_nonce'], 'sp_save_user_access' ) && current_user_can( 'manage_options' ) ) {
            $target_user_id = absint( $_POST['sp_target_user_id'] ?? 0 );
            if ( $target_user_id && $target_user_id !== get_current_user_id() ) {
                $all_areas    = array_keys( sp_get_access_areas() );
                $granted      = [];
                foreach ( $all_areas as $area_slug ) {
                    if ( ! empty( $_POST[ 'sp_area_' . $area_slug ] ) ) {
                        $granted[] = $area_slug;
                    }
                }
                $role_template = sanitize_text_field( $_POST['sp_role_template'] ?? '' );

                if ( empty( $granted ) ) {
                    // No areas selected — remove all SP access
                    delete_user_meta( $target_user_id, 'sp_access_areas' );
                    delete_user_meta( $target_user_id, 'sp_role_template' );
                } else {
                    update_user_meta( $target_user_id, 'sp_access_areas', $granted );
                    update_user_meta( $target_user_id, 'sp_role_template', $role_template );
                }

                sp_audit(
                    'user_access_updated',
                    sprintf( 'Access updated for user #%d: %s', $target_user_id, implode( ', ', $granted ) ?: 'none' ),
                    'settings'
                );

                echo '<div class="notice notice-success is-dismissible"><p>'
                   . esc_html__( 'User access updated.', 'societypress' ) . '</p></div>';
            }
        }
    }

    // Handle revoke action
    if ( isset( $_GET['sp_revoke'] ) && isset( $_GET['_wpnonce'] ) ) {
        $revoke_id = absint( $_GET['sp_revoke'] );
        if ( wp_verify_nonce( $_GET['_wpnonce'], 'sp_revoke_' . $revoke_id ) && current_user_can( 'manage_options' ) ) {
            delete_user_meta( $revoke_id, 'sp_access_areas' );
            delete_user_meta( $revoke_id, 'sp_role_template' );
            sp_audit( 'user_access_revoked', sprintf( 'All SP access revoked for user #%d', $revoke_id ), 'settings' );
            echo '<div class="notice notice-success is-dismissible"><p>'
               . esc_html__( 'Access revoked.', 'societypress' ) . '</p></div>';
        }
    }

    $areas          = sp_get_access_areas();
    $role_templates = sp_get_role_templates();

    // Editing a specific user?
    $editing_user_id = absint( $_GET['edit_user'] ?? 0 );
    $editing_user    = $editing_user_id ? get_userdata( $editing_user_id ) : null;

    // Get all users who have SP access areas (non-admin staff)
    $sp_staff_ids = $wpdb->get_col(
        "SELECT DISTINCT user_id FROM {$wpdb->usermeta} WHERE meta_key = 'sp_access_areas'"
    );
    $sp_staff = [];
    foreach ( $sp_staff_ids as $uid ) {
        $u = get_userdata( (int) $uid );
        if ( $u ) {
            $sp_staff[] = $u;
        }
    }

    ?>
    <div class="wrap">
        <h1><?php esc_html_e( 'User Access', 'societypress' ); ?></h1>
        <p><?php esc_html_e( 'Grant non-administrator users access to specific sections of the admin panel. WordPress administrators always have full access.', 'societypress' ); ?></p>

        <?php if ( $editing_user && ! user_can( $editing_user, 'manage_options' ) ) : ?>
            <?php
            $user_areas     = get_user_meta( $editing_user->ID, 'sp_access_areas', true ) ?: [];
            $user_role_tpl  = get_user_meta( $editing_user->ID, 'sp_role_template', true ) ?: '';
            ?>
            <!-- Edit User Access Form -->
            <div style="max-width:700px; background:#fff; border:1px solid #c3c4c7; border-radius:4px; padding:20px; margin-bottom:30px;">
                <h2 style="margin-top:0;">
                    <?php
                    printf(
                        /* translators: %s: user display name */
                        esc_html__( 'Editing Access for: %s', 'societypress' ),
