/**
 * Settings fields: Hero Slider
 *
 * WHY: The admin needs to configure multiple slides — each with an image,
 *      heading, subtitle, and optional button. We use a repeater pattern
 *      (same as time slots and speaker rows) with a <template> for adding
 *      new slides via JS.
 */
function sp_builder_fields_hero_slider( $index, array $settings ): void {
    $slides    = $settings['slides'] ?? [];
    $autoplay  = $settings['autoplay'] ?? 1;
    $interval  = $settings['interval'] ?? 5;
    $height    = $settings['height'] ?? '400';
    $overlay   = $settings['overlay'] ?? 1;
    $name      = "sp_widgets[{$index}][settings]";
    ?>
    <div class="sp-slider-settings">
        <p>
            <label><strong>Slider Height (px)</strong></label><br>
            <input type="number" name="<?php echo $name; ?>[height]" value="<?php echo esc_attr( $height ); ?>" min="200" max="800" step="50" style="width:100px;">
        </p>
        <p>
            <label>
                <input type="checkbox" name="<?php echo $name; ?>[autoplay]" value="1" <?php checked( $autoplay, 1 ); ?>>
                Auto-advance slides
            </label>
            &nbsp; every
            <input type="number" name="<?php echo $name; ?>[interval]" value="<?php echo esc_attr( $interval ); ?>" min="2" max="15" style="width:60px;"> seconds
        </p>
        <p>
            <label>
                <input type="checkbox" name="<?php echo $name; ?>[overlay]" value="1" <?php checked( $overlay, 1 ); ?>>
                Dark overlay on images (improves text readability)
            </label>
        </p>

        <h4 style="margin: 16px 0 8px;">Slides</h4>
        <div class="sp-slider-slides" data-name="<?php echo esc_attr( $name ); ?>">
            <?php if ( ! empty( $slides ) ) : ?>
                <?php foreach ( $slides as $si => $slide ) : ?>
                    <div class="sp-slider-slide-row" style="border:1px solid #c3c4c7; padding:12px; margin-bottom:8px; border-radius:4px; background:#fafafa;">
                        <p>
                            <label><strong>Image or Video URL</strong></label><br>
                            <input type="text" name="<?php echo $name; ?>[slides][<?php echo $si; ?>][image]"
                                   value="<?php echo esc_attr( $slide['image'] ?? '' ); ?>" style="width:100%;"
                                   placeholder="Paste image URL or use Media Library">
                            <button type="button" class="button sp-media-select" style="margin-top:4px;">Choose Image</button>
                        </p>
                        <!-- WHY: Per-line repeater replaces the old single textarea so each
                             line of overlay text can have its own size, weight, and color.
                             This lets Harold style slides differently — white text on dark
                             video, dark text on light images, accent-colored emphasis, etc. -->
                        <div style="margin-bottom:12px;">
                            <label><strong>Overlay Text Lines</strong></label>
                            <div class="sp-slider-lines" data-name="<?php echo esc_attr( $name ); ?>[slides][<?php echo $si; ?>]">
                                <?php
                                $lines = $slide['lines'] ?? [];
                                if ( ! empty( $lines ) && is_array( $lines ) ) :
                                    foreach ( $lines as $li => $line ) :
                                ?>
                                    <div class="sp-slider-line-row" style="display:flex; gap:6px; align-items:center; margin-bottom:6px; flex-wrap:wrap;">
                                        <input type="text" name="<?php echo $name; ?>[slides][<?php echo $si; ?>][lines][<?php echo $li; ?>][text]"
                                               value="<?php echo esc_attr( $line['text'] ?? '' ); ?>" style="flex:1; min-width:180px;" placeholder="Line text">
                                        <select name="<?php echo $name; ?>[slides][<?php echo $si; ?>][lines][<?php echo $li; ?>][size]" style="width:90px;">
                                            <option value="small" <?php selected( $line['size'] ?? 'medium', 'small' ); ?>>Small</option>
                                            <option value="medium" <?php selected( $line['size'] ?? 'medium', 'medium' ); ?>><?php esc_html_e( 'Medium', 'societypress' ); ?></option>
                                            <option value="large" <?php selected( $line['size'] ?? 'medium', 'large' ); ?>><?php esc_html_e( 'Large', 'societypress' ); ?></option>
                                        </select>
                                        <select name="<?php echo $name; ?>[slides][<?php echo $si; ?>][lines][<?php echo $li; ?>][weight]" style="width:80px;">
                                            <option value="light" <?php selected( $line['weight'] ?? 'light', 'light' ); ?>>Light</option>
                                            <option value="bold" <?php selected( $line['weight'] ?? 'light', 'bold' ); ?>>Bold</option>
                                        </select>
                                        <select name="<?php echo $name; ?>[slides][<?php echo $si; ?>][lines][<?php echo $li; ?>][color]" style="width:85px;">
                                            <option value="white" <?php selected( $line['color'] ?? 'white', 'white' ); ?>>White</option>
                                            <option value="dark" <?php selected( $line['color'] ?? 'white', 'dark' ); ?>>Dark</option>
                                            <option value="accent" <?php selected( $line['color'] ?? 'white', 'accent' ); ?>>Accent</option>
                                        </select>
                                        <button type="button" class="button sp-slider-remove-line" style="color:#b32d2e;" title="Remove line">&times;</button>
                                    </div>
                                <?php
                                    endforeach;
                                endif;
                                ?>
                            </div>
                            <button type="button" class="button sp-slider-add-line" style="margin-top:4px;">+ Add Line</button>
                        </div>
                        <p>
                            <label><strong>Button Text</strong></label><br>
                            <input type="text" name="<?php echo $name; ?>[slides][<?php echo $si; ?>][btn_text]"
                                   value="<?php echo esc_attr( $slide['btn_text'] ?? '' ); ?>" style="width:48%; display:inline-block;" placeholder="e.g., Learn More">
                            <input type="text" name="<?php echo $name; ?>[slides][<?php echo $si; ?>][btn_url]"
                                   value="<?php echo esc_attr( $slide['btn_url'] ?? '' ); ?>" style="width:48%; display:inline-block;" placeholder="Button URL">
                        </p>
                        <button type="button" class="button sp-slider-remove-slide" style="color:#b32d2e;">Remove Slide</button>
                    </div>
                <?php endforeach; ?>
            <?php endif; ?>
        </div>
        <button type="button" class="button sp-slider-add-slide">+ Add Slide</button>

        <template class="sp-slider-slide-template">
            <div class="sp-slider-slide-row" style="border:1px solid #c3c4c7; padding:12px; margin-bottom:8px; border-radius:4px; background:#fafafa;">
                <p>
                    <label><strong>Image or Video URL</strong></label><br>
                    <input type="text" data-field="image" value="" style="width:100%;" placeholder="Paste image URL or use Media Library">
                    <button type="button" class="button sp-media-select" style="margin-top:4px;">Choose Image</button>
                </p>
                <!-- WHY: Lines repeater in the template starts empty — Harold adds
                     lines after creating the slide. The data-field-group attribute
                     tells the JS to set name prefixes on child inputs when cloning. -->
                <div style="margin-bottom:12px;">
                    <label><strong>Overlay Text Lines</strong></label>
                    <div class="sp-slider-lines" data-field-group="lines">
                        <!-- Lines added dynamically via Add Line button -->
                    </div>
                    <button type="button" class="button sp-slider-add-line" style="margin-top:4px;">+ Add Line</button>
                </div>
                <p>
                    <label><strong>Button Text</strong></label><br>
                    <input type="text" data-field="btn_text" value="" style="width:48%; display:inline-block;" placeholder="e.g., Learn More">
                    <input type="text" data-field="btn_url" value="" style="width:48%; display:inline-block;" placeholder="Button URL">
                </p>
                <button type="button" class="button sp-slider-remove-slide" style="color:#b32d2e;">Remove Slide</button>
            </div>
        </template>

        <!-- WHY: Separate template for individual text lines within a slide.
             Used by both "Add Line" inside existing slides and "Add Line"
             inside newly-added slides. Kept outside the slide template so
             the browser doesn't nest <template> tags (some browsers choke). -->
        <template class="sp-slider-line-template">
            <div class="sp-slider-line-row" style="display:flex; gap:6px; align-items:center; margin-bottom:6px; flex-wrap:wrap;">
                <input type="text" data-line-field="text" value="" style="flex:1; min-width:180px;" placeholder="Line text">
                <select data-line-field="size" style="width:90px;">
                    <option value="small">Small</option>
                    <option value="medium" selected>Medium</option>
                    <option value="large">Large</option>
                </select>
                <select data-line-field="weight" style="width:80px;">
                    <option value="light" selected>Light</option>
                    <option value="bold">Bold</option>
                </select>
                <select data-line-field="color" style="width:85px;">
                    <option value="white" selected>White</option>
                    <option value="dark">Dark</option>
                    <option value="accent">Accent</option>
                </select>
                <button type="button" class="button sp-slider-remove-line" style="color:#b32d2e;" title="Remove line">&times;</button>
            </div>
        </template>

        <script>
        (function() {
            // WHY: All click handlers use event delegation on document so they
            // work on hero_slider widgets added dynamically via the builder's
            // "Add Widget" picker, and on lines/slides added after page load.

            // Add slide — delegated
            document.addEventListener('click', function(e) {
                if (!e.target.classList.contains('sp-slider-add-slide')) return;
                var wrapper   = e.target.closest('.sp-slider-settings');
                if (!wrapper) return;
                var container = wrapper.querySelector('.sp-slider-slides');
                var tpl       = wrapper.querySelector('.sp-slider-slide-template');
                if (!container || !tpl) return;
                var clone    = tpl.content.cloneNode(true);
                var baseName = container.getAttribute('data-name');
                var idx      = container.querySelectorAll('.sp-slider-slide-row').length;
                // WHY: Only set names on direct slide-level fields (image, btn_text, btn_url).
                // Lines inside the slide get their names set by the Add Line handler.
                clone.querySelectorAll('[data-field]').forEach(function(input) {
                    var field = input.getAttribute('data-field');
                    input.setAttribute('name', baseName + '[slides][' + idx + '][' + field + ']');
                    input.removeAttribute('data-field');
                });
                // WHY: The lines container inside a new slide needs its data-name
                // set so Add Line knows what name prefix to use for line inputs.
                var linesDiv = clone.querySelector('[data-field-group="lines"]');
                if (linesDiv) {
                    linesDiv.setAttribute('data-name', baseName + '[slides][' + idx + ']');
                    linesDiv.removeAttribute('data-field-group');
                }
                container.appendChild(clone);
            });

            // Remove slide — delegated
            document.addEventListener('click', function(e) {
                if (e.target.classList.contains('sp-slider-remove-slide')) {
                    e.target.closest('.sp-slider-slide-row').remove();
                }
            });

            // Add line — delegated
            // WHY: Finds the lines container relative to the clicked button,
            // clones the line template, and assigns name attributes based on
            // the container's data-name and the current line count.
            document.addEventListener('click', function(e) {
                if (!e.target.classList.contains('sp-slider-add-line')) return;
                var wrapper    = e.target.closest('.sp-slider-settings');
                var linesDiv   = e.target.previousElementSibling;
                if (!linesDiv || !linesDiv.classList.contains('sp-slider-lines')) {
                    // WHY: fallback — button might be a sibling of the container
                    linesDiv = e.target.parentElement.querySelector('.sp-slider-lines');
                }
                if (!wrapper || !linesDiv) return;
                var lineTpl = wrapper.querySelector('.sp-slider-line-template');
                if (!lineTpl) return;
                var clone    = lineTpl.content.cloneNode(true);
                var baseName = linesDiv.getAttribute('data-name');
                var lineIdx  = linesDiv.querySelectorAll('.sp-slider-line-row').length;
                clone.querySelectorAll('[data-line-field]').forEach(function(input) {
                    var field = input.getAttribute('data-line-field');
                    input.setAttribute('name', baseName + '[lines][' + lineIdx + '][' + field + ']');
                    input.removeAttribute('data-line-field');
                });
                linesDiv.appendChild(clone);
            });

            // Remove line — delegated
            document.addEventListener('click', function(e) {
                if (e.target.classList.contains('sp-slider-remove-line')) {
                    e.target.closest('.sp-slider-line-row').remove();
                }
            });
        })();
        </script>
    </div>
    <?php
}


// ============================================================================
// PAGE BUILDER — SAVE META BOX
// ============================================================================

/**
 * Save page builder widget configuration when the page is saved.
 */
add_action( 'save_post_page', function ( $post_id, $post ) {
    if ( defined( 'DOING_AUTOSAVE' ) && DOING_AUTOSAVE ) return;
    if ( ! isset( $_POST['sp_page_builder_nonce'] ) ) return;
    if ( ! wp_verify_nonce( $_POST['sp_page_builder_nonce'], 'sp_page_builder_save' ) ) return;
    if ( ! current_user_can( 'edit_page', $post_id ) ) return;
    if ( get_page_template_slug( $post_id ) !== 'sp-builder' ) return;

    $registry    = sp_get_widget_registry();
    $raw_widgets = $_POST['sp_widgets'] ?? [];
    $clean       = [];

    foreach ( $raw_widgets as $w ) {
        $type = sanitize_key( $w['type'] ?? '' );
        if ( ! isset( $registry[ $type ] ) ) continue;

        $s = $w['settings'] ?? [];
        $clean[] = [
            'type'     => $type,
            'settings' => sp_sanitize_builder_widget( $type, $s ),
        ];
    }

    update_post_meta( $post_id, '_sp_page_widgets', $clean );
}, 10, 2 );


/**
 * Sanitize widget settings by type.
 *
 * @param string $type     Widget type key.
 * @param array  $settings Raw settings from $_POST.
 * @return array Sanitized settings.
 */
function sp_sanitize_builder_widget( string $type, array $settings ): array {
    switch ( $type ) {
        case 'rich_text':
            return [ 'content' => wp_kses_post( $settings['content'] ?? '' ) ];

        case 'member_directory':
            return [
                'login_required' => ! empty( $settings['login_required'] ),
                'per_page'       => absint( $settings['per_page'] ?? 25 ),
            ];

        case 'surname_lookup':
            return [ 'login_required' => ! empty( $settings['login_required'] ) ];

        case 'membership_tiers':
            return [
                'show_prices'   => ! empty( $settings['show_prices'] ),
                'show_inactive' => ! empty( $settings['show_inactive'] ),
            ];

        case 'contact_card':
            return [
                'show_address' => ! empty( $settings['show_address'] ),
                'show_phone'   => ! empty( $settings['show_phone'] ),
                'show_email'   => ! empty( $settings['show_email'] ),
                'show_hours'   => ! empty( $settings['show_hours'] ),
            ];

        case 'member_stats':
            return [
                'show_tier_breakdown' => ! empty( $settings['show_tier_breakdown'] ),
                'show_status_counts'  => ! empty( $settings['show_status_counts'] ),
            ];

        case 'heading':
            return [
                'text'         => sanitize_text_field( $settings['text'] ?? '' ),
                'subtitle'     => sanitize_text_field( $settings['subtitle'] ?? '' ),
                'level'        => in_array( $settings['level'] ?? 'h2', [ 'h1', 'h2', 'h3', 'h4' ], true ) ? $settings['level'] : 'h2',
                'show_divider' => ! empty( $settings['show_divider'] ),
                'alignment'    => in_array( $settings['alignment'] ?? 'left', [ 'left', 'center', 'right' ], true ) ? $settings['alignment'] : 'left',
            ];

        case 'image':
            return [
                'image_id'  => absint( $settings['image_id'] ?? 0 ),
                'caption'   => sanitize_text_field( $settings['caption'] ?? '' ),
                'link_url'  => esc_url_raw( $settings['link_url'] ?? '' ),
                'size'      => in_array( $settings['size'] ?? 'large', [ 'medium', 'large', 'full' ], true ) ? $settings['size'] : 'large',
                'alignment' => in_array( $settings['alignment'] ?? 'center', [ 'left', 'center', 'right' ], true ) ? $settings['alignment'] : 'center',
            ];

        case 'button':
            return [
                'text'       => sanitize_text_field( $settings['text'] ?? '' ),
                'url'        => esc_url_raw( $settings['url'] ?? '' ),
                'style'      => in_array( $settings['style'] ?? 'primary', [ 'primary', 'secondary', 'outline' ], true ) ? $settings['style'] : 'primary',
                'alignment'  => in_array( $settings['alignment'] ?? 'left', [ 'left', 'center', 'right' ], true ) ? $settings['alignment'] : 'left',
                'new_window' => ! empty( $settings['new_window'] ),
            ];

        case 'contact_form':
            return [ 'intro_text' => sanitize_text_field( $settings['intro_text'] ?? '' ) ];

        case 'upcoming_events':
            return [
                'count'         => in_array( (int) ( $settings['count'] ?? 5 ), [ 3, 5, 10, 15, 20 ], true )
                                   ? (int) $settings['count'] : 5,
                'category_id'   => absint( $settings['category_id'] ?? 0 ),
                'show_date'     => ! empty( $settings['show_date'] ) ? 1 : 0,
                'show_time'     => ! empty( $settings['show_time'] ) ? 1 : 0,
                'show_location' => ! empty( $settings['show_location'] ) ? 1 : 0,
            ];

        case 'event_calendar':
            return [
                'category_id' => absint( $settings['category_id'] ?? 0 ),
                'heading'     => sanitize_text_field( $settings['heading'] ?? '' ),
            ];

        case 'community_link':
            return [
                'label'       => sanitize_text_field( $settings['label'] ?? 'Join the Discussion' ),
                'description' => sanitize_text_field( $settings['description'] ?? '' ),
                'style'       => in_array( $settings['style'] ?? 'primary', [ 'primary', 'secondary', 'outline' ], true )
                                 ? $settings['style'] : 'primary',
            ];

        case 'newsletter_archive':
            return [
                'count'          => in_array( (int) ( $settings['count'] ?? 10 ), [ 5, 10, 15, 20, 50 ], true )
                                    ? (int) $settings['count'] : 10,
                'show_excerpt'   => ! empty( $settings['show_excerpt'] ),
                'show_date'      => ! empty( $settings['show_date'] ),
                'login_required' => ! empty( $settings['login_required'] ),
            ];

        case 'volunteer_stats':
            return [
                'show_count'          => ! empty( $settings['show_count'] ),
                'show_hours'          => ! empty( $settings['show_hours'] ),
                'show_top_volunteers' => ! empty( $settings['show_top_volunteers'] ),
                'time_period'         => in_array( $settings['time_period'] ?? 'year', [ 'year', 'all' ], true )
                                         ? $settings['time_period'] : 'year',
            ];

        case 'photo_gallery':
            return [
                'display_mode'   => in_array( $settings['display_mode'] ?? 'albums', [ 'albums', 'single' ], true )
                                    ? $settings['display_mode'] : 'albums',
                'album_id'       => absint( $settings['album_id'] ?? 0 ),
                'columns'        => in_array( (int) ( $settings['columns'] ?? 3 ), [ 2, 3, 4, 5 ], true )
                                    ? (int) $settings['columns'] : 3,
                'count'          => in_array( (int) ( $settings['count'] ?? 12 ), [ 6, 12, 24, 48 ], true )
                                    ? (int) $settings['count'] : 12,
                'login_required' => ! empty( $settings['login_required'] ),
            ];

        case 'resource_links':
            return [
                'category_id'       => absint( $settings['category_id'] ?? 0 ),
                'featured_only'     => ! empty( $settings['featured_only'] ),
                'count'             => in_array( (int) ( $settings['count'] ?? 20 ), [ 10, 20, 50, 100 ], true )
                                       ? (int) $settings['count'] : 20,
                'show_descriptions' => ! empty( $settings['show_descriptions'] ),
                'login_required'    => ! empty( $settings['login_required'] ),
            ];

        case 'library_catalog':
            return [
                'show_search'    => ! empty( $settings['show_search'] ),
                'category_id'    => absint( $settings['category_id'] ?? 0 ),
                'available_only' => ! empty( $settings['available_only'] ),
                'count'          => in_array( (int) ( $settings['count'] ?? 25 ), [ 10, 25, 50, 100 ], true )
                                    ? (int) $settings['count'] : 25,
                'login_required' => ! empty( $settings['login_required'] ),
            ];

        case 'hero_slider':
            // WHY: Each slide has image URL, heading, subtitle, and optional CTA
            // button. We sanitize the slides array individually to prevent XSS
            // and ensure all URLs are safe. Height and interval are clamped to
            // reasonable ranges so Harold can't accidentally break the layout.
            $slides_raw = $settings['slides'] ?? [];
            $slides     = [];
            // WHY: Valid values for per-line style dropdowns. Anything outside
            // these lists defaults to safe values, so Harold can't inject
            // arbitrary CSS through the size/weight/color fields.
            $valid_sizes   = [ 'small', 'medium', 'large' ];
            $valid_weights = [ 'light', 'bold' ];
            $valid_colors  = [ 'white', 'dark', 'accent' ];
            if ( is_array( $slides_raw ) ) {
                foreach ( $slides_raw as $slide ) {
                    if ( ! is_array( $slide ) ) continue;
                    // WHY: Per-line repeater data replaces the old overlay_text
                    // textarea. Each line has text + size/weight/color dropdowns.
                    $lines_raw = $slide['lines'] ?? [];
                    $lines     = [];
                    if ( is_array( $lines_raw ) ) {
                        foreach ( $lines_raw as $line ) {
                            if ( ! is_array( $line ) ) continue;
                            $text = sanitize_text_field( $line['text'] ?? '' );
                            if ( '' === $text ) continue; // WHY: skip blank lines
                            $lines[] = [
                                'text'   => $text,
                                'size'   => in_array( $line['size'] ?? 'medium', $valid_sizes, true ) ? $line['size'] : 'medium',
                                'weight' => in_array( $line['weight'] ?? 'light', $valid_weights, true ) ? $line['weight'] : 'light',
                                'color'  => in_array( $line['color'] ?? 'white', $valid_colors, true ) ? $line['color'] : 'white',
                            ];
                        }
                    }
                    $slides[] = [
                        'image'    => esc_url_raw( $slide['image'] ?? '' ),
                        'lines'    => $lines,
                        'btn_text' => sanitize_text_field( $slide['btn_text'] ?? '' ),
                        'btn_url'  => esc_url_raw( $slide['btn_url'] ?? '' ),
                    ];
                }
            }
            $height = absint( $settings['height'] ?? 400 );
            $height = max( 200, min( 800, $height ) );
            $interval = absint( $settings['interval'] ?? 5 );
            $interval = max( 2, min( 15, $interval ) );
            return [
                'height'   => $height,
                'autoplay' => ! empty( $settings['autoplay'] ),
                'interval' => $interval,
                'overlay'  => ! empty( $settings['overlay'] ),
                'slides'   => $slides,
            ];

        default:
            return [];
    }
}


// ============================================================================
// PAGE BUILDER — ADMIN ENQUEUE (SCRIPTS + STYLES + MEDIA)
// ============================================================================

/**
 * Enqueue admin assets for the page builder.
 *
 * WHY: Only loads on page edit screens. We need the media uploader for the
 * Image widget and wp_editor for the Rich Text widget.
 */
add_action( 'admin_enqueue_scripts', function ( $hook ) {
    // WHY: The builder needs wp_enqueue_media() and wp_enqueue_editor() for the
    // Image widget and Rich Text widget. Originally only loaded on native WP
    // page screens; now also loads on our custom SocietyPress page editor
    // (admin_page_sp-page-edit) so the builder works there too.
    $is_native_page = in_array( $hook, [ 'post.php', 'post-new.php' ], true )
                      && ( $s = get_current_screen() ) && 'page' === $s->post_type;
    $is_sp_editor   = ( 'admin_page_sp-page-edit' === $hook );

    if ( ! $is_native_page && ! $is_sp_editor ) return;

    wp_enqueue_media();
    wp_enqueue_editor();
});


// ============================================================================
// PAGE BUILDER — ADMIN CSS (inline in admin_head)
// ============================================================================

add_action( 'admin_head', function () {
    $screen = get_current_screen();
    if ( ! $screen ) return;
    // WHY: Builder CSS needs to load on the native WP page editor AND the
    // custom SocietyPress page editor so the widget cards, picker modal,
    // and layout all render correctly in both contexts.
    if ( 'page' !== $screen->id && 'admin_page_sp-page-edit' !== $screen->id ) return;
    ?>
    <style id="sp-builder-admin-css">
        .sp-builder-card { border: 1px solid #c3c4c7; border-radius: 4px; margin-bottom: 10px; background: #fff; }
        .sp-builder-card-header { display: flex; align-items: center; padding: 10px 12px; background: #f6f7f7; border-bottom: 1px solid #c3c4c7; cursor: pointer; user-select: none; gap: 8px; }
        .sp-builder-card-header:hover { background: #f0f0f1; }
        .sp-builder-card-body { padding: 15px; }
        .sp-builder-field { margin-bottom: 12px; }
        .sp-builder-field:last-child { margin-bottom: 0; }
        .sp-builder-btn { background: none; border: 1px solid transparent; border-radius: 3px; cursor: pointer; padding: 2px 6px; font-size: 14px; line-height: 1; color: #50575e; }
        .sp-builder-btn:hover { background: #dcdcde; border-color: #c3c4c7; }
        .sp-builder-remove:hover { color: #d63638; background: #fcf0f1; border-color: #d63638; }
        .sp-builder-picker { position: fixed; top: 0; left: 0; right: 0; bottom: 0; background: rgba(0,0,0,0.6); z-index: 100100; display: flex; align-items: center; justify-content: center; }
        .sp-builder-picker-inner { background: #fff; border-radius: 8px; max-width: 650px; width: 90%; max-height: 80vh; overflow-y: auto; padding: 24px; }
        .sp-builder-picker-grid { display: grid; grid-template-columns: 1fr 1fr; gap: 10px; margin-bottom: 20px; }
        .sp-builder-picker-item { display: flex; flex-direction: column; align-items: flex-start; padding: 12px; border: 1px solid #c3c4c7; border-radius: 6px; background: #fff; cursor: pointer; text-align: left; transition: border-color 0.15s, box-shadow 0.15s; }
        .sp-builder-picker-item:hover { border-color: #2271b1; box-shadow: 0 0 0 1px #2271b1; }
    </style>
    <?php
});


// ============================================================================
// PAGE BUILDER — ADMIN JAVASCRIPT (inline in admin_footer)
// ============================================================================

add_action( 'admin_footer', function () {
    $screen = get_current_screen();
    if ( ! $screen ) return;
    // WHY: Builder JS (widget add/remove/reorder, picker, media library) must
    // run on both the native WP page editor and the custom SocietyPress editor.
    if ( 'page' !== $screen->id && 'admin_page_sp-page-edit' !== $screen->id ) return;
    ?>
    <script id="sp-builder-admin-js">
    jQuery(function($) {
        'use strict';
        var $wrap   = $('#sp-builder-wrap');
        if (!$wrap.length) return;

        var $list   = $('#sp-builder-widgets');
        var $picker = $('#sp-builder-picker');
        var $addBtn = $('#sp-builder-add-btn');

        // Open/close picker
        $addBtn.on('click', function() { $picker.show(); });
        $picker.on('click', '.sp-builder-picker-close', function() { $picker.hide(); });
        $picker.on('click', function(e) { if (e.target === this) $picker.hide(); });
        $(document).on('keydown', function(e) { if (e.key === 'Escape' && $picker.is(':visible')) $picker.hide(); });

        // Add widget
        $picker.on('click', '.sp-builder-picker-item', function() {
            var type = $(this).data('widget-type');
            var $tpl = $('#sp-builder-templates .sp-builder-template[data-widget-type="' + type + '"]');
            if ($tpl.length) {
                var $clone = $tpl.children().first().clone(true);
                $list.append($clone);
                reindex();
                $clone.find('.sp-builder-card-body').show();
            }
            $picker.hide();
        });

        // Remove widget
        $list.on('click', '.sp-builder-remove', function(e) {
            e.stopPropagation();
            if (!confirm('<?php echo esc_js( __( 'Remove this widget?', 'societypress' ) ); ?>')) return;
            $(this).closest('.sp-builder-card').remove();
            reindex();
        });

        // Move up/down
        $list.on('click', '.sp-builder-move-up', function(e) {
            e.stopPropagation();
            var $c = $(this).closest('.sp-builder-card'), $p = $c.prev('.sp-builder-card');
            if ($p.length) { $c.insertBefore($p); reindex(); }
        });
        $list.on('click', '.sp-builder-move-down', function(e) {
            e.stopPropagation();
            var $c = $(this).closest('.sp-builder-card'), $n = $c.next('.sp-builder-card');
            if ($n.length) { $c.insertAfter($n); reindex(); }
        });

        // Toggle expand/collapse
        $list.on('click', '.sp-builder-card-header', function(e) {
            if ($(e.target).closest('.sp-builder-card-actions').length) return;
            $(this).siblings('.sp-builder-card-body').slideToggle(150);
        });
        $list.on('click', '.sp-builder-toggle', function(e) {
            e.stopPropagation();
            $(this).closest('.sp-builder-card').find('.sp-builder-card-body').slideToggle(150);
        });

        // Re-index field names after add/remove/reorder
        function reindex() {
            $list.children('.sp-builder-card').each(function(i) {
                $(this).find('input, select, textarea').each(function() {
                    var name = $(this).attr('name');
                    if (name) {
                        $(this).attr('name', name.replace(/sp_widgets\[\d+\]/, 'sp_widgets[' + i + ']')
                                                   .replace(/sp_widgets\[__INDEX__\]/, 'sp_widgets[' + i + ']'));
                    }
                    var id = $(this).attr('id');
                    if (id && id.indexOf('sp_widget_editor_') === 0) {
                        $(this).attr('id', 'sp_widget_editor_' + i);
                    }
                });
            });
        }

        // Media library for Image widget
        $list.on('click', '.sp-builder-image-select', function(e) {
            e.preventDefault();
            var $field = $(this).closest('.sp-builder-image-field');
            var frame = wp.media({ title: 'Select Image', button: { text: 'Use This Image' }, multiple: false, library: { type: 'image' } });
            frame.on('select', function() {
                var att = frame.state().get('selection').first().toJSON();
                var url = att.sizes && att.sizes.medium ? att.sizes.medium.url : att.url;
                $field.find('.sp-builder-image-id').val(att.id);
                $field.find('.sp-builder-image-preview img').attr('src', url);
                $field.find('.sp-builder-image-preview').show();
                $field.find('.sp-builder-image-select').text('Change Image');
                $field.find('.sp-builder-image-remove').show();
            });
            frame.open();
        });
        $list.on('click', '.sp-builder-image-remove', function(e) {
            e.preventDefault();
            var $field = $(this).closest('.sp-builder-image-field');
            $field.find('.sp-builder-image-id').val('');
            $field.find('.sp-builder-image-preview').hide();
            $field.find('.sp-builder-image-select').text('Select Image');
            $(this).hide();
        });

        // Media library for Hero Slider slide images
        // WHY: Slide image fields store a URL (not an attachment ID) because the
        // slider renderer uses the URL directly via esc_url(). We open the WP
        // media frame, grab the full-size URL from the selected attachment, and
        // write it into the text input that's the sibling of the clicked button.
        // Delegation on $(document) because slider cards are cloned dynamically.
        $(document).on('click', '.sp-media-select', function(e) {
            e.preventDefault();
            var $btn   = $(this);
            var $input = $btn.closest('p').find('input[type="text"]');
            var frame  = wp.media({
                title: 'Choose Slide Media',
                button: { text: 'Use This' },
                multiple: false,
                library: { type: ['image', 'video'] }
            });
            frame.on('select', function() {
                var att = frame.state().get('selection').first().toJSON();
                // Use the full-size URL for the slider — it renders at full width
                $input.val(att.url);
            });
            frame.open();
        });
    });
    </script>
    <?php
});


// ============================================================================
// PAGE BUILDER — FRONTEND TEMPLATE RENDERING
// ============================================================================

/**
 * When WordPress loads a page using the "SocietyPress Builder" template,
 * render the builder widgets instead of normal post content.
 *
 * WHY: Same approach as the directory — hijack template_include, render our
 * own content between get_header() and get_footer(), return blank template.
 */
add_filter( 'template_include', function ( $template ) {

    if ( ! is_page() || get_page_template_slug() !== 'sp-builder' ) {
        return $template;
    }

    // If a child theme provides front-page.php and this IS the front page,
    // let the child theme handle it — don't hijack with the Page Builder.
    // WHY: Child themes need to be able to override the homepage layout.
    //      The the society theme (and any future child theme) provides its own
    //      front-page.php with a custom hero, sections, etc. Without this
    //      check, the Page Builder always wins because it renders inline
    //      before returning a blank template.
    if ( is_front_page() && file_exists( get_stylesheet_directory() . '/front-page.php' ) && get_stylesheet() !== get_template() ) {
        return $template;
    }

    // Enqueue frontend styles
    add_action( 'wp_head', 'sp_builder_frontend_styles' );

    // Enqueue frontend JS (for contact form AJAX)
    add_action( 'wp_footer', 'sp_builder_frontend_scripts' );

    get_header();

    echo '<div class="site-content"><div class="content-area-full">';
    echo '<article class="page type-page">';

    // Page title — skip on the front page because "Home" as a big heading
    // above a hero slider looks wrong. Interior builder pages still get it.
    if ( ! is_front_page() ) {
        echo '<header class="entry-header"><h1 class="entry-title">' . esc_html( get_the_title() ) . '</h1></header>';
    }

    // Render widgets
    echo '<div class="entry-content">';
    sp_render_builder_widgets( get_the_ID() );
    echo '</div>';

    echo '</article>';
    echo '</div></div>';

    get_footer();

    return sp_get_blank_template_path();
});


/**
 * Render all builder widgets for a page.
 *
 * @param int $post_id The page ID.
 */
function sp_render_builder_widgets( int $post_id ): void {
    $widgets = get_post_meta( $post_id, '_sp_page_widgets', true );
    if ( ! is_array( $widgets ) || empty( $widgets ) ) {
        return;
    }

    echo '<div class="sp-builder-content">';

    foreach ( $widgets as $widget ) {
        $type     = $widget['type'] ?? '';
        $settings = $widget['settings'] ?? [];

        $fn = 'sp_render_builder_widget_' . $type;
        if ( function_exists( $fn ) ) {
            echo '<section class="sp-widget sp-widget--' . esc_attr( $type ) . '">';
            $fn( $settings );
            echo '</section>';
        }
    }

    echo '</div>';
}


// ============================================================================
// PAGE BUILDER — FRONTEND WIDGET RENDERERS
// ============================================================================

/**
 * Render: Rich Text
 */
function sp_render_builder_widget_rich_text( array $s ): void {
    $content = $s['content'] ?? '';
    if ( empty( $content ) ) return;
    echo '<div class="sp-widget-rich-text">';
    echo do_shortcode( wpautop( $content ) );
    echo '</div>';
}

/**
 * Render: Member Directory
 *
 * WHY: Reuses the existing sp_render_directory() function and directory styles
 * that already exist in this file. No code duplication.
 */
function sp_render_builder_widget_member_directory( array $s ): void {
    $login_required = $s['login_required'] ?? true;

    if ( $login_required && ! is_user_logged_in() ) {
        echo '<div class="sp-widget-login-required">';
        echo '<p>Please <a href="' . esc_url( wp_login_url( get_permalink() ) ) . '">log in</a> to view the member directory.</p>';
        echo '</div>';
        return;
    }

    // Load directory styles
    sp_directory_styles();

    // Render the directory using the existing function
    $settings = get_option( 'societypress_settings', [] );
    if ( ! empty( $s['per_page'] ) ) {
        $settings['dir_per_page'] = $s['per_page'];
    }
    echo '<div class="sp-directory-wrap" style="margin:0; padding:0;">';
    sp_render_directory( $settings );
    echo '</div>';
}

/**
 * Render: Surname Lookup
 */
function sp_render_builder_widget_surname_lookup( array $s ): void {
    global $wpdb;
    $login_required = $s['login_required'] ?? true;

    if ( $login_required && ! is_user_logged_in() ) {
        echo '<div class="sp-widget-login-required">';
        echo '<p>Please <a href="' . esc_url( wp_login_url( get_permalink() ) ) . '">log in</a> to search surnames.</p>';
        echo '</div>';
        return;
    }

    $prefix = $wpdb->prefix . 'sp_';
    $search = isset( $_GET['sp_surname'] ) ? sanitize_text_field( $_GET['sp_surname'] ) : '';

    echo '<div class="sp-widget-surname-lookup">';
    echo '<form method="get" style="display:flex; gap:8px; margin-bottom:20px;">';
    echo '<input type="text" name="sp_surname" value="' . esc_attr( $search ) . '" placeholder="Search surnames..." style="flex:1; padding:10px; border:1px solid #ccc; border-radius:6px; font-size:16px;">';
    echo '<button type="submit" class="sp-btn sp-btn-primary">Search</button>';
    echo '</form>';

    if ( ! empty( $search ) ) {
        $like = '%' . $wpdb->esc_like( $search ) . '%';
        // WHY: We also select m.user_id so the "Contact Researcher" button
        //      can reference the researcher without exposing their email.
        $results = $wpdb->get_results( $wpdb->prepare(
            "SELECT s.surname, s.county, s.state, s.country, s.year_from, s.year_to,
                    m.user_id, m.first_name, m.last_name
             FROM {$prefix}member_surnames s
             INNER JOIN {$prefix}members m ON s.user_id = m.user_id
             WHERE s.surname LIKE %s AND m.status = 'active'
             ORDER BY s.surname ASC, m.last_name ASC",
            $like
        ) );

        if ( ! empty( $results ) ) {
            echo '<h3>' . count( $results ) . ' result' . ( count( $results ) !== 1 ? 's' : '' ) . ' found</h3>';
            echo '<table style="width:100%; border-collapse:collapse;">';
            echo '<thead><tr>';
            echo '<th style="padding:8px 12px; text-align:left; border-bottom:2px solid #ddd; background:#f8f8f8;">Surname</th>';
            echo '<th style="padding:8px 12px; text-align:left; border-bottom:2px solid #ddd; background:#f8f8f8;">Location</th>';
            echo '<th style="padding:8px 12px; text-align:left; border-bottom:2px solid #ddd; background:#f8f8f8;">Time Period</th>';
            echo '<th style="padding:8px 12px; text-align:left; border-bottom:2px solid #ddd; background:#f8f8f8;">Researcher</th>';
            echo '<th style="padding:8px 12px; text-align:center; border-bottom:2px solid #ddd; background:#f8f8f8;">Contact</th>';
            echo '</tr></thead><tbody>';

            // WHY: Track which user IDs we've already checked for opt-out so we
            //      don't re-query the same member's preferences on every row.
            $contact_allowed_cache = [];

            foreach ( $results as $row ) {
                $loc = implode( ', ', array_filter( [ $row->county, $row->state, $row->country ] ) ) ?: '—';
                $period = ( $row->year_from && $row->year_to ) ? "{$row->year_from}–{$row->year_to}"
                    : ( $row->year_from ? "{$row->year_from}–" : ( $row->year_to ? "–{$row->year_to}" : '—' ) );

                // Check if this researcher allows surname contact emails.
                // WHY: Members can opt out via pref_email_surnames in their profile.
                //      We cache the result per user_id to avoid repeated DB queries
                //      when a researcher has multiple surnames listed.
                if ( ! isset( $contact_allowed_cache[ $row->user_id ] ) ) {
                    $meta_val = $wpdb->get_var( $wpdb->prepare(
                        "SELECT meta_value FROM {$prefix}member_meta
                         WHERE user_id = %d AND meta_key = 'pref_email_surnames'",
                        $row->user_id
                    ) );
                    // Default to allowed (1) if no preference has been set
                    $contact_allowed_cache[ $row->user_id ] = ( $meta_val === '0' ) ? false : true;
                }

                echo '<tr>';
                echo '<td style="padding:8px 12px; border-bottom:1px solid #eee;"><strong>' . esc_html( $row->surname ) . '</strong></td>';
                echo '<td style="padding:8px 12px; border-bottom:1px solid #eee;">' . esc_html( $loc ) . '</td>';
                echo '<td style="padding:8px 12px; border-bottom:1px solid #eee;">' . esc_html( $period ) . '</td>';
                echo '<td style="padding:8px 12px; border-bottom:1px solid #eee;">' . esc_html( $row->first_name . ' ' . $row->last_name ) . '</td>';

                // Contact button — only shown if researcher allows it
                echo '<td style="padding:8px 12px; border-bottom:1px solid #eee; text-align:center;">';
                if ( $contact_allowed_cache[ $row->user_id ] && is_user_logged_in() ) {
                    echo '<button type="button" class="sp-btn sp-btn-outline sp-surname-contact-btn" '
                       . 'data-researcher-id="' . esc_attr( $row->user_id ) . '" '
                       . 'data-researcher-name="' . esc_attr( $row->first_name . ' ' . $row->last_name ) . '" '
                       . 'data-surname="' . esc_attr( $row->surname ) . '" '
                       . 'style="padding:4px 12px; font-size:13px;">Contact</button>';
                } elseif ( ! is_user_logged_in() ) {
                    echo '<span style="color:#999; font-size:12px;">Log in to contact</span>';
                } else {
                    echo '<span style="color:#999; font-size:12px;">—</span>';
                }
                echo '</td>';

                echo '</tr>';
            }
            echo '</tbody></table>';

            // Surname contact modal — shown when any Contact button is clicked.
            // WHY: Uses a simple inline modal instead of a separate page so the
            //      user stays in context. The researcher's email is never exposed
            //      to the sender — the AJAX handler sends on their behalf with
            //      the sender's email only in the Reply-To header.
            if ( is_user_logged_in() ) {
                $current_user = wp_get_current_user();
                ?>
                <div id="sp-surname-contact-modal" style="display:none; position:fixed; inset:0; z-index:100000; background:rgba(0,0,0,0.5); align-items:center; justify-content:center;">
                    <div style="background:#fff; border-radius:12px; padding:32px; max-width:480px; width:90%; position:relative; box-shadow:0 20px 60px rgba(0,0,0,0.3);">
                        <button type="button" id="sp-surname-contact-close" style="position:absolute; top:12px; right:16px; background:none; border:none; font-size:24px; cursor:pointer; color:#999;">&times;</button>
                        <h3 style="margin:0 0 8px; font-size:18px;">Contact Researcher</h3>
                        <p id="sp-surname-contact-desc" style="color:#666; margin:0 0 20px; font-size:14px;"></p>
                        <div id="sp-surname-contact-msg" style="display:none; padding:10px 14px; border-radius:6px; margin-bottom:16px;"></div>
                        <form id="sp-surname-contact-form">
                            <?php wp_nonce_field( 'sp_surname_contact', 'sp_surname_contact_nonce' ); ?>
                            <input type="hidden" name="researcher_id" id="sp-surname-researcher-id" value="">
                            <div style="display:flex; gap:12px; margin-bottom:16px;">
                                <div style="flex:1;">
                                    <label style="display:block; font-weight:600; margin-bottom:4px; font-size:14px;"><?php esc_html_e( 'Your Name', 'societypress' ); ?></label>
                                    <input type="text" name="sender_name" value="<?php echo esc_attr( $current_user->display_name ); ?>" required style="width:100%; padding:8px 12px; border:1px solid #ccc; border-radius:6px;">
                                </div>
                                <div style="flex:1;">
                                    <label style="display:block; font-weight:600; margin-bottom:4px; font-size:14px;"><?php esc_html_e( 'Your Email', 'societypress' ); ?></label>
                                    <input type="email" name="sender_email" value="<?php echo esc_attr( $current_user->user_email ); ?>" required style="width:100%; padding:8px 12px; border:1px solid #ccc; border-radius:6px;">
                                </div>
                            </div>
                            <div style="margin-bottom:16px;">
                                <label style="display:block; font-weight:600; margin-bottom:4px; font-size:14px;"><?php esc_html_e( 'Message', 'societypress' ); ?></label>
                                <textarea name="message" rows="4" required style="width:100%; padding:8px 12px; border:1px solid #ccc; border-radius:6px; font-family:inherit;" placeholder="Tell them about your research interest..."></textarea>
                            </div>
                            <button type="submit" class="sp-btn sp-btn-primary" style="width:100%;">Send Message</button>
                        </form>
                    </div>
                </div>
                <script>
                (function(){
                    // WHY: Event delegation from the parent container so buttons
                    //      added dynamically (unlikely here, but defensive) still work.
                    document.addEventListener('click', function(e) {
                        var btn = e.target.closest('.sp-surname-contact-btn');
                        if (!btn) return;
                        var modal = document.getElementById('sp-surname-contact-modal');
                        document.getElementById('sp-surname-researcher-id').value = btn.dataset.researcherId;
                        document.getElementById('sp-surname-contact-desc').textContent =
                            'Send a message to ' + btn.dataset.researcherName + ' about the surname "' + btn.dataset.surname + '".';
                        document.getElementById('sp-surname-contact-msg').style.display = 'none';
                        modal.style.display = 'flex';
                    });

                    document.getElementById('sp-surname-contact-close').addEventListener('click', function() {
                        document.getElementById('sp-surname-contact-modal').style.display = 'none';
                    });

                    // Close modal on backdrop click
                    document.getElementById('sp-surname-contact-modal').addEventListener('click', function(e) {
                        if (e.target === this) this.style.display = 'none';
                    });

                    document.getElementById('sp-surname-contact-form').addEventListener('submit', function(e) {
                        e.preventDefault();
                        var form = this;
                        var msgBox = document.getElementById('sp-surname-contact-msg');
                        var submitBtn = form.querySelector('button[type="submit"]');
                        submitBtn.disabled = true;
                        submitBtn.textContent = 'Sending...';

                        var formData = new FormData(form);
                        formData.append('action', 'sp_surname_contact');

                        fetch(<?php echo wp_json_encode( admin_url( 'admin-ajax.php' ) ); ?>, {
                            method: 'POST',
                            body: formData,
                            credentials: 'same-origin'
                        })
                        .then(function(r) { return r.json(); })
                        .then(function(data) {
                            msgBox.style.display = 'block';
                            if (data.success) {
                                msgBox.style.background = '#edfaef';
                                msgBox.style.color = '#0a6b2e';
                                msgBox.textContent = data.data.message || 'Message sent!';
                                form.querySelector('textarea[name="message"]').value = '';
                                setTimeout(function() {
                                    document.getElementById('sp-surname-contact-modal').style.display = 'none';
                                }, 2000);
                            } else {
                                msgBox.style.background = '#fef0f0';
                                msgBox.style.color = '#b32d2e';
                                msgBox.textContent = data.data || 'Something went wrong.';
                            }
                        })
                        .catch(function() {
                            msgBox.style.display = 'block';
                            msgBox.style.background = '#fef0f0';
                            msgBox.style.color = '#b32d2e';
                            msgBox.textContent = 'Network error. Please try again.';
                        })
                        .finally(function() {
                            submitBtn.disabled = false;
                            submitBtn.textContent = 'Send Message';
                        });
                    });
                })();
                </script>
                <?php
            }
        } else {
            echo '<p style="color:#666; font-style:italic;">No surnames found matching your search.</p>';
        }
    }
    echo '</div>';
}

/**
 * Render: Membership Tiers
 */
function sp_render_builder_widget_membership_tiers( array $s ): void {
    global $wpdb;
    $show_prices   = $s['show_prices'] ?? true;
    $show_inactive = $s['show_inactive'] ?? false;
    $prefix = $wpdb->prefix . 'sp_';

    $where = $show_inactive ? '' : 'WHERE active = 1';
    $tiers = $wpdb->get_results( "SELECT name, price, duration_months, active FROM {$prefix}membership_tiers {$where} ORDER BY sort_order ASC, name ASC" );

    if ( empty( $tiers ) ) {
        echo '<p>No membership tiers have been configured yet.</p>';
        return;
    }

    echo '<div class="sp-tiers-grid" style="display:grid; grid-template-columns:repeat(auto-fill, minmax(200px, 1fr)); gap:16px;">';
    foreach ( $tiers as $tier ) {
        $opacity = $tier->active ? '' : ' opacity:0.6;';
        echo '<div style="background:#fff; border:1px solid #e0e0e0; border-radius:8px; padding:20px; text-align:center;' . $opacity . '">';
        echo '<h3 style="margin:0 0 8px; color:#1e3a5f;">' . esc_html( $tier->name ) . '</h3>';
        if ( $show_prices ) {
            $price = floatval( $tier->price );
            echo '<div style="font-size:24px; font-weight:700; color:var(--sp-color-primary);">' . ( $price > 0 ? esc_html( sp_format_currency( $price ) ) : esc_html__( 'Free', 'societypress' ) ) . '</div>';
            if ( $price > 0 && $tier->duration_months ) {
                $d = intval( $tier->duration_months );
                /* translators: %d: number of months in billing cycle */
                echo '<div style="font-size:14px; color:#666;">' . ( $d === 12 ? esc_html__( 'per year', 'societypress' ) : esc_html( sprintf( __( 'per %d months', 'societypress' ), $d ) ) ) . '</div>';
            }
        }
        if ( ! $tier->active ) {
            echo '<div style="margin-top:8px; font-size:12px; color:#999; font-style:italic;">' . esc_html__( 'Not currently available', 'societypress' ) . '</div>';
        }
        echo '</div>';
    }
    echo '</div>';
}

/**
 * Render: Contact Card
 */
function sp_render_builder_widget_contact_card( array $s ): void {
    $settings     = get_option( 'societypress_settings', [] );
    $show_address = $s['show_address'] ?? true;
    $show_phone   = $s['show_phone'] ?? true;
    $show_email   = $s['show_email'] ?? true;
    $show_hours   = $s['show_hours'] ?? true;

    $org_name = $settings['organization_name'] ?? get_bloginfo( 'name' );
    $address  = $settings['organization_address'] ?? '';
    $phone    = $settings['organization_phone'] ?? '';
    $email    = $settings['organization_email'] ?? get_option( 'admin_email' );
    $hours    = $settings['organization_hours'] ?? '';

    echo '<div style="background:#f9f9f9; border:1px solid #e0e0e0; border-radius:8px; padding:24px;">';
    echo '<h3 style="margin:0 0 16px; color:#1e3a5f;">' . esc_html( $org_name ) . '</h3>';

    if ( $show_address && $address ) {
        echo '<div style="display:flex; align-items:flex-start; gap:12px; margin-bottom:12px;">';
        echo '<span class="dashicons dashicons-location-alt" style="color:var(--sp-color-primary); margin-top:2px;"></span>';
        echo '<address style="font-style:normal;">' . nl2br( esc_html( $address ) ) . '</address>';
        echo '</div>';
    }
    if ( $show_phone && $phone ) {
        $tel = preg_replace( '/[^0-9+]/', '', $phone );
        echo '<div style="display:flex; align-items:center; gap:12px; margin-bottom:12px;">';
        echo '<span class="dashicons dashicons-phone" style="color:var(--sp-color-primary);"></span>';
        echo '<a href="tel:' . esc_attr( $tel ) . '">' . esc_html( $phone ) . '</a>';
        echo '</div>';
    }
    if ( $show_email && $email ) {
        echo '<div style="display:flex; align-items:center; gap:12px; margin-bottom:12px;">';
        echo '<span class="dashicons dashicons-email" style="color:var(--sp-color-primary);"></span>';
        echo sp_obfuscate_email( $email );
        echo '</div>';
    }
    if ( $show_hours && $hours ) {
        echo '<div style="display:flex; align-items:flex-start; gap:12px;">';
        echo '<span class="dashicons dashicons-clock" style="color:var(--sp-color-primary); margin-top:2px;"></span>';
        echo '<span>' . nl2br( esc_html( $hours ) ) . '</span>';
        echo '</div>';
    }
    echo '</div>';
}

/**
 * Render: Quick Stats
 */
function sp_render_builder_widget_member_stats( array $s ): void {
    global $wpdb;
    $prefix = $wpdb->prefix . 'sp_';
    $show_tier_breakdown = $s['show_tier_breakdown'] ?? true;
    $show_status_counts  = $s['show_status_counts'] ?? false;

    $total  = (int) $wpdb->get_var( "SELECT COUNT(*) FROM {$prefix}members" );
    $active = (int) $wpdb->get_var( $wpdb->prepare( "SELECT COUNT(*) FROM {$prefix}members WHERE status = %s", 'active' ) );

    echo '<div class="sp-widget-stats">';

    // Main stats
    echo '<div style="display:flex; gap:16px; margin-bottom:24px;">';
    echo '<div style="flex:1; background:#f0f6fc; border:1px solid #bae0fd; border-radius:8px; padding:20px; text-align:center;">';
    echo '<div style="font-size:36px; font-weight:700; color:#0369a1; line-height:1;">' . number_format( $total ) . '</div>';
    echo '<div style="font-size:14px; color:#666;">Total Members</div>';
    echo '</div>';
    echo '<div style="flex:1; background:#f0f6fc; border:1px solid #bae0fd; border-radius:8px; padding:20px; text-align:center;">';
    echo '<div style="font-size:36px; font-weight:700; color:#0369a1; line-height:1;">' . number_format( $active ) . '</div>';
    echo '<div style="font-size:14px; color:#666;">Active Members</div>';
    echo '</div>';
    echo '</div>';

    if ( $show_status_counts ) {
        $statuses = $wpdb->get_results( "SELECT status, COUNT(*) as count FROM {$prefix}members GROUP BY status ORDER BY count DESC" );
        if ( $statuses ) {
            echo '<h4 style="font-size:13px; text-transform:uppercase; letter-spacing:0.05em; color:#666; margin:0 0 8px;">By Status</h4>';
            echo '<ul style="list-style:none; padding:0; margin:0 0 16px;">';
            foreach ( $statuses as $st ) {
                echo '<li style="display:flex; justify-content:space-between; padding:8px 0; border-bottom:1px solid #f0f0f0;">';
                echo '<span>' . esc_html( ucfirst( $st->status ) ) . '</span>';
                echo '<span style="font-weight:600;">' . number_format( $st->count ) . '</span>';
                echo '</li>';
            }
            echo '</ul>';
        }
    }

    if ( $show_tier_breakdown ) {
        $tiers = $wpdb->get_results(
            "SELECT t.name, COUNT(m.user_id) as count
             FROM {$prefix}membership_tiers t
             LEFT JOIN {$prefix}members m ON m.tier_id = t.id AND m.status = 'active'
             WHERE t.active = 1
             GROUP BY t.id ORDER BY t.sort_order ASC"
        );
        if ( $tiers ) {
            echo '<h4 style="font-size:13px; text-transform:uppercase; letter-spacing:0.05em; color:#666; margin:0 0 8px;">By Membership Level</h4>';
            echo '<ul style="list-style:none; padding:0; margin:0;">';
            foreach ( $tiers as $t ) {
                echo '<li style="display:flex; justify-content:space-between; padding:8px 0; border-bottom:1px solid #f0f0f0;">';
                echo '<span>' . esc_html( $t->name ) . '</span>';
                echo '<span style="font-weight:600;">' . number_format( $t->count ) . '</span>';
                echo '</li>';
            }
            echo '</ul>';
        }
    }

    echo '</div>';
}

/**
 * Render: Heading / Divider
 */
function sp_render_builder_widget_heading( array $s ): void {
    $text         = $s['text'] ?? '';
    $subtitle     = $s['subtitle'] ?? '';
    $level        = in_array( $s['level'] ?? 'h2', [ 'h1', 'h2', 'h3', 'h4' ], true ) ? $s['level'] : 'h2';
    $show_divider = $s['show_divider'] ?? true;
    $alignment    = $s['alignment'] ?? 'left';

    if ( empty( $text ) ) return;

    $align = $alignment !== 'left' ? ' style="text-align:' . $alignment . ';"' : '';
    echo '<div class="sp-widget-heading"' . $align . '>';
    echo '<' . $level . ' style="margin:0 0 8px; color:#1e3a5f;">' . esc_html( $text ) . '</' . $level . '>';
    if ( $subtitle ) {
        echo '<p style="margin:0 0 12px; color:#666; font-size:18px;">' . esc_html( $subtitle ) . '</p>';
    }
    if ( $show_divider ) {
        $hr_margin = $alignment === 'center' ? 'auto' : ( $alignment === 'right' ? '0 0 0 auto' : '0' );
        echo '<hr style="border:none; border-top:2px solid var(--sp-color-primary); width:60px; margin:' . $hr_margin . ';">';
    }
    echo '</div>';
}

/**
 * Render: Image
 */
function sp_render_builder_widget_image( array $s ): void {
    $image_id  = $s['image_id'] ?? 0;
    $caption   = $s['caption'] ?? '';
    $link_url  = $s['link_url'] ?? '';
    $size      = $s['size'] ?? 'large';
    $alignment = $s['alignment'] ?? 'center';

    if ( ! $image_id ) return;

    $img = wp_get_attachment_image( $image_id, $size, false, [ 'style' => 'max-width:100%; height:auto; border-radius:6px;', 'loading' => 'lazy' ] );
    if ( ! $img ) return;

    $align = $alignment !== 'left' ? ' style="text-align:' . $alignment . ';"' : '';
    echo '<figure' . $align . ' style="margin:0;">';
    echo $link_url ? '<a href="' . esc_url( $link_url ) . '">' . $img . '</a>' : $img;
    if ( $caption ) {
        echo '<figcaption style="margin-top:8px; color:#666; font-size:14px; font-style:italic;">' . esc_html( $caption ) . '</figcaption>';
    }
    echo '</figure>';
}

/**
 * Render: Button / CTA
 */
function sp_render_builder_widget_button( array $s ): void {
    $text       = $s['text'] ?? '';
    $url        = $s['url'] ?? '';
    $style      = $s['style'] ?? 'primary';
    $alignment  = $s['alignment'] ?? 'left';
    $new_window = $s['new_window'] ?? false;

    if ( empty( $text ) || empty( $url ) ) return;

    $target = $new_window ? ' target="_blank" rel="noopener noreferrer"' : '';
    $align  = $alignment !== 'left' ? ' style="text-align:' . $alignment . ';"' : '';

    echo '<div class="sp-widget-button"' . $align . '>';
    echo '<a href="' . esc_url( $url ) . '" class="sp-btn sp-btn-' . esc_attr( $style ) . '"' . $target . '>' . esc_html( $text ) . '</a>';
    echo '</div>';
}

/**
 * Render: Contact Form
 */
function sp_render_builder_widget_contact_form( array $s ): void {
    $intro = $s['intro_text'] ?? '';
    $form_id = 'sp-bld-contact-' . wp_unique_id();

    echo '<div class="sp-widget-contact-form" id="' . esc_attr( $form_id ) . '" style="max-width:600px;">';
    if ( $intro ) {
        echo '<p style="margin-bottom:16px; color:#555;">' . esc_html( $intro ) . '</p>';
    }
    echo '<div class="sp-contact-message" style="display:none; padding:12px 16px; border-radius:6px; margin-bottom:16px;"></div>';
    ?>
    <form class="sp-builder-contact-form-inner" method="post">
        <?php wp_nonce_field( 'sp_builder_contact', 'sp_builder_contact_nonce' ); ?>
        <div style="position:absolute; left:-9999px;" aria-hidden="true"><input type="text" name="sp_website_url" tabindex="-1" autocomplete="off"></div>

        <div style="display:flex; gap:16px; margin-bottom:16px;">
            <div style="flex:1;">
                <label style="display:block; font-weight:600; margin-bottom:4px;">Name <span style="color:#d63638;">*</span></label>
                <input type="text" name="sp_contact_name" required style="width:100%; padding:8px 12px; border:1px solid #ccc; border-radius:6px; font-size:16px;">
            </div>
            <div style="flex:1;">
                <label style="display:block; font-weight:600; margin-bottom:4px;">Email <span style="color:#d63638;">*</span></label>
                <input type="email" name="sp_contact_email" required style="width:100%; padding:8px 12px; border:1px solid #ccc; border-radius:6px; font-size:16px;">
            </div>
        </div>
        <div style="margin-bottom:16px;">
            <label style="display:block; font-weight:600; margin-bottom:4px;">Message <span style="color:#d63638;">*</span></label>
            <textarea name="sp_contact_message" rows="5" required style="width:100%; padding:8px 12px; border:1px solid #ccc; border-radius:6px; font-size:16px; font-family:inherit;"></textarea>
        </div>
        <button type="submit" class="sp-btn sp-btn-primary">Send Message</button>
    </form>
    <?php
    echo '</div>';
}


// ============================================================================
// PAGE BUILDER — CONTACT FORM AJAX HANDLER
// ============================================================================

add_action( 'wp_ajax_sp_builder_contact_form', 'sp_handle_builder_contact_form' );
add_action( 'wp_ajax_nopriv_sp_builder_contact_form', 'sp_handle_builder_contact_form' );

function sp_handle_builder_contact_form(): void {
    if ( ! check_ajax_referer( 'sp_builder_contact', 'sp_builder_contact_nonce', false ) ) {
        wp_send_json_error( [ 'message' => __( 'Security check failed. Please refresh and try again.', 'societypress' ) ] );
    }
    if ( ! empty( $_POST['sp_website_url'] ) ) {
        wp_send_json_success( [ 'message' => __( 'Thank you for your message!', 'societypress' ) ] );
    }

    $name    = sanitize_text_field( $_POST['sp_contact_name'] ?? '' );
    $email   = sanitize_email( $_POST['sp_contact_email'] ?? '' );
    $message = sanitize_textarea_field( $_POST['sp_contact_message'] ?? '' );

    if ( ! $name || ! $email || ! $message ) {
        wp_send_json_error( [ 'message' => __( 'Please fill in all required fields.', 'societypress' ) ] );
    }
    if ( ! is_email( $email ) ) {
        wp_send_json_error( [ 'message' => __( 'Please enter a valid email address.', 'societypress' ) ] );
    }

    $settings  = get_option( 'societypress_settings', [] );
    $to        = $settings['organization_email'] ?? get_option( 'admin_email' );
    $site_name = get_bloginfo( 'name' );

    $sent = wp_mail(
        $to,
        sprintf( '[%s] Message from %s', $site_name, $name ),
        sprintf( "Name: %s\nEmail: %s\n\nMessage:\n%s\n\n---\nSent from %s contact form", $name, $email, $message, $site_name ),
        [ 'Content-Type: text/plain; charset=UTF-8', sprintf( 'Reply-To: %s <%s>', $name, $email ) ]
    );

    if ( $sent ) {
        wp_send_json_success( [ 'message' => __( 'Thank you for your message! We will get back to you soon.', 'societypress' ) ] );
    } else {
        wp_send_json_error( [ 'message' => __( 'There was a problem sending your message. Please try again later.', 'societypress' ) ] );
    }
}


