function sp_builder_frontend_scripts(): void {
    ?>
    <script id="sp-builder-frontend-js">
    jQuery(function($) {
        'use strict';
        $('.sp-builder-contact-form-inner').on('submit', function(e) {
            e.preventDefault();
            var $form = $(this), $wrap = $form.closest('.sp-widget-contact-form');
            var $msg = $wrap.find('.sp-contact-message'), $btn = $form.find('button[type="submit"]');
            var origText = $btn.text();

            $btn.prop('disabled', true).text('Sending...');
            $msg.hide().removeClass('sp-success sp-error');

            $.ajax({
                url: '<?php echo esc_url( admin_url( 'admin-ajax.php' ) ); ?>',
                type: 'POST',
                data: $form.serialize() + '&action=sp_builder_contact_form',
                dataType: 'json',
                success: function(r) {
                    $msg.text(r.data.message);
                    $msg.addClass(r.success ? 'sp-success' : 'sp-error').show();
                    if (r.success) $form.find('input[type="text"], input[type="email"], textarea').val('');
                },
                error: function() {
                    $msg.addClass('sp-error').text('An unexpected error occurred. Please try again.').show();
                },
                complete: function() { $btn.prop('disabled', false).text(origText); }
            });
        });
    });
    </script>
    <?php
}


// ============================================================================
// ============================================================================
// EVENTS — TIME SLOTS (CRUD FUNCTIONS)
// ============================================================================
//
// WHY: Events can have multiple time slots (e.g., a workshop with 3 sessions).
//      Members register for a specific slot, and each slot has its own capacity.
//      These functions handle creating, reading, updating, and deleting slots,
//      plus capacity checking for registration.
// ============================================================================

/**
 * Create a new event time slot.
 *
 * WHY: Called from the event edit form when Harold adds a new slot row.
 *
 * @param int   $event_id The event ID.
 * @param array $data     Slot data: start_time, end_time, capacity, description, sort_order, is_active.
 * @return int|false The new slot ID on success, false on failure.
 */
function sp_slot_create( int $event_id, array $data ) {
    global $wpdb;
    $table = $wpdb->prefix . 'sp_event_slots';

    // Validate required fields
    if ( empty( $data['start_time'] ) || empty( $data['end_time'] ) ) {
        return false;
    }

    // Get the next sort order for this event if not provided
    if ( ! isset( $data['sort_order'] ) ) {
        $max_order = $wpdb->get_var( $wpdb->prepare(
            "SELECT MAX(sort_order) FROM {$table} WHERE event_id = %d",
            $event_id
        ) );
        $data['sort_order'] = $max_order !== null ? (int) $max_order + 1 : 0;
    }

    $insert_data = [
        'event_id'    => $event_id,
        'start_time'  => sp_sanitize_slot_time( $data['start_time'] ),
        'end_time'    => sp_sanitize_slot_time( $data['end_time'] ),
        'capacity'    => isset( $data['capacity'] ) && $data['capacity'] !== '' ? absint( $data['capacity'] ) : null,
        'description' => isset( $data['description'] ) ? sanitize_text_field( $data['description'] ) : null,
        'sort_order'  => absint( $data['sort_order'] ),
        'is_active'   => isset( $data['is_active'] ) ? absint( $data['is_active'] ) : 1,
    ];

    $format = [ '%d', '%s', '%s', '%d', '%s', '%d', '%d' ];

    // Handle NULL capacity (unlimited)
    if ( $insert_data['capacity'] === null ) {
        $format[3] = null;
    }

    $result = $wpdb->insert( $table, $insert_data, $format );

    return $result === false ? false : (int) $wpdb->insert_id;
}

/**
 * Update an existing slot.
 *
 * WHY: Called when Harold edits a slot row on the event edit form.
 *
 * @param int   $slot_id The slot ID.
 * @param array $data    Updated data.
 * @return bool True on success, false on failure.
 */
function sp_slot_update( int $slot_id, array $data ): bool {
    global $wpdb;
    $table = $wpdb->prefix . 'sp_event_slots';

    $update_data = [];
    $format      = [];

    if ( isset( $data['start_time'] ) ) {
        $update_data['start_time'] = sp_sanitize_slot_time( $data['start_time'] );
        $format[] = '%s';
    }

    if ( isset( $data['end_time'] ) ) {
        $update_data['end_time'] = sp_sanitize_slot_time( $data['end_time'] );
        $format[] = '%s';
    }

    if ( array_key_exists( 'capacity', $data ) ) {
        // Allow setting capacity to NULL (unlimited) by passing empty string or null
        $update_data['capacity'] = ( $data['capacity'] === '' || $data['capacity'] === null ) ? null : absint( $data['capacity'] );
        $format[] = $update_data['capacity'] === null ? null : '%d';
    }

    if ( isset( $data['description'] ) ) {
        $update_data['description'] = sanitize_text_field( $data['description'] );
        $format[] = '%s';
    }

    if ( isset( $data['sort_order'] ) ) {
        $update_data['sort_order'] = absint( $data['sort_order'] );
        $format[] = '%d';
    }

    if ( isset( $data['is_active'] ) ) {
        $update_data['is_active'] = absint( $data['is_active'] );
        $format[] = '%d';
    }

    if ( empty( $update_data ) ) {
        return true; // Nothing to update
    }

    $result = $wpdb->update( $table, $update_data, [ 'id' => $slot_id ], $format, [ '%d' ] );

    return $result !== false;
}

/**
 * Delete a slot (soft or hard).
 *
 * WHY: Soft-delete (is_active = 0) is the default to preserve registration
 *      history. Hard-delete removes the slot and its registrations entirely.
 *
 * @param int  $slot_id    The slot ID.
 * @param bool $soft_delete Whether to soft-delete (default true).
 * @return bool True on success.
 */
function sp_slot_delete( int $slot_id, bool $soft_delete = true ): bool {
    global $wpdb;

    if ( $soft_delete ) {
        return sp_slot_update( $slot_id, [ 'is_active' => 0 ] );
    }

    // Hard delete — also removes registrations for this slot
    $wpdb->delete(
        $wpdb->prefix . 'sp_event_registrations',
        [ 'slot_id' => $slot_id ],
        [ '%d' ]
    );

    $result = $wpdb->delete(
        $wpdb->prefix . 'sp_event_slots',
        [ 'id' => $slot_id ],
        [ '%d' ]
    );

    return $result !== false;
}

/**
 * Get a single slot by ID.
 *
 * @param int $slot_id The slot ID.
 * @return object|null Slot data or null if not found.
 */
function sp_slot_get( int $slot_id ) {
    global $wpdb;

    return $wpdb->get_row( $wpdb->prepare(
        "SELECT * FROM {$wpdb->prefix}sp_event_slots WHERE id = %d",
        $slot_id
    ) );
}

/**
 * Get all slots for an event.
 *
 * WHY: Used to display available time slots on the event page and in the
 *      admin event edit form.
 *
 * @param int  $event_id    The event post ID.
 * @param bool $active_only Whether to only return active slots.
 * @return array Array of slot objects.
 */
function sp_slots_get_by_event( int $event_id, bool $active_only = true ): array {
    global $wpdb;
    $table = $wpdb->prefix . 'sp_event_slots';

    $where_active = $active_only ? 'AND is_active = 1' : '';

    $results = $wpdb->get_results( $wpdb->prepare(
        "SELECT * FROM {$table}
         WHERE event_id = %d {$where_active}
         ORDER BY sort_order ASC, start_time ASC",
        $event_id
    ) );

    return $results ?: [];
}

/**
 * Get the number of confirmed registrations for a specific slot.
 *
 * WHY: Used for capacity checking before allowing new slot registrations.
 *      Only counts 'confirmed' registrations — cancelled and waitlisted don't
 *      count against capacity. Uses SUM(party_size) because a single
 *      registration can represent a group (e.g., member + 2 guests).
 *
 * @param int $slot_id The slot ID.
 * @return int Number of confirmed spots taken (sum of party_size).
 */
function sp_slot_get_registration_count( int $slot_id ): int {
    global $wpdb;

    $count = $wpdb->get_var( $wpdb->prepare(
        "SELECT COALESCE(SUM(party_size), 0) FROM {$wpdb->prefix}sp_event_registrations
         WHERE slot_id = %d AND status = 'confirmed'",
        $slot_id
    ) );

    return (int) $count;
}

/**
 * Get the remaining capacity for a slot.
 *
 * WHY: Shows members how many spots are left and determines whether they
 *      can register or must join the waitlist.
 *
 * @param int $slot_id The slot ID.
 * @return int|null Remaining spots, or null if unlimited capacity.
 */
function sp_slot_get_remaining_capacity( int $slot_id ): ?int {
    $slot = sp_slot_get( $slot_id );

    if ( ! $slot ) {
        return 0;
    }

    // NULL capacity means unlimited
    if ( $slot->capacity === null ) {
        return null;
    }

    $registered = sp_slot_get_registration_count( $slot_id );
    $remaining  = (int) $slot->capacity - $registered;

    return max( 0, $remaining );
}

/**
 * Check if a slot has available capacity.
 *
 * WHY: Quick boolean check before attempting registration — avoids the
 *      complexity of null-checking the remaining capacity return value.
 *
 * @param int $slot_id The slot ID.
 * @return bool True if slot has capacity (or is unlimited).
 */
function sp_slot_has_capacity( int $slot_id ): bool {
    $remaining = sp_slot_get_remaining_capacity( $slot_id );

    // NULL means unlimited
    if ( $remaining === null ) {
        return true;
    }

    return $remaining > 0;
}

/**
 * Format a slot's time range for display.
 *
 * WHY: Provides a human-readable time range like "10:00 AM – 11:00 AM"
 *      for the frontend and admin. Uses WordPress date_i18n() so the format
 *      respects the site's locale settings.
 *
 * @param object|array $slot   Slot data with start_time and end_time.
 * @param string       $format PHP time format. Default 'g:i A'.
 * @return string Formatted time range, or empty if data missing.
 */
function sp_slot_format_time_range( $slot, string $format = 'g:i A' ): string {
    $start = is_object( $slot ) ? ( $slot->start_time ?? '' ) : ( $slot['start_time'] ?? '' );
    $end   = is_object( $slot ) ? ( $slot->end_time ?? '' ) : ( $slot['end_time'] ?? '' );

    if ( empty( $start ) || empty( $end ) ) {
        return '';
    }

    return wp_date( $format, strtotime( $start ) ) . ' \u2013 ' . wp_date( $format, strtotime( $end ) );
}

/**
 * Sanitize a time string to HH:MM:SS format.
 *
 * WHY: HTML time inputs send "HH:MM" but we store "HH:MM:SS" in the database
 *      for consistency. This also handles edge cases like AM/PM formatted
 *      strings or malformed input.
 *
 * @param string $time Time string in various formats.
 * @return string Time in H:i:s format.
 */
function sp_sanitize_slot_time( string $time ): string {
    // If already in HH:MM:SS format, validate and return
    if ( preg_match( '/^\d{2}:\d{2}:\d{2}$/', $time ) ) {
        return $time;
    }

    // If in HH:MM format (from HTML time input), append :00
    if ( preg_match( '/^\d{2}:\d{2}$/', $time ) ) {
        return $time . ':00';
    }

    // Try to parse and format consistently
    $timestamp = strtotime( $time );
    if ( $timestamp === false ) {
        return '00:00:00';
    }

    return date( 'H:i:s', $timestamp );
}

/**
 * Save all slots for an event from the admin edit form.
 *
 * WHY: The event edit form has repeatable slot rows. When saved, we need to
 *      create new slots, update existing ones, and soft-delete any that were
 *      removed. This handles the full save cycle in one call.
 *
 * @param int   $event_id   The event ID.
 * @param array $slots_data Array of slot data from the form.
 * @return bool True on success.
 */
function sp_slots_save_event( int $event_id, array $slots_data ): bool {
    // Get existing slot IDs for this event (including inactive, so we can reactivate)
    $existing_slots = sp_slots_get_by_event( $event_id, false );
    $existing_ids   = array_map( function( $s ) { return (int) $s->id; }, $existing_slots );
    $submitted_ids  = [];

    // Process each submitted slot row
    foreach ( $slots_data as $index => $slot_data ) {
        // Skip empty rows (no times entered)
        if ( empty( $slot_data['start_time'] ) && empty( $slot_data['end_time'] ) ) {
            continue;
        }

        $slot_data['sort_order'] = $index;
        $slot_data['is_active']  = 1;

        if ( ! empty( $slot_data['id'] ) && in_array( (int) $slot_data['id'], $existing_ids, true ) ) {
            // Update existing slot
            sp_slot_update( (int) $slot_data['id'], $slot_data );
            $submitted_ids[] = (int) $slot_data['id'];
        } else {
            // Create new slot
            $new_id = sp_slot_create( $event_id, $slot_data );
            if ( $new_id ) {
                $submitted_ids[] = $new_id;
            }
        }
    }

    // Soft-delete slots that were removed from the form
    $removed_ids = array_diff( $existing_ids, $submitted_ids );
    foreach ( $removed_ids as $removed_id ) {
        sp_slot_delete( $removed_id, true );
    }

    return true;
}

/**
 * Delete all slots for an event.
 *
 * WHY: Used when an event is deleted to clean up associated slots.
 *
 * @param int  $event_id    The event ID.
 * @param bool $soft_delete Whether to soft-delete instead of hard-delete.
 * @return bool True on success.
 */
function sp_slots_delete_by_event( int $event_id, bool $soft_delete = true ): bool {
    global $wpdb;
    $table = $wpdb->prefix . 'sp_event_slots';

    if ( $soft_delete ) {
        $result = $wpdb->update(
            $table,
            [ 'is_active' => 0 ],
            [ 'event_id' => $event_id ],
            [ '%d' ],
            [ '%d' ]
        );
        return $result !== false;
    }

    // Hard delete — also remove registrations for these slots
    $slot_ids = $wpdb->get_col( $wpdb->prepare(
        "SELECT id FROM {$table} WHERE event_id = %d",
        $event_id
    ) );

    if ( ! empty( $slot_ids ) ) {
        $placeholders = implode( ',', array_fill( 0, count( $slot_ids ), '%d' ) );
        $wpdb->query( $wpdb->prepare(
            "DELETE FROM {$wpdb->prefix}sp_event_registrations WHERE slot_id IN ({$placeholders})",
            $slot_ids
        ) );
    }

    $result = $wpdb->delete( $table, [ 'event_id' => $event_id ], [ '%d' ] );

    return $result !== false;
}


// ============================================================================
// EVENTS — LIST TABLE (Admin)
// ============================================================================
//
// WHY: WP_List_Table gives Harold a familiar interface — the same layout he
//      sees on the Members page. Sortable columns, search, filter dropdowns,
//      pagination, and row actions all come for free. We just tell it what
//      data to show and how to fetch it.
// ============================================================================

class SP_Events_List_Table extends WP_List_Table {

    public function __construct() {
        parent::__construct( [
            'singular' => 'event',
            'plural'   => 'events',
            'ajax'     => false,
        ] );
    }

    /**
     * Define the columns Harold sees in the event list.
     *
     * WHY each column:
     *   Title         — primary identifier, links to edit
     *   Date/Time     — when the event happens (the most important detail)
     *   Location      — where it is (or "Virtual" for online events)
     *   Category      — color-coded badge for quick visual scanning
     *   Registrations — how many people signed up vs. capacity
     *   Status        — scheduled, cancelled, postponed, completed
     */
    public function get_columns(): array {
        return [
            'cb'            => '<input type="checkbox" />',
            'title'         => __( 'Title', 'societypress' ),
            'event_date'    => __( 'Date / Time', 'societypress' ),
            'location'      => __( 'Location', 'societypress' ),
            'category'      => __( 'Category', 'societypress' ),
            'registrations' => __( 'Registrations', 'societypress' ),
            'status'        => __( 'Status', 'societypress' ),
        ];
    }

    /**
     * Which columns can be clicked to sort the list.
     */
    public function get_sortable_columns(): array {
        return [
            'title'      => [ 'title', false ],
            'event_date' => [ 'event_date', true ],  // Default sort: nearest date first
            'status'     => [ 'status', false ],
        ];
    }

    /**
     * Bulk actions dropdown — appears above the table.
     */
    protected function get_bulk_actions(): array {
        return [
            'delete' => __( 'Delete', 'societypress' ),
        ];
    }

    /**
     * Checkbox column for bulk actions.
     */
    protected function column_cb( $item ): string {
        return sprintf(
            '<input type="checkbox" name="event[]" value="%d" />',
            $item->id
        );
    }

    /**
     * Title column — the primary column with row actions.
     *
     * Shows the event title as a link to the edit page, with Edit, Duplicate,
     * Cancel, and Delete row actions on hover.
     */
    protected function column_title( $item ): string {
        $edit_url = admin_url( 'admin.php?page=sp-event-edit&event_id=' . $item->id );
        $title    = '<strong><a href="' . esc_url( $edit_url ) . '">' . esc_html( $item->title ) . '</a></strong>';

        // External/imported event indicators — Harold can see at a glance which
        // events come from outside sources without opening each one.
        if ( ! empty( $item->external_source ) ) {
            if ( $item->external_source === 'ical_feed' ) {
                $title .= ' <span style="background: #dbe9f4; color: #2271b1; padding: 1px 6px; border-radius: 3px; font-size: 11px; font-weight: 500; vertical-align: middle;" title="' . esc_attr__( 'Imported from iCal feed', 'societypress' ) . '">&#128279; ' . esc_html__( 'iCal', 'societypress' ) . '</span>';
            } elseif ( $item->external_source === 'manual' ) {
                $title .= ' <span style="background: #fef0e5; color: #b35a00; padding: 1px 6px; border-radius: 3px; font-size: 11px; font-weight: 500; vertical-align: middle;" title="' . esc_attr__( 'Links to external website', 'societypress' ) . '">&#8599; ' . esc_html__( 'External', 'societypress' ) . '</span>';
            }
        }

        // Build row actions
        $actions = [
            'edit' => sprintf( '<a href="%s">%s</a>', esc_url( $edit_url ), esc_html__( 'Edit', 'societypress' ) ),
        ];

        // Duplicate — creates a copy of the event
        $duplicate_url = wp_nonce_url(
            admin_url( 'admin.php?page=sp-events&action=duplicate&event_id=' . $item->id ),
            'sp_duplicate_event_' . $item->id
        );
        $actions['duplicate'] = sprintf( '<a href="%s">%s</a>', esc_url( $duplicate_url ), esc_html__( 'Duplicate', 'societypress' ) );

        // Cancel — only for scheduled events
        if ( $item->status === 'scheduled' ) {
            $cancel_url = wp_nonce_url(
                admin_url( 'admin.php?page=sp-events&action=cancel&event_id=' . $item->id ),
                'sp_cancel_event_' . $item->id
            );
            $actions['cancel'] = sprintf(
                '<a href="%s" onclick="return confirm(\'%s\');">%s</a>',
                esc_url( $cancel_url ),
                esc_js( __( 'Cancel this event?', 'societypress' ) ),
                esc_html__( 'Cancel', 'societypress' )
            );
        }

        // Delete — JS-based POST to avoid nested forms inside the list table
        $actions['delete'] = '<a href="#" style="color:#b32d2e;" onclick="if(confirm(\'' . esc_js( __( 'Permanently delete this event?', 'societypress' ) ) . '\')){var f=document.createElement(\'form\');f.method=\'post\';f.action=\'' . esc_url( admin_url( 'admin.php?page=sp-events' ) ) . '\';var d=[[\'_wpnonce\',\'' . wp_create_nonce( 'sp_delete_event_' . $item->id ) . '\'],[\'action\',\'delete\'],[\'event_id\',\'' . (int) $item->id . '\']];d.forEach(function(p){var i=document.createElement(\'input\');i.type=\'hidden\';i.name=p[0];i.value=p[1];f.appendChild(i);});document.body.appendChild(f);f.submit();}return false;">' . esc_html__( 'Delete', 'societypress' ) . '</a>';

        return $title . $this->row_actions( $actions );
    }

    /**
     * Date/Time column — formatted for easy scanning.
     *
     * WHY: Shows the date prominently with start/end time below it.
     *      Uses WordPress's configured date format so it matches what
     *      Harold sees everywhere else on the site.
     */
    protected function column_event_date( $item ): string {
        $date = date_i18n( get_option( 'date_format', 'F j, Y' ), strtotime( $item->event_date ) );
        $output = '<strong>' . esc_html( $date ) . '</strong>';

        if ( ! empty( $item->start_time ) ) {
            $time_str = date_i18n( get_option( 'time_format', 'g:i A' ), strtotime( $item->start_time ) );
            if ( ! empty( $item->end_time ) ) {
                $time_str .= ' – ' . date_i18n( get_option( 'time_format', 'g:i A' ), strtotime( $item->end_time ) );
            }
            $output .= '<br><span style="color: #787c82;">' . esc_html( $time_str ) . '</span>';
        }

        return $output;
    }

    /**
     * Location column — shows venue name or "Virtual" badge.
     */
    protected function column_location( $item ): string {
        if ( ! empty( $item->location_name ) ) {
            $output = esc_html( $item->location_name );
            if ( $item->is_virtual ) {
                $output .= ' <span style="background: #dbe9f4; color: var(--sp-color-primary); padding: 2px 6px; border-radius: 3px; font-size: 11px;">+ Virtual</span>';
            }
            return $output;
        }
        if ( $item->is_virtual ) {
            return '<span style="background: #dbe9f4; color: var(--sp-color-primary); padding: 2px 6px; border-radius: 3px; font-size: 11px;">' . esc_html__( 'Virtual', 'societypress' ) . '</span>';
        }
        return '—';
    }

    /**
     * Category column — color-coded badge.
     *
     * WHY: A small colored pill makes it easy to visually group events by
     *      type. Harold can instantly spot all "Workshop" events (green) vs.
     *      "General Meeting" events (blue) without reading every row.
     */
    protected function column_category( $item ): string {
        if ( empty( $item->category_id ) || empty( $item->category_name ) ) {
            return '—';
        }
        // Category name and color are pre-fetched via JOIN in prepare_items()
        return sprintf(
            '<span style="background: %s; color: #fff; padding: 3px 8px; border-radius: 3px; font-size: 12px; font-weight: 500; white-space: nowrap;">%s</span>',
            esc_attr( $item->category_color ?: '#2271b1' ),
            esc_html( $item->category_name )
        );
    }

    /**
     * Registrations column — shows count vs. capacity (if limited).
     *
     * WHY: Harold needs to see at a glance how many people have signed up
     *      and whether the event is approaching capacity. "12 / 30" is
     *      immediately clear. If registration is disabled, we show "—".
     */
    protected function column_registrations( $item ): string {
        if ( ! $item->registration_enabled ) {
            return '<span style="color: #787c82;">—</span>';
        }
        // Registration count is pre-fetched via subquery JOIN in prepare_items()
        $count = (int) ( $item->reg_count ?? 0 );

        if ( $item->registration_limit ) {
            $pct   = ( $count / $item->registration_limit ) * 100;
            $color = $pct >= 90 ? '#d63638' : ( $pct >= 70 ? '#dba617' : '#50575e' );
            return sprintf(
                '<span style="color: %s; font-weight: 500;">%d / %d</span>',
                $color, $count, $item->registration_limit
            );
        }
        return sprintf( '<span style="font-weight: 500;">%d</span>', $count );
    }

    /**
     * Status column — color-coded badge so Harold can see at a glance.
     */
    protected function column_status( $item ): string {
        $colors = [
            'scheduled' => '#2271b1',
            'cancelled' => '#d63638',
            'postponed' => '#dba617',
            'completed' => '#00a32a',
        ];
        $color = $colors[ $item->status ] ?? '#787c82';
        $label = ucfirst( $item->status );

        return sprintf(
            '<span style="color: %s; font-weight: 600;">%s</span>',
            esc_attr( $color ),
            esc_html( $label )
        );
    }

    /**
     * Extra controls between bulk actions and the table — filter dropdowns.
     *
     * WHY: Harold needs to quickly filter by category ("show me all workshops"),
     *      by status ("show me cancelled events"), and by timeframe ("show me
     *      only upcoming events"). These dropdowns appear right above the table.
     *
     * @param string $which 'top' or 'bottom' of the table.
     */
    protected function extra_tablenav( $which ): void {
        if ( $which !== 'top' ) {
            return;
        }
        global $wpdb;

        $current_category  = $_GET['event_category'] ?? '';
        $current_status    = $_GET['event_status'] ?? '';
        $current_timeframe = $_GET['event_timeframe'] ?? 'upcoming';

        echo '<div class="alignleft actions">';

        // Category filter
        $categories = $wpdb->get_results(
            "SELECT id, name FROM {$wpdb->prefix}sp_event_categories WHERE active = 1 ORDER BY sort_order"
        );
        echo '<select name="event_category">';
        echo '<option value="">' . esc_html__( 'All Categories', 'societypress' ) . '</option>';
        foreach ( $categories as $cat ) {
            printf(
                '<option value="%d" %s>%s</option>',
                $cat->id,
                selected( $current_category, $cat->id, false ),
                esc_html( $cat->name )
            );
        }
        echo '</select>';

        // Status filter
        $statuses = [ 'scheduled', 'cancelled', 'postponed', 'completed' ];
        echo '<select name="event_status">';
        echo '<option value="">' . esc_html__( 'All Statuses', 'societypress' ) . '</option>';
        foreach ( $statuses as $s ) {
            printf(
                '<option value="%s" %s>%s</option>',
                esc_attr( $s ),
                selected( $current_status, $s, false ),
                esc_html( ucfirst( $s ) )
            );
        }
        echo '</select>';

        // Timeframe filter
        $timeframes = [
            'upcoming' => __( 'Upcoming', 'societypress' ),
            'past'     => __( 'Past', 'societypress' ),
            'all'      => __( 'All', 'societypress' ),
        ];
        echo '<select name="event_timeframe">';
        foreach ( $timeframes as $val => $label ) {
            printf(
                '<option value="%s" %s>%s</option>',
                esc_attr( $val ),
                selected( $current_timeframe, $val, false ),
                esc_html( $label )
            );
        }
        echo '</select>';

        submit_button( __( 'Filter', 'societypress' ), '', 'filter_action', false );
        echo '</div>';
    }

    /**
     * Fetch event data from the database.
     *
     * Handles searching, filtering by category/status/timeframe, sorting,
     * and pagination — everything Harold needs to manage a full calendar
     * of society events.
     */
    public function prepare_items(): void {
        global $wpdb;

        $per_page = 20;
        $table    = $wpdb->prefix . 'sp_events';

        // Build the WHERE clause from search and filters
        $where  = [];
        $values = [];

        // Search — checks title and description
        $search = $_GET['s'] ?? '';
        if ( ! empty( $search ) ) {
            $like     = '%' . $wpdb->esc_like( $search ) . '%';
            $where[]  = "(e.title LIKE %s OR e.description LIKE %s)";
            $values[] = $like;
            $values[] = $like;
        }

        // Category filter
        $cat_filter = $_GET['event_category'] ?? '';
        if ( ! empty( $cat_filter ) ) {
            $where[]  = "e.category_id = %d";
            $values[] = (int) $cat_filter;
        }

        // Status filter
        $status_filter = $_GET['event_status'] ?? '';
        if ( ! empty( $status_filter ) ) {
            $where[]  = "e.status = %s";
            $values[] = $status_filter;
        }

        // Timeframe filter (defaults to upcoming)
        $timeframe = $_GET['event_timeframe'] ?? 'upcoming';
        if ( $timeframe === 'upcoming' ) {
            $where[]  = "e.event_date >= %s";
            $values[] = current_time( 'Y-m-d' );
        } elseif ( $timeframe === 'past' ) {
            $where[]  = "e.event_date < %s";
            $values[] = current_time( 'Y-m-d' );
        }
        // 'all' — no date filter

        $where_sql = ! empty( $where ) ? 'WHERE ' . implode( ' AND ', $where ) : '';

        // Sorting — default to event_date ASC for upcoming, DESC for past
        $allowed_orderby = [ 'title', 'event_date', 'status' ];
        $orderby = $_GET['orderby'] ?? 'event_date';
        if ( ! in_array( $orderby, $allowed_orderby, true ) ) {
            $orderby = 'event_date';
        }

        // Smart default sort direction: upcoming events nearest-first (ASC),
        // past events most-recent-first (DESC), all events nearest-first.
        $default_order = ( $timeframe === 'past' ) ? 'desc' : 'asc';
        $order = ( $_GET['order'] ?? $default_order ) === 'desc' ? 'DESC' : 'ASC';

        // Count total items (for pagination)
        $count_sql = "SELECT COUNT(*) FROM {$table} e {$where_sql}";
        if ( ! empty( $values ) ) {
            $total_items = (int) $wpdb->get_var( $wpdb->prepare( $count_sql, ...$values ) );
        } else {
            $total_items = (int) $wpdb->get_var( $count_sql );
        }

        // Pagination
        $current_page = $this->get_pagenum();
        $offset       = ( $current_page - 1 ) * $per_page;

        // Fetch the rows — JOIN categories and subquery registration counts
        // WHY: Previously each row triggered separate queries for category name/color
        //      and registration count (N+1 problem). With 50+ events this created
        //      100+ extra queries per page load. Now we get everything in one query.
        $reg_table = $wpdb->prefix . 'sp_event_registrations';
        $cat_table = $wpdb->prefix . 'sp_event_categories';
        $query = "SELECT e.*,
                         c.name AS category_name, c.color AS category_color,
                         COALESCE(reg_counts.reg_count, 0) AS reg_count
                  FROM {$table} e
                  LEFT JOIN {$cat_table} c ON e.category_id = c.id
                  LEFT JOIN (
                      SELECT event_id, SUM(party_size) AS reg_count
                      FROM {$reg_table}
                      WHERE status IN ('confirmed', 'waitlisted')
                      GROUP BY event_id
                  ) reg_counts ON reg_counts.event_id = e.id
                  {$where_sql}
                  ORDER BY e.{$orderby} {$order}
                  LIMIT %d OFFSET %d";

        $query_values = array_merge( $values, [ $per_page, $offset ] );
        $this->items  = $wpdb->get_results( $wpdb->prepare( $query, ...$query_values ) );

        // Tell WP_List_Table about columns and pagination
        $this->_column_headers = [
            $this->get_columns(),
            [],                          // hidden columns (none)
            $this->get_sortable_columns(),
        ];

        $this->set_pagination_args( [
            'total_items' => $total_items,
            'per_page'    => $per_page,
            'total_pages' => ceil( $total_items / $per_page ),
        ] );
    }

    /**
     * Message shown when there are no events yet.
     */
    public function no_items(): void {
        echo esc_html__( 'No events found.', 'societypress' ) . ' <a href="' . esc_url( admin_url( 'admin.php?page=sp-event-edit' ) ) . '">' . esc_html__( 'Create your first event', 'societypress' ) . '</a>.';
    }
}


// ============================================================================
// EVENTS — ACTION HANDLERS (delete, duplicate, cancel)
// ============================================================================
//
// WHY: Same pattern as the member delete handlers — these run on admin_init
//      BEFORE any HTML output, so wp_redirect() works cleanly. If we tried
//      to redirect inside the page callback, WordPress would have already
//      sent headers and the redirect would fail.
// ============================================================================

add_action( 'admin_init', function () {
    // Only run on the Events page
    if ( ! isset( $_GET['page'] ) || $_GET['page'] !== 'sp-events' ) {
        return;
    }
    if ( ! current_user_can( 'manage_options' ) ) {
        return;
    }

    global $wpdb;
    $events_table = $wpdb->prefix . 'sp_events';
    $action       = $_GET['action'] ?? $_POST['action'] ?? '';

    // ---- Single event delete — POST-only to prevent browser prefetch accidents ----
    if ( $action === 'delete' && ! empty( $_POST['event_id'] ) ) {
        $event_id = (int) $_POST['event_id'];
        check_admin_referer( 'sp_delete_event_' . $event_id );

        // Get title before delete for the audit log
        $del_title = $wpdb->get_var( $wpdb->prepare( "SELECT title FROM {$events_table} WHERE id = %d", $event_id ) );

        $wpdb->delete( $events_table, [ 'id' => $event_id ], [ '%d' ] );

        // Also clean up related data
        $wpdb->delete( $wpdb->prefix . 'sp_event_speaker_assignments', [ 'event_id' => $event_id ], [ '%d' ] );
        $wpdb->delete( $wpdb->prefix . 'sp_event_registrations', [ 'event_id' => $event_id ], [ '%d' ] );
        $wpdb->delete( $wpdb->prefix . 'sp_event_reminders', [ 'event_id' => $event_id ], [ '%d' ] );
        sp_slots_delete_by_event( $event_id, false ); // Hard-delete slots too

        sp_audit( 'event_deleted', "Event deleted: " . ( $del_title ?: "#{$event_id}" ), 'event', $event_id );

        // Invalidate iCal feed caches so subscription feeds reflect the deletion
        delete_transient( 'sp_ical_feed_public' );
        delete_transient( 'sp_ical_feed_members' );

        wp_redirect( admin_url( 'admin.php?page=sp-events&deleted=1' ) );
        exit;
    }

    // ---- Bulk delete ----
    if ( $action === 'delete' && ! empty( $_POST['event'] ) ) {
        check_admin_referer( 'bulk-events' );

        $ids = array_map( 'intval', (array) $_POST['event'] );

        // Fetch titles before deletion so the audit log has something useful
        // WHY: Once the rows are gone, we can't look up the names.
        $titles_map = [];
        if ( $ids ) {
            $id_placeholders = implode( ',', array_fill( 0, count( $ids ), '%d' ) );
            $rows = $wpdb->get_results( $wpdb->prepare(
                "SELECT id, title FROM {$events_table} WHERE id IN ({$id_placeholders})",
                ...$ids
            ) );
            foreach ( $rows as $row ) {
                $titles_map[ $row->id ] = $row->title;
            }
        }

        foreach ( $ids as $event_id ) {
            $wpdb->delete( $events_table, [ 'id' => $event_id ], [ '%d' ] );
            $wpdb->delete( $wpdb->prefix . 'sp_event_speaker_assignments', [ 'event_id' => $event_id ], [ '%d' ] );
            $wpdb->delete( $wpdb->prefix . 'sp_event_registrations', [ 'event_id' => $event_id ], [ '%d' ] );
            $wpdb->delete( $wpdb->prefix . 'sp_event_reminders', [ 'event_id' => $event_id ], [ '%d' ] );
            sp_slots_delete_by_event( $event_id, false ); // Hard-delete slots too

            sp_audit( 'event_deleted', 'Event deleted: ' . ( $titles_map[ $event_id ] ?? "#{$event_id}" ), 'event', $event_id );
        }

        // Invalidate iCal feed caches so subscription feeds reflect the deletions
        delete_transient( 'sp_ical_feed_public' );
        delete_transient( 'sp_ical_feed_members' );

        wp_redirect( admin_url( 'admin.php?page=sp-events&deleted=' . count( $ids ) ) );
        exit;
    }

    // ---- Duplicate event ----
    // WHY: Harold often runs the same event monthly — "General Meeting" with
    //      slightly different details. Duplicate copies everything except the
    //      date, so he just updates the date and any changed details.
    if ( $action === 'duplicate' && ! empty( $_GET['event_id'] ) ) {
        $event_id = (int) $_GET['event_id'];
        check_admin_referer( 'sp_duplicate_event_' . $event_id );

        $event = $wpdb->get_row( $wpdb->prepare(
            "SELECT * FROM {$events_table} WHERE id = %d", $event_id
        ), ARRAY_A );

        if ( $event ) {
            // Remove the original's ID and timestamps so we get a fresh row
            unset( $event['id'], $event['created_at'], $event['updated_at'] );

            // Mark as a copy so Harold knows it's new
            $event['title']  = $event['title'] . ' (Copy)';
            $event['slug']   = $event['slug'] . '-copy-' . time();
            $event['status'] = 'scheduled';

            // Clear recurrence link — the copy is standalone
            $event['recurrence_parent_id'] = null;
            $event['recurrence_rule']      = null;
            $event['recurrence_end_date']  = null;

            $event['created_by'] = get_current_user_id();

            $wpdb->insert( $events_table, $event );
            $new_id = $wpdb->insert_id;

            // Also copy speaker assignments
            if ( $new_id ) {
                $speakers = $wpdb->get_results( $wpdb->prepare(
                    "SELECT speaker_id, role, sort_order FROM {$wpdb->prefix}sp_event_speaker_assignments WHERE event_id = %d",
                    $event_id
                ), ARRAY_A );
                foreach ( $speakers as $spk ) {
                    $spk['event_id'] = $new_id;
                    $wpdb->insert( $wpdb->prefix . 'sp_event_speaker_assignments', $spk );
                }
            }

            wp_redirect( admin_url( 'admin.php?page=sp-event-edit&event_id=' . $new_id . '&duplicated=1' ) );
            exit;
        }

        wp_redirect( admin_url( 'admin.php?page=sp-events' ) );
        exit;
    }

    // ---- Cancel event ----
    // WHY: Cancelling is different from deleting — the event stays in the
    //      database with status "cancelled" so it still appears in reports
    //      and the calendar (with a "Cancelled" badge). This is a soft action.
    if ( $action === 'cancel' && ! empty( $_GET['event_id'] ) ) {
        $event_id = (int) $_GET['event_id'];
        check_admin_referer( 'sp_cancel_event_' . $event_id );

        $wpdb->update(
            $events_table,
            [ 'status' => 'cancelled' ],
            [ 'id' => $event_id ],
            [ '%s' ],
            [ '%d' ]
        );

        // Invalidate iCal feed caches — cancelled events are excluded from feeds
        delete_transient( 'sp_ical_feed_public' );
        delete_transient( 'sp_ical_feed_members' );

        wp_redirect( admin_url( 'admin.php?page=sp-events&cancelled=1' ) );
        exit;
    }
});


// ============================================================================
// EVENTS — LIST PAGE RENDERER
// ============================================================================

/**
 * Render the Events admin page — list table with filters, search, and actions.
 *
 * WHY: Same pattern as sp_render_members_page(). The WP_List_Table class does
 *      the heavy lifting — we just wrap it with a page title, Add New button,
 *      and success/error notices.
 */
function sp_render_events_page(): void {
    $table = new SP_Events_List_Table();
    $table->prepare_items();
    ?>
    <div class="wrap">
        <h1 class="wp-heading-inline"><?php esc_html_e( 'Events', 'societypress' ); ?></h1>
        <a href="<?php echo esc_url( admin_url( 'admin.php?page=sp-event-edit' ) ); ?>" class="page-title-action">
            Add New
        </a>
        <hr class="wp-header-end">

        <?php
        // Success notices
        if ( isset( $_GET['deleted'] ) ) {
            $count = (int) $_GET['deleted'];
            if ( $count > 0 ) {
                printf(
                    '<div class="notice notice-success is-dismissible"><p>%s</p></div>',
                    esc_html( sprintf(
                        /* translators: %d: number of events deleted */
                        _n( '%d event deleted.', '%d events deleted.', $count, 'societypress' ),
                        $count
                    ) )
                );
            }
        }
        if ( isset( $_GET['cancelled'] ) ) {
            echo '<div class="notice notice-success is-dismissible"><p>' . esc_html__( 'Event cancelled.', 'societypress' ) . '</p></div>';
        }
        if ( isset( $_GET['saved'] ) ) {
            echo '<div class="notice notice-success is-dismissible"><p>' . esc_html__( 'Event saved.', 'societypress' ) . '</p></div>';
        }
        ?>

        <form method="get">
            <input type="hidden" name="page" value="sp-events">
            <?php
            $table->search_box( 'Search Events', 'sp-event-search' );
            $table->display();
            ?>
        </form>
    </div>
    <?php
}


// ============================================================================
// EVENTS — SAVE HANDLER (runs on admin_init before any output)
// ============================================================================
//
// WHY: Same pattern as the member save handler — we process the form submission
//      on admin_init so we can redirect cleanly after saving. If we tried to
//      save inside the page callback, headers would already be sent.
// ============================================================================

add_action( 'admin_init', function () {
    if ( ! isset( $_POST['sp_event_nonce'] ) ) {
        return;
    }
    if ( ! wp_verify_nonce( $_POST['sp_event_nonce'], 'sp_save_event' ) ) {
        wp_die( esc_html__( 'Security check failed.', 'societypress' ) );
    }
    if ( ! current_user_can( 'manage_options' ) ) {
        wp_die( esc_html__( 'Unauthorized.', 'societypress' ) );
    }

    global $wpdb;
    $events_table = $wpdb->prefix . 'sp_events';
    $event_id     = (int) ( $_POST['event_id'] ?? 0 );

    // Generate a URL-safe slug from the title
    // WHY: Slugs are used in frontend event URLs (?sp_event=slug). We create
    //      them from the title automatically so Harold doesn't have to think
    //      about URL formatting. sanitize_title() handles the heavy lifting.
    $title = sanitize_text_field( $_POST['event_title'] ?? '' );
    $slug  = sanitize_title( $title );

    // Ensure slug uniqueness — append a number if the slug already exists
    // for a different event.
    $existing_slug = $wpdb->get_var( $wpdb->prepare(
        "SELECT id FROM {$events_table} WHERE slug = %s AND id != %d",
        $slug, $event_id
    ) );
    if ( $existing_slug ) {
        $slug .= '-' . time();
    }

    // Build the data array for insert/update
    $data = [
        'title'                => $title,
        'slug'                 => $slug,
        'description'          => wp_kses_post( $_POST['event_description'] ?? '' ),
        'category_id'          => ! empty( $_POST['event_category_id'] ) ? (int) $_POST['event_category_id'] : null,
        'status'               => in_array( $_POST['event_status'] ?? '', [ 'scheduled', 'cancelled', 'postponed', 'completed' ], true )
                                  ? $_POST['event_status'] : 'scheduled',
        'event_date'           => sanitize_text_field( $_POST['event_date'] ?? '' ),
        'start_time'           => ! empty( $_POST['event_start_time'] ) ? sanitize_text_field( $_POST['event_start_time'] ) : null,
        'end_time'             => ! empty( $_POST['event_end_time'] ) ? sanitize_text_field( $_POST['event_end_time'] ) : null,
        'location_name'        => sanitize_text_field( $_POST['event_location_name'] ?? '' ),
        'location_address'     => sanitize_textarea_field( $_POST['event_location_address'] ?? '' ),
        'is_virtual'           => ! empty( $_POST['event_is_virtual'] ) ? 1 : 0,
        'virtual_url'          => esc_url_raw( $_POST['event_virtual_url'] ?? '' ),
        'image_id'             => ! empty( $_POST['event_image_id'] ) ? (int) $_POST['event_image_id'] : null,
        'visibility'           => in_array( $_POST['event_visibility'] ?? '', [ 'public', 'members_only' ], true )
                                  ? $_POST['event_visibility'] : 'public',
        'notice_only'          => ! empty( $_POST['event_notice_only'] ) ? 1 : 0,
        'registration_enabled' => ! empty( $_POST['event_registration_enabled'] ) ? 1 : 0,
        'registration_limit'   => ! empty( $_POST['event_registration_limit'] ) ? (int) $_POST['event_registration_limit'] : null,
        'guest_registration'   => ! empty( $_POST['event_guest_registration'] ) ? 1 : 0,
        'member_price'         => ! empty( $_POST['event_member_price'] ) ? number_format( (float) $_POST['event_member_price'], 2, '.', '' ) : '0.00',
        'nonmember_price'      => ! empty( $_POST['event_nonmember_price'] ) ? number_format( (float) $_POST['event_nonmember_price'], 2, '.', '' ) : '0.00',
        'payment_mode'         => in_array( $_POST['event_payment_mode'] ?? '', [ 'none', 'at_door', 'online', 'either' ], true )
                                  ? $_POST['event_payment_mode'] : 'none',
        'price_description'    => sanitize_text_field( $_POST['event_price_description'] ?? '' ),
        'contact_name'         => sanitize_text_field( $_POST['event_contact_name'] ?? '' ),
        'contact_email'        => sanitize_email( $_POST['event_contact_email'] ?? '' ),
        'contact_phone'        => sanitize_text_field( $_POST['event_contact_phone'] ?? '' ),
        // External URL — links this event to an outside website instead of showing
        // a SocietyPress detail page. When set manually, external_source = 'manual'.
        // iCal-imported events use 'ical_feed' and are managed by the sync process —
        // we DON'T overwrite their external_source when saving via the form.
        'external_url'         => ! empty( $_POST['event_external_url'] ) ? esc_url_raw( $_POST['event_external_url'] ) : null,
    ];

    // Determine external_source — preserve 'ical_feed' for events still attached
    // to a feed (editing them in the admin doesn't detach them automatically).
    if ( $event_id > 0 ) {
        $existing_source = $wpdb->get_var( $wpdb->prepare(
            "SELECT external_source FROM {$events_table} WHERE id = %d",
            $event_id
        ) );
        if ( $existing_source === 'ical_feed' ) {
            // Don't change external_source — it's managed by the sync process.
            // Harold can use "Detach from Feed" if he wants to take ownership.
        } else {
            $data['external_source'] = ! empty( $_POST['event_external_url'] ) ? 'manual' : null;
        }
    } else {
        $data['external_source'] = ! empty( $_POST['event_external_url'] ) ? 'manual' : null;
    }

    if ( $event_id > 0 ) {
        // Capture old event data BEFORE updating — we need to compare fields
        // to decide whether to send update/cancellation emails to registrants.
        $old_event = $wpdb->get_row( $wpdb->prepare(
            "SELECT * FROM {$events_table} WHERE id = %d", $event_id
        ) );

        // Update existing event
        $wpdb->update( $events_table, $data, [ 'id' => $event_id ] );

        // Check if we need to notify registrants about changes
        if ( $old_event && $old_event->registration_enabled ) {
            // Event cancelled — notify all confirmed/waitlisted registrants
            if ( $old_event->status === 'scheduled' && $data['status'] === 'cancelled' ) {
                sp_send_event_cancellation_emails( $event_id, $old_event->title );
            }
            // Key details changed (date, time, location) — notify registrants
            elseif ( $data['status'] === 'scheduled' ) {
                $changed_fields = [];
                if ( $old_event->event_date !== $data['event_date'] ) {
                    $changed_fields[] = 'date';
                }
                if ( $old_event->start_time !== $data['start_time'] || $old_event->end_time !== $data['end_time'] ) {
                    $changed_fields[] = 'time';
                }
                if ( $old_event->location_name !== $data['location_name'] || $old_event->location_address !== $data['location_address'] ) {
                    $changed_fields[] = 'location';
                }
                if ( ! empty( $changed_fields ) ) {
                    $new_event = $wpdb->get_row( $wpdb->prepare(
                        "SELECT * FROM {$events_table} WHERE id = %d", $event_id
                    ) );
                    sp_send_event_update_emails( $new_event, $changed_fields );
                }
            }
        }
    } else {
        // Insert new event
        $data['created_by'] = get_current_user_id();
        $wpdb->insert( $events_table, $data );
        $event_id = $wpdb->insert_id;
    }

    // ---- Save speaker assignments ----
    // WHY: Speaker assignments are a many-to-many relationship. We delete all
    //      existing assignments for this event and re-insert from the form data.
    //      This is simpler than tracking individual adds/removes and handles
    //      reordering naturally.
    $assign_table = $wpdb->prefix . 'sp_event_speaker_assignments';
    $wpdb->delete( $assign_table, [ 'event_id' => $event_id ], [ '%d' ] );

    if ( ! empty( $_POST['event_speakers'] ) && is_array( $_POST['event_speakers'] ) ) {
        $sort = 0;
        foreach ( $_POST['event_speakers'] as $speaker_data ) {
            $speaker_id = (int) ( $speaker_data['id'] ?? 0 );
            if ( $speaker_id > 0 ) {
                $role = in_array( $speaker_data['role'] ?? '', [ 'speaker', 'instructor', 'moderator', 'panelist' ], true )
                    ? $speaker_data['role'] : 'speaker';
                $wpdb->insert( $assign_table, [
                    'event_id'   => $event_id,
                    'speaker_id' => $speaker_id,
                    'role'       => $role,
                    'sort_order' => $sort++,
                ] );
            }
        }
    }

    // ---- Save time slots ----
    // WHY: The repeatable slot rows in the form are processed here. We pass
    //      the entire array to sp_slots_save_event() which handles creates,
    //      updates, and soft-deletes for removed rows.
    if ( ! empty( $_POST['event_slots'] ) && is_array( $_POST['event_slots'] ) ) {
        sp_slots_save_event( $event_id, $_POST['event_slots'] );
    } else {
        // No slots submitted — if event had slots before, soft-delete them all
        // (only if this is an existing event, not a new one)
        if ( $event_id > 0 ) {
            $existing_slot_count = $wpdb->get_var( $wpdb->prepare(
                "SELECT COUNT(*) FROM {$wpdb->prefix}sp_event_slots WHERE event_id = %d AND is_active = 1",
                $event_id
            ) );
            if ( (int) $existing_slot_count > 0 ) {
                sp_slots_delete_by_event( $event_id, true );
            }
        }
    }

    // ---- Save recurrence rule ----
    // WHY: If this is a new event or an existing parent event, save the
    //      recurrence rule and end date so "Generate Occurrences" can work.
    $recurrence_type = sanitize_text_field( $_POST['event_recurrence_type'] ?? '' );
    if ( $recurrence_type && ! empty( $data['event_date'] ) ) {
        $event_date_ts = strtotime( $data['event_date'] );
        $rule = '';

        if ( $recurrence_type === 'weekly' ) {
            // weekly:N where N = day of week (0=Sun, 6=Sat)
            $rule = 'weekly:' . date( 'w', $event_date_ts );
        } elseif ( $recurrence_type === 'monthly-nth' ) {
            // monthly-nth:W-D where W = week number (1-5), D = day of week
            $day_of_week = (int) date( 'w', $event_date_ts );
            $day_of_month = (int) date( 'j', $event_date_ts );
            $week_num = (int) ceil( $day_of_month / 7 );
            $rule = 'monthly-nth:' . $week_num . '-' . $day_of_week;
        } elseif ( $recurrence_type === 'monthly-date' ) {
            // monthly-date:D where D = day of month
            $rule = 'monthly-date:' . date( 'j', $event_date_ts );
        }

        if ( $rule ) {
            $end_date = ! empty( $_POST['event_recurrence_end'] )
                ? sanitize_text_field( $_POST['event_recurrence_end'] )
                : date( 'Y-m-d', strtotime( '+12 months', $event_date_ts ) );

            $wpdb->update( $events_table, [
                'recurrence_rule'     => $rule,
                'recurrence_end_date' => $end_date,
            ], [ 'id' => $event_id ] );
        }
    } elseif ( empty( $recurrence_type ) ) {
        // Recurrence was removed — clear the rule but keep existing children
        $wpdb->update( $events_table, [
            'recurrence_rule'     => null,
            'recurrence_end_date' => null,
        ], [ 'id' => $event_id ] );
    }

    // Audit log: event create or update
    $event_title = sanitize_text_field( $_POST['event_title'] ?? '' );
    if ( (int) ( $_POST['event_id'] ?? 0 ) > 0 ) {
        sp_audit( 'event_updated', "Event updated: {$event_title}", 'event', $event_id );
    } else {
        sp_audit( 'event_created', "Event created: {$event_title}", 'event', $event_id );
    }

    // Invalidate iCal feed caches so subscription feeds reflect the change
    // WHY: Without this, calendar apps would get stale data for up to 1 hour
    //      after an event is created or modified.
    delete_transient( 'sp_ical_feed_public' );
    delete_transient( 'sp_ical_feed_members' );

    wp_redirect( admin_url( 'admin.php?page=sp-events&saved=1' ) );
    exit;
});


// ============================================================================
// EVENTS — ADD/EDIT PAGE RENDERER
// ============================================================================
//
// WHY: One form handles both "Add New Event" and "Edit Event." If an event_id
//      is in the URL, we load that event's data and pre-fill the form. If not,
//      we show empty fields with sensible defaults from Settings.
//
// SECTIONS:
//   1. Basic Info     — Title, Category, Status, Description, Featured Image
//   2. Date & Time    — Date, Start Time, End Time
//   3. Location       — Name, Address, Virtual checkbox + URL
//   4. Registration   — Enable toggle, Limit, Guest reg, Visibility, Pricing
//   5. Contact        — Name, Email, Phone
// ============================================================================

// WHY: wp_enqueue_media() must run during admin_enqueue_scripts — NOT inside
//      the page callback. If called during render, the media modal scripts
//      arrive after wp_head() and wp.media is undefined, so the "Select Image"
//      button silently does nothing.
add_action( 'admin_enqueue_scripts', function ( $hook ) {
    if ( strpos( $hook, 'sp-event-edit' ) === false ) {
        return;
    }
    wp_enqueue_media();
});

function sp_render_event_edit_page(): void {
    global $wpdb;

    $event_id = (int) ( $_GET['event_id'] ?? 0 );
    $event    = null;
    $settings = get_option( 'societypress_settings', [] );

    // Load existing event data if editing
    if ( $event_id > 0 ) {
        $event = $wpdb->get_row( $wpdb->prepare(
            "SELECT * FROM {$wpdb->prefix}sp_events WHERE id = %d",
            $event_id
        ) );
        if ( ! $event ) {
            echo '<div class="wrap"><h1>' . esc_html__( 'Event Not Found', 'societypress' ) . '</h1><p>' . esc_html__( 'The requested event does not exist.', 'societypress' ) . '</p></div>';
            return;
        }
    }

    // Helper to get field value: from event if editing, or default
    $val = function ( string $field, $default = '' ) use ( $event ) {
        if ( $event && isset( $event->$field ) ) {
            return $event->$field;
        }
        return $default;
    };

    // Fetch categories for the dropdown
    $categories = $wpdb->get_results(
        "SELECT id, name FROM {$wpdb->prefix}sp_event_categories WHERE active = 1 ORDER BY sort_order"
    );

    $page_title = $event ? 'Edit Event' : 'Add New Event';

    // Default values from settings for new events
    $default_visibility   = $settings['events_default_visibility'] ?? 'public';
    $default_registration = $settings['events_default_registration'] ?? 0;
    $default_guest_reg    = $settings['events_guest_registration'] ?? 0;

    ?>
    <div class="wrap">
        <h1><?php echo esc_html( $page_title ); ?></h1>

        <?php if ( isset( $_GET['duplicated'] ) ) : ?>
            <div class="notice notice-info is-dismissible">
                <p>Event duplicated. Update the details below and save.</p>
            </div>
        <?php endif; ?>

        <?php
        // iCal-imported event notice — warn Harold that manual edits will be
        // overwritten the next time the feed syncs. The "Detach from Feed"
        // button severs the link so the event becomes a standalone local event.
        if ( $event && $event->external_source === 'ical_feed' && ! empty( $event->feed_id ) ) :
            $feed_label = $wpdb->get_var( $wpdb->prepare(
                "SELECT label FROM {$wpdb->prefix}sp_ical_feeds WHERE id = %d",
                $event->feed_id
            ) );
        ?>
