    </div>

    <!-- Event Edit Page JavaScript -->
    <script>
    (function() {
        'use strict';

        // ---- Virtual event toggle: show/hide the meeting URL field ----
        var virtualCheckbox = document.getElementById('event_is_virtual');
        var virtualUrlRow   = document.getElementById('sp-virtual-url-row');
        if (virtualCheckbox && virtualUrlRow) {
            virtualCheckbox.addEventListener('change', function() {
                virtualUrlRow.style.display = this.checked ? '' : 'none';
            });
        }

        // ---- Notice Only toggle: hide registration section when checked ----
        // WHY: Notice-only events don't have registration, pricing, or a detail
        //      page. Hiding the entire registration section when this is checked
        //      prevents confusing field combinations (e.g., notice_only + registration_enabled).
        var noticeCheckbox = document.getElementById('event_notice_only');
        var regSectionHdr  = document.getElementById('sp-registration-section-header');
        var regCheckboxRow = document.getElementById('sp-registration-checkbox-row');
        var regFields      = document.getElementById('sp-registration-fields');
        if (noticeCheckbox) {
            noticeCheckbox.addEventListener('change', function() {
                var hide = this.checked;
                if (regSectionHdr)  regSectionHdr.style.display  = hide ? 'none' : '';
                if (regCheckboxRow) regCheckboxRow.style.display  = hide ? 'none' : '';
                if (regFields)      regFields.style.display       = hide ? 'none' : '';
            });
        }

        // ---- Registration toggle: show/hide registration fields ----
        var regCheckbox = document.getElementById('event_registration_enabled');
        if (regCheckbox && regFields) {
            regCheckbox.addEventListener('change', function() {
                regFields.style.display = this.checked ? '' : 'none';
            });
        }

        // ---- Featured Image picker (uses WordPress Media Library) ----
        // WHY window.load: WordPress media scripts (wp.media) may be enqueued
        //      in the admin footer, which hasn't printed yet when this inline
        //      script runs mid-page. Deferring to window load guarantees all
        //      scripts — head and footer — have finished loading.
        window.addEventListener('load', function() {
            var imageBtn    = document.getElementById('sp-event-image-btn');
            var imageRemove = document.getElementById('sp-event-image-remove');
            var imageInput  = document.getElementById('event_image_id');
            var imagePreview = document.getElementById('sp-event-image-preview');

            if (imageBtn && typeof wp !== 'undefined' && wp.media) {
                var frame;

                imageBtn.addEventListener('click', function(e) {
                    e.preventDefault();

                    if (frame) {
                        frame.open();
                        return;
                    }

                    frame = wp.media({
                        title:    'Select Event Image',
                        button:   { text: 'Use this image' },
                        multiple: false,
                        library:  { type: 'image' }
                    });

                    frame.on('select', function() {
                        var attachment = frame.state().get('selection').first().toJSON();
                        imageInput.value = attachment.id;
                        var url = attachment.sizes && attachment.sizes.medium
                                ? attachment.sizes.medium.url
                                : attachment.url;
                        imagePreview.innerHTML = '<img src="' + url + '" style="max-width: 300px; height: auto; border-radius: 4px;">';
                        imageBtn.textContent = 'Change Image';
                        if (imageRemove) imageRemove.style.display = '';
                    });

                    frame.open();
                });

                if (imageRemove) {
                    imageRemove.addEventListener('click', function(e) {
                        e.preventDefault();
                        imageInput.value = '';
                        imagePreview.innerHTML = '';
                        imageBtn.textContent = 'Select Image';
                        this.style.display = 'none';
                    });
                }
            }
        });

        // ---- Phone number auto-formatting for contact phone ----
        // WHY: Same formatting as everywhere else in SocietyPress — consistent
        //      (XXX) XXX-XXXX pattern. International numbers starting with "+"
        //      are left alone.
        var phoneField = document.getElementById('event_contact_phone');
        if (phoneField) {
            function formatPhone(value) {
                if (!value) return '';
                if (value.charAt(0) === '+') return value;
                var digits = value.replace(/\D/g, '');
                if (digits.length < 4) return digits;
                if (digits.length <= 6) return '(' + digits.substring(0, 3) + ') ' + digits.substring(3);
                if (digits.length > 10) digits = digits.substring(0, 10);
                return '(' + digits.substring(0, 3) + ') ' + digits.substring(3, 6) + '-' + digits.substring(6);
            }

            // Format existing value on page load
            if (phoneField.value) phoneField.value = formatPhone(phoneField.value);

            phoneField.addEventListener('input', function() {
                var pos = this.selectionStart;
                var oldLen = this.value.length;
                var formatted = formatPhone(this.value);
                this.value = formatted;
                var newPos = pos + (formatted.length - oldLen);
                if (newPos < 0) newPos = 0;
                if (newPos > formatted.length) newPos = formatted.length;
                this.setSelectionRange(newPos, newPos);
            });

            // Strip to digits on submit for clean storage
            var form = phoneField.closest('form');
            if (form) {
                form.addEventListener('submit', function() {
                    if (phoneField.value && phoneField.value.charAt(0) !== '+') {
                        phoneField.value = phoneField.value.replace(/\D/g, '');
                    }
                });
            }
        }

        // ---- Time Slot rows: add / remove ----
        // WHY: Same pattern as speaker rows — Harold clicks "+ Add Time Slot"
        //      to clone a template row, and the X button removes a row. The
        //      index counter ensures unique form field names.
        var slotContainer = document.getElementById('sp-event-slots-container');
        var addSlotBtn    = document.getElementById('sp-add-slot-btn');
        var slotTemplate  = document.getElementById('sp-slot-row-template');
        var slotIdx       = document.querySelectorAll('.sp-slot-row').length;

        if (addSlotBtn && slotTemplate && slotContainer) {
            addSlotBtn.addEventListener('click', function() {
                var html = slotTemplate.innerHTML.replace(/__IDX__/g, slotIdx++);
                var temp = document.createElement('div');
                temp.innerHTML = html.trim();
                var row = temp.firstElementChild;
                slotContainer.appendChild(row);
                row.querySelector('.sp-remove-slot').addEventListener('click', function() {
                    row.remove();
                });
            });
        }

        // Remove buttons on existing slot rows
        document.querySelectorAll('.sp-remove-slot').forEach(function(btn) {
            btn.addEventListener('click', function() {
                this.closest('.sp-slot-row').remove();
            });
        });

        // ---- Speaker rows: add / remove ----
        var speakerContainer = document.getElementById('sp-assigned-speakers');
        var addSpeakerBtn    = document.getElementById('sp-add-speaker-btn');
        var speakerTemplate  = document.getElementById('sp-speaker-row-template');
        var speakerIdx       = document.querySelectorAll('.sp-speaker-row').length;

        if (addSpeakerBtn && speakerTemplate && speakerContainer) {
            addSpeakerBtn.addEventListener('click', function() {
                var html = speakerTemplate.innerHTML.replace(/__IDX__/g, speakerIdx++);
                var temp = document.createElement('div');
                temp.innerHTML = html.trim();
                var row = temp.firstElementChild;
                speakerContainer.appendChild(row);
                row.querySelector('.sp-remove-speaker').addEventListener('click', function() {
                    row.remove();
                });
            });
        }

        // Remove buttons on existing speaker rows
        document.querySelectorAll('.sp-remove-speaker').forEach(function(btn) {
            btn.addEventListener('click', function() {
                this.closest('.sp-speaker-row').remove();
            });
        });

        // ---- Recurrence toggle: show/hide end date row ----
        var recurrenceType = document.getElementById('sp-recurrence-type');
        var recurrenceEnd  = document.getElementById('sp-recurrence-end-row');
        if (recurrenceType && recurrenceEnd) {
            recurrenceType.addEventListener('change', function() {
                recurrenceEnd.style.display = this.value ? '' : 'none';
            });
        }

        // ---- Regenerate occurrences (AJAX) ----
        var regenBtn    = document.getElementById('sp-regenerate-occurrences');
        var regenStatus = document.getElementById('sp-regen-status');
        if (regenBtn) {
            regenBtn.addEventListener('click', function() {
                if (!confirm('<?php echo esc_js( __( 'Generate future occurrences? Existing events in the series will not be affected.', 'societypress' ) ); ?>')) return;
                regenBtn.disabled = true;
                regenStatus.textContent = 'Generating\u2026';

                var fd = new FormData();
                fd.append('action', 'sp_regenerate_occurrences');
                fd.append('event_id', regenBtn.getAttribute('data-event-id'));
                fd.append('nonce', '<?php echo wp_create_nonce( "sp_recurrence" ); ?>');

                fetch('<?php echo admin_url( "admin-ajax.php" ); ?>', { method: 'POST', body: fd, credentials: 'same-origin' })
                    .then(function(r) { return r.json(); })
                    .then(function(data) {
                        regenBtn.disabled = false;
                        regenStatus.textContent = data.success
                            ? data.data.created + ' new occurrence(s) created.'
                            : (data.data || 'Error generating occurrences.');
                    })
                    .catch(function() {
                        regenBtn.disabled = false;
                        regenStatus.textContent = 'Something went wrong.';
                    });
            });
        }

        // ---- Detach from series (AJAX) ----
        var detachBtn = document.getElementById('sp-detach-from-series');
        if (detachBtn) {
            detachBtn.addEventListener('click', function() {
                if (!confirm('<?php echo esc_js( __( 'Detach this event from its recurring series? This cannot be undone.', 'societypress' ) ); ?>')) return;
                detachBtn.disabled = true;

                var fd = new FormData();
                fd.append('action', 'sp_detach_from_series');
                fd.append('event_id', detachBtn.getAttribute('data-event-id'));
                fd.append('nonce', '<?php echo wp_create_nonce( "sp_recurrence" ); ?>');

                fetch('<?php echo admin_url( "admin-ajax.php" ); ?>', { method: 'POST', body: fd, credentials: 'same-origin' })
                    .then(function(r) { return r.json(); })
                    .then(function(data) {
                        if (data.success) {
                            location.reload();
                        } else {
                            alert(data.data || 'Could not detach.');
                            detachBtn.disabled = false;
                        }
                    });
            });
        }

        // ---- Detach from iCal feed (AJAX) ----
        // WHY: When an event was imported from an iCal feed, Harold may want to
        //      edit it without future syncs overwriting his changes. This button
        //      clears the feed_id and external_source so the event becomes standalone.
        var detachFeedBtn = document.getElementById('sp-detach-from-feed');
        if (detachFeedBtn) {
            detachFeedBtn.addEventListener('click', function() {
                if (!confirm('<?php echo esc_js( __( 'Detach this event from its iCal feed? It will become a standalone event and won\'t be updated by future syncs.', 'societypress' ) ); ?>')) return;
                detachFeedBtn.disabled = true;
                detachFeedBtn.textContent = '<?php echo esc_js( __( 'Detaching...', 'societypress' ) ); ?>';

                var fd = new FormData();
                fd.append('action', 'sp_detach_event_from_feed');
                fd.append('event_id', detachFeedBtn.getAttribute('data-event-id'));
                fd.append('_wpnonce', detachFeedBtn.getAttribute('data-nonce'));

                fetch('<?php echo admin_url( "admin-ajax.php" ); ?>', { method: 'POST', body: fd, credentials: 'same-origin' })
                    .then(function(r) { return r.json(); })
                    .then(function(data) {
                        if (data.success) {
                            location.reload();
                        } else {
                            alert(data.data || '<?php echo esc_js( __( 'Could not detach.', 'societypress' ) ); ?>');
                            detachFeedBtn.disabled = false;
                            detachFeedBtn.textContent = '<?php echo esc_js( __( 'Detach from Feed', 'societypress' ) ); ?>';
                        }
                    });
            });
        }

    })();
    </script>
    <?php
}


// ============================================================================
// EVENT CATEGORIES — ADMIN PAGE (CRUD)
// ============================================================================
//
// WHY: Harold needs to manage event categories — add new ones, change colors,
//      reorder them, deactivate categories that are no longer used. This page
//      provides an inline add/edit interface (no separate edit page needed)
//      that saves via AJAX for a snappy experience.
//
// DESIGN: A simple table with inline editing. Each row has the category name,
//         color picker, sort order, and active toggle. New categories are added
//         via a form at the top. Existing categories can be edited inline.
//         All saves go through AJAX handlers registered below.
// ============================================================================

