// ============================================================================
// EVENTS — FRONTEND PAGE TEMPLATE REGISTRATION
// ============================================================================
//
// WHY: Same pattern as the Membership Directory. We register an "Events"
//      page template that Harold selects from the Template dropdown when
//      editing a page. WordPress handles showing it in the dropdown; we
//      handle rendering when it's loaded on the frontend.
//
// TWO VIEWS on one page:
//   - List View (default): Event cards with search, filters, pagination
//   - Calendar View (toggle): Month grid with color-coded event dots
//
// DETAIL PAGE:
//   Uses a query var (?sp_event=slug) on the same page to show a single
//   event's full details. This avoids creating a custom post type or
//   rewrite rules — keeps everything in one place.
// ============================================================================

/**
 * Register the "Events" page template.
 */
add_filter( 'theme_page_templates', function ( $templates ) {
    $templates['sp-events'] = 'Events';
    return $templates;
});

/**
 * Register the sp_event query var so WordPress doesn't strip it.
 *
 * WHY: WordPress ignores query vars it doesn't know about. We need
 *      ?sp_event=slug to work on the events page for detail views.
 */
add_filter( 'query_vars', function ( $vars ) {
    $vars[] = 'sp_event';
    // WHY: sp_ical_feed is used by the calendar subscription feed handler.
    //      Without registering it, WordPress strips it from the URL and the
    //      feed handler never fires.
    $vars[] = 'sp_ical_feed';
    return $vars;
});

/**
 * Intercept the template load for the Events page and render our content.
 */
add_filter( 'template_include', function ( $template ) {

    if ( is_page() && get_page_template_slug() === 'sp-events' ) {

        $settings = get_option( 'societypress_settings', [] );

        // Enqueue our events styles and scripts
        add_action( 'wp_head', 'sp_events_frontend_styles' );
        add_action( 'wp_footer', 'sp_events_frontend_scripts' );

        get_header();

        echo '<div class="sp-events-wrap">';

        // Check if we're viewing a single event detail page
        $event_slug = get_query_var( 'sp_event', '' );

        if ( ! empty( $event_slug ) ) {
            sp_render_event_detail( $event_slug, $settings );
        } else {
            sp_render_events_listing( $settings );
        }

        echo '</div>';

        get_footer();

        return sp_get_blank_template_path();
    }

    return $template;
});


// ============================================================================
// EVENTS — STANDALONE CALENDAR PAGE TEMPLATE
// ============================================================================

/**
 * Register the "Calendar" page template.
 *
 * WHY: Harold might want a dedicated calendar page separate from the events
 *      listing — no list view, no search/filter bar, just a clean monthly
 *      calendar grid. This shows up in the Template dropdown in the page editor.
 */
add_filter( 'theme_page_templates', function ( $templates ) {
    $templates['sp-calendar'] = __( 'Calendar', 'societypress' );
    return $templates;
});

/**
 * Register sp_cal_cat query var for the calendar category filter.
 *
 * WHY: The standalone calendar template has a category filter dropdown that
 *      uses ?sp_cal_cat=ID in the URL. WordPress strips unknown query vars,
 *      so we need to register it.
 */
add_filter( 'query_vars', function ( $vars ) {
    $vars[] = 'sp_cal_cat';
    return $vars;
});

/**
 * Intercept the template load for the Calendar page and render the grid.
 *
 * WHY: Since sp-calendar isn't a physical theme file, WordPress would 404.
 *      We catch it here, render the calendar with the theme's header/footer,
 *      and return a blank template so WordPress doesn't try to load anything.
 */
add_filter( 'template_include', function ( $template ) {

    if ( ! is_page() || get_page_template_slug() !== 'sp-calendar' ) {
        return $template;
    }

    // Output calendar CSS and queue JS for footer
    add_action( 'wp_head', 'sp_events_calendar_styles' );
    add_action( 'wp_footer', 'sp_events_calendar_scripts', 50 );

    get_header();

    global $wpdb;
    $base_url = get_permalink();
    $page_title = get_the_title();

    // Category filter from query param
    $cat_filter = absint( get_query_var( 'sp_cal_cat', 0 ) );

    // Fetch active event categories for the filter dropdown
    $categories = $wpdb->get_results(
        "SELECT id, name FROM {$wpdb->prefix}sp_event_categories WHERE active = 1 ORDER BY sort_order, name"
    );

    echo '<div class="site-content"><div class="content-area-full" style="max-width:var(--sp-content-width,1100px); margin:0 auto; padding:40px 20px;">';

    // Page heading
    echo '<h1 style="margin:0 0 24px; font-size:28px; font-weight:700; color:#1d2327;">'
         . esc_html( $page_title ) . '</h1>';

    // Category filter bar — only show if there are categories to filter by
    if ( ! empty( $categories ) ) {
        echo '<form method="get" action="' . esc_url( $base_url ) . '" style="margin-bottom:20px; display:flex; gap:8px; align-items:center; flex-wrap:wrap;">';

        // Preserve the current month if set
        $current_cal_month = isset( $_GET['sp_cal_month'] ) ? sanitize_text_field( $_GET['sp_cal_month'] ) : '';
        if ( $current_cal_month && preg_match( '/^\d{4}-\d{2}$/', $current_cal_month ) ) {
            echo '<input type="hidden" name="sp_cal_month" value="' . esc_attr( $current_cal_month ) . '">';
        }

        echo '<select name="sp_cal_cat" style="padding:8px 12px; border:1px solid #ddd; border-radius:6px; font-size:14px;">';
        echo '<option value="0">' . esc_html__( 'All Categories', 'societypress' ) . '</option>';
        foreach ( $categories as $cat ) {
            echo '<option value="' . esc_attr( $cat->id ) . '"' . selected( $cat_filter, (int) $cat->id, false ) . '>'
                 . esc_html( $cat->name ) . '</option>';
        }
        echo '</select>';
        echo '<button type="submit" style="padding:8px 16px; background:var(--sp-color-primary,#1e3a5f); color:#fff; border:none; border-radius:6px; font-size:14px; cursor:pointer;">'
             . esc_html__( 'Filter', 'societypress' ) . '</button>';

        if ( $cat_filter > 0 ) {
            echo '<a href="' . esc_url( $base_url ) . '" style="font-size:14px; color:#666; text-decoration:none;">'
                 . esc_html__( 'Clear', 'societypress' ) . '</a>';
        }
        // Add subscribe dropdown inline with the filter form
        sp_render_subscribe_dropdown( 'calendar' );

        echo '</form>';
    } else {
        // No categories, but still show the subscribe button
        sp_render_subscribe_dropdown( 'calendar' );
    }

    // Extra args to preserve in calendar nav links
    $extra_args = [];
    if ( $cat_filter > 0 ) {
        $extra_args['sp_cal_cat'] = $cat_filter;
    }

    // Render the shared calendar grid
    sp_render_calendar_grid( $cat_filter, $base_url, $extra_args );

    echo '</div></div>';

    get_footer();

    return sp_get_blank_template_path();
});


// ============================================================================
// EVENTS — SHARED CALENDAR GRID RENDERER
// ============================================================================

/**
 * Render a monthly calendar grid with event pills, mobile dots, and nav.
 *
 * WHY: The calendar grid is used in three places — the events listing page
 *      (calendar view toggle), the Page Builder "Events Calendar" widget,
 *      and the standalone "Calendar" page template. Centralizing the
 *      rendering here keeps one source of truth: same HTML structure, same
 *      mobile behavior, same category-colored pills everywhere.
 *
 * @param int    $category_id  Optional category filter (0 = all).
 * @param string $base_url     The page URL for nav links and event detail links.
 * @param array  $extra_args   Extra query args to preserve in nav links (e.g., sp_view, sp_cat).
 */
function sp_render_calendar_grid( int $category_id = 0, string $base_url = '', array $extra_args = [] ): void {
    global $wpdb;

    $settings    = get_option( 'societypress_settings', [] );
    $events_table = $wpdb->prefix . 'sp_events';
    $cats_table   = $wpdb->prefix . 'sp_event_categories';

    if ( empty( $base_url ) ) {
        $base_url = get_permalink();
    }

    // ---- Determine which month to display ----
    // WHY: The sp_cal_month query param lets users navigate months via
    //      prev/next links. Default to current month if not set or invalid.
    $cal_month = isset( $_GET['sp_cal_month'] ) ? sanitize_text_field( $_GET['sp_cal_month'] ) : date( 'Y-m' );
    if ( ! preg_match( '/^\d{4}-\d{2}$/', $cal_month ) ) {
        $cal_month = date( 'Y-m' );
    }

    $cal_year    = (int) substr( $cal_month, 0, 4 );
    $cal_mon     = (int) substr( $cal_month, 5, 2 );
    $days_in     = (int) date( 't', mktime( 0, 0, 0, $cal_mon, 1, $cal_year ) );
    $first_dow   = (int) date( 'w', mktime( 0, 0, 0, $cal_mon, 1, $cal_year ) ); // 0=Sun
    $month_label = wp_date( 'F Y', mktime( 0, 0, 0, $cal_mon, 1, $cal_year ) );

    // ---- Start day of week (Sunday or Monday) ----
    $start_day  = (int) ( $settings['events_calendar_start_day'] ?? 0 );
    $day_names  = $start_day === 1
                ? [ 'Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat', 'Sun' ]
                : [ 'Sun', 'Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat' ];

    // Adjust first day of week offset for Monday start
    if ( $start_day === 1 ) {
        $first_offset = ( $first_dow === 0 ) ? 6 : $first_dow - 1;
    } else {
        $first_offset = $first_dow;
    }

    // ---- Fetch events for this month ----
    $month_start = sprintf( '%04d-%02d-01', $cal_year, $cal_mon );
    $month_end   = sprintf( '%04d-%02d-%02d', $cal_year, $cal_mon, $days_in );

    $cal_where  = [ "e.status != 'cancelled'", "e.event_date >= %s", "e.event_date <= %s" ];
    $cal_params = [ $month_start, $month_end ];

    if ( $category_id > 0 ) {
        $cal_where[]  = 'e.category_id = %d';
        $cal_params[] = $category_id;
    }

    if ( ! is_user_logged_in() ) {
        $cal_where[] = "e.visibility = 'public'";
    }

    $cal_sql = "SELECT e.id, e.title, e.slug, e.event_date, e.start_time,
                       e.notice_only, e.external_url,
                       c.name AS category_name, c.color AS category_color
                FROM {$events_table} e
                LEFT JOIN {$cats_table} c ON e.category_id = c.id
                WHERE " . implode( ' AND ', $cal_where ) . "
                ORDER BY e.event_date ASC, e.start_time ASC";
    $cal_events = $wpdb->get_results( $wpdb->prepare( $cal_sql, ...$cal_params ) );

    // ---- Build day → events lookup ----
    $events_by_day = [];
    foreach ( $cal_events as $ce ) {
        $day = (int) substr( $ce->event_date, 8, 2 );
        $events_by_day[ $day ][] = $ce;
    }

    $today_str = current_time( 'Y-m-d' );

    // ---- Find the events listing page for detail links ----
    // WHY: Event pills link to the event detail page (?sp_event=slug) on
    //      whichever page uses the sp-events template. If no events page
    //      exists, pills still show but without links.
    $events_page_url = '';
    $events_pages = get_pages( [ 'meta_key' => '_wp_page_template', 'meta_value' => 'sp-events' ] );
    if ( ! empty( $events_pages ) ) {
        $events_page_url = get_permalink( $events_pages[0]->ID );
    }

    // ---- Prev/Next month links ----
    $prev_month = date( 'Y-m', mktime( 0, 0, 0, $cal_mon - 1, 1, $cal_year ) );
    $next_month = date( 'Y-m', mktime( 0, 0, 0, $cal_mon + 1, 1, $cal_year ) );
    $cal_nav_args = $extra_args;
    $cal_nav_args['sp_cal_month'] = $prev_month;
    $prev_url = add_query_arg( $cal_nav_args, $base_url );
    $cal_nav_args['sp_cal_month'] = $next_month;
    $next_url = add_query_arg( $cal_nav_args, $base_url );

    ?>
    <div class="sp-calendar-wrap">
        <!-- Calendar Navigation -->
        <div class="sp-calendar-nav">
            <a href="<?php echo esc_url( $prev_url ); ?>"
               class="sp-cal-nav-btn">&laquo; <?php echo esc_html__( 'Prev', 'societypress' ); ?></a>
            <h2 class="sp-cal-month-label"><?php echo esc_html( $month_label ); ?></h2>
            <a href="<?php echo esc_url( $next_url ); ?>"
               class="sp-cal-nav-btn"><?php echo esc_html__( 'Next', 'societypress' ); ?> &raquo;</a>
        </div>

        <!-- Calendar Grid -->
        <div class="sp-calendar-grid">
            <!-- Day headers -->
            <?php foreach ( $day_names as $dn ) : ?>
                <div class="sp-cal-header"><?php echo esc_html( $dn ); ?></div>
            <?php endforeach; ?>

            <!-- Empty cells before first day -->
            <?php for ( $i = 0; $i < $first_offset; $i++ ) : ?>
                <div class="sp-cal-day sp-cal-empty"></div>
            <?php endfor; ?>

            <!-- Day cells -->
            <?php for ( $d = 1; $d <= $days_in; $d++ ) :
                $date_str  = sprintf( '%04d-%02d-%02d', $cal_year, $cal_mon, $d );
                $is_today  = ( $date_str === $today_str );
                $has_events = isset( $events_by_day[ $d ] );
                $day_class = 'sp-cal-day';
                if ( $is_today ) $day_class .= ' sp-cal-today';
                if ( $has_events ) $day_class .= ' sp-cal-has-events';
            ?>
                <div class="<?php echo $day_class; ?>">
                    <div class="sp-cal-day-num"><?php echo $d; ?></div>
                    <?php if ( $has_events ) : ?>
                        <div class="sp-cal-events">
                            <?php foreach ( $events_by_day[ $d ] as $ce ) :
                                // Notice-only events never link to a detail page —
                                // they're informational entries (holidays, board meetings, etc.)
                                $is_notice = ! empty( $ce->notice_only );
                                // External events link to the external URL instead of the
                                // internal detail page — the event lives on another site.
                                $is_external = ! empty( $ce->external_url );
                                if ( $is_external ) {
                                    $detail_url = $ce->external_url;
                                } elseif ( ! $is_notice && $events_page_url ) {
                                    $detail_url = add_query_arg( 'sp_event', $ce->slug, $events_page_url );
                                } else {
                                    $detail_url = '';
                                }
                                $color = $ce->category_color ?: '#2271b1';
                                $notice_class = $is_notice ? ' sp-cal-event--notice' : '';
                                $external_class = $is_external ? ' sp-cal-event--external' : '';
                                // External links open in a new tab so users don't leave the calendar
                                $link_target = $is_external ? ' target="_blank" rel="noopener"' : '';
                            ?>
                                <?php if ( $detail_url ) : ?>
                                <a href="<?php echo esc_url( $detail_url ); ?>"
                                   class="sp-cal-event<?php echo $notice_class . $external_class; ?>"
                                   style="background: <?php echo esc_attr( $color ); ?>;"
                                   title="<?php echo esc_attr( $ce->title ); ?>"<?php echo $link_target; ?>>
                                    <span class="sp-cal-event-title"><?php echo esc_html( $ce->title ); ?><?php if ( $is_external ) echo ' &#8599;'; ?></span>
                                    <?php if ( $ce->start_time ) : ?>
                                        <span class="sp-cal-event-time"><?php echo esc_html( wp_date( 'g:iA', strtotime( $ce->start_time ) ) ); ?></span>
                                    <?php endif; ?>
                                </a>
                                <?php else : ?>
                                <span class="sp-cal-event<?php echo $notice_class; ?>"
                                      style="background: <?php echo esc_attr( $color ); ?>;"
                                      title="<?php echo esc_attr( $ce->title ); ?>">
                                    <span class="sp-cal-event-title"><?php echo esc_html( $ce->title ); ?></span>
                                    <?php if ( $ce->start_time ) : ?>
                                        <span class="sp-cal-event-time"><?php echo esc_html( wp_date( 'g:iA', strtotime( $ce->start_time ) ) ); ?></span>
                                    <?php endif; ?>
                                </span>
                                <?php endif; ?>
                            <?php endforeach; ?>
                        </div>
                        <!-- Mobile: dots instead of full titles -->
                        <div class="sp-cal-dots">
                            <?php foreach ( $events_by_day[ $d ] as $ce ) :
                                $color = $ce->category_color ?: '#2271b1';
                            ?>
                                <span class="sp-cal-dot" style="background: <?php echo esc_attr( $color ); ?>;"></span>
                            <?php endforeach; ?>
                        </div>
                    <?php endif; ?>
                </div>
            <?php endfor; ?>

            <!-- Empty cells after last day to fill the row -->
            <?php
            $total_cells = $first_offset + $days_in;
            $remainder   = $total_cells % 7;
            if ( $remainder > 0 ) :
                for ( $i = 0; $i < ( 7 - $remainder ); $i++ ) :
            ?>
                <div class="sp-cal-day sp-cal-empty"></div>
            <?php endfor; endif; ?>
        </div>

        <!-- Mobile: expanded day panel (populated by JS on tap) -->
        <div class="sp-cal-mobile-panel" id="sp-cal-mobile-panel" style="display: none;">
            <div class="sp-cal-mobile-panel-header">
                <span id="sp-cal-mobile-date"></span>
                <button type="button" class="sp-cal-mobile-close" id="sp-cal-mobile-close">&times;</button>
            </div>
            <div id="sp-cal-mobile-events"></div>
        </div>
    </div>
    <?php
}


// ============================================================================
// EVENTS — SUBSCRIBE TO CALENDAR UI (shared renderer)
// ============================================================================

/**
 * Render the "Subscribe to Calendar" dropdown button.
 *
 * WHY: This widget appears on the events listing, calendar page, and event
 *      detail pages. Rather than duplicating the HTML in three places, we
 *      centralize it here. The dropdown shows a webcal:// one-click subscribe
 *      link, a copyable URL for Google Calendar (which doesn't support webcal),
 *      and — if the user is logged in — a members-only feed URL that includes
 *      their personal token.
 *
 * @param string $context   Where this is being rendered: 'listing', 'calendar', or 'detail'.
 *                          Controls minor layout variations.
 */
function sp_render_subscribe_dropdown( string $context = 'listing' ): void {
    $settings = get_option( 'societypress_settings', [] );

    // Don't render anything if the feed is disabled (defaults to enabled)
    if ( empty( $settings['events_ical_feed_enabled'] ?? 1 ) ) return;

    // Output shared CSS/JS once, even if this function is called multiple times
    // WHY: This function can appear on the events listing, calendar page, and
    //      event detail page. Using a static flag prevents duplicate style/script
    //      blocks when multiple instances exist on the same page.
    static $assets_output = false;
    if ( ! $assets_output ) {
        $assets_output = true;
        add_action( 'wp_footer', 'sp_ical_subscribe_scripts', 99 );
    }

    // Build the public feed URLs
    $public_url    = home_url( '?sp_ical_feed=public' );
    $webcal_url    = str_replace( [ 'https://', 'http://' ], 'webcal://', $public_url );
    $members_url   = '';
    $members_webcal = '';
    $nonce         = '';

    // If the user is logged in, build their personalized members-only feed URL
    if ( is_user_logged_in() ) {
        $token          = sp_get_or_create_ical_token( get_current_user_id() );
        $members_url    = home_url( '?sp_ical_feed=' . $token );
        $members_webcal = str_replace( [ 'https://', 'http://' ], 'webcal://', $members_url );
        $nonce          = wp_create_nonce( 'sp_ical_token' );
    }

    // Unique ID suffix so multiple instances on one page don't clash
    $uid = 'sp-ical-' . $context;

    ?>
    <div class="sp-ical-subscribe-wrap" id="<?php echo esc_attr( $uid ); ?>">
        <button type="button" class="sp-ical-subscribe-btn" aria-expanded="false"
                aria-controls="<?php echo esc_attr( $uid ); ?>-dropdown">
            <span class="sp-ical-icon">&#128197;</span>
            <?php esc_html_e( 'Subscribe', 'societypress' ); ?>
            <span class="sp-ical-caret">&#9660;</span>
        </button>

        <div class="sp-ical-dropdown" id="<?php echo esc_attr( $uid ); ?>-dropdown" style="display:none;">
            <!-- Public feed -->
            <div class="sp-ical-section">
                <div class="sp-ical-section-label"><?php esc_html_e( 'Public Events', 'societypress' ); ?></div>
                <a href="<?php echo esc_url( $webcal_url ); ?>" class="sp-ical-action-link">
                    <?php esc_html_e( 'Subscribe in Calendar App', 'societypress' ); ?>
                </a>
                <div class="sp-ical-copy-row">
                    <input type="text" readonly value="<?php echo esc_url( $public_url ); ?>"
                           class="sp-ical-url-input" aria-label="<?php esc_attr_e( 'Public calendar feed URL', 'societypress' ); ?>">
                    <button type="button" class="sp-ical-copy-btn" data-url="<?php echo esc_url( $public_url ); ?>">
                        <?php esc_html_e( 'Copy', 'societypress' ); ?>
                    </button>
                </div>
                <div class="sp-ical-hint"><?php esc_html_e( 'For Google Calendar, copy the URL and paste it under "Other calendars > From URL."', 'societypress' ); ?></div>
            </div>

            <?php if ( $members_url ) : ?>
            <!-- Members-only feed — only shown to logged-in users -->
            <div class="sp-ical-section sp-ical-members-section">
                <div class="sp-ical-section-label"><?php esc_html_e( 'All Events (Including Members-Only)', 'societypress' ); ?></div>
                <a href="<?php echo esc_url( $members_webcal ); ?>" class="sp-ical-action-link">
                    <?php esc_html_e( 'Subscribe in Calendar App', 'societypress' ); ?>
                </a>
                <div class="sp-ical-copy-row">
                    <input type="text" readonly value="<?php echo esc_url( $members_url ); ?>"
                           class="sp-ical-url-input sp-ical-members-url"
                           aria-label="<?php esc_attr_e( 'Members-only calendar feed URL', 'societypress' ); ?>">
                    <button type="button" class="sp-ical-copy-btn" data-url="<?php echo esc_url( $members_url ); ?>">
                        <?php esc_html_e( 'Copy', 'societypress' ); ?>
                    </button>
                </div>
                <div class="sp-ical-hint"><?php esc_html_e( 'This URL is personal to you. Do not share it.', 'societypress' ); ?></div>
                <button type="button" class="sp-ical-regen-btn"
                        data-nonce="<?php echo esc_attr( $nonce ); ?>"
                        data-ajax-url="<?php echo esc_url( admin_url( 'admin-ajax.php' ) ); ?>">
                    <?php esc_html_e( 'Regenerate URL', 'societypress' ); ?>
                </button>
            </div>
            <?php endif; ?>
        </div>
    </div>
    <?php
}


// ============================================================================
// EVENTS — SUBSCRIBE UI: FOOTER SCRIPTS
// ============================================================================

/**
 * Output vanilla JS for the subscribe dropdown behavior.
 *
 * WHY: This runs in wp_footer so all the dropdown HTML has been rendered.
 *      Handles toggle open/close, click-away, copy-to-clipboard with feedback,
 *      and AJAX token regeneration for member feeds.
 */
function sp_ical_subscribe_scripts(): void {
    ?>
    <script id="sp-ical-subscribe-js">
    (function() {
        'use strict';

        // ---- Toggle dropdown open/close ----
        // WHY: Each subscribe button toggles its own dropdown. We use event
        //      delegation on the document so dynamically-added buttons work too.
        document.addEventListener('click', function(e) {
            var btn = e.target.closest('.sp-ical-subscribe-btn');
            if (btn) {
                e.preventDefault();
                e.stopPropagation();
                var wrap     = btn.closest('.sp-ical-subscribe-wrap');
                var dropdown = wrap.querySelector('.sp-ical-dropdown');
                var isOpen   = dropdown.style.display !== 'none';

                // Close all other open dropdowns first
                document.querySelectorAll('.sp-ical-dropdown').forEach(function(dd) {
                    dd.style.display = 'none';
                    var ddBtn = dd.closest('.sp-ical-subscribe-wrap').querySelector('.sp-ical-subscribe-btn');
                    if (ddBtn) ddBtn.setAttribute('aria-expanded', 'false');
                });

                if (!isOpen) {
                    dropdown.style.display = 'block';
                    btn.setAttribute('aria-expanded', 'true');
                }
                return;
            }

            // ---- Copy URL to clipboard ----
            var copyBtn = e.target.closest('.sp-ical-copy-btn');
            if (copyBtn) {
                e.preventDefault();
                var url = copyBtn.getAttribute('data-url');
                if (navigator.clipboard && navigator.clipboard.writeText) {
                    navigator.clipboard.writeText(url).then(function() {
                        spIcalShowCopied(copyBtn);
                    });
                } else {
                    // Fallback for older browsers — use a temporary textarea
                    var ta = document.createElement('textarea');
                    ta.value = url;
                    ta.style.position = 'fixed';
                    ta.style.opacity = '0';
                    document.body.appendChild(ta);
                    ta.select();
                    document.execCommand('copy');
                    document.body.removeChild(ta);
                    spIcalShowCopied(copyBtn);
                }
                return;
            }

            // ---- Regenerate token ----
            var regenBtn = e.target.closest('.sp-ical-regen-btn');
            if (regenBtn) {
                e.preventDefault();
                var nonce   = regenBtn.getAttribute('data-nonce');
                var ajaxUrl = regenBtn.getAttribute('data-ajax-url');
                var section = regenBtn.closest('.sp-ical-members-section');

                regenBtn.disabled = true;
                regenBtn.textContent = '<?php echo esc_js( __( 'Regenerating...', 'societypress' ) ); ?>';

                var fd = new FormData();
                fd.append('action', 'sp_regenerate_ical_token');
                fd.append('nonce', nonce);

                fetch(ajaxUrl, { method: 'POST', body: fd, credentials: 'same-origin' })
                    .then(function(r) { return r.json(); })
                    .then(function(data) {
                        if (data.success) {
                            // Update ALL member URL inputs on the page (there may be
                            // multiple subscribe dropdowns)
                            document.querySelectorAll('.sp-ical-members-url').forEach(function(input) {
                                input.value = data.data.url;
                            });
                            // Update the copy button data-url attribute
                            if (section) {
                                var copyBtnInner = section.querySelector('.sp-ical-copy-btn');
                                if (copyBtnInner) copyBtnInner.setAttribute('data-url', data.data.url);
                            }
                            // Update webcal link
                            if (section) {
                                var webcalLink = section.querySelector('.sp-ical-action-link');
                                if (webcalLink) {
                                    webcalLink.href = data.data.url.replace(/^https?:\/\//, 'webcal://');
                                }
                            }
                            regenBtn.textContent = '<?php echo esc_js( __( 'Done! URL updated.', 'societypress' ) ); ?>';
                            setTimeout(function() {
                                regenBtn.textContent = '<?php echo esc_js( __( 'Regenerate URL', 'societypress' ) ); ?>';
                                regenBtn.disabled = false;
                            }, 3000);
                        } else {
                            regenBtn.textContent = '<?php echo esc_js( __( 'Error — try again', 'societypress' ) ); ?>';
                            regenBtn.disabled = false;
                        }
                    })
                    .catch(function() {
                        regenBtn.textContent = '<?php echo esc_js( __( 'Error — try again', 'societypress' ) ); ?>';
                        regenBtn.disabled = false;
                    });
                return;
            }

            // ---- Click-away to close all dropdowns ----
            // WHY: If the click wasn't on a subscribe button, copy button, or regen
            //      button, and it wasn't inside a dropdown, close everything.
            if (!e.target.closest('.sp-ical-dropdown')) {
                document.querySelectorAll('.sp-ical-dropdown').forEach(function(dd) {
                    dd.style.display = 'none';
                    var ddBtn = dd.closest('.sp-ical-subscribe-wrap').querySelector('.sp-ical-subscribe-btn');
                    if (ddBtn) ddBtn.setAttribute('aria-expanded', 'false');
                });
            }
        });

        // Show "Copied!" feedback on a copy button, then revert
        function spIcalShowCopied(btn) {
            var original = btn.textContent;
            btn.textContent = '<?php echo esc_js( __( 'Copied!', 'societypress' ) ); ?>';
            btn.classList.add('sp-ical-copied');
            setTimeout(function() {
                btn.textContent = original;
                btn.classList.remove('sp-ical-copied');
            }, 2000);
        }
    })();
    </script>
    <?php
}


// ============================================================================
// EVENTS — FRONTEND LISTING (List View + Calendar View)
// ============================================================================

/**
 * Render the events listing page — filters, search, list/calendar toggle,
 * event cards, and pagination.
 *
 * WHY: This is the public-facing events page that members and visitors see.
 *      It needs to be clean, scannable, and easy for octogenarians to use.
 *      Event cards show the most important info at a glance: date, title,
 *      time, location, and category. Clicking an event goes to the detail page.
 *
 * @param array $settings The societypress_settings option array.
 */
function sp_render_events_listing( array $settings ): void {
    global $wpdb;

    $events_table = $wpdb->prefix . 'sp_events';
    $cats_table   = $wpdb->prefix . 'sp_event_categories';
    $reg_table    = $wpdb->prefix . 'sp_event_registrations';
    $per_page     = (int) ( $settings['events_per_page'] ?? 12 );
    $base_url     = get_permalink();

    // ---- Collect filter parameters from the URL ----
    $search     = isset( $_GET['sp_search'] ) ? sanitize_text_field( wp_unslash( $_GET['sp_search'] ) ) : '';
    $cat_filter = isset( $_GET['sp_cat'] ) ? (int) $_GET['sp_cat'] : 0;
    $timeframe  = isset( $_GET['sp_time'] ) ? sanitize_text_field( $_GET['sp_time'] ) : '12months';
    $view       = isset( $_GET['sp_view'] ) ? sanitize_text_field( $_GET['sp_view'] ) : 'list';

    // ---- Build the WHERE clause ----
    $where  = [ "e.status != 'cancelled'" ];
    $params = [];

    // Notice-only events appear on the calendar but not in the list view.
    // WHY: They're informational — holidays, board meetings — and have no detail
    //      page, no description, no registration. Showing them in the list would
    //      just create dead-end cards members can't click into.
    $where[] = "(e.notice_only = 0 OR e.notice_only IS NULL)";

    // Visibility filter — hide members_only events from non-logged-in visitors
    if ( ! is_user_logged_in() ) {
        $where[] = "e.visibility = 'public'";
    }

    // Search
    if ( $search !== '' ) {
        $like     = '%' . $wpdb->esc_like( $search ) . '%';
        $where[]  = "(e.title LIKE %s OR e.description LIKE %s OR e.location_name LIKE %s)";
        $params[] = $like;
        $params[] = $like;
        $params[] = $like;
    }

    // Category filter
    if ( $cat_filter > 0 ) {
        $where[]  = "e.category_id = %d";
        $params[] = $cat_filter;
    }

    // Timeframe filter
    $today = current_time( 'Y-m-d' );
    switch ( $timeframe ) {
        case '30days':
            $where[]  = "e.event_date >= %s AND e.event_date <= %s";
            $params[] = $today;
            $params[] = date( 'Y-m-d', strtotime( '+30 days' ) );
            break;
        case '3months':
            $where[]  = "e.event_date >= %s AND e.event_date <= %s";
            $params[] = $today;
            $params[] = date( 'Y-m-d', strtotime( '+3 months' ) );
            break;
        case '6months':
            $where[]  = "e.event_date >= %s AND e.event_date <= %s";
            $params[] = $today;
            $params[] = date( 'Y-m-d', strtotime( '+6 months' ) );
            break;
        case '12months':
            $where[]  = "e.event_date >= %s AND e.event_date <= %s";
            $params[] = $today;
            $params[] = date( 'Y-m-d', strtotime( '+12 months' ) );
            break;
        case 'all':
            $where[]  = "e.event_date >= %s";
            $params[] = $today;
            break;
        case 'past':
            $where[]  = "e.event_date < %s";
            $params[] = $today;
            break;
    }

    $where_sql = 'WHERE ' . implode( ' AND ', $where );

    // ---- Count total for pagination ----
    $count_sql = "SELECT COUNT(*) FROM {$events_table} e {$where_sql}";
    if ( ! empty( $params ) ) {
        $total = (int) $wpdb->get_var( $wpdb->prepare( $count_sql, ...$params ) );
    } else {
        $total = (int) $wpdb->get_var( $count_sql );
    }

    $total_pages  = max( 1, (int) ceil( $total / $per_page ) );
    $current_page = max( 1, (int) ( $_GET['sp_page'] ?? 1 ) );
    $offset       = ( $current_page - 1 ) * $per_page;

    // ---- Fetch events ----
    $order = ( $timeframe === 'past' ) ? 'DESC' : 'ASC';
    $query = "SELECT e.*, c.name AS category_name, c.color AS category_color
              FROM {$events_table} e
              LEFT JOIN {$cats_table} c ON e.category_id = c.id
              {$where_sql}
              ORDER BY e.event_date {$order}, e.start_time ASC
              LIMIT %d OFFSET %d";
    $query_params = array_merge( $params, [ $per_page, $offset ] );
    $events = $wpdb->get_results( $wpdb->prepare( $query, ...$query_params ) );

    // ---- Fetch all categories for the filter dropdown ----
    $categories = $wpdb->get_results(
        "SELECT id, name FROM {$cats_table} WHERE active = 1 ORDER BY sort_order"
    );

    // Calendar events are now fetched inside sp_render_calendar_grid() — no
    // need to pre-fetch here. The shared function handles its own data query
    // scoped to the displayed month, which is more efficient than the old
    // approach of fetching 13 months of events up front.

    // ---- Build persistent query args for pagination links ----
    $page_args = [];
    if ( $search !== '' ) $page_args['sp_search'] = $search;
    if ( $cat_filter > 0 ) $page_args['sp_cat'] = $cat_filter;
    if ( $timeframe !== '12months' ) $page_args['sp_time'] = $timeframe;
    if ( $view !== 'list' ) $page_args['sp_view'] = $view;

    ?>

    <!-- ================================================================ -->
    <!-- FILTER BAR: Search, Category, Timeframe, View Toggle             -->
    <!-- ================================================================ -->
    <div class="sp-events-filters">
        <form method="get" action="<?php echo esc_url( $base_url ); ?>" class="sp-events-filter-form">

            <div class="sp-events-filter-row">
                <!-- Search -->
                <div class="sp-events-search-wrap">
                    <input type="text" name="sp_search" value="<?php echo esc_attr( $search ); ?>"
                           placeholder="<?php echo esc_attr__( 'Search events...', 'societypress' ); ?>" class="sp-events-search-input">
                </div>

                <!-- Category -->
                <select name="sp_cat" class="sp-events-filter-select">
                    <option value="0"><?php esc_html_e( 'All Categories', 'societypress' ); ?></option>
                    <?php foreach ( $categories as $cat ) : ?>
                        <option value="<?php echo esc_attr( $cat->id ); ?>"
                            <?php selected( $cat_filter, $cat->id ); ?>>
                            <?php echo esc_html( $cat->name ); ?>
                        </option>
                    <?php endforeach; ?>
                </select>

                <!-- Timeframe -->
                <select name="sp_time" class="sp-events-filter-select">
                    <?php
                    $timeframes = [
                        '30days'   => __( 'Next 30 Days', 'societypress' ),
                        '3months'  => __( 'Next 3 Months', 'societypress' ),
                        '6months'  => __( 'Next 6 Months', 'societypress' ),
                        '12months' => __( 'Next 12 Months', 'societypress' ),
                        'all'      => __( 'All Upcoming', 'societypress' ),
                        'past'     => __( 'Past Events', 'societypress' ),
                    ];
                    foreach ( $timeframes as $tval => $tlabel ) :
                    ?>
                        <option value="<?php echo esc_attr( $tval ); ?>"
                            <?php selected( $timeframe, $tval ); ?>>
                            <?php echo esc_html( $tlabel ); ?>
                        </option>
                    <?php endforeach; ?>
                </select>

                <button type="submit" class="sp-events-filter-btn"><?php esc_html_e( 'Filter', 'societypress' ); ?></button>

                <?php if ( $search !== '' || $cat_filter > 0 || $timeframe !== '12months' ) : ?>
                    <a href="<?php echo esc_url( $base_url ); ?>" class="sp-events-clear-link"><?php esc_html_e( 'Clear', 'societypress' ); ?></a>
                <?php endif; ?>
            </div>

            <!-- View Toggle: List / Calendar + Subscribe -->
            <div class="sp-events-toolbar">
                <div class="sp-events-view-toggle">
                    <a href="<?php echo esc_url( add_query_arg( array_merge( $page_args, [ 'sp_view' => 'list' ] ), $base_url ) ); ?>"
                       class="sp-view-btn <?php echo $view === 'list' ? 'sp-view-active' : ''; ?>">
                        <span class="sp-view-icon">&#9776;</span> <?php esc_html_e( 'List', 'societypress' ); ?>
                    </a>
                    <a href="<?php echo esc_url( add_query_arg( array_merge( $page_args, [ 'sp_view' => 'calendar' ] ), $base_url ) ); ?>"
                       class="sp-view-btn <?php echo $view === 'calendar' ? 'sp-view-active' : ''; ?>">
                        <span class="sp-view-icon">&#9638;</span> <?php esc_html_e( 'Calendar', 'societypress' ); ?>
                    </a>
                </div>
                <?php sp_render_subscribe_dropdown( 'listing' ); ?>
            </div>
        </form>
    </div>

    <?php if ( $view === 'calendar' ) : ?>

    <!-- ================================================================ -->
    <!-- CALENDAR VIEW (rendered by shared sp_render_calendar_grid)        -->
    <!-- ================================================================ -->
    <?php
    // WHY: Calendar rendering is now a shared function so the same grid
    //      can be used by the Page Builder widget and standalone template.
    //      We pass the category filter and extra args so the nav links
    //      preserve the current filter state and view toggle.
    $cal_extra_args = $page_args;
    $cal_extra_args['sp_view'] = 'calendar';
    sp_render_calendar_grid( $cat_filter, $base_url, $cal_extra_args );
    ?>

    <?php else : ?>

    <!-- ================================================================ -->
    <!-- LIST VIEW: Event Cards                                            -->
    <!-- ================================================================ -->

    <?php if ( empty( $events ) ) : ?>
        <div class="sp-events-empty">
            <p><?php
                if ( $search !== '' ) {
                    /* translators: %s: search query */
                    echo esc_html( sprintf( __( 'No events found matching "%s".', 'societypress' ), $search ) );
                } else {
                    esc_html_e( 'No events found.', 'societypress' );
                }
            ?></p>
            <?php if ( $search !== '' || $cat_filter > 0 ) : ?>
                <p><a href="<?php echo esc_url( $base_url ); ?>"><?php esc_html_e( 'View all upcoming events', 'societypress' ); ?></a></p>
            <?php endif; ?>
        </div>
    <?php else : ?>

        <div class="sp-events-count">
            <?php
            if ( $total === 1 ) {
                echo '<p>1 event</p>';
            } else {
                printf( '<p>%s events</p>', number_format_i18n( $total ) );
            }
            ?>
        </div>

        <?php
        // WHY: Batch-fetch registration counts for all events in one query instead
        //      of querying per-card inside the loop (N+1 problem). With 12 events
        //      per page, this eliminates 12 individual COUNT queries.
        $event_ids  = wp_list_pluck( $events, 'id' );
        $reg_counts = [];
        if ( $event_ids ) {
            $placeholders = implode( ',', array_fill( 0, count( $event_ids ), '%d' ) );
            $counts = $wpdb->get_results( $wpdb->prepare(
                "SELECT event_id, COALESCE(SUM(party_size), 0) as total
                 FROM {$reg_table}
                 WHERE event_id IN ($placeholders) AND status IN ('confirmed','waitlisted')
                 GROUP BY event_id",
                ...$event_ids
            ) );
            foreach ( $counts as $c ) {
                $reg_counts[ (int) $c->event_id ] = (int) $c->total;
            }
        }
        ?>
        <div class="sp-events-list">
            <?php foreach ( $events as $ev ) :
                // External events link directly to the external URL and open in a new tab.
                // Internal events link to the SocietyPress detail page as usual.
                $is_external = ! empty( $ev->external_url );
                $detail_url  = $is_external
                    ? $ev->external_url
                    : add_query_arg( 'sp_event', $ev->slug, $base_url );
                $link_target = $is_external ? ' target="_blank" rel="noopener"' : '';

                $date_ts    = strtotime( $ev->event_date );
                $day_num    = wp_date( 'j', $date_ts );
                $day_name   = wp_date( 'D', $date_ts );
                $month_name = wp_date( 'M', $date_ts );

                // Build time string
                $time_str = '';
                if ( ! empty( $ev->start_time ) ) {
                    $time_str = wp_date( 'g:i A', strtotime( $ev->start_time ) );
                    if ( ! empty( $ev->end_time ) ) {
                        $time_str .= ' – ' . wp_date( 'g:i A', strtotime( $ev->end_time ) );
                    }
                }

                // Location string
                $location = '';
                if ( ! empty( $ev->location_name ) ) {
                    $location = $ev->location_name;
                }
                if ( $ev->is_virtual && empty( $location ) ) {
                    $location = 'Virtual Event';
                } elseif ( $ev->is_virtual ) {
                    $location .= ' + Virtual';
                }

                // Registration info (uses batch-fetched counts from above)
                $reg_info = '';
                if ( $ev->registration_enabled ) {
                    $reg_count = $reg_counts[ $ev->id ] ?? 0;
                    if ( $ev->registration_limit ) {
                        $spots_left = max( 0, $ev->registration_limit - $reg_count );
                        if ( $spots_left === 0 ) {
                            $reg_info = 'Full — Waitlist Available';
                        } else {
                            $reg_info = $spots_left . ' spot' . ( $spots_left !== 1 ? 's' : '' ) . ' remaining';
                        }
                    }
                }
            ?>
                <article class="sp-event-card">
                    <a href="<?php echo esc_url( $detail_url ); ?>" class="sp-event-card-link"<?php echo $link_target; ?>>

                        <!-- Date block -->
                        <div class="sp-event-date-block">
                            <span class="sp-event-month"><?php echo esc_html( $month_name ); ?></span>
                            <span class="sp-event-day"><?php echo esc_html( $day_num ); ?></span>
                            <span class="sp-event-dow"><?php echo esc_html( $day_name ); ?></span>
                        </div>

                        <!-- Event details -->
                        <div class="sp-event-details">
                            <h3 class="sp-event-title"><?php echo esc_html( $ev->title ); ?></h3>

                            <div class="sp-event-meta">
                                <?php if ( $time_str ) : ?>
                                    <span class="sp-event-meta-item sp-event-time">
                                        &#128339; <?php echo esc_html( $time_str ); ?>
                                    </span>
                                <?php endif; ?>

                                <?php if ( $location ) : ?>
                                    <span class="sp-event-meta-item sp-event-location">
                                        &#128205; <?php echo esc_html( $location ); ?>
                                    </span>
                                <?php endif; ?>
                            </div>

                            <div class="sp-event-badges">
                                <?php if ( ! empty( $ev->category_name ) ) : ?>
                                    <span class="sp-event-badge" style="background: <?php echo esc_attr( $ev->category_color ?: '#2271b1' ); ?>;">
                                        <?php echo esc_html( $ev->category_name ); ?>
                                    </span>
                                <?php endif; ?>

                                <?php if ( $ev->status === 'postponed' ) : ?>
                                    <span class="sp-event-badge sp-badge-postponed"><?php esc_html_e( 'Postponed', 'societypress' ); ?></span>
                                <?php endif; ?>

                                <?php
                                // WHY show both prices: Members and non-members see
                                // different fees. Showing both up front sets expectations
                                // and highlights the membership value — "Members $5 /
                                // Non-Members $10" makes the benefit obvious.
                                $m_price  = (float) $ev->member_price;
                                $nm_price = (float) $ev->nonmember_price;

                                if ( $m_price > 0 && $nm_price > 0 ) : ?>
                                    <span class="sp-event-price">
                                        <?php echo esc_html__( 'Members', 'societypress' ) . ' ' . esc_html( sp_format_currency( $m_price ) ); ?>
                                        / <?php echo esc_html__( 'Non-Members', 'societypress' ) . ' ' . esc_html( sp_format_currency( $nm_price ) ); ?>
                                    </span>
                                <?php elseif ( $m_price > 0 ) : ?>
                                    <span class="sp-event-price"><?php echo esc_html( sp_format_currency( $m_price ) ); ?></span>
                                <?php elseif ( $nm_price > 0 ) : ?>
                                    <span class="sp-event-price">
                                        <?php echo esc_html__( 'Free for Members', 'societypress' ); ?>
                                        / <?php echo esc_html__( 'Non-Members', 'societypress' ) . ' ' . esc_html( sp_format_currency( $nm_price ) ); ?>
                                    </span>
                                <?php elseif ( $ev->registration_enabled ) : ?>
                                    <span class="sp-event-price sp-event-free"><?php esc_html_e( 'Free', 'societypress' ); ?></span>
                                <?php endif; ?>

                                <?php if ( $reg_info ) : ?>
                                    <span class="sp-event-reg-info"><?php echo esc_html( $reg_info ); ?></span>
                                <?php endif; ?>

                                <?php if ( $ev->visibility === 'members_only' ) : ?>
                                    <span class="sp-event-badge sp-badge-members"><?php esc_html_e( 'Members Only', 'societypress' ); ?></span>
                                <?php endif; ?>

                                <?php if ( $is_external ) : ?>
                                    <span class="sp-event-badge sp-badge-external"><?php esc_html_e( 'External', 'societypress' ); ?> &#8599;</span>
                                <?php endif; ?>
                            </div>
                        </div>

                    </a>
                </article>
            <?php endforeach; ?>
        </div>

        <!-- Pagination -->
        <?php if ( $total_pages > 1 ) : ?>
        <nav class="sp-events-pagination" aria-label="Events pagination">
            <?php if ( $current_page > 1 ) : ?>
                <a href="<?php echo esc_url( add_query_arg( array_merge( $page_args, [ 'sp_page' => $current_page - 1 ] ), $base_url ) ); ?>"
                   class="sp-page-link sp-page-prev">&laquo; Previous</a>
            <?php endif; ?>

            <?php
            $range = 2;
            $start = max( 1, $current_page - $range );
            $end   = min( $total_pages, $current_page + $range );

            if ( $start > 1 ) : ?>
                <a href="<?php echo esc_url( add_query_arg( array_merge( $page_args, [ 'sp_page' => 1 ] ), $base_url ) ); ?>"
                   class="sp-page-link">1</a>
                <?php if ( $start > 2 ) : ?>
                    <span class="sp-page-ellipsis">&hellip;</span>
                <?php endif; ?>
            <?php endif; ?>

            <?php for ( $p = $start; $p <= $end; $p++ ) : ?>
                <?php if ( $p === $current_page ) : ?>
                    <span class="sp-page-link sp-page-current"><?php echo $p; ?></span>
                <?php else : ?>
                    <a href="<?php echo esc_url( add_query_arg( array_merge( $page_args, [ 'sp_page' => $p ] ), $base_url ) ); ?>"
                       class="sp-page-link"><?php echo $p; ?></a>
                <?php endif; ?>
            <?php endfor; ?>

            <?php if ( $end < $total_pages ) : ?>
                <?php if ( $end < $total_pages - 1 ) : ?>
                    <span class="sp-page-ellipsis">&hellip;</span>
                <?php endif; ?>
                <a href="<?php echo esc_url( add_query_arg( array_merge( $page_args, [ 'sp_page' => $total_pages ] ), $base_url ) ); ?>"
                   class="sp-page-link"><?php echo $total_pages; ?></a>
            <?php endif; ?>

            <?php if ( $current_page < $total_pages ) : ?>
                <a href="<?php echo esc_url( add_query_arg( array_merge( $page_args, [ 'sp_page' => $current_page + 1 ] ), $base_url ) ); ?>"
                   class="sp-page-link sp-page-next">Next &raquo;</a>
            <?php endif; ?>
        </nav>
        <?php endif; ?>

    <?php endif; // empty( $events ) ?>

    <?php endif; // view === calendar ?>

    <?php
}


// ============================================================================
// EVENTS — FRONTEND DETAIL PAGE
// ============================================================================

/**
 * Render a single event's detail page.
 *
 * WHY: Members click an event from the listing or calendar to see full details —
 *      the description, speaker info, location, registration status, and contact.
 *      This is the "event flyer" equivalent for the web.
 *
 * @param string $slug     The event slug from the URL query var.
 * @param array  $settings The societypress_settings option array.
 */
function sp_render_event_detail( string $slug, array $settings ): void {
    global $wpdb;

    $events_table = $wpdb->prefix . 'sp_events';
    $cats_table   = $wpdb->prefix . 'sp_event_categories';
    $reg_table    = $wpdb->prefix . 'sp_event_registrations';

    // Fetch the event
    $event = $wpdb->get_row( $wpdb->prepare(
        "SELECT e.*, c.name AS category_name, c.color AS category_color
         FROM {$events_table} e
         LEFT JOIN {$cats_table} c ON e.category_id = c.id
         WHERE e.slug = %s",
        $slug
    ) );

    if ( ! $event ) {
        echo '<div class="sp-event-not-found">';
        echo '<h2>Event Not Found</h2>';
        echo '<p>The event you\'re looking for doesn\'t exist or has been removed.</p>';
        echo '<p><a href="' . esc_url( get_permalink() ) . '">&larr; Back to Events</a></p>';
        echo '</div>';
        return;
    }

    // External events show a minimal card with key info and a prominent link
    // to the external event page. We don't redirect because showing the title,
    // date, and description is useful context — the user can click through when ready.
    if ( ! empty( $event->external_url ) ) {
        $ext_date_display = date_i18n( 'l, F j, Y', strtotime( $event->event_date ) );
        $ext_time_display = '';
        if ( ! empty( $event->start_time ) ) {
            $ext_time_display = wp_date( 'g:i A', strtotime( $event->start_time ) );
            if ( ! empty( $event->end_time ) ) {
                $ext_time_display .= ' – ' . wp_date( 'g:i A', strtotime( $event->end_time ) );
            }
        }
        ?>
        <div class="sp-event-back">
            <a href="<?php echo esc_url( get_permalink() ); ?>">&larr; <?php esc_html_e( 'Back to Events', 'societypress' ); ?></a>
        </div>

        <article class="sp-event-external-card">
            <div class="sp-event-external-badge"><?php esc_html_e( 'External Event', 'societypress' ); ?></div>

            <h1 class="sp-event-detail-title"><?php echo esc_html( $event->title ); ?></h1>

            <?php if ( ! empty( $event->category_name ) ) : ?>
                <span class="sp-event-badge" style="background: <?php echo esc_attr( $event->category_color ?: '#2271b1' ); ?>; margin-bottom: 16px; display: inline-block;">
                    <?php echo esc_html( $event->category_name ); ?>
                </span>
            <?php endif; ?>

            <div class="sp-event-key-details" style="margin-bottom: 20px;">
                <div class="sp-event-detail-item">
                    <span class="sp-detail-icon">&#128197;</span>
                    <div>
                        <strong><?php echo esc_html( $ext_date_display ); ?></strong>
                        <?php if ( $ext_time_display ) : ?>
                            <br><span class="sp-detail-secondary"><?php echo esc_html( $ext_time_display ); ?></span>
                        <?php endif; ?>
                    </div>
                </div>

                <?php if ( ! empty( $event->location_name ) ) : ?>
                <div class="sp-event-detail-item">
                    <span class="sp-detail-icon">&#128205;</span>
                    <div><strong><?php echo esc_html( $event->location_name ); ?></strong></div>
                </div>
                <?php endif; ?>
            </div>

            <?php if ( ! empty( $event->description ) ) : ?>
                <div class="sp-event-description" style="margin-bottom: 24px;">
                    <?php echo wp_kses_post( $event->description ); ?>
                </div>
            <?php endif; ?>

            <a href="<?php echo esc_url( $event->external_url ); ?>"
               class="sp-external-event-btn"
               target="_blank" rel="noopener">
                <?php esc_html_e( 'Visit Event Page', 'societypress' ); ?> &rarr;
            </a>
        </article>
        <?php
        return;
    }

    // Notice-only events have no detail page — redirect back to the events listing.
    // WHY: These are informational calendar entries (holidays, board meetings) that
    //      don't need a full detail page. If someone types the URL directly or
    //      follows a stale link, send them back to the events page gracefully.
    if ( ! empty( $event->notice_only ) ) {
        echo '<div class="sp-event-not-found">';
        echo '<h2>' . esc_html( $event->title ) . '</h2>';
        echo '<p>' . esc_html( date_i18n( 'l, F j, Y', strtotime( $event->event_date ) ) ) . '</p>';
        echo '<p>' . esc_html__( 'This is a calendar notice — no additional details or registration are available.', 'societypress' ) . '</p>';
        echo '<p><a href="' . esc_url( get_permalink() ) . '">&larr; ' . esc_html__( 'Back to Events', 'societypress' ) . '</a></p>';
        echo '</div>';
        return;
    }

    // Visibility check — members_only events require login
    if ( $event->visibility === 'members_only' && ! is_user_logged_in() ) {
        echo '<div class="sp-event-login-required">';
        echo '<h2>' . esc_html__( 'Members Only', 'societypress' ) . '</h2>';
        echo '<p>' . sprintf(
            /* translators: %s: login link HTML */
            esc_html__( 'This event is only visible to logged-in members. Please %s to view details.', 'societypress' ),
            '<a href="' . esc_url( wp_login_url( add_query_arg( 'sp_event', $slug, get_permalink() ) ) ) . '">' . esc_html__( 'log in', 'societypress' ) . '</a>'
        ) . '</p>';
        echo '</div>';
        return;
    }

    // Registration count
    $reg_count = 0;
    if ( $event->registration_enabled ) {
        $reg_count = (int) $wpdb->get_var( $wpdb->prepare(
            "SELECT COALESCE(SUM(party_size), 0) FROM {$reg_table}
             WHERE event_id = %d AND status = 'confirmed'",
            $event->id
        ) );
    }

    // Check if current user is already registered
    // WHY: For events with slots, a user can be registered for some slots
    //      but not others. We need to know WHICH slots they're in, not just
    //      whether they have ANY registration. $user_registered controls
    //      whether to show the "You're registered!" block or the form.
    //      For slotted events, we always show the form (so they can pick
    //      additional slots) plus a summary of their existing registrations.
    $user_registered = false;
    $user_slot_registrations = [];
    if ( is_user_logged_in() && $event->registration_enabled ) {
        $user_regs = $wpdb->get_results( $wpdb->prepare(
            "SELECT r.id, r.slot_id, r.status, r.party_size,
                    s.start_time AS slot_start, s.end_time AS slot_end, s.description AS slot_desc
             FROM {$reg_table} r
             LEFT JOIN {$wpdb->prefix}sp_event_slots s ON r.slot_id = s.id
             WHERE r.event_id = %d AND r.user_id = %d AND r.status IN ('confirmed', 'waitlisted')
             ORDER BY s.start_time ASC",
            $event->id, get_current_user_id()
        ) );
        if ( $user_regs ) {
            foreach ( $user_regs as $ur ) {
                $user_slot_registrations[] = $ur;
            }
        }
        // For events WITHOUT slots, use the old behavior (single registration)
        // For events WITH slots, always show the form so they can add more slots
        $user_registered = ! empty( $user_slot_registrations ) && empty( sp_slots_get_by_event( (int) $event->id, true ) );
    }

    // Load event time slots for display
    // WHY: If this event has time slots, we need them both for the detail display
    //      (showing available sessions) and the registration form (slot picker).
    $event_slots = sp_slots_get_by_event( (int) $event->id, true );

    // Featured image
    $image_url = '';
    if ( $event->image_id ) {
        $image_url = wp_get_attachment_image_url( $event->image_id, 'large' );
    }

    // Format date
    $date_ts      = strtotime( $event->event_date );
    $date_display = date_i18n( 'l, F j, Y', $date_ts ); // e.g., "Saturday, March 14, 2026"

    // Format time
    $time_display = '';
    if ( ! empty( $event->start_time ) ) {
        $time_display = wp_date( 'g:i A', strtotime( $event->start_time ) );
        if ( ! empty( $event->end_time ) ) {
            $time_display .= ' – ' . wp_date( 'g:i A', strtotime( $event->end_time ) );
        }
    }

    // Build slot display data for the detail page
    // WHY: When an event has slots, we show them instead of (or alongside) the
    //      main start/end time. Each slot shows its time range, capacity status,
    //      and a description if one was provided.
    $slot_display_data = [];
    if ( ! empty( $event_slots ) ) {
        foreach ( $event_slots as $es ) {
            $slot_reg_count = sp_slot_get_registration_count( (int) $es->id );
            $slot_remaining = sp_slot_get_remaining_capacity( (int) $es->id );
            $slot_display_data[] = (object) [
                'id'          => (int) $es->id,
                'time_range'  => sp_slot_format_time_range( $es ),
                'description' => $es->description ?? '',
                'capacity'    => $es->capacity !== null ? (int) $es->capacity : null,
                'registered'  => $slot_reg_count,
                'remaining'   => $slot_remaining,
                'is_full'     => $slot_remaining !== null && $slot_remaining <= 0,
            ];
        }
    }

    $events_page_url = get_permalink();

    ?>

    <!-- Back link -->
    <div class="sp-event-back">
        <a href="<?php echo esc_url( $events_page_url ); ?>">&larr; Back to Events</a>
    </div>

    <article class="sp-event-detail">

        <!-- Header: Title + Badges -->
        <header class="sp-event-header">
            <?php if ( $event->status === 'cancelled' ) : ?>
                <div class="sp-event-cancelled-banner">This event has been cancelled.</div>
            <?php elseif ( $event->status === 'postponed' ) : ?>
                <div class="sp-event-postponed-banner">This event has been postponed. Check back for updated details.</div>
            <?php endif; ?>

            <h1 class="sp-event-detail-title"><?php echo esc_html( $event->title ); ?></h1>

            <div class="sp-event-detail-badges">
                <?php if ( ! empty( $event->category_name ) ) : ?>
                    <span class="sp-event-badge" style="background: <?php echo esc_attr( $event->category_color ?: '#2271b1' ); ?>;">
                        <?php echo esc_html( $event->category_name ); ?>
                    </span>
                <?php endif; ?>

                <?php if ( $event->visibility === 'members_only' ) : ?>
                    <span class="sp-event-badge sp-badge-members"><?php esc_html_e( 'Members Only', 'societypress' ); ?></span>
                <?php endif; ?>
            </div>
        </header>

        <!-- Featured Image -->
        <?php if ( $image_url ) : ?>
            <div class="sp-event-image">
                <img src="<?php echo esc_url( $image_url ); ?>" alt="<?php echo esc_attr( $event->title ); ?>">
            </div>
        <?php endif; ?>

        <!-- Key Details: Date, Time, Location -->
        <div class="sp-event-key-details">
            <div class="sp-event-detail-item">
                <span class="sp-detail-icon">&#128197;</span>
                <div>
                    <strong><?php echo esc_html( $date_display ); ?></strong>
                    <?php if ( $time_display ) : ?>
                        <br><span class="sp-detail-secondary"><?php echo esc_html( $time_display ); ?></span>
                    <?php endif; ?>
                </div>
            </div>

            <?php if ( ! empty( $event->location_name ) || $event->is_virtual ) : ?>
            <div class="sp-event-detail-item">
                <span class="sp-detail-icon">&#128205;</span>
                <div>
                    <?php if ( ! empty( $event->location_name ) ) : ?>
                        <strong><?php echo esc_html( $event->location_name ); ?></strong>
                        <?php if ( ! empty( $event->location_address ) ) : ?>
                            <br><span class="sp-detail-secondary"><?php echo esc_html( $event->location_address ); ?></span>
                        <?php endif; ?>
                    <?php endif; ?>

                    <?php if ( $event->is_virtual ) : ?>
                        <?php if ( ! empty( $event->location_name ) ) : ?>
                            <br>
                        <?php endif; ?>
                        <span class="sp-detail-virtual">&#128187; Virtual / Online</span>
                        <?php if ( ! empty( $event->virtual_url ) && is_user_logged_in() ) : ?>
                            <br><a href="<?php echo esc_url( $event->virtual_url ); ?>" target="_blank" rel="noopener"
                                   class="sp-virtual-link">Join Online Meeting &rarr;</a>
                        <?php endif; ?>
                    <?php endif; ?>
                </div>
            </div>
            <?php endif; ?>

            <!-- Add to Calendar link -->
            <?php
            // WHY: Universal .ics download works with Google Calendar, Apple Calendar,
            //      Outlook, and every other major calendar app. Placed in the key details
            //      section so it's visually grouped with the date/time/location info —
            //      the natural place a member would look for "add this to my calendar."
            $ics_url = add_query_arg( 'sp_ics', $event->id, home_url( '/' ) );
            ?>
            <div class="sp-event-detail-item sp-event-add-to-cal">
                <span class="sp-detail-icon">&#128198;</span>
                <div>
                    <a href="<?php echo esc_url( $ics_url ); ?>" class="sp-add-to-cal-link"
                       title="<?php esc_attr_e( 'Download .ics file to add this event to your calendar', 'societypress' ); ?>">
                        <?php esc_html_e( 'Add to Calendar', 'societypress' ); ?>
                    </a>
                    <?php
                    // "Subscribe to All Events" link — opens the subscribe dropdown
                    // WHY: After adding a single event, some members want to subscribe
                    //      to ALL events so they auto-sync. We surface the option here
                    //      while they're in a "calendar management" mindset.
                    $feed_settings = get_option( 'societypress_settings', [] );
                    if ( ! empty( $feed_settings['events_ical_feed_enabled'] ?? 1 ) ) :
                    ?>
                        <span class="sp-detail-separator">&middot;</span>
                        <?php sp_render_subscribe_dropdown( 'detail' ); ?>
                    <?php endif; ?>
                </div>
            </div>
        </div>

        <!-- Time Slots (if event has multiple sessions) -->
        <?php if ( ! empty( $slot_display_data ) ) : ?>
            <div class="sp-event-slots-section">
                <h2>Available Sessions</h2>
                <div class="sp-event-slots-grid">
                    <?php foreach ( $slot_display_data as $sd ) : ?>
                        <div class="sp-event-slot-card <?php echo $sd->is_full ? 'sp-slot-full' : ''; ?>">
                            <div class="sp-slot-time"><?php echo esc_html( $sd->time_range ); ?></div>
                            <?php if ( $sd->description ) : ?>
                                <div class="sp-slot-desc"><?php echo esc_html( $sd->description ); ?></div>
                            <?php endif; ?>
                            <?php if ( $sd->capacity !== null ) : ?>
                                <div class="sp-slot-capacity">
                                    <?php if ( $sd->is_full ) : ?>
                                        <span class="sp-slot-full-label">Full</span>
                                    <?php else : ?>
                                        <?php echo $sd->remaining; ?> of <?php echo $sd->capacity; ?> spots left
                                    <?php endif; ?>
                                </div>
                            <?php endif; ?>
                        </div>
                    <?php endforeach; ?>
                </div>
            </div>
        <?php endif; ?>

        <!-- Description -->
        <?php if ( ! empty( $event->description ) ) : ?>
            <div class="sp-event-description">
                <?php echo wp_kses_post( wpautop( $event->description ) ); ?>
            </div>
        <?php endif; ?>

        <!-- Speakers Section -->
        <?php
        // Fetch speakers assigned to this event
        $speakers = $wpdb->get_results( $wpdb->prepare(
            "SELECT s.*, sa.role
             FROM {$wpdb->prefix}sp_event_speaker_assignments sa
             JOIN {$wpdb->prefix}sp_event_speakers s ON sa.speaker_id = s.id
             WHERE sa.event_id = %d
             ORDER BY sa.sort_order",
            $event->id
        ) );

        if ( ! empty( $speakers ) ) :
        ?>
            <div class="sp-event-speakers">
                <h2><?php echo count( $speakers ) === 1 ? 'Speaker' : 'Speakers'; ?></h2>
                <?php foreach ( $speakers as $speaker ) :
                    $photo_url = '';
                    if ( $speaker->photo_id ) {
                        $photo_url = wp_get_attachment_image_url( $speaker->photo_id, 'thumbnail' );
                    }
                    $role_labels = [
                        'speaker'    => 'Speaker',
                        'instructor' => 'Instructor',
                        'moderator'  => 'Moderator',
                        'panelist'   => 'Panelist',
                    ];
                    $role_label = $role_labels[ $speaker->role ] ?? 'Speaker';
                ?>
                    <div class="sp-speaker-card">
                        <?php if ( $photo_url ) : ?>
                            <img src="<?php echo esc_url( $photo_url ); ?>" alt="<?php echo esc_attr( $speaker->name ); ?>"
                                 class="sp-speaker-photo">
                        <?php endif; ?>
                        <div class="sp-speaker-info">
                            <p class="sp-speaker-name"><?php echo esc_html( $speaker->name ); ?></p>
                            <?php if ( ! empty( $speaker->title ) ) : ?>
                                <p class="sp-speaker-title"><?php echo esc_html( $speaker->title ); ?></p>
                            <?php endif; ?>
                            <?php if ( count( $speakers ) > 1 || $speaker->role !== 'speaker' ) : ?>
                                <span class="sp-speaker-role"><?php echo esc_html( $role_label ); ?></span>
                            <?php endif; ?>
                            <?php if ( ! empty( $speaker->bio ) ) : ?>
                                <p class="sp-speaker-bio"><?php echo esc_html( $speaker->bio ); ?></p>
                            <?php endif; ?>
                            <?php if ( ! empty( $speaker->website ) ) : ?>
                                <p><a href="<?php echo esc_url( $speaker->website ); ?>" target="_blank" rel="noopener"
                                       class="sp-speaker-website">Website &rarr;</a></p>
                            <?php endif; ?>
                        </div>
                    </div>
                <?php endforeach; ?>
            </div>
        <?php endif; ?>

        <!-- Registration Section -->
        <?php if ( $event->registration_enabled && $event->status === 'scheduled' ) : ?>
            <div class="sp-event-registration">
                <h2>Registration</h2>

                <!-- Pricing info -->
                <?php if ( (float) $event->member_price > 0 || (float) $event->nonmember_price > 0 ) : ?>
                    <div class="sp-event-pricing">
                        <?php if ( (float) $event->member_price > 0 ) : ?>
                            <div class="sp-price-item">
                                <span class="sp-price-label">Members:</span>
                                <span class="sp-price-amount"><?php echo esc_html( sp_format_currency( $event->member_price ) ); ?></span>
                            </div>
                        <?php else : ?>
                            <div class="sp-price-item">
                                <span class="sp-price-label">Members:</span>
                                <span class="sp-price-amount sp-price-free">Free</span>
                            </div>
                        <?php endif; ?>

                        <?php if ( $event->guest_registration ) : ?>
                            <?php if ( (float) $event->nonmember_price > 0 ) : ?>
                                <div class="sp-price-item">
                                    <span class="sp-price-label">Non-Members:</span>
                                    <span class="sp-price-amount"><?php echo esc_html( sp_format_currency( $event->nonmember_price ) ); ?></span>
                                </div>
                            <?php else : ?>
                                <div class="sp-price-item">
                                    <span class="sp-price-label">Non-Members:</span>
                                    <span class="sp-price-amount sp-price-free">Free</span>
                                </div>
                            <?php endif; ?>
                        <?php endif; ?>

                        <?php if ( ! empty( $event->price_description ) ) : ?>
                            <p class="sp-price-note"><?php echo esc_html( $event->price_description ); ?></p>
                        <?php endif; ?>
                    </div>
                <?php endif; ?>

                <!-- Spots remaining -->
                <?php if ( $event->registration_limit ) : ?>
                    <?php
                    $spots_left = max( 0, $event->registration_limit - $reg_count );
                    $pct = ( $reg_count / $event->registration_limit ) * 100;
                    ?>
                    <div class="sp-event-capacity">
                        <div class="sp-capacity-bar">
                            <div class="sp-capacity-fill" style="width: <?php echo min( 100, $pct ); ?>%;
                                background: <?php echo $pct >= 90 ? '#d63638' : ( $pct >= 70 ? '#dba617' : '#00a32a' ); ?>;"></div>
                        </div>
                        <p class="sp-capacity-text">
                            <?php if ( $spots_left === 0 ) : ?>
                                <strong>Event is full.</strong> You can join the waitlist.
                            <?php else : ?>
                                <?php echo $spots_left; ?> of <?php echo $event->registration_limit; ?> spots remaining
                            <?php endif; ?>
                        </p>
                    </div>
                <?php endif; ?>

                <!-- Registration status / button -->
                <?php if ( $user_registered ) : ?>
                    <?php
                    // Fetch the user's actual registration record for status + cancel
                    $user_reg = $wpdb->get_row( $wpdb->prepare(
                        "SELECT id, status, party_size FROM {$reg_table}
                         WHERE event_id = %d AND user_id = %d AND status IN ('confirmed', 'waitlisted')",
                        $event->id, get_current_user_id()
                    ) );
                    ?>
                    <div class="sp-reg-confirmed" id="sp-reg-status-area">
                        <?php if ( $user_reg && $user_reg->status === 'waitlisted' ) : ?>
                            <p>&#128203; <strong>You're on the waitlist.</strong></p>
                            <p class="sp-reg-note">We'll notify you if a spot opens up.</p>
                        <?php else : ?>
                            <p>&#9989; <strong>You're registered!</strong></p>
                            <p class="sp-reg-note">You'll receive a reminder email before the event.</p>
                        <?php endif; ?>
                        <button type="button" class="sp-reg-cancel-btn" id="sp-cancel-reg-btn"
                                data-event-id="<?php echo esc_attr( $event->id ); ?>"
                                data-reg-id="<?php echo esc_attr( $user_reg->id ?? 0 ); ?>">
                            Cancel My Registration
                        </button>
                    </div>
                <?php else : ?>
                    <div class="sp-reg-action" id="sp-reg-form-area">
                        <?php if ( is_user_logged_in() ) : ?>
                            <!-- Logged-in member registration form -->
                            <div class="sp-reg-form" id="sp-member-reg-form">
                                <?php if ( ! empty( $user_slot_registrations ) ) : ?>
                                    <div class="sp-user-slot-regs" style="margin-bottom: 16px; padding: 12px; background: #f0f6fc; border: 1px solid #c3d4e8; border-radius: 6px;">
                                        <p style="margin: 0 0 8px; font-weight: 600;">Your Registrations:</p>
                                        <?php foreach ( $user_slot_registrations as $usr ) : ?>
                                            <div class="sp-user-slot-reg-row" style="display: flex; align-items: center; gap: 8px; margin-bottom: 6px;">
                                                <span style="flex: 1;">
                                                    <?php if ( $usr->slot_start ) : ?>
                                                        <?php echo esc_html( wp_date( 'g:i A', strtotime( $usr->slot_start ) ) . ' – ' . wp_date( 'g:i A', strtotime( $usr->slot_end ) ) ); ?>
                                                        <?php if ( $usr->slot_desc ) : ?>
                                                            <span style="color: #6b7280;"> — <?php echo esc_html( $usr->slot_desc ); ?></span>
                                                        <?php endif; ?>
                                                    <?php else : ?>
                                                        General Registration
                                                    <?php endif; ?>
                                                    <?php if ( $usr->status === 'waitlisted' ) : ?>
                                                        <span style="color: #dba617; font-size: 12px;">(waitlisted)</span>
                                                    <?php else : ?>
                                                        <span style="color: #00a32a; font-size: 12px;">(confirmed)</span>
                                                    <?php endif; ?>
                                                </span>
                                                <button type="button" class="sp-reg-cancel-btn sp-slot-cancel-btn"
                                                        data-event-id="<?php echo esc_attr( $event->id ); ?>"
                                                        data-reg-id="<?php echo esc_attr( $usr->id ); ?>"
                                                        style="font-size: 12px; padding: 2px 8px;">
                                                    Cancel
                                                </button>
                                            </div>
                                        <?php endforeach; ?>
                                    </div>
                                <?php endif; ?>
                                <?php if ( ! empty( $slot_display_data ) ) : ?>
                                    <?php
                                    // Filter out slots the user is already registered for
                                    $user_slot_ids = array_map( function( $r ) { return (int) $r->slot_id; }, $user_slot_registrations );
                                    $available_slots = array_filter( $slot_display_data, function( $sd ) use ( $user_slot_ids ) {
                                        return ! in_array( $sd->id, $user_slot_ids, true );
                                    } );
                                    ?>
                                    <?php if ( ! empty( $available_slots ) ) : ?>
                                    <div class="sp-reg-form-row">
                                        <label for="sp-reg-slot">Select a Session <span class="sp-required">*</span></label>
                                        <select id="sp-reg-slot" required>
                                            <option value="">— Choose a time slot —</option>
                                            <?php foreach ( $slot_display_data as $sd ) : ?>
                                                <option value="<?php echo esc_attr( $sd->id ); ?>"
                                                    <?php echo $sd->is_full ? 'data-full="1"' : ''; ?>>
                                                    <?php echo esc_html( $sd->time_range ); ?>
                                                    <?php if ( $sd->description ) echo ' — ' . esc_html( $sd->description ); ?>
                                                    <?php if ( $sd->is_full ) echo ' (FULL — waitlist)'; ?>
                                                    <?php if ( $sd->capacity !== null && ! $sd->is_full ) echo ' (' . $sd->remaining . ' spots)'; ?>
                                                </option>
                                            <?php endforeach; ?>
                                        </select>
                                    </div>
                                    <?php endif; ?>
                                <?php endif; ?>
                                <div class="sp-reg-form-row">
                                    <label for="sp-reg-party-size"><?php esc_html_e( 'How many attending?', 'societypress' ); ?></label>
                                    <select id="sp-reg-party-size">
                                        <?php for ( $i = 1; $i <= 10; $i++ ) : ?>
                                            <option value="<?php echo $i; ?>"><?php echo $i; ?><?php echo $i === 1 ? ' (just me)' : ' people'; ?></option>
                                        <?php endfor; ?>
                                    </select>
                                </div>
                                <?php
                                // Show fee info if this event costs money
                                // WHY: People need to know what they're going to pay BEFORE
                                //      they click the button. The fee summary updates dynamically
                                //      via JS when party size changes.
                                $member_fee = (float) $event->member_price;
                                if ( $member_fee > 0 ) : ?>
                                    <div class="sp-reg-fee-summary" id="sp-fee-summary">
                                        <span class="sp-fee-label">Fee:</span>
                                        <span class="sp-fee-amount" id="sp-fee-display">
                                            <?php echo esc_html( sp_format_currency( $member_fee ) ); ?>
                                        </span>
                                        <span class="sp-fee-per-person" id="sp-fee-per-person">
                                            (<?php echo esc_html( sp_format_currency( $member_fee ) ); ?>/person)
                                        </span>
                                        <?php if ( ! empty( $event->price_description ) ) : ?>
                                            <span class="sp-fee-note"><?php echo esc_html( $event->price_description ); ?></span>
                                        <?php endif; ?>
                                    </div>
                                <?php endif; ?>
                                <?php
                                // Determine button text based on capacity and payment mode
                                $is_full = $event->registration_limit && $reg_count >= $event->registration_limit;
                                ?>
                                <?php if ( $is_full ) : ?>
                                    <button type="button" class="sp-reg-submit-btn" id="sp-register-btn"
                                            data-event-id="<?php echo esc_attr( $event->id ); ?>"
                                            data-pay-method="none">
                                        Join Waitlist
                                    </button>
                                <?php elseif ( $show_pay_btn && $show_door_btn ) : ?>
                                    <!-- "Either" mode — two buttons so the registrant can choose -->
                                    <div class="sp-reg-pay-options">
                                        <button type="button" class="sp-reg-submit-btn sp-pay-online-btn" id="sp-register-btn"
                                                data-event-id="<?php echo esc_attr( $event->id ); ?>"
                                                data-pay-method="online">
                                            Pay Now with Card
                                        </button>
                                        <button type="button" class="sp-reg-submit-btn sp-pay-door-btn" id="sp-register-door-btn"
                                                data-event-id="<?php echo esc_attr( $event->id ); ?>"
                                                data-pay-method="at_door">
                                            Register — Pay at Door
                                        </button>
                                    </div>
                                <?php elseif ( $show_pay_btn ) : ?>
                                    <button type="button" class="sp-reg-submit-btn sp-pay-online-btn" id="sp-register-btn"
                                            data-event-id="<?php echo esc_attr( $event->id ); ?>"
                                            data-pay-method="online">
                                        Pay &amp; Register
                                    </button>
                                <?php else : ?>
                                    <button type="button" class="sp-reg-submit-btn" id="sp-register-btn"
                                            data-event-id="<?php echo esc_attr( $event->id ); ?>"
                                            data-pay-method="<?php echo $member_fee > 0 ? 'at_door' : 'none'; ?>">
                                        Register Now
                                    </button>
                                <?php endif; ?>
                                <div class="sp-reg-message" id="sp-reg-message" style="display: none;"></div>
                            </div>
                        <?php elseif ( $event->guest_registration ) : ?>
                            <!-- Guest registration form (not logged in, guest allowed) -->
                            <div class="sp-reg-form" id="sp-guest-reg-form">
                                <p class="sp-reg-form-intro">Register as a guest, or <a href="<?php echo esc_url( wp_login_url( add_query_arg( 'sp_event', $slug, get_permalink() ) ) ); ?>">log in</a> if you're a member.</p>
                                <div class="sp-reg-form-row">
                                    <label for="sp-guest-name">Full Name <span class="sp-required">*</span></label>
                                    <input type="text" id="sp-guest-name" required placeholder="Your full name">
                                </div>
                                <div class="sp-reg-form-row">
                                    <label for="sp-guest-email">Email <span class="sp-required">*</span></label>
                                    <input type="email" id="sp-guest-email" required placeholder="your@email.com">
                                </div>
                                <div class="sp-reg-form-row">
                                    <label for="sp-guest-phone">Phone <span class="sp-reg-optional">(optional)</span></label>
                                    <input type="tel" id="sp-guest-phone" placeholder="(555) 555-1234">
                                </div>
                                <?php if ( ! empty( $slot_display_data ) ) : ?>
                                    <div class="sp-reg-form-row">
                                        <label for="sp-guest-slot">Select a Session <span class="sp-required">*</span></label>
                                        <select id="sp-guest-slot" required>
                                            <option value="">— Choose a time slot —</option>
                                            <?php foreach ( $slot_display_data as $sd ) : ?>
                                                <option value="<?php echo esc_attr( $sd->id ); ?>"
                                                    <?php echo $sd->is_full ? 'data-full="1"' : ''; ?>>
                                                    <?php echo esc_html( $sd->time_range ); ?>
                                                    <?php if ( $sd->description ) echo ' — ' . esc_html( $sd->description ); ?>
                                                    <?php if ( $sd->is_full ) echo ' (FULL — waitlist)'; ?>
                                                    <?php if ( $sd->capacity !== null && ! $sd->is_full ) echo ' (' . $sd->remaining . ' spots)'; ?>
                                                </option>
                                            <?php endforeach; ?>
                                        </select>
                                    </div>
                                <?php endif; ?>
                                <div class="sp-reg-form-row">
                                    <label for="sp-guest-party-size"><?php esc_html_e( 'How many attending?', 'societypress' ); ?></label>
                                    <select id="sp-guest-party-size">
                                        <?php for ( $i = 1; $i <= 10; $i++ ) : ?>
                                            <option value="<?php echo $i; ?>"><?php echo $i; ?><?php echo $i === 1 ? ' (just me)' : ' people'; ?></option>
                                        <?php endfor; ?>
                                    </select>
                                </div>
                                <?php
                                // Show fee info for guests (non-member pricing)
                                $guest_fee = (float) $event->nonmember_price;
                                if ( $guest_fee > 0 ) : ?>
                                    <div class="sp-reg-fee-summary" id="sp-guest-fee-summary">
                                        <span class="sp-fee-label">Fee:</span>
                                        <span class="sp-fee-amount" id="sp-guest-fee-display">
                                            <?php echo esc_html( sp_format_currency( $guest_fee ) ); ?>
                                        </span>
                                        <span class="sp-fee-per-person" id="sp-guest-fee-per-person">
                                            (<?php echo esc_html( sp_format_currency( $guest_fee ) ); ?>/person)
                                        </span>
                                        <?php if ( ! empty( $event->price_description ) ) : ?>
                                            <span class="sp-fee-note"><?php echo esc_html( $event->price_description ); ?></span>
                                        <?php endif; ?>
                                    </div>
                                <?php endif; ?>
                                <?php
                                $is_full = $event->registration_limit && $reg_count >= $event->registration_limit;
                                ?>
                                <?php if ( $is_full ) : ?>
                                    <button type="button" class="sp-reg-submit-btn" id="sp-guest-register-btn"
                                            data-event-id="<?php echo esc_attr( $event->id ); ?>"
                                            data-pay-method="none">
                                        Join Waitlist
                                    </button>
                                <?php elseif ( $show_pay_btn && $show_door_btn ) : ?>
                                    <div class="sp-reg-pay-options">
                                        <button type="button" class="sp-reg-submit-btn sp-pay-online-btn" id="sp-guest-register-btn"
                                                data-event-id="<?php echo esc_attr( $event->id ); ?>"
                                                data-pay-method="online">
                                            Pay Now with Card
                                        </button>
                                        <button type="button" class="sp-reg-submit-btn sp-pay-door-btn" id="sp-guest-register-door-btn"
                                                data-event-id="<?php echo esc_attr( $event->id ); ?>"
                                                data-pay-method="at_door">
                                            Register — Pay at Door
                                        </button>
                                    </div>
                                <?php elseif ( $show_pay_btn ) : ?>
                                    <button type="button" class="sp-reg-submit-btn sp-pay-online-btn" id="sp-guest-register-btn"
                                            data-event-id="<?php echo esc_attr( $event->id ); ?>"
                                            data-pay-method="online">
                                        Pay &amp; Register
                                    </button>
                                <?php else : ?>
                                    <button type="button" class="sp-reg-submit-btn" id="sp-guest-register-btn"
                                            data-event-id="<?php echo esc_attr( $event->id ); ?>"
                                            data-pay-method="<?php echo $guest_fee > 0 ? 'at_door' : 'none'; ?>">
                                        Register Now
                                    </button>
                                <?php endif; ?>
                                <div class="sp-reg-message" id="sp-reg-message" style="display: none;"></div>
                            </div>
                        <?php else : ?>
                            <!-- Not logged in, no guest registration -->
                            <p class="sp-reg-login-prompt">
                                Please <a href="<?php echo esc_url( wp_login_url( add_query_arg( 'sp_event', $slug, get_permalink() ) ) ); ?>">log in</a> to register for this event.
                            </p>
                        <?php endif; ?>
                    </div>
                <?php endif; ?>
            </div>
        <?php endif; ?>

        <!-- Contact Section -->
        <?php if ( ! empty( $event->contact_name ) || ! empty( $event->contact_email ) || ! empty( $event->contact_phone ) ) : ?>
            <div class="sp-event-contact">
                <h2>Contact</h2>
                <?php if ( ! empty( $event->contact_name ) ) : ?>
                    <p class="sp-contact-name"><?php echo esc_html( $event->contact_name ); ?></p>
                <?php endif; ?>
                <?php if ( ! empty( $event->contact_email ) ) : ?>
                    <p><?php echo sp_obfuscate_email( $event->contact_email ); ?></p>
                <?php endif; ?>
                <?php if ( ! empty( $event->contact_phone ) ) : ?>
                    <?php
                    $phone_digits = preg_replace( '/\D/', '', $event->contact_phone );
                    $phone_display = $event->contact_phone;
                    if ( strlen( $phone_digits ) === 10 ) {
                        $phone_display = '(' . substr( $phone_digits, 0, 3 ) . ') ' . substr( $phone_digits, 3, 3 ) . '-' . substr( $phone_digits, 6 );
                    }
                    ?>
                    <p><a href="tel:<?php echo esc_attr( $phone_digits ); ?>"><?php echo esc_html( $phone_display ); ?></a></p>
                <?php endif; ?>
            </div>
        <?php endif; ?>

    </article>

    <?php if ( $event->registration_enabled && $event->status === 'scheduled' ) : ?>
        <!-- Registration data for AJAX calls -->
        <?php
        // Determine if Stripe is available for this event
        // WHY: The frontend JS needs to know whether to offer online payment
        //      vs. just a plain registration. We check both the event's payment
        //      mode AND whether Stripe keys are actually configured — no point
        //      showing a "Pay Now" button if the society hasn't set up Stripe.
        $sp_settings    = get_option( 'societypress_settings', [] );
        $stripe_ready   = sp_stripe_is_configured( $sp_settings );
        $payment_mode   = $event->payment_mode ?? 'none';
        $has_fee        = ( (float) $event->member_price > 0 || (float) $event->nonmember_price > 0 );
        $show_pay_btn   = $has_fee && $stripe_ready && in_array( $payment_mode, [ 'online', 'either' ], true );
        $show_door_btn  = $has_fee && in_array( $payment_mode, [ 'at_door', 'either' ], true );
        $pay_only       = $has_fee && $payment_mode === 'online' && $stripe_ready;
        ?>
        <script>
        var spRegData = {
            ajaxUrl:      '<?php echo admin_url( "admin-ajax.php" ); ?>',
            nonce:        '<?php echo wp_create_nonce( "sp_event_register" ); ?>',
            showPayBtn:   <?php echo $show_pay_btn ? 'true' : 'false'; ?>,
            showDoorBtn:  <?php echo $show_door_btn ? 'true' : 'false'; ?>,
            payOnly:      <?php echo $pay_only ? 'true' : 'false'; ?>,
            memberPrice:  <?php echo (float) $event->member_price; ?>,
            nonmemberPrice: <?php echo (float) $event->nonmember_price; ?>,
            currency:     '<?php echo strtoupper( $sp_settings['stripe_currency'] ?? 'USD' ); ?>'
        };
        </script>
    <?php endif; ?>
    <?php
}


// ============================================================================
// EVENTS — FRONTEND CSS
// ============================================================================

/**
 * Output event page styles in <head>.
 *
 * WHY: Only loaded on pages using the events template. Clean, responsive
 *      design that works with any WordPress theme. Mobile breakpoint at
 *      768px converts cards to stacked layout and calendar to dot view.
 */
function sp_events_frontend_styles(): void {
    ?>
    <style id="sp-events-frontend-css">
        /* ---- Wrapper ---- */
        .sp-events-wrap {
            margin: 40px auto;
            padding: 0 20px;
            font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, Oxygen, Ubuntu, sans-serif;
        }

        /* ================================================================ */
        /* FILTER BAR                                                        */
        /* ================================================================ */
        .sp-events-filters {
            margin-bottom: 24px;
            padding-bottom: 16px;
            border-bottom: 1px solid #eee;
        }
        .sp-events-filter-form {
            display: flex;
            flex-direction: column;
            gap: 12px;
        }
        .sp-events-filter-row {
            display: flex;
            flex-wrap: wrap;
            gap: 8px;
            align-items: center;
        }
        .sp-events-search-wrap {
            flex: 1;
            min-width: 200px;
        }
        .sp-events-search-input {
            width: 100%;
            padding: 10px 14px;
            font-size: 16px;
            border: 2px solid #ddd;
            border-radius: 6px;
            outline: none;
            transition: border-color 0.2s;
            box-sizing: border-box;
        }
        .sp-events-search-input:focus {
            border-color: var(--sp-color-primary);
        }
        .sp-events-filter-select {
            padding: 10px 12px;
            font-size: 15px;
            border: 2px solid #ddd;
            border-radius: 6px;
            background: #fff;
            cursor: pointer;
        }
        .sp-events-filter-btn {
            padding: 10px 24px;
            font-size: 15px;
            font-weight: 600;
            color: #fff;
            background: var(--sp-color-primary);
            border: none;
            border-radius: 6px;
            cursor: pointer;
        }
        .sp-events-filter-btn:hover { background: var(--sp-color-primary-hover); }
        .sp-events-clear-link {
            font-size: 14px;
            color: #666;
            text-decoration: none;
            padding: 10px 8px;
        }
        .sp-events-clear-link:hover { color: #d63638; }

        /* View toggle */
        .sp-events-view-toggle {
            display: flex;
            gap: 4px;
        }
        .sp-view-btn {
            padding: 8px 16px;
            font-size: 14px;
            font-weight: 500;
            color: #555;
            text-decoration: none;
            border: 2px solid #ddd;
            border-radius: 6px;
            transition: all 0.15s;
        }
        .sp-view-btn:hover { border-color: var(--sp-color-primary); color: var(--sp-color-primary); }
        .sp-view-active {
            background: var(--sp-color-primary);
            color: #fff !important;
            border-color: var(--sp-color-primary);
        }
        .sp-view-icon { margin-right: 4px; }

        /* ================================================================ */
        /* EVENT CARDS (List View)                                           */
        /* ================================================================ */
        .sp-events-count {
            margin-bottom: 8px;
            color: #787c82;
            font-size: 14px;
        }
        .sp-events-list {
            display: flex;
            flex-direction: column;
            gap: 12px;
        }
        .sp-event-card {
            border: 1px solid #e8e8e8;
            border-radius: 8px;
            background: #fff;
            transition: box-shadow 0.2s, border-color 0.2s;
        }
        .sp-event-card:hover {
            box-shadow: 0 2px 8px rgba(0,0,0,0.08);
            border-color: #ccc;
        }
        .sp-event-card-link {
            display: flex;
            align-items: stretch;
            text-decoration: none;
            color: inherit;
        }
        .sp-event-date-block {
            display: flex;
            flex-direction: column;
            align-items: center;
            justify-content: center;
            min-width: 80px;
            padding: 16px 12px;
            background: #f7f7f7;
            border-radius: 8px 0 0 8px;
            border-right: 1px solid #e8e8e8;
        }
        .sp-event-month {
            font-size: 12px;
            font-weight: 600;
            text-transform: uppercase;
            color: #d63638;
            letter-spacing: 0.5px;
        }
        .sp-event-day {
            font-size: 28px;
            font-weight: 700;
            line-height: 1.1;
            color: #1d2327;
        }
        .sp-event-dow {
            font-size: 12px;
            color: #787c82;
            text-transform: uppercase;
        }
        .sp-event-details {
            flex: 1;
            padding: 16px 20px;
            min-width: 0;
        }
        .sp-event-title {
            margin: 0 0 6px 0;
            font-size: 17px;
            font-weight: 600;
            color: #1d2327;
            line-height: 1.3;
        }
        .sp-event-meta {
            display: flex;
            flex-wrap: wrap;
            gap: 12px;
            margin-bottom: 8px;
        }
        .sp-event-meta-item {
            font-size: 14px;
            color: #555;
        }
        .sp-event-badges {
            display: flex;
            flex-wrap: wrap;
            gap: 6px;
            align-items: center;
        }
        .sp-event-badge {
            display: inline-block;
            padding: 3px 10px;
            font-size: 12px;
            font-weight: 600;
            color: #fff;
            border-radius: 4px;
            white-space: nowrap;
        }
        .sp-badge-postponed { background: #dba617; }
        .sp-badge-members { background: #787c82; }
        .sp-badge-external { background: #2271b1; }
        .sp-event-price {
            font-size: 13px;
            font-weight: 600;
            color: #1d2327;
        }
        .sp-event-free { color: #00a32a; }
        .sp-event-reg-info {
            font-size: 12px;
            color: #787c82;
        }

        /* ================================================================ */
        /* CALENDAR VIEW                                                     */
        /* ================================================================ */
        .sp-calendar-wrap {
            margin-top: 8px;
        }
        .sp-calendar-nav {
            display: flex;
            align-items: center;
            justify-content: space-between;
            margin-bottom: 16px;
        }
        .sp-cal-nav-btn {
            padding: 8px 16px;
            font-size: 14px;
            font-weight: 500;
            color: var(--sp-color-primary);
            text-decoration: none;
            border: 2px solid #ddd;
            border-radius: 6px;
        }
        .sp-cal-nav-btn:hover { border-color: var(--sp-color-primary); }
        .sp-cal-month-label {
            margin: 0;
            font-size: 22px;
            font-weight: 600;
            color: #1d2327;
        }
        .sp-calendar-grid {
            display: grid;
            grid-template-columns: repeat(7, 1fr);
            border: 1px solid #e0e0e0;
            border-radius: 8px;
            overflow: hidden;
        }
        .sp-cal-header {
            padding: 10px;
            font-size: 13px;
            font-weight: 600;
            text-align: center;
            color: #555;
            background: #f7f7f7;
            border-bottom: 1px solid #e0e0e0;
        }
        .sp-cal-day {
            min-height: 100px;
            padding: 6px;
            border-right: 1px solid #eee;
            border-bottom: 1px solid #eee;
            background: #fff;
            position: relative;
        }
        .sp-cal-day:nth-child(7n) { border-right: none; }
        .sp-cal-empty { background: #fafafa; }
        .sp-cal-today {
            background: #f0f7fd;
        }
        .sp-cal-today .sp-cal-day-num {
            background: var(--sp-color-primary);
            color: #fff;
            border-radius: 50%;
            width: 26px;
            height: 26px;
            display: inline-flex;
            align-items: center;
            justify-content: center;
        }
        .sp-cal-day-num {
            font-size: 13px;
            font-weight: 600;
            color: #555;
            margin-bottom: 4px;
        }
        .sp-cal-events {
            display: flex;
            flex-direction: column;
            gap: 2px;
        }
        .sp-cal-event {
            display: block;
            padding: 2px 6px;
            border-radius: 3px;
            color: #fff;
            text-decoration: none;
            font-size: 11px;
            line-height: 1.3;
            overflow: hidden;
            white-space: nowrap;
            text-overflow: ellipsis;
            transition: opacity 0.15s;
        }
        .sp-cal-event:hover { opacity: 0.85; }
        /* Notice-only events: no pointer, slightly transparent to signal "informational" */
        .sp-cal-event--notice { opacity: 0.75; cursor: default; }
        .sp-cal-event--notice:hover { opacity: 0.75; }
        /* External events: subtle dashed border so Harold can distinguish at a glance */
        .sp-cal-event--external { border: 1px dashed rgba(255,255,255,0.5); }
        .sp-cal-event-title { font-weight: 500; }
        .sp-cal-event-time {
            font-size: 10px;
            opacity: 0.85;
            margin-left: 4px;
        }

        /* Mobile dots (hidden on desktop) */
        .sp-cal-dots { display: none; }
        .sp-cal-dot {
            display: inline-block;
            width: 6px;
            height: 6px;
            border-radius: 50%;
            margin: 1px;
        }

        /* Mobile panel for calendar day tap */
        .sp-cal-mobile-panel {
            margin-top: 12px;
            border: 1px solid #e0e0e0;
            border-radius: 8px;
            background: #fff;
            overflow: hidden;
        }
        .sp-cal-mobile-panel-header {
            display: flex;
            justify-content: space-between;
            align-items: center;
            padding: 12px 16px;
            background: #f7f7f7;
            border-bottom: 1px solid #e0e0e0;
            font-weight: 600;
        }
        .sp-cal-mobile-close {
            background: none;
            border: none;
            font-size: 22px;
            cursor: pointer;
            color: #555;
            padding: 0 4px;
        }
        .sp-cal-mobile-event {
            display: block;
            padding: 12px 16px;
            border-bottom: 1px solid #eee;
            text-decoration: none;
            color: inherit;
        }
        .sp-cal-mobile-event:last-child { border-bottom: none; }
        .sp-cal-mobile-event-title {
            font-weight: 600;
            color: #1d2327;
        }
        .sp-cal-mobile-event-time {
            font-size: 13px;
            color: #787c82;
            margin-top: 2px;
        }

        /* ================================================================ */
        /* EVENT DETAIL PAGE                                                 */
        /* ================================================================ */
        .sp-event-back {
            margin-bottom: 20px;
        }
        .sp-event-back a {
            color: var(--sp-color-primary);
            text-decoration: none;
            font-size: 15px;
        }
        .sp-event-back a:hover { text-decoration: underline; }

        .sp-event-detail {
            max-width: 800px;
        }
        .sp-event-header { margin-bottom: 24px; }
        .sp-event-cancelled-banner,
        .sp-event-postponed-banner {
            padding: 12px 16px;
            border-radius: 6px;
            font-weight: 600;
            margin-bottom: 16px;
        }
        .sp-event-cancelled-banner {
            background: #fce4e4;
            color: #d63638;
            border: 1px solid #f5c6c6;
        }
        .sp-event-postponed-banner {
            background: #fff8e5;
            color: #996800;
            border: 1px solid #f0d68a;
        }
        .sp-event-detail-title {
            margin: 0 0 12px 0;
            font-size: 28px;
            font-weight: 700;
            color: #1d2327;
            line-height: 1.2;
        }
        .sp-event-detail-badges {
            display: flex;
            flex-wrap: wrap;
            gap: 8px;
        }
        .sp-event-image {
            margin-bottom: 24px;
        }
        .sp-event-image img {
            width: 100%;
            max-width: 800px;
            height: auto;
            border-radius: 8px;
        }

        /* Key details (date, location) */
        .sp-event-key-details {
            display: flex;
            flex-direction: column;
            gap: 16px;
            padding: 20px;
            background: #f7f7f7;
            border-radius: 8px;
            margin-bottom: 24px;
        }
        .sp-event-detail-item {
            display: flex;
            gap: 12px;
            align-items: flex-start;
        }
        .sp-detail-icon {
            font-size: 20px;
            flex-shrink: 0;
            width: 28px;
            text-align: center;
        }
        .sp-detail-secondary { color: #555; font-size: 14px; }
        .sp-detail-virtual { color: var(--sp-color-primary); font-weight: 500; }
        .sp-virtual-link {
            color: var(--sp-color-primary);
            font-weight: 500;
            text-decoration: none;
        }
        .sp-virtual-link:hover { text-decoration: underline; }

        /* Add to Calendar link */
        .sp-add-to-cal-link {
            color: var(--sp-color-primary);
            font-weight: 500;
            text-decoration: none;
            font-size: 15px;
        }
        .sp-add-to-cal-link:hover { text-decoration: underline; }

        /* Separator between "Add to Calendar" and "Subscribe" */
        .sp-detail-separator {
            margin: 0 8px;
            color: #999;
            font-size: 14px;
        }
        /* On the detail page, the subscribe dropdown should align inline */
        .sp-event-add-to-cal .sp-ical-subscribe-wrap {
            display: inline-block;
            vertical-align: middle;
        }
        .sp-event-add-to-cal .sp-ical-subscribe-btn {
            padding: 4px 12px;
            font-size: 13px;
            border-width: 1px;
        }
        .sp-event-add-to-cal .sp-ical-dropdown {
            left: 0;
            right: auto;
        }

        /* Description */
        .sp-event-description {
            margin-bottom: 24px;
            font-size: 16px;
            line-height: 1.7;
            color: #333;
        }

        /* Speakers section */
        .sp-event-speakers {
            margin-bottom: 24px;
        }
        .sp-event-speakers h2 {
            font-size: 20px;
            margin: 0 0 16px 0;
        }
        .sp-speaker-card {
            display: flex;
            gap: 16px;
            padding: 16px;
            background: #f7f7f7;
            border-radius: 8px;
            margin-bottom: 12px;
        }
        .sp-speaker-photo {
            width: 80px;
            height: 80px;
            border-radius: 50%;
            object-fit: cover;
            flex-shrink: 0;
        }
        .sp-speaker-info {
            flex: 1;
        }
        .sp-speaker-name {
            margin: 0 0 2px 0;
            font-size: 16px;
            font-weight: 600;
            color: #1d2327;
        }
        .sp-speaker-title {
            margin: 0 0 4px 0;
            font-size: 14px;
            color: #555;
        }
        .sp-speaker-role {
            display: inline-block;
            padding: 1px 8px;
            background: #e0e0e0;
            color: #555;
            border-radius: 3px;
            font-size: 12px;
            margin-bottom: 6px;
        }
        .sp-speaker-bio {
            margin: 6px 0 0 0;
            font-size: 14px;
            line-height: 1.5;
            color: #3c434a;
        }
        .sp-speaker-website {
            color: var(--sp-color-primary);
            text-decoration: none;
            font-size: 13px;
        }
        .sp-speaker-website:hover { text-decoration: underline; }

        /* Registration section */
        .sp-event-registration {
            padding: 24px;
            background: #f7f7f7;
            border-radius: 8px;
            margin-bottom: 24px;
        }
        .sp-event-registration h2 {
            margin: 0 0 16px 0;
            font-size: 20px;
        }
        .sp-event-pricing {
            margin-bottom: 16px;
        }
        .sp-price-item {
            display: flex;
            gap: 8px;
            margin-bottom: 4px;
            font-size: 15px;
        }
        .sp-price-label { color: #555; }
        .sp-price-amount { font-weight: 600; }
        .sp-price-free { color: #00a32a; }
        .sp-price-note {
            font-size: 13px;
            color: #787c82;
            margin-top: 4px;
        }

        /* Capacity bar */
        .sp-event-capacity { margin-bottom: 16px; }
        .sp-capacity-bar {
            height: 8px;
            background: #e0e0e0;
            border-radius: 4px;
            overflow: hidden;
            margin-bottom: 6px;
        }
        .sp-capacity-fill {
            height: 100%;
            border-radius: 4px;
            transition: width 0.3s;
        }
        .sp-capacity-text {
            font-size: 14px;
            color: #555;
            margin: 0;
        }

        .sp-reg-confirmed {
            padding: 16px;
            background: #edf7ed;
            border: 1px solid #c3e6c3;
            border-radius: 6px;
        }
        .sp-reg-confirmed p { margin: 0; }
        .sp-reg-note { font-size: 13px; color: #555; margin-top: 4px !important; }

        /* Registration form */
        .sp-reg-form {
            margin-top: 8px;
        }
        .sp-reg-form-intro {
            font-size: 14px;
            color: #555;
            margin-bottom: 12px;
        }
        .sp-reg-form-intro a { color: var(--sp-color-primary); }
        .sp-reg-form-row {
            margin-bottom: 12px;
        }
        .sp-reg-form-row label {
            display: block;
            font-size: 14px;
            font-weight: 500;
            margin-bottom: 4px;
            color: #333;
        }
        .sp-required { color: #d63638; }
        .sp-reg-optional { color: #787c82; font-weight: normal; font-size: 13px; }
        .sp-reg-form-row input[type="text"],
        .sp-reg-form-row input[type="email"],
        .sp-reg-form-row input[type="tel"] {
            width: 100%;
            max-width: 400px;
            padding: 8px 12px;
            border: 1px solid #c3c4c7;
            border-radius: 4px;
            font-size: 15px;
            font-family: inherit;
        }
        .sp-reg-form-row input:focus {
            border-color: var(--sp-color-primary);
            outline: none;
            box-shadow: 0 0 0 1px var(--sp-color-primary);
        }
        .sp-reg-form-row select {
            padding: 8px 12px;
            border: 1px solid #c3c4c7;
            border-radius: 4px;
            font-size: 15px;
            font-family: inherit;
            background: #fff;
        }
        .sp-reg-submit-btn {
            display: inline-block;
            padding: 12px 32px;
            background: var(--sp-color-primary);
            color: #fff;
            border: none;
            border-radius: 4px;
            font-size: 16px;
            font-weight: 500;
            cursor: pointer;
            font-family: inherit;
            transition: background 0.15s;
        }
        .sp-reg-submit-btn:hover { background: var(--sp-color-primary-hover); }
        .sp-reg-submit-btn:disabled {
            background: #a7aaad;
            cursor: not-allowed;
        }
        .sp-reg-cancel-btn {
            display: inline-block;
            margin-top: 12px;
            padding: 6px 16px;
            background: none;
            color: #d63638;
            border: 1px solid #d63638;
            border-radius: 4px;
            font-size: 13px;
            cursor: pointer;
            font-family: inherit;
            transition: all 0.15s;
        }
        .sp-reg-cancel-btn:hover {
            background: #d63638;
            color: #fff;
        }
        .sp-reg-cancel-btn:disabled {
            opacity: 0.5;
            cursor: not-allowed;
        }
        .sp-reg-message {
            margin-top: 8px;
            padding: 8px 12px;
            border-radius: 4px;
            font-size: 14px;
        }
        .sp-reg-msg-error {
            background: #fcf0f1;
            border: 1px solid #d63638;
            color: #d63638;
        }
        .sp-reg-msg-success {
            background: #edf7ed;
            border: 1px solid #c3e6c3;
            color: #00a32a;
        }
        .sp-reg-login-prompt {
            padding: 12px 16px;
            background: #f0f6fc;
            border: 1px solid #c3d9ed;
            border-radius: 6px;
            color: var(--sp-color-primary);
            font-size: 14px;
        }
        .sp-reg-login-prompt a { color: var(--sp-color-primary); font-weight: 500; }

        /* Fee summary — shows cost before they click Register */
        .sp-reg-fee-summary {
            display: flex;
            align-items: center;
            flex-wrap: wrap;
            gap: 6px;
            padding: 10px 14px;
            background: #fef8e8;
            border: 1px solid #e5c76b;
            border-radius: 6px;
            margin-bottom: 16px;
            font-size: 14px;
        }
        .sp-fee-label { font-weight: 600; color: #1d2327; }
        .sp-fee-amount { font-weight: 700; font-size: 16px; color: #1d2327; }
        .sp-fee-per-person { color: #787c82; font-size: 12px; }
        .sp-fee-note { color: #666; font-size: 12px; font-style: italic; }

        /* Payment option buttons — "either" mode shows two side-by-side */
        .sp-reg-pay-options {
            display: flex;
            gap: 10px;
            flex-wrap: wrap;
        }
        .sp-reg-pay-options .sp-reg-submit-btn {
            flex: 1;
            min-width: 140px;
        }
        .sp-pay-online-btn {
            background: var(--sp-color-primary) !important;
        }
        .sp-pay-online-btn:hover {
            background: var(--sp-color-primary-hover) !important;
        }
        .sp-pay-door-btn {
            background: #50575e !important;
        }
        .sp-pay-door-btn:hover {
            background: #3c4043 !important;
        }

        /* Contact section */
        .sp-event-contact {
            padding: 24px;
            background: #f7f7f7;
            border-radius: 8px;
            margin-bottom: 24px;
        }
        /* Time Slots display cards */
.sp-event-slots-section {
    margin: 24px 0;
}
.sp-event-slots-section h2 {
    font-size: 1.3em;
    margin-bottom: 12px;
}
.sp-event-slots-grid {
    display: grid;
    grid-template-columns: repeat(auto-fill, minmax(220px, 1fr));
    gap: 12px;
}
.sp-event-slot-card {
    padding: 12px 16px;
    border: 1px solid var(--sp-color-border, #e5e7eb);
    border-radius: 6px;
    background: var(--sp-color-bg, #fff);
}
.sp-event-slot-card.sp-slot-full {
    opacity: 0.65;
    border-color: #d63638;
}
.sp-slot-time {
    font-weight: 600;
    font-size: 1.05em;
    margin-bottom: 4px;
}
.sp-slot-desc {
    color: var(--sp-color-text-secondary, #6b7280);
    font-size: 0.9em;
    margin-bottom: 4px;
}
.sp-slot-capacity {
    font-size: 0.85em;
    color: var(--sp-color-text-secondary, #6b7280);
}
.sp-slot-full-label {
    color: #d63638;
    font-weight: 600;
}

.sp-event-contact h2 {
            margin: 0 0 12px 0;
            font-size: 20px;
        }
        .sp-event-contact p { margin: 0 0 4px 0; }
        .sp-contact-name { font-weight: 600; }
        .sp-event-contact a { color: var(--sp-color-primary); text-decoration: none; }
        .sp-event-contact a:hover { text-decoration: underline; }

        /* Not found / login required */
        .sp-event-not-found,
        .sp-event-login-required {
            text-align: center;
            padding: 60px 20px;
        }
        .sp-event-not-found h2,
        .sp-event-login-required h2 {
            font-size: 24px;
            margin-bottom: 8px;
        }
        .sp-events-empty {
            text-align: center;
            padding: 40px 20px;
            color: #787c82;
        }

        /* External event detail card — shown when an event lives on another site */
        .sp-event-external-card {
            max-width: 700px;
            margin: 0 auto 40px;
            padding: 32px;
            background: #fff;
            border: 2px solid #e0e0e0;
            border-radius: 12px;
            box-shadow: 0 2px 8px rgba(0,0,0,0.06);
        }
        .sp-event-external-badge {
            display: inline-block;
            background: #2271b1;
            color: #fff;
            font-size: 12px;
            font-weight: 600;
            padding: 3px 10px;
            border-radius: 4px;
            margin-bottom: 12px;
            text-transform: uppercase;
            letter-spacing: 0.5px;
        }
        .sp-external-event-btn {
            display: inline-block;
            padding: 14px 28px;
            background: var(--sp-color-primary, #2271b1);
            color: #fff;
            text-decoration: none;
            border-radius: 8px;
            font-size: 16px;
            font-weight: 600;
            transition: background 0.2s;
        }
        .sp-external-event-btn:hover {
            opacity: 0.9;
            color: #fff;
        }

        /* ================================================================ */
        /* PAGINATION (shared with directory)                                */
        /* ================================================================ */
        .sp-events-pagination {
            display: flex;
            gap: 4px;
            justify-content: center;
            align-items: center;
            margin-top: 24px;
            padding-top: 16px;
            border-top: 1px solid #eee;
        }

        /* ================================================================ */
        /* TOOLBAR — View toggle + Subscribe button alignment                */
        /* ================================================================ */
        .sp-events-toolbar {
            display: flex;
            align-items: center;
            justify-content: space-between;
            flex-wrap: wrap;
            gap: 8px;
        }

        /* ================================================================ */
        /* SUBSCRIBE TO CALENDAR — Dropdown UI                               */
        /* ================================================================ */
        .sp-ical-subscribe-wrap {
            position: relative;
