        .sp-ical-copy-row {
            display: flex;
            gap: 4px;
            margin-bottom: 6px;
        }
        .sp-ical-url-input {
            flex: 1;
            padding: 6px 8px;
            font-size: 12px;
            border: 1px solid var(--sp-color-border, #ddd);
