/**
 * Output the calendar mobile-tap JavaScript.
 *
 * WHY: On mobile, the full event titles are hidden and replaced with dots.
 *      Tapping a day cell opens a panel below the calendar that lists the
 *      day's events. This JS is identical to what's in sp_events_frontend_scripts()
 *      but isolated so it can be loaded independently for the Page Builder
 *      widget and standalone calendar template.
 */
function sp_events_calendar_scripts(): void {
    ?>
    <script id="sp-calendar-widget-js">
    (function() {
        'use strict';

        // ---- Calendar mobile: tap day to show events panel ----
        var calDays = document.querySelectorAll('.sp-cal-has-events');
        var panel   = document.getElementById('sp-cal-mobile-panel');
        var panelDate   = document.getElementById('sp-cal-mobile-date');
        var panelEvents = document.getElementById('sp-cal-mobile-events');
        var closeBtn    = document.getElementById('sp-cal-mobile-close');

        if (calDays.length && panel) {
            calDays.forEach(function(day) {
                day.addEventListener('click', function(e) {
                    // Only on mobile (when dots are visible)
                    if (window.innerWidth > 768) return;

                    // Don't intercept link clicks inside event titles
                    if (e.target.closest('.sp-cal-event')) return;

                    var dayNum = this.querySelector('.sp-cal-day-num').textContent;
                    var monthLabel = document.querySelector('.sp-cal-month-label');
                    panelDate.textContent = monthLabel ? monthLabel.textContent + ' ' + dayNum : 'Day ' + dayNum;

                    // Build event list from the hidden .sp-cal-events links
                    var events = this.querySelectorAll('.sp-cal-event');
                    var html = '';
                    events.forEach(function(ev) {
                        var title = ev.querySelector('.sp-cal-event-title');
                        var time  = ev.querySelector('.sp-cal-event-time');
                        var href  = ev.href || '#';
                        html += '<a class="sp-cal-mobile-event" href="' + href + '">';
                        html += '<div class="sp-cal-mobile-event-title">' + (title ? title.textContent : '') + '</div>';
                        if (time) {
                            html += '<div class="sp-cal-mobile-event-time">' + time.textContent + '</div>';
                        }
                        html += '</a>';
                    });
                    panelEvents.innerHTML = html;
                    panel.style.display = 'block';
                    panel.scrollIntoView({ behavior: 'smooth', block: 'nearest' });
                });
            });

            if (closeBtn) {
                closeBtn.addEventListener('click', function() {
                    panel.style.display = 'none';
                });
            }
        }
    })();
    </script>
    <?php
}


// ============================================================================
// STRIPE PAYMENT INTEGRATION
// ============================================================================
//
// WHY: Societies that charge for workshops, seminars, or annual events need a
//      way to collect payment online. We use Stripe Checkout (hosted) — the
//      registrant clicks "Pay Now," gets redirected to Stripe's secure page,
//      enters their card, and comes back. The society's site never touches
//      credit card numbers, which means zero PCI compliance work.
//
// ARCHITECTURE:
//   1. sp_stripe_is_configured() — checks if API keys exist
//   2. sp_stripe_get_secret_key() — returns the active secret key (test/live)
//   3. sp_create_stripe_checkout_session() — calls Stripe API to create session
//   4. sp_handle_stripe_return() — processes the redirect back from Stripe
//   5. sp_test_stripe_connection AJAX — admin "Test Connection" button
//   6. sp_admin_refund_payment AJAX — admin refund button
//
// The society admin provides their own Stripe API keys in Settings > Events.
// SocietyPress never touches the money — it goes straight to the society's
// Stripe account.
// ============================================================================


/**
 * Check whether Stripe API keys are configured.
 *
 * WHY: Several places need to know if Stripe is ready — the registration form
 *      (to decide which buttons to show), the AJAX handler (to validate), and
 *      the settings page (to show connection status). One function, one truth.
 *
 * @param array $settings The societypress_settings option array.
 * @return bool True if both publishable and secret keys are set.
 */
function sp_stripe_is_configured( array $settings ): bool {
    $test_mode = ! empty( $settings['stripe_test_mode'] );
    $pub_key   = $test_mode
        ? ( $settings['stripe_test_publishable_key'] ?? '' )
        : ( $settings['stripe_live_publishable_key'] ?? '' );
    $secret    = $test_mode
        ? ( $settings['stripe_test_secret_key'] ?? '' )
        : ( $settings['stripe_live_secret_key'] ?? '' );
    return ! empty( $pub_key ) && ! empty( $secret );
}


/**
 * Get the active Stripe secret key (test or live depending on mode).
 *
 * @param array $settings The societypress_settings option array.
 * @return string The secret key, or empty string if not configured.
 */
function sp_stripe_get_secret_key( array $settings ): string {
    $test_mode = ! empty( $settings['stripe_test_mode'] );
    return $test_mode
        ? ( $settings['stripe_test_secret_key'] ?? '' )
        : ( $settings['stripe_live_secret_key'] ?? '' );
}


/**
 * Create a Stripe Checkout Session for an event registration payment.
 *
 * WHY: Stripe Checkout is a hosted payment page. We tell Stripe "charge $X for
 *      event Y" and it gives us a URL. The registrant goes there, enters their
 *      card on Stripe's secure page, and Stripe redirects them back to our site
 *      when done. This eliminates PCI compliance entirely — our server never
 *      sees a credit card number.
 *
 * We use the Stripe REST API directly via wp_remote_post() instead of the PHP
 * SDK to avoid adding a Composer dependency. The API is simple enough for our
 * use case — we only need Checkout Sessions and Refunds.
 *
 * @param object $event            The event row from sp_events.
 * @param int    $registration_id  The new registration ID.
 * @param float  $fee_amount       Total fee to charge.
 * @param array  $settings         The societypress_settings option array.
 * @return string|WP_Error         The checkout URL on success, WP_Error on failure.
 */
function sp_create_stripe_checkout_session( object $event, int $registration_id, float $fee_amount, array $settings ) {
    $secret_key = sp_stripe_get_secret_key( $settings );
    if ( empty( $secret_key ) ) {
        return new WP_Error( 'stripe_not_configured', __( 'Stripe is not configured.', 'societypress' ) );
    }

    $currency = $settings['stripe_currency'] ?? 'usd';

    // Stripe expects amounts in the smallest currency unit (cents for USD)
    // WHY: $25.00 becomes 2500. This is a Stripe convention to avoid
    //      floating-point rounding issues.
    $amount_cents = (int) round( $fee_amount * 100 );

    // Build the return URLs
    // WHY: After the customer pays (or cancels), Stripe redirects them back to
    //      our event detail page with query parameters so we know what happened.
    //      We include the registration_id so we can look up and update the record.
    $events_page_id = 0;
    $pages = get_pages( [ 'meta_key' => '_wp_page_template', 'meta_value' => 'sp-events' ] );
    if ( ! empty( $pages ) ) {
        $events_page_id = $pages[0]->ID;
    }

    $base_url = $events_page_id
        ? add_query_arg( 'sp_event', $event->slug, get_permalink( $events_page_id ) )
        : home_url();

    $success_url = add_query_arg( [
        'sp_payment' => 'success',
        'sp_session' => '{CHECKOUT_SESSION_ID}',
    ], $base_url );

    $cancel_url = add_query_arg( [
        'sp_payment' => 'cancelled',
    ], $base_url );

    // Build the line item description
    $site_name = get_bloginfo( 'name' );
    $line_item_name = $event->title;
    if ( strlen( $line_item_name ) > 100 ) {
        $line_item_name = substr( $line_item_name, 0, 97 ) . '...';
    }

    // Call the Stripe API to create a Checkout Session
    $response = wp_remote_post( 'https://api.stripe.com/v1/checkout/sessions', [
        'timeout' => 30,
        'headers' => [
            'Authorization' => 'Bearer ' . $secret_key,
            'Content-Type'  => 'application/x-www-form-urlencoded',
        ],
        'body' => [
            'payment_method_types[0]' => 'card',
            'mode'                    => 'payment',
            'success_url'             => $success_url,
            'cancel_url'              => $cancel_url,
            'client_reference_id'     => (string) $registration_id,
            'metadata[registration_id]' => (string) $registration_id,
            'metadata[event_id]'        => (string) $event->id,
            'metadata[site_url]'        => home_url(),
            'line_items[0][price_data][currency]'     => $currency,
            'line_items[0][price_data][unit_amount]'   => $amount_cents,
            'line_items[0][price_data][product_data][name]' => $line_item_name,
            'line_items[0][price_data][product_data][description]' =>
                /* translators: %1$s: event title, %2$s: site name */
                sprintf( __( 'Registration for %1$s — %2$s', 'societypress' ), $event->title, $site_name ),
            'line_items[0][quantity]' => 1,
        ],
    ] );

    if ( is_wp_error( $response ) ) {
        return new WP_Error( 'stripe_api_error', __( 'Could not connect to payment processor. Please try again.', 'societypress' ) );
    }

    $body = json_decode( wp_remote_retrieve_body( $response ), true );
    $code = wp_remote_retrieve_response_code( $response );

    if ( $code !== 200 || empty( $body['url'] ) ) {
        $error_msg = $body['error']['message'] ?? 'Payment setup failed. Please try again.';
        error_log( 'SocietyPress Stripe error: ' . $error_msg );
        return new WP_Error( 'stripe_session_error', __( 'Could not set up payment. Please try again or choose to pay at the door.', 'societypress' ) );
    }

    // Store the Stripe session ID on the registration for later verification
    global $wpdb;
    $wpdb->update(
        $wpdb->prefix . 'sp_event_registrations',
        [ 'notes' => 'stripe_session:' . $body['id'] ],
        [ 'id' => $registration_id ]
    );

    return $body['url'];
}


/**
 * Handle the return from Stripe Checkout.
 *
 * WHY: After paying on Stripe's page, the customer is redirected back to the
 *      event detail page with ?sp_payment=success&sp_session=cs_xxx in the URL.
 *      We verify the session with Stripe's API, confirm the payment actually
 *      went through, and update the registration record accordingly.
 *
 *      This runs early (on template_redirect) so the registration is already
 *      updated by the time the page renders — the frontend JS just shows a
 *      "Payment received" message based on the URL parameter.
 */
add_action( 'template_redirect', function () {
    // Only process Stripe returns on the events page
    if ( ! is_page() || get_page_template_slug() !== 'sp-events' ) return;

    $payment_status = sanitize_text_field( $_GET['sp_payment'] ?? '' );
    $session_id     = sanitize_text_field( $_GET['sp_session'] ?? '' );

    // Only handle successful returns with a session ID
    if ( $payment_status !== 'success' || empty( $session_id ) ) return;

    $settings   = get_option( 'societypress_settings', [] );
    $secret_key = sp_stripe_get_secret_key( $settings );

    if ( empty( $secret_key ) ) return;

    // Verify the Checkout Session with Stripe
    // WHY: We never trust the URL parameters alone — an attacker could craft a
    //      fake success URL. We call Stripe's API to confirm the session exists
    //      and payment actually succeeded before marking anything as paid.
    $response = wp_remote_get( 'https://api.stripe.com/v1/checkout/sessions/' . $session_id, [
        'timeout' => 15,
        'headers' => [
            'Authorization' => 'Bearer ' . $secret_key,
        ],
    ] );

    if ( is_wp_error( $response ) ) return;

    $body = json_decode( wp_remote_retrieve_body( $response ), true );

    if ( empty( $body['payment_status'] ) || $body['payment_status'] !== 'paid' ) return;

    // Find the registration from the session metadata
    $registration_id = (int) ( $body['client_reference_id'] ?? 0 );
    if ( ! $registration_id ) return;

    global $wpdb;
    $reg_table = $wpdb->prefix . 'sp_event_registrations';

    // Only update if still in pending payment status
    // WHY: Prevents double-processing if the user refreshes the success page
    //      or if a webhook fires at the same time (future enhancement).
    $reg = $wpdb->get_row( $wpdb->prepare(
        "SELECT * FROM {$reg_table} WHERE id = %d", $registration_id
    ) );

    if ( ! $reg || $reg->payment_status === 'paid' ) return;

    $wpdb->update(
        $reg_table,
        [
            'payment_status' => 'paid',
            'payment_method' => 'stripe',
            'payment_date'   => current_time( 'mysql' ),
            'notes'          => 'stripe_session:' . $session_id . '|stripe_pi:' . ( $body['payment_intent'] ?? '' ),
        ],
        [ 'id' => $registration_id ]
    );

    // Send confirmation email now that payment is confirmed
    // WHY: For Stripe payments, we hold the confirmation email until payment
    //      actually goes through. Nobody wants a "you're registered!" email
    //      followed by "just kidding, your card was declined."
    $event = $wpdb->get_row( $wpdb->prepare(
        "SELECT * FROM {$wpdb->prefix}sp_events WHERE id = %d", $reg->event_id
    ) );

    if ( $event ) {
        $recipient_email = '';
        if ( $reg->user_id ) {
            $user = get_userdata( $reg->user_id );
            $recipient_email = $user ? $user->user_email : '';
        } elseif ( $reg->guest_email ) {
            $recipient_email = $reg->guest_email;
        }
        if ( $recipient_email ) {
            sp_send_registration_email(
                $event, $registration_id, 'confirmed',
                $recipient_email, (int) $reg->party_size, (float) $reg->fee_amount
            );
        }
    }
} );


// ============================================================================
// EVENTS — iCAL HELPERS (shared between .ics download + subscription feed)
// ============================================================================
//
// WHY: Both the single-event .ics download and the calendar subscription feed
//      need to produce identical, RFC 5545-compliant output. Extracting these
//      helpers into standalone functions avoids duplication and ensures any
//      future fix to iCal formatting applies everywhere at once.
// ============================================================================

/**
 * RFC 5545 line folding — lines must not exceed 75 octets.
 *
 * WHY: Some calendar apps (notably Outlook) strictly enforce this limit.
 *      We fold long lines by inserting CRLF + space at the 75-byte boundary.
 *      mb_strlen/mb_substr with UTF-8 encoding prevent splitting multibyte
 *      characters (e.g., accented names, CJK) mid-byte, which would produce
 *      invalid UTF-8 and corrupt text in calendar apps.
 *
 * @param string $line A single iCal content line (property + value).
 * @return string The line folded to comply with the 75-octet rule.
 */
function sp_ical_fold_line( string $line ): string {
    if ( mb_strlen( $line, 'UTF-8' ) <= 75 ) return $line;
    $folded = '';
    while ( mb_strlen( $line, 'UTF-8' ) > 75 ) {
        if ( $folded === '' ) {
            $folded .= mb_substr( $line, 0, 75, 'UTF-8' );
            $line    = mb_substr( $line, 75, null, 'UTF-8' );
        } else {
            // Continuation lines start with a space (counts toward the 75)
            $folded .= "\r\n " . mb_substr( $line, 0, 74, 'UTF-8' );
            $line    = mb_substr( $line, 74, null, 'UTF-8' );
        }
    }
    if ( $line !== '' ) {
        $folded .= "\r\n " . $line;
    }
    return $folded;
}

/**
 * Escape iCal text values per RFC 5545 §3.3.11.
 *
 * WHY: Semicolons, commas, and backslashes have special meaning in iCal
 *      property values. Without escaping, an event titled "Meet & Greet,
 *      January 5" would break parsing in strict calendar clients.
 *
 * @param string $text Raw text to escape.
 * @return string Text safe for use in iCal property values.
 */
function sp_ical_escape_text( string $text ): string {
    $text = str_replace( '\\', '\\\\', $text );
    $text = str_replace( ';', '\\;', $text );
    $text = str_replace( ',', '\\,', $text );
    return $text;
}

/**
 * Build DTSTART and DTEND lines for an event.
 *
 * WHY: If the event has a start_time, we create a timed event in UTC.
 *      If no time is set, it's treated as an all-day event (DATE format).
 *      All-day DTEND is the day AFTER the event (exclusive end per RFC 5545).
 *
 * @param object $event Event row from the database.
 * @return array Associative array with 'dtstart' and 'dtend' iCal lines.
 */
function sp_ical_build_dt_lines( object $event ): array {
    $event_date = $event->event_date; // YYYY-MM-DD
    $tz         = wp_timezone();

    if ( ! empty( $event->start_time ) ) {
        // Timed event — convert site-local time to UTC for the .ics
        $start_dt = new DateTime( $event_date . ' ' . $event->start_time, $tz );
        $start_dt->setTimezone( new DateTimeZone( 'UTC' ) );

        if ( ! empty( $event->end_time ) ) {
            $end_dt = new DateTime( $event_date . ' ' . $event->end_time, $tz );
            $end_dt->setTimezone( new DateTimeZone( 'UTC' ) );
        } else {
            // No end time — default to 1 hour after start
            $end_dt = clone $start_dt;
            $end_dt->modify( '+1 hour' );
        }

        return [
            'dtstart' => 'DTSTART:' . $start_dt->format( 'Ymd\THis\Z' ),
            'dtend'   => 'DTEND:' . $end_dt->format( 'Ymd\THis\Z' ),
        ];
    }

    // All-day event — use DATE format (no time component)
    $date_val = str_replace( '-', '', $event_date );
    $next_day = date( 'Ymd', strtotime( $event_date . ' +1 day' ) );

    return [
        'dtstart' => 'DTSTART;VALUE=DATE:' . $date_val,
        'dtend'   => 'DTEND;VALUE=DATE:' . $next_day,
    ];
}

/**
 * Build a combined LOCATION string for an event.
 *
 * WHY: Calendar apps display a single location field. Combining venue name,
 *      address, and virtual URL into one comma-separated string gives users
 *      maximum context in their calendar app without needing to open the event.
 *
 * @param object $event Event row from the database.
 * @return string Combined location string (may be empty).
 */
function sp_ical_build_location( object $event ): string {
    $parts = [];
    if ( ! empty( $event->location_name ) ) {
        $parts[] = $event->location_name;
    }
    if ( ! empty( $event->location_address ) ) {
        $parts[] = $event->location_address;
    }
    if ( $event->is_virtual && ! empty( $event->virtual_url ) ) {
        $parts[] = $event->virtual_url;
    }
    return implode( ', ', $parts );
}

/**
 * Build a plain-text DESCRIPTION for an event's iCal entry.
 *
 * WHY: iCal DESCRIPTION is plain text — HTML tags would render as literal
 *      text in calendar apps. We strip tags, normalize line breaks, and
 *      append the virtual meeting URL so members can join directly from
 *      their calendar without navigating back to the website.
 *
 * @param object $event Event row from the database.
 * @return string Plain-text description with iCal-escaped newlines.
 */
function sp_ical_build_description( object $event ): string {
    $description = '';
    if ( ! empty( $event->description ) ) {
        $description = wp_strip_all_tags( $event->description );
        // Normalize line breaks to \n, then escape for iCal
        $description = str_replace( [ "\r\n", "\r" ], "\n", $description );
        $description = str_replace( "\n", "\\n", $description );
    }

    // Add virtual meeting URL to description if available
    if ( $event->is_virtual && ! empty( $event->virtual_url ) ) {
        if ( $description ) {
            $description .= "\\n\\n";
        }
        $description .= __( 'Join online:', 'societypress' ) . ' ' . $event->virtual_url;
    }

    return $description;
}


// ============================================================================
// EVENTS — ADD TO CALENDAR (.ICS DOWNLOAD)
// ============================================================================

/**
 * Serve an .ics file for a single event when ?sp_ics=EVENT_ID is in the URL.
 *
 * WHY: Members want to add society events to their personal calendars (Google,
 *      Apple, Outlook). The simplest, most universal way to do this is an .ics
 *      file — every major calendar app supports it. We intercept early on
 *      template_redirect, generate RFC 5545 compliant VCALENDAR/VEVENT data,
 *      and send it as a file download. No AJAX, no JS dependency — just a link.
 *
 * RFC 5545 compliance notes:
 * - DTSTART/DTEND use YYYYMMDD for all-day events, YYYYMMDDTHHmmssZ for timed
 * - UID is globally unique per event (site URL + event ID)
 * - DESCRIPTION is plain text (HTML stripped), CRLF line breaks per spec
 * - LOCATION combines venue name + address for maximum calendar app compatibility
 * - Lines longer than 75 octets are folded per RFC 5545 §3.1
 *
 * Now uses the shared sp_ical_* helper functions defined above, so formatting
 * stays in sync with the calendar subscription feed.
 */
add_action( 'template_redirect', function () {
    if ( ! isset( $_GET['sp_ics'] ) ) return;

    $event_id = (int) $_GET['sp_ics'];
    if ( $event_id < 1 ) return;

    global $wpdb;
    $event = $wpdb->get_row( $wpdb->prepare(
        "SELECT * FROM {$wpdb->prefix}sp_events WHERE id = %d",
        $event_id
    ) );

    if ( ! $event ) {
        wp_die( __( 'Event not found.', 'societypress' ), 404 );
    }

    // Visibility check — members_only events require login
    if ( $event->visibility === 'members_only' && ! is_user_logged_in() ) {
        wp_die( __( 'You must be logged in to download this event.', 'societypress' ), 403 );
    }

    // Build date/time, location, and description using shared helpers
    $dt          = sp_ical_build_dt_lines( $event );
    $location    = sp_ical_build_location( $event );
    $description = sp_ical_build_description( $event );

    // Unique ID per event — required by RFC 5545
    // WHY: Calendar apps use UID to detect updates vs new events. Using the
    //      site URL + event ID guarantees uniqueness across installations.
    $uid     = 'sp-event-' . $event->id . '@' . wp_parse_url( home_url(), PHP_URL_HOST );
    $dtstamp = gmdate( 'Ymd\THis\Z' );

    // Build the iCal content using shared helpers
    $lines = [
        'BEGIN:VCALENDAR',
        'VERSION:2.0',
        'PRODID:-//SocietyPress//Events//EN',
        'CALSCALE:GREGORIAN',
        'METHOD:PUBLISH',
        'BEGIN:VEVENT',
        sp_ical_fold_line( 'UID:' . $uid ),
        'DTSTAMP:' . $dtstamp,
        sp_ical_fold_line( $dt['dtstart'] ),
        sp_ical_fold_line( $dt['dtend'] ),
        sp_ical_fold_line( 'SUMMARY:' . sp_ical_escape_text( $event->title ) ),
    ];

    if ( $location ) {
        $lines[] = sp_ical_fold_line( 'LOCATION:' . sp_ical_escape_text( $location ) );
    }
    if ( $description ) {
        $lines[] = sp_ical_fold_line( 'DESCRIPTION:' . sp_ical_escape_text( $description ) );
    }

    // Add URL — use external_url if set (the event lives on another site),
    // otherwise link to the SocietyPress event detail page.
    // WHY: Some calendar apps (Google Calendar, Apple Calendar) show a clickable
    //      "More Info" link when URL is present — drives people back to the site.
    if ( ! empty( $event->external_url ) ) {
        $lines[] = sp_ical_fold_line( 'URL:' . $event->external_url );
    } else {
        $events_page_id = $wpdb->get_var(
            "SELECT p.ID FROM {$wpdb->posts} p
             INNER JOIN {$wpdb->postmeta} pm ON p.ID = pm.post_id
             WHERE pm.meta_key = '_wp_page_template' AND pm.meta_value = 'sp-events'
             AND p.post_status = 'publish' LIMIT 1"
        );
        if ( $events_page_id ) {
            $event_url = add_query_arg( 'sp_event', $event->slug, get_permalink( $events_page_id ) );
            $lines[]   = sp_ical_fold_line( 'URL:' . $event_url );
        }
    }

    $lines[] = 'END:VEVENT';
    $lines[] = 'END:VCALENDAR';

    // Use CRLF line endings per RFC 5545
    $ics_content = implode( "\r\n", $lines ) . "\r\n";

    // Sanitize filename — strip non-alphanumeric characters for safety
    $safe_title = sanitize_file_name( $event->title );
    $filename   = $safe_title . '.ics';

    // Send headers and content
    header( 'Content-Type: text/calendar; charset=utf-8' );
    header( 'Content-Disposition: attachment; filename="' . $filename . '"' );
    header( 'Content-Length: ' . strlen( $ics_content ) );
    header( 'Cache-Control: no-cache, no-store, must-revalidate' );
    echo $ics_content;
    exit;
} );


// ============================================================================
// EVENTS — iCAL CALENDAR SUBSCRIPTION FEED
// ============================================================================

/**
 * Serve an iCal feed that calendar apps (Google Calendar, Apple Calendar,
 * Outlook) can subscribe to for automatic event updates.
 *
 * Two modes:
 *   - Public: ?sp_ical_feed=public — only public-visibility events
 *   - Members-only: ?sp_ical_feed=TOKEN — includes members-only events
 *
 * WHY: Unlike the single-event .ics download (which adds one event), a
 *      subscription feed lets calendar apps poll this URL periodically and
 *      automatically show new/changed/removed events. This is the standard
 *      way calendar apps stay synced — Google Calendar, Apple Calendar, and
 *      Outlook all support it natively.
 *
 * We cache the output as a transient for 1 hour and invalidate whenever
 * events are created, updated, or deleted (see cache invalidation calls
 * in the save/delete handlers).
 *
 * Priority 5 so this runs early on template_redirect, before template loading.
 */
add_action( 'template_redirect', function () {
    if ( ! isset( $_GET['sp_ical_feed'] ) ) return;

    $feed_param = sanitize_text_field( $_GET['sp_ical_feed'] );
    if ( ! $feed_param ) return;

    // Bail if the events module is disabled
    if ( ! sp_module_enabled( 'events' ) ) return;

    // Bail with 404 if the admin has turned off the iCal feed
    // WHY: We default to enabled (1) so the feed works out of the box on new
    //      installations before the admin has visited the Events settings page.
    $settings = get_option( 'societypress_settings', [] );
    if ( empty( $settings['events_ical_feed_enabled'] ?? 1 ) ) {
        status_header( 404 );
        exit;
    }

    global $wpdb;
    $prefix             = $wpdb->prefix . 'sp_';
    $include_members_only = false;
    $transient_key      = 'sp_ical_feed_public';

    if ( $feed_param !== 'public' ) {
        // Authenticated feed — look up the token in user_meta.
        // WHY: Calendar apps can't send WordPress auth cookies, so each member
        //      gets an opaque token in their feed URL. We validate it here by
        //      checking if any user has this token stored as sp_ical_token.
        $users = get_users( [
            'meta_key'   => 'sp_ical_token',
            'meta_value' => $feed_param,
            'number'     => 1,
            'fields'     => 'ID',
        ] );
        if ( empty( $users ) ) {
            status_header( 403 );
            wp_die( esc_html__( 'Invalid calendar feed URL.', 'societypress' ) );
        }
        $include_members_only = true;
        $transient_key        = 'sp_ical_feed_members';
    }

    // Check transient cache — avoid regenerating the feed on every poll
    $cached = get_transient( $transient_key );
    if ( $cached !== false ) {
        header( 'Content-Type: text/calendar; charset=utf-8' );
        header( 'Cache-Control: public, max-age=3600' );
        echo $cached;
        exit;
    }

    // Query events: next 12 months + past 30 days
    // WHY: Past 30 days ensures recently-passed events still show in the
    //      calendar (some members check "what was that event last week?").
    //      12 months forward covers the typical planning horizon.
    $date_start = wp_date( 'Y-m-d', strtotime( '-30 days' ) );
    $date_end   = wp_date( 'Y-m-d', strtotime( '+12 months' ) );

    $visibility_sql = $include_members_only
        ? ""
        : " AND e.visibility = 'public'";

    // phpcs:ignore WordPress.DB.PreparedSQL.InterpolatedNotPrepared -- $visibility_sql is static
    $events = $wpdb->get_results( $wpdb->prepare(
        "SELECT e.* FROM {$prefix}events e
         WHERE e.status != 'cancelled'
         AND (e.notice_only = 0 OR e.notice_only IS NULL)
         AND e.event_date >= %s
         AND e.event_date <= %s
         {$visibility_sql}
         ORDER BY e.event_date ASC",
        $date_start,
        $date_end
    ) );

    // Build the VCALENDAR wrapper
    $site_name = get_bloginfo( 'name' );
    $cal_name  = $include_members_only
        ? $site_name . ' ' . __( 'Events (Members)', 'societypress' )
        : $site_name . ' ' . __( 'Events', 'societypress' );

    $output  = "BEGIN:VCALENDAR\r\n";
    $output .= "VERSION:2.0\r\n";
    $output .= "PRODID:-//SocietyPress//Events//EN\r\n";
    $output .= "CALSCALE:GREGORIAN\r\n";
    $output .= "METHOD:PUBLISH\r\n";
    $output .= sp_ical_fold_line( "X-WR-CALNAME:" . sp_ical_escape_text( $cal_name ) ) . "\r\n";
    // REFRESH-INTERVAL tells compliant calendar apps to re-fetch every hour
    $output .= "REFRESH-INTERVAL;VALUE=DURATION:PT1H\r\n";
    // X-PUBLISHED-TTL is the legacy equivalent for older apps (Outlook, etc.)
    $output .= "X-PUBLISHED-TTL:PT1H\r\n";

    $host = wp_parse_url( home_url(), PHP_URL_HOST );

    // Look up the events page once for building event URLs
    $events_page_id = $wpdb->get_var(
        "SELECT p.ID FROM {$wpdb->posts} p
         INNER JOIN {$wpdb->postmeta} pm ON p.ID = pm.post_id
         WHERE pm.meta_key = '_wp_page_template' AND pm.meta_value = 'sp-events'
         AND p.post_status = 'publish' LIMIT 1"
    );

    foreach ( $events as $event ) {
        $dt          = sp_ical_build_dt_lines( $event );
        $location    = sp_ical_build_location( $event );
        $description = sp_ical_build_description( $event );

        $output .= "BEGIN:VEVENT\r\n";
        $output .= sp_ical_fold_line( "UID:sp-event-{$event->id}@{$host}" ) . "\r\n";
        $output .= "DTSTAMP:" . gmdate( 'Ymd\THis\Z' ) . "\r\n";
        $output .= sp_ical_fold_line( $dt['dtstart'] ) . "\r\n";
        $output .= sp_ical_fold_line( $dt['dtend'] ) . "\r\n";
        $output .= sp_ical_fold_line( "SUMMARY:" . sp_ical_escape_text( $event->title ) ) . "\r\n";

        if ( $location ) {
            $output .= sp_ical_fold_line( "LOCATION:" . sp_ical_escape_text( $location ) ) . "\r\n";
        }
        if ( $description ) {
            $output .= sp_ical_fold_line( "DESCRIPTION:" . sp_ical_escape_text( $description ) ) . "\r\n";
        }

        // Link — use external_url if set (manual or imported events that live on
        // another site), otherwise link to the SocietyPress event detail page.
        if ( ! empty( $event->external_url ) ) {
            $output .= sp_ical_fold_line( "URL:" . $event->external_url ) . "\r\n";
        } elseif ( $events_page_id && ! empty( $event->slug ) ) {
            $event_url = add_query_arg( 'sp_event', $event->slug, get_permalink( $events_page_id ) );
            $output .= sp_ical_fold_line( "URL:" . $event_url ) . "\r\n";
        }

        $output .= "END:VEVENT\r\n";
    }

    $output .= "END:VCALENDAR\r\n";

    // Cache for 1 hour — calendar apps will get stale data at most 1 hour
    set_transient( $transient_key, $output, HOUR_IN_SECONDS );

    // Serve the feed
    header( 'Content-Type: text/calendar; charset=utf-8' );
    header( 'Cache-Control: public, max-age=3600' );
    echo $output;
    exit;
}, 5 );


// ============================================================================
// EVENTS — iCAL TOKEN MANAGEMENT
// ============================================================================
//
// WHY: Calendar apps can't send WordPress cookies, so members need a unique,
//      opaque token in their feed URL. These functions handle creating, reading,
//      and regenerating that token. Regeneration is exposed via AJAX so members
//      can revoke old URLs if they're compromised or shared accidentally.
// ============================================================================

/**
 * Get or create a per-user iCal feed token.
 *
 * WHY: We lazily create the token the first time a member views their feed URL.
 *      This avoids creating tokens for members who never use the feature.
 *
 * @param int $user_id WordPress user ID.
 * @return string The 32-character alphanumeric token.
 */
function sp_get_or_create_ical_token( int $user_id ): string {
    $token = get_user_meta( $user_id, 'sp_ical_token', true );
    if ( ! $token ) {
        // wp_generate_password with $special_chars=false, $extra_special_chars=true
        // gives us a URL-safe alphanumeric string that's unpredictable enough
        // to serve as a bearer token for a calendar feed.
        $token = wp_generate_password( 32, false, false );
        update_user_meta( $user_id, 'sp_ical_token', $token );
    }
    return $token;
}

/**
 * Regenerate a user's iCal feed token, invalidating the old URL.
 *
 * WHY: If a member accidentally shares their feed URL (which contains their
 *      token), they can regenerate it. The old URL stops working immediately,
 *      and they get a fresh one to paste into their calendar app.
 *
 * @param int $user_id WordPress user ID.
 * @return string The new 32-character token.
 */
function sp_regenerate_ical_token( int $user_id ): string {
    $token = wp_generate_password( 32, false, false );
    update_user_meta( $user_id, 'sp_ical_token', $token );
    return $token;
}

/**
 * AJAX: Regenerate the current user's iCal feed token.
 *
 * WHY: Called from the subscribe dropdown when a member clicks "Regenerate URL."
 *      Returns the new URL so JS can update the display without a page reload.
 */
add_action( 'wp_ajax_sp_regenerate_ical_token', function () {
    check_ajax_referer( 'sp_ical_token', 'nonce' );

    if ( ! is_user_logged_in() ) {
        wp_send_json_error( [ 'message' => __( 'You must be logged in.', 'societypress' ) ] );
    }

    $token = sp_regenerate_ical_token( get_current_user_id() );
    $url   = home_url( '?sp_ical_feed=' . $token );

    wp_send_json_success( [
        'url'     => $url,
        'message' => __( 'Feed URL regenerated. Update your calendar app with the new URL.', 'societypress' ),
    ] );
} );


// ============================================================================
// STRIPE — TEST CONNECTION AJAX HANDLER
// ============================================================================

/**
 * AJAX: Test that the saved Stripe API keys are valid.
 *
 * WHY: Harold just pasted two cryptic strings and has no idea if they work.
 *      This makes a tiny API call to Stripe (retrieve account balance) that
 *      will succeed with valid keys and fail with invalid ones. The admin gets
 *      an instant green checkmark or red X — no guessing.
 */
add_action( 'wp_ajax_sp_test_stripe_connection', function () {
    if ( ! check_ajax_referer( 'sp_stripe_test', 'nonce', false ) ) {
        wp_send_json_error( __( 'Security check failed.', 'societypress' ) );
    }

    if ( ! current_user_can( 'manage_options' ) ) {
        wp_send_json_error( __( 'Permission denied.', 'societypress' ) );
    }

    $settings   = get_option( 'societypress_settings', [] );
    $secret_key = sp_stripe_get_secret_key( $settings );

    if ( empty( $secret_key ) ) {
        wp_send_json_error( __( 'No API keys found. Please enter your keys and save settings first.', 'societypress' ) );
    }

    // Call Stripe's /v1/balance endpoint — the simplest authenticated call
    // WHY: If we can retrieve the account balance, the key is valid. This
    //      endpoint is cheap, fast, and doesn't create or modify anything.
    $response = wp_remote_get( 'https://api.stripe.com/v1/balance', [
        'timeout' => 15,
        'headers' => [
            'Authorization' => 'Bearer ' . $secret_key,
        ],
    ] );

    if ( is_wp_error( $response ) ) {
        wp_send_json_error( __( 'Could not reach Stripe. Please check your internet connection.', 'societypress' ) );
    }

    $code = wp_remote_retrieve_response_code( $response );
    $body = json_decode( wp_remote_retrieve_body( $response ), true );

    if ( $code === 200 ) {
        wp_send_json_success();
    } elseif ( $code === 401 ) {
        wp_send_json_error( __( 'Invalid API key. Please double-check your keys in Stripe dashboard.', 'societypress' ) );
    } else {
        /* translators: %d: HTTP status code from Stripe API */
        $msg = $body['error']['message'] ?? sprintf( __( 'Unexpected error (HTTP %d)', 'societypress' ), $code );
        wp_send_json_error( $msg );
    }
} );


// ============================================================================
// STRIPE — ADMIN REFUND HANDLER
// ============================================================================

/**
 * AJAX: Issue a full refund for a Stripe payment.
 *
 * WHY: Sometimes an event gets cancelled, someone can't make it after paying,
 *      or there's a billing dispute. The admin needs a one-click refund button
 *      right in the registrations table — they shouldn't have to log into
 *      Stripe's dashboard to find the payment and refund it manually.
 */
add_action( 'wp_ajax_sp_admin_refund_payment', function () {
    if ( ! check_ajax_referer( 'sp_admin_registration', 'nonce', false ) ) {
        wp_send_json_error( __( 'Security check failed.', 'societypress' ) );
    }

    if ( ! current_user_can( 'manage_options' ) ) {
        wp_send_json_error( __( 'Permission denied.', 'societypress' ) );
    }

    global $wpdb;
    $reg_table = $wpdb->prefix . 'sp_event_registrations';

    $registration_id = (int) ( $_POST['registration_id'] ?? 0 );
    if ( ! $registration_id ) {
        wp_send_json_error( __( 'Invalid registration.', 'societypress' ) );
    }

    $reg = $wpdb->get_row( $wpdb->prepare(
        "SELECT * FROM {$reg_table} WHERE id = %d", $registration_id
    ) );

    if ( ! $reg ) {
        wp_send_json_error( __( 'Registration not found.', 'societypress' ) );
    }

    if ( $reg->payment_status !== 'paid' || $reg->payment_method !== 'stripe' ) {
        wp_send_json_error( __( 'This registration was not paid via Stripe.', 'societypress' ) );
    }

    // Extract the Stripe PaymentIntent ID from the notes field
    // WHY: We stored it as "stripe_session:cs_xxx|stripe_pi:pi_xxx" when the
    //      payment was confirmed. The PaymentIntent ID is what Stripe needs to
    //      process a refund.
    $payment_intent = '';
    if ( preg_match( '/stripe_pi:(\S+)/', $reg->notes ?? '', $matches ) ) {
        $payment_intent = $matches[1];
    }

    if ( empty( $payment_intent ) ) {
        wp_send_json_error( __( 'Could not find payment reference. Please refund manually in Stripe dashboard.', 'societypress' ) );
    }

    $settings   = get_option( 'societypress_settings', [] );
    $secret_key = sp_stripe_get_secret_key( $settings );

    if ( empty( $secret_key ) ) {
        wp_send_json_error( __( 'Stripe is not configured.', 'societypress' ) );
    }

    // Call Stripe's Refund API
    $response = wp_remote_post( 'https://api.stripe.com/v1/refunds', [
        'timeout' => 30,
        'headers' => [
            'Authorization' => 'Bearer ' . $secret_key,
            'Content-Type'  => 'application/x-www-form-urlencoded',
        ],
        'body' => [
            'payment_intent' => $payment_intent,
        ],
    ] );

    if ( is_wp_error( $response ) ) {
        wp_send_json_error( __( 'Could not connect to Stripe. Please try again.', 'societypress' ) );
    }

    $body = json_decode( wp_remote_retrieve_body( $response ), true );
    $code = wp_remote_retrieve_response_code( $response );

    // WHY: Stripe refunds can return 'succeeded' (instant) or 'pending' (bank
    //      processing delay). Both are valid success states — 'pending' just means
    //      the funds haven't cleared yet, but the refund is committed.
    $status = $body['status'] ?? '';
    if ( $code === 200 && in_array( $status, [ 'succeeded', 'pending' ], true ) ) {
        // Update registration to reflect the refund
        $wpdb->update(
            $reg_table,
            [
                'payment_status' => 'refunded',
                'notes'          => $reg->notes . '|refund:' . ( $body['id'] ?? 'unknown' ),
            ],
            [ 'id' => $registration_id ]
        );
        $message = ( $status === 'pending' )
            ? __( 'Refund initiated — processing with payment provider.', 'societypress' )
            : __( 'Refund processed successfully.', 'societypress' );
        wp_send_json_success( [ 'message' => $message ] );
    } else {
        $error_msg = $body['error']['message'] ?? 'Refund failed (HTTP ' . $code . ')';
        wp_send_json_error( $error_msg );
    }
} );


// ============================================================================
// PAGE BUILDER — FRONTEND WIDGET RENDERERS (NEW FEATURES)
// ============================================================================

/**
 * Render: Community Link
 *
 * WHY: Feature 1 — a simple styled card/button that links to an external
 *      community forum (Facebook group, Discord, etc.). If no URL is configured
 *      in Settings > Organization, visitors see nothing and admins see a notice.
 */
function sp_render_builder_widget_community_link( array $s ): void {
    $settings = get_option( 'societypress_settings', [] );
    $url      = $settings['community_forum_url'] ?? '';
    $label    = $s['label'] ?? __( 'Join Our Community', 'societypress' );
    $desc     = $s['description'] ?? __( 'Connect with fellow members in our online community.', 'societypress' );
    $style    = $s['button_style'] ?? 'primary';

    if ( empty( $url ) ) {
        // Only show a notice to admins — visitors see nothing
        if ( current_user_can( 'manage_options' ) ) {
            echo '<div class="sp-widget-community-link" style="padding:20px; background:#fef9e7; border:1px dashed #d4a017; border-radius:8px; text-align:center;">';
            echo '<p style="margin:0; color:#8a6d00;">' . esc_html__( 'Community Forum URL not configured.', 'societypress' ) . ' <a href="' . esc_url( admin_url( 'admin.php?page=sp-settings-organization' ) ) . '">' . esc_html__( 'Set it in Settings &rarr; Organization', 'societypress' ) . '</a>.</p>';
            echo '</div>';
        }
        return;
    }

    echo '<div class="sp-widget-community-link" style="text-align:center; padding:32px; background:linear-gradient(135deg, #f0f7ff 0%, #e8f4f8 100%); border-radius:12px;">';
    echo '<h3 style="margin:0 0 8px; font-size:22px; color:#1d2327;">' . esc_html( $label ) . '</h3>';
    if ( $desc ) {
        echo '<p style="margin:0 0 20px; color:#555; font-size:16px;">' . esc_html( $desc ) . '</p>';
    }
    echo '<a href="' . esc_url( $url ) . '" target="_blank" rel="noopener noreferrer" class="sp-btn sp-btn-' . esc_attr( $style ) . '" style="font-size:16px;">';
    echo esc_html( $label ) . ' &rarr;</a>';
    echo '</div>';
}

/**
 * Render: Newsletter Archive
 *
 * WHY: Feature 8 — shows recent posts from the "Newsletter" category so
 *      Harold can publish newsletter summaries as regular blog posts and
 *      have them appear on any page via the Page Builder.
 */
function sp_render_builder_widget_newsletter_archive( array $s ): void {
    $login_required = $s['login_required'] ?? false;
    if ( $login_required && ! is_user_logged_in() ) {
        echo '<div class="sp-widget-login-required">';
        echo '<p>' . esc_html__( 'Please', 'societypress' ) . ' <a href="' . esc_url( wp_login_url( get_permalink() ) ) . '">' . esc_html__( 'log in', 'societypress' ) . '</a> ' . esc_html__( 'to view newsletters.', 'societypress' ) . '</p>';
        echo '</div>';
        return;
    }

    $count        = max( 1, (int) ( $s['count'] ?? 5 ) );
    $show_excerpt = $s['show_excerpt'] ?? true;
    $show_date    = $s['show_date'] ?? true;

    // Get the Newsletter category — created on activation
    $cat = get_category_by_slug( 'newsletter' );
    if ( ! $cat ) {
        if ( current_user_can( 'manage_options' ) ) {
            echo '<p style="color:#8a6d00; padding:12px; background:#fef9e7; border-radius:6px;">' . esc_html__( 'Newsletter category not found. Try deactivating and reactivating the plugin.', 'societypress' ) . '</p>';
        }
        return;
    }

    $posts = get_posts( [
        'category'       => $cat->term_id,
        'posts_per_page' => $count,
        'post_status'    => 'publish',
        'orderby'        => 'date',
        'order'          => 'DESC',
    ] );

    echo '<div class="sp-widget-newsletter-archive">';
    if ( empty( $posts ) ) {
        echo '<p style="color:#666; font-style:italic;">' . esc_html__( 'No newsletters published yet.', 'societypress' ) . '</p>';
    } else {
        echo '<ul style="list-style:none; margin:0; padding:0;">';
        foreach ( $posts as $post ) {
            echo '<li style="padding:16px 0; border-bottom:1px solid #eee;">';
            echo '<a href="' . esc_url( get_permalink( $post ) ) . '" style="font-size:17px; font-weight:600; color:var(--sp-color-primary); text-decoration:none;">';
            echo esc_html( $post->post_title ) . '</a>';
            if ( $show_date ) {
                echo '<span style="display:block; color:#999; font-size:13px; margin-top:2px;">'
                   . esc_html( get_the_date( '', $post ) ) . '</span>';
            }
            if ( $show_excerpt && $post->post_excerpt ) {
                echo '<p style="margin:6px 0 0; color:#555; font-size:14px;">' . esc_html( $post->post_excerpt ) . '</p>';
            }
            echo '</li>';
        }
        echo '</ul>';
    }
    echo '</div>';
}

/**
 * Render: Volunteer Stats
 *
 * WHY: Feature 4 — a public-facing widget showing volunteer activity.
 *      Highlights the community's collective effort with total hours,
 *      active volunteer count, and optionally top contributors.
 */
function sp_render_builder_widget_volunteer_stats( array $s ): void {
    global $wpdb;
    $prefix = $wpdb->prefix . 'sp_';

    $show_count = $s['show_count'] ?? true;
    $show_hours = $s['show_hours'] ?? true;
    $show_top   = $s['show_top_volunteers'] ?? false;
    $period     = $s['time_period'] ?? 'year';

    // Build date constraint based on time period
    $date_clause = '';
    if ( $period === 'year' ) {
        $date_clause = $wpdb->prepare( ' AND vh.activity_date >= %s', date( 'Y-01-01' ) );
    } elseif ( $period === 'month' ) {
        $date_clause = $wpdb->prepare( ' AND vh.activity_date >= %s', date( 'Y-m-01' ) );
    }
    // 'all' = no date constraint

    $stats_html = [];

    if ( $show_count ) {
        $active_count = (int) $wpdb->get_var(
            "SELECT COUNT(DISTINCT vr.user_id) FROM {$prefix}volunteer_roles vr WHERE vr.status = 'active'"
        );
        $stats_html[] = '<div style="text-align:center; flex:1; min-width:140px;">'
                      . '<div style="font-size:36px; font-weight:700; color:var(--sp-color-primary);">' . number_format( $active_count ) . '</div>'
                      . '<div style="font-size:14px; color:#666; margin-top:4px;">' . esc_html__( 'Active Volunteers', 'societypress' ) . '</div></div>';
    }

    if ( $show_hours ) {
        $total_hours = (float) $wpdb->get_var(
            "SELECT COALESCE(SUM(vh.hours), 0) FROM {$prefix}volunteer_hours vh WHERE 1=1{$date_clause}"
        );
        $period_label = $period === 'year' ? __( 'This Year', 'societypress' ) : ( $period === 'month' ? __( 'This Month', 'societypress' ) : __( 'All Time', 'societypress' ) );
        $stats_html[] = '<div style="text-align:center; flex:1; min-width:140px;">'
                      . '<div style="font-size:36px; font-weight:700; color:var(--sp-color-primary);">' . number_format( $total_hours, 1 ) . '</div>'
                      . '<div style="font-size:14px; color:#666; margin-top:4px;">' . esc_html__( 'Hours', 'societypress' ) . ' ' . esc_html( $period_label ) . '</div></div>';
    }

    echo '<div class="sp-widget-volunteer-stats">';
    if ( ! empty( $stats_html ) ) {
        echo '<div style="display:flex; flex-wrap:wrap; gap:24px; justify-content:center; margin-bottom:' . ( $show_top ? '24px' : '0' ) . ';">';
        echo implode( '', $stats_html );
        echo '</div>';
    }

    if ( $show_top ) {
        $top = $wpdb->get_results(
            "SELECT vh.user_id, m.first_name, m.last_name, SUM(vh.hours) as total_hours
             FROM {$prefix}volunteer_hours vh
             INNER JOIN {$prefix}members m ON vh.user_id = m.user_id
             WHERE 1=1{$date_clause}
             GROUP BY vh.user_id, m.first_name, m.last_name
             ORDER BY total_hours DESC
             LIMIT 5"
        );
        if ( ! empty( $top ) ) {
            echo '<h4 style="margin:0 0 12px; font-size:16px; color:#1d2327;">' . esc_html__( 'Top Contributors', 'societypress' ) . '</h4>';
            echo '<ol style="margin:0; padding:0 0 0 20px;">';
            foreach ( $top as $v ) {
                echo '<li style="padding:4px 0; font-size:15px;">';
                echo esc_html( $v->first_name . ' ' . $v->last_name );
                echo ' <span style="color:#666;">(' . number_format( (float) $v->total_hours, 1 ) . ' hrs)</span>';
                echo '</li>';
            }
            echo '</ol>';
        }
    }
    echo '</div>';
}


/**
 * Render: Photo Gallery
 *
 * WHY: Feature 5 — displays photo albums or a single album's images on the
 *      frontend. Uses a pure CSS :target lightbox so it works without
 *      JavaScript and is fully accessible.
 */
function sp_render_builder_widget_photo_gallery( array $s ): void {
    global $wpdb;
    $prefix = $wpdb->prefix . 'sp_';

    $login_required = $s['login_required'] ?? false;
    if ( $login_required && ! is_user_logged_in() ) {
        echo '<div class="sp-widget-login-required">';
        echo '<p>' . esc_html__( 'Please', 'societypress' ) . ' <a href="' . esc_url( wp_login_url( get_permalink() ) ) . '">' . esc_html__( 'log in', 'societypress' ) . '</a> ' . esc_html__( 'to view photos.', 'societypress' ) . '</p>';
        echo '</div>';
        return;
    }

    $display_mode = $s['display_mode'] ?? 'albums';
    $album_id     = absint( $s['album_id'] ?? 0 );
    $columns      = max( 2, min( 6, (int) ( $s['columns'] ?? 3 ) ) );
    $count        = max( 1, (int) ( $s['count'] ?? 12 ) );

    echo '<div class="sp-widget-photo-gallery">';

    if ( $display_mode === 'single' && $album_id ) {
        // Single album view — show photos in a grid
        $album = $wpdb->get_row( $wpdb->prepare(
            "SELECT * FROM {$prefix}photo_albums WHERE id = %d", $album_id
        ) );
        if ( ! $album ) {
            echo '<p style="color:#666;">' . esc_html__( 'Album not found.', 'societypress' ) . '</p></div>';
            return;
        }

        // Visibility check
        if ( $album->visibility === 'members_only' && ! is_user_logged_in() ) {
            echo '<p>' . esc_html__( 'Please', 'societypress' ) . ' <a href="' . esc_url( wp_login_url( get_permalink() ) ) . '">' . esc_html__( 'log in', 'societypress' ) . '</a> ' . esc_html__( 'to view this album.', 'societypress' ) . '</p></div>';
            return;
        }

        if ( $album->title ) {
            echo '<h3 style="margin:0 0 16px;">' . esc_html( $album->title ) . '</h3>';
        }
        if ( $album->description ) {
            echo '<p style="color:#555; margin:0 0 16px;">' . esc_html( $album->description ) . '</p>';
        }

        $items = $wpdb->get_results( $wpdb->prepare(
            "SELECT * FROM {$prefix}photo_album_items WHERE album_id = %d ORDER BY sort_order ASC LIMIT %d",
            $album_id, $count
        ) );

        if ( empty( $items ) ) {
            echo '<p style="color:#666; font-style:italic;">' . esc_html__( 'No photos in this album yet.', 'societypress' ) . '</p>';
        } else {
            $col_width = round( 100 / $columns, 2 );
            echo '<div style="display:flex; flex-wrap:wrap; gap:8px;">';
            foreach ( $items as $i => $item ) {
                $img_url   = wp_get_attachment_image_url( $item->attachment_id, 'medium' );
                $full_url  = wp_get_attachment_image_url( $item->attachment_id, 'full' );
                $target_id = 'sp-photo-' . $album_id . '-' . $item->id;

                if ( ! $img_url ) continue;

                // Thumbnail
                echo '<a href="#' . esc_attr( $target_id ) . '" style="width:calc(' . $col_width . '% - 8px); aspect-ratio:1; overflow:hidden; border-radius:6px; display:block;">';
                echo '<img src="' . esc_url( $img_url ) . '" alt="' . esc_attr( $item->caption ?: 'Photo ' . ( $i + 1 ) ) . '" style="width:100%; height:100%; object-fit:cover;" loading="lazy">';
                echo '</a>';

                // CSS :target lightbox — appears when the thumbnail's anchor is clicked
                echo '<div id="' . esc_attr( $target_id ) . '" class="sp-lightbox" style="display:none; position:fixed; inset:0; z-index:100000; background:rgba(0,0,0,0.9); align-items:center; justify-content:center;">';
                echo '<a href="#" style="position:absolute; inset:0; z-index:1;"></a>';
                echo '<img src="' . esc_url( $full_url ?: $img_url ) . '" alt="' . esc_attr( $item->caption ) . '" style="max-width:90vw; max-height:90vh; object-fit:contain; position:relative; z-index:2; border-radius:4px;">';
                if ( $item->caption ) {
                    echo '<p style="position:absolute; bottom:20px; left:50%; transform:translateX(-50%); color:#fff; font-size:14px; z-index:2; background:rgba(0,0,0,0.6); padding:6px 16px; border-radius:4px;">' . esc_html( $item->caption ) . '</p>';
                }
                echo '</div>';
            }
            echo '</div>';

            // CSS for the :target lightbox
            echo '<style>.sp-lightbox:target{display:flex!important;}</style>';
        }
    } else {
        // Albums grid view — show album covers
        $visibility_clause = is_user_logged_in() ? '' : " AND visibility = 'public'";
        $albums = $wpdb->get_results(
            "SELECT * FROM {$prefix}photo_albums WHERE 1=1{$visibility_clause} ORDER BY sort_order ASC, created_at DESC LIMIT {$count}"
        );

        if ( empty( $albums ) ) {
            echo '<p style="color:#666; font-style:italic;">' . esc_html__( 'No photo albums yet.', 'societypress' ) . '</p>';
        } else {
            $col_width = round( 100 / $columns, 2 );
            echo '<div style="display:flex; flex-wrap:wrap; gap:16px;">';
            foreach ( $albums as $album ) {
                $cover_url = $album->cover_image_id
                    ? wp_get_attachment_image_url( $album->cover_image_id, 'medium' )
                    : '';
                $photo_count = (int) $wpdb->get_var( $wpdb->prepare(
                    "SELECT COUNT(*) FROM {$prefix}photo_album_items WHERE album_id = %d", $album->id
                ) );

                echo '<div style="width:calc(' . $col_width . '% - 16px); min-width:200px;">';
                if ( $cover_url ) {
                    echo '<div style="aspect-ratio:4/3; overflow:hidden; border-radius:8px; margin-bottom:8px;">';
                    echo '<img src="' . esc_url( $cover_url ) . '" alt="' . esc_attr( $album->title ) . '" style="width:100%; height:100%; object-fit:cover;" loading="lazy">';
                    echo '</div>';
                } else {
                    echo '<div style="aspect-ratio:4/3; background:#f0f0f0; border-radius:8px; margin-bottom:8px; display:flex; align-items:center; justify-content:center; color:#999;">';
                    echo '<span class="dashicons dashicons-format-gallery" style="font-size:48px; width:48px; height:48px;"></span>';
                    echo '</div>';
                }
                echo '<h4 style="margin:0 0 4px; font-size:16px;">' . esc_html( $album->title ) . '</h4>';
                /* translators: %d: number of photos */
                echo '<span style="color:#666; font-size:13px;">' . sprintf( _n( '%d photo', '%d photos', $photo_count, 'societypress' ), $photo_count ) . '</span>';
                echo '</div>';
            }
            echo '</div>';
        }
    }
    echo '</div>';
}

/**
 * Render: Resource Links
 *
 * WHY: Feature 6 — displays useful genealogy links grouped by category.
 *      Helps members discover external research databases, archives, and
 *      tools that the society recommends.
 */
function sp_render_builder_widget_resource_links( array $s ): void {
    global $wpdb;
    $prefix = $wpdb->prefix . 'sp_';

    $login_required = $s['login_required'] ?? false;
    if ( $login_required && ! is_user_logged_in() ) {
        echo '<div class="sp-widget-login-required">';
        /* translators: %s: login URL */
        echo '<p>' . sprintf( __( 'Please <a href="%s">log in</a> to view resources.', 'societypress' ), esc_url( wp_login_url( get_permalink() ) ) ) . '</p>';
        echo '</div>';
        return;
    }

    $category_id    = absint( $s['category_id'] ?? 0 );
    $featured_only  = $s['featured_only'] ?? false;
    $count          = max( 1, (int) ( $s['count'] ?? 50 ) );
    $show_desc      = $s['show_descriptions'] ?? true;

    $where = [ 'r.active = 1' ];
    if ( $category_id ) {
        $where[] = $wpdb->prepare( 'r.category_id = %d', $category_id );
    }
    if ( $featured_only ) {
        $where[] = 'r.featured = 1';
    }
    $where_sql = implode( ' AND ', $where );

    $resources = $wpdb->get_results(
        "SELECT r.*, rc.name as category_name
         FROM {$prefix}resources r
         LEFT JOIN {$prefix}resource_categories rc ON r.category_id = rc.id
         WHERE {$where_sql}
         ORDER BY rc.sort_order ASC, rc.name ASC, r.sort_order ASC, r.title ASC
         LIMIT {$count}"
    );

    echo '<div class="sp-widget-resource-links">';
    if ( empty( $resources ) ) {
        echo '<p style="color:#666; font-style:italic;">' . esc_html__( 'No resources available yet.', 'societypress' ) . '</p>';
    } else {
        // Group by category for display
        $grouped = [];
        foreach ( $resources as $r ) {
            $cat_name = $r->category_name ?: __( 'Uncategorized', 'societypress' );
            $grouped[ $cat_name ][] = $r;
        }

        foreach ( $grouped as $cat_name => $items ) {
            echo '<div style="margin-bottom:24px;">';
            echo '<h4 style="margin:0 0 12px; font-size:16px; color:#1d2327; border-bottom:2px solid #eee; padding-bottom:8px;">' . esc_html( $cat_name ) . '</h4>';
            echo '<ul style="list-style:none; margin:0; padding:0;">';
            foreach ( $items as $item ) {
                echo '<li style="padding:8px 0; border-bottom:1px solid #f0f0f0;">';
                echo '<a href="' . esc_url( $item->url ) . '" target="_blank" rel="noopener noreferrer" style="font-weight:600; color:var(--sp-color-primary); text-decoration:none; font-size:15px;">';
                echo esc_html( $item->title );
                if ( $item->featured ) {
                    echo ' <span style="background:#fef0c7; color:#92400e; font-size:11px; padding:2px 6px; border-radius:4px; font-weight:500; margin-left:4px;">' . esc_html__( 'Featured', 'societypress' ) . '</span>';
                }
                echo '</a>';
                if ( $show_desc && $item->description ) {
                    echo '<p style="margin:4px 0 0; color:#555; font-size:13px;">' . esc_html( $item->description ) . '</p>';
                }
                echo '</li>';
            }
            echo '</ul></div>';
        }
    }
    echo '</div>';
}

/**
 * Render: Library Catalog (Enhanced Landing Page)
 *
 * WHY: The catalog is the crown jewel of any genealogical society's website.
 *      19,000+ items need a proper landing experience — not just a raw table dump.
 *      Inspired by NEHGS (tabbed search, researcher-focused) and NGS (visual
 *      browsing, cover images, editorial feel). The page has three zones:
 *
 *      1. Collection overview — stats that convey the depth of the collection
 *      2. Tabbed search — keyword/title/author/subject/call# (like an OPAC)
 *      3. Browse sections — media type cards + popular subject tags
 *      4. Results table — the existing paginated, sortable, expandable catalog
 *
 *      Browse sections auto-hide when a search/filter is active so the results
 *      get top billing. They reappear when filters are cleared.
 */
function sp_render_builder_widget_library_catalog( array $s ): void {
    global $wpdb;
    $prefix = $wpdb->prefix . 'sp_';

    // ---- Access control ----
    $login_required = $s['login_required'] ?? false;
    if ( $login_required && ! is_user_logged_in() ) {
        echo '<div class="sp-widget-login-required">';
        echo '<p>' . esc_html__( 'Please', 'societypress' ) . ' <a href="' . esc_url( wp_login_url( get_permalink() ) ) . '">' . esc_html__( 'log in', 'societypress' ) . '</a> ' . esc_html__( 'to browse the catalog.', 'societypress' ) . '</p>';
        echo '</div>';
        return;
    }

    // ---- Widget settings ----
    $show_search    = $s['show_search'] ?? true;
    $show_landing   = $s['show_landing'] ?? true;
    $category_id    = absint( $s['category_id'] ?? 0 );
    $available_only = $s['available_only'] ?? false;
    $per_page       = max( 1, (int) ( $s['count'] ?? 25 ) );

    // ---- Read URL parameters ----
    $search       = isset( $_GET['sp_lib_search'] ) ? sanitize_text_field( $_GET['sp_lib_search'] ) : '';
    $search_field = isset( $_GET['sp_lib_field'] ) ? sanitize_text_field( $_GET['sp_lib_field'] ) : 'keyword';
    $media_filter = isset( $_GET['sp_lib_media'] ) ? sanitize_text_field( $_GET['sp_lib_media'] ) : '';
    $subj_filter  = isset( $_GET['sp_lib_subject'] ) ? sanitize_text_field( $_GET['sp_lib_subject'] ) : '';
    $acq_filter   = isset( $_GET['sp_lib_acq'] ) ? sanitize_text_field( $_GET['sp_lib_acq'] ) : '';
    $sort_by      = isset( $_GET['sp_lib_sort'] ) ? sanitize_text_field( $_GET['sp_lib_sort'] ) : 'title';
    $page_num     = max( 1, absint( $_GET['sp_lib_pg'] ?? 1 ) );

    // Validate search field tab
    $allowed_fields = [ 'keyword', 'title', 'author', 'subject', 'call_number' ];
    if ( ! in_array( $search_field, $allowed_fields, true ) ) {
        $search_field = 'keyword';
    }

    // Validate sort column
    $allowed_sorts = [ 'title', 'author', 'pub_year', 'call_number', 'media_type' ];
    if ( ! in_array( $sort_by, $allowed_sorts, true ) ) {
        $sort_by = 'title';
    }
    $order_sql = 'li.' . $sort_by . ' ASC';
    // For pub_year, newest first is more useful
    if ( $sort_by === 'pub_year' ) {
        $order_sql = 'li.pub_year DESC';
    }

    // ---- Build WHERE clause ----
    $where = [ '1=1' ];
    if ( $category_id ) {
        $where[] = $wpdb->prepare( 'li.category_id = %d', $category_id );
    }
    if ( $available_only ) {
        $where[] = 'li.available = 1';
    }

    // WHY: Tabbed search — instead of one generic search box, let the researcher
    //      target a specific field (title, author, subject, call number) or search
    //      everything (keyword). This mirrors how real library OPACs work and helps
    //      researchers who know exactly what they're looking for.
    if ( $search ) {
        $like = '%' . $wpdb->esc_like( $search ) . '%';
        switch ( $search_field ) {
            case 'title':
                $where[] = $wpdb->prepare( 'li.title LIKE %s', $like );
                break;
            case 'author':
                $where[] = $wpdb->prepare( 'li.author LIKE %s', $like );
                break;
            case 'subject':
                $where[] = $wpdb->prepare( 'li.subject LIKE %s', $like );
                break;
            case 'call_number':
                $where[] = $wpdb->prepare( 'li.call_number LIKE %s', $like );
                break;
            default: // keyword — all fields
                $where[] = $wpdb->prepare(
                    '(li.title LIKE %s OR li.author LIKE %s OR li.call_number LIKE %s OR li.subject LIKE %s OR li.surname LIKE %s OR li.description LIKE %s)',
                    $like, $like, $like, $like, $like, $like
                );
                break;
        }
    }
    if ( $media_filter ) {
        $where[] = $wpdb->prepare( 'li.media_type = %s', $media_filter );
    }
    if ( $subj_filter ) {
        // Subject is comma-separated — match as substring
        $like = '%' . $wpdb->esc_like( $subj_filter ) . '%';
        $where[] = $wpdb->prepare( 'li.subject LIKE %s', $like );
    }
    if ( $acq_filter ) {
        $where[] = $wpdb->prepare( 'li.acq_code = %s', $acq_filter );
    }
    $where_sql = implode( ' AND ', $where );

    // ---- Detect whether any search/filter is active ----
    // WHY: When the user hasn't searched or filtered yet, we show the full landing
    //      page experience (stats, browse cards, subjects). Once they've drilled in,
    //      those sections collapse so results get the spotlight.
    $has_active_filter = ( $search || $media_filter || $subj_filter || $acq_filter );

    // ---- Get dropdown values (always from full catalog, not filtered) ----
    $media_types = $wpdb->get_col( "SELECT DISTINCT media_type FROM {$prefix}library_items WHERE media_type IS NOT NULL AND media_type != '' ORDER BY media_type ASC" );
    $acq_codes   = $wpdb->get_col( "SELECT DISTINCT acq_code FROM {$prefix}library_items WHERE acq_code IS NOT NULL AND acq_code != '' ORDER BY acq_code ASC" );

    // ---- Count + fetch results ----
    $offset = ( $page_num - 1 ) * $per_page;
    $total  = (int) $wpdb->get_var( "SELECT COUNT(*) FROM {$prefix}library_items li WHERE {$where_sql}" );
    $items  = $wpdb->get_results(
        "SELECT li.*, lc.name as category_name
         FROM {$prefix}library_items li
         LEFT JOIN {$prefix}library_categories lc ON li.category_id = lc.id
         WHERE {$where_sql}
         ORDER BY {$order_sql}
         LIMIT {$per_page} OFFSET {$offset}"
    );
    $total_pages = (int) ceil( $total / $per_page );

    // ---- Collection-wide stats (for the landing header) ----
    // WHY: Showing the breadth of the collection upfront — "19,418 items across
    //      6 formats" — immediately tells a researcher this is a serious library,
    //      not a shelf of pamphlets. Cached via transient so we don't re-count
    //      on every page load.
    $stats = get_transient( 'sp_library_catalog_stats' );
    if ( false === $stats ) {
        $total_items = (int) $wpdb->get_var( "SELECT COUNT(*) FROM {$prefix}library_items" );
        $type_counts = $wpdb->get_results(
            "SELECT media_type, COUNT(*) as cnt FROM {$prefix}library_items WHERE media_type IS NOT NULL AND media_type != '' GROUP BY media_type ORDER BY cnt DESC"
        );
        // Top subjects for the tag cloud
        $subject_rows = $wpdb->get_col(
            "SELECT subject FROM {$prefix}library_items WHERE subject IS NOT NULL AND subject != ''"
        );
        $subject_counts = [];
        foreach ( $subject_rows as $subj_raw ) {
            foreach ( explode( ',', $subj_raw ) as $part ) {
                $part = trim( $part );
                if ( $part ) {
                    $subject_counts[ $part ] = ( $subject_counts[ $part ] ?? 0 ) + 1;
                }
            }
        }
        arsort( $subject_counts );

        $stats = [
            'total'          => $total_items,
            'type_counts'    => $type_counts,
            'subject_counts' => array_slice( $subject_counts, 0, 24, true ),
        ];
        // Cache for 1 hour — stats don't change often and the query is expensive
        set_transient( 'sp_library_catalog_stats', $stats, HOUR_IN_SECONDS );
    }

    // Unique ID so multiple catalog widgets on one page don't collide
    $uid = 'sp-catalog-' . wp_rand( 1000, 9999 );

    echo '<div class="sp-widget-library-catalog" id="' . esc_attr( $uid ) . '">';

    // ---- Inline styles ----
    // WHY: Scoped inside the widget so they don't leak into the rest of the page.
    //      Uses CSS custom properties from the design system where available.
    ?>
    <style>
        .sp-widget-library-catalog { font-family: var(--sp-font-body, -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, sans-serif); }

        /* ================================================================
           COLLECTION HEADER — stats bar at the top of the landing page
           ================================================================ */
        .sp-catalog-header { margin-bottom: 32px; }
        .sp-catalog-header h2 {
            font-size: 28px; font-weight: 700; margin: 0 0 8px 0;
            color: var(--sp-color-primary, #1a1a2e);
        }
        .sp-catalog-header .sp-catalog-subtitle {
            font-size: 16px; color: #555; margin: 0 0 20px 0; line-height: 1.5;
        }
        .sp-catalog-stats-bar {
            display: flex; flex-wrap: wrap; gap: 12px;
        }
        .sp-catalog-stat {
            background: #f8f9fa; border: 1px solid #e9ecef; border-radius: 8px;
            padding: 14px 20px; text-align: center; min-width: 100px;
        }
        .sp-catalog-stat-number {
            font-size: 24px; font-weight: 700;
            color: var(--sp-color-primary, #1a1a2e);
            display: block; line-height: 1.2;
        }
        .sp-catalog-stat-label {
            font-size: 12px; color: #666; text-transform: uppercase;
            letter-spacing: 0.04em; font-weight: 500; margin-top: 2px; display: block;
        }

        /* ================================================================
           TABBED SEARCH — OPAC-style search with field targeting
           ================================================================ */
        .sp-catalog-search { margin-bottom: 28px; }
        .sp-catalog-tabs {
            display: flex; gap: 0; border-bottom: 2px solid #d0d5dd; margin-bottom: 0;
        }
        .sp-catalog-tab {
            padding: 10px 18px; font-size: 14px; font-weight: 500; color: #555;
            background: none; border: none; border-bottom: 2px solid transparent;
            margin-bottom: -2px; cursor: pointer; transition: all 0.15s ease;
        }
        .sp-catalog-tab:hover { color: var(--sp-color-primary, #1a1a2e); background: #f8f9fa; }
        .sp-catalog-tab.active {
            color: var(--sp-color-primary, #1a1a2e); font-weight: 600;
            border-bottom-color: var(--sp-color-accent, #667eea);
            background: #f8f9fa;
        }
        .sp-catalog-search-form {
            display: flex; gap: 0; background: #f8f9fa;
            border: 1px solid #d0d5dd; border-top: none;
            border-radius: 0 0 8px 8px; padding: 16px;
        }
        .sp-catalog-search-form input[type="text"] {
            flex: 1; padding: 12px 16px; border: 1px solid #d0d5dd;
            border-radius: 6px 0 0 6px; font-size: 15px;
            border-right: none; background: #fff;
        }
        .sp-catalog-search-form input[type="text"]:focus {
            outline: none; border-color: var(--sp-color-accent, #667eea);
            box-shadow: 0 0 0 2px rgba(102, 126, 234, 0.15);
        }
        .sp-catalog-search-form button[type="submit"] {
            padding: 12px 24px; border: 1px solid var(--sp-color-primary, #1a1a2e);
            background: var(--sp-color-primary, #1a1a2e); color: #fff;
            font-size: 15px; font-weight: 600; cursor: pointer;
            border-radius: 0 6px 6px 0; white-space: nowrap;
            transition: background 0.15s ease;
        }
        .sp-catalog-search-form button[type="submit"]:hover {
            background: var(--sp-color-accent, #667eea);
            border-color: var(--sp-color-accent, #667eea);
        }

        /* Additional filter row below the search bar */
        .sp-catalog-filter-row {
            display: flex; flex-wrap: wrap; gap: 10px; padding: 12px 16px;
            background: #f8f9fa; border: 1px solid #d0d5dd; border-top: none;
            border-radius: 0 0 8px 8px; margin-top: -8px; padding-top: 0;
        }
        .sp-catalog-filter-row select {
            padding: 8px 10px; border: 1px solid #d0d5dd; border-radius: 6px;
            font-size: 13px; background: #fff; min-width: 130px;
        }

        /* ================================================================
           BROWSE SECTIONS — media type cards + subject tag cloud
           ================================================================ */
        .sp-catalog-browse { margin-bottom: 32px; }
        .sp-catalog-browse h3 {
            font-size: 16px; font-weight: 700; margin: 0 0 14px 0;
            color: var(--sp-color-primary, #1a1a2e);
            text-transform: uppercase; letter-spacing: 0.03em;
        }
        .sp-catalog-type-grid {
            display: grid; grid-template-columns: repeat(auto-fill, minmax(150px, 1fr));
            gap: 12px; margin-bottom: 28px;
        }
        .sp-catalog-type-card {
            display: block; background: #fff; border: 1px solid #e0e0e0;
            border-radius: 8px; padding: 18px 14px; text-align: center;
            text-decoration: none; color: inherit;
            transition: all 0.15s ease; cursor: pointer;
        }
        .sp-catalog-type-card:hover {
            border-color: var(--sp-color-accent, #667eea);
            box-shadow: 0 2px 8px rgba(0,0,0,0.08);
            transform: translateY(-1px);
        }
        .sp-catalog-type-card.active {
            border-color: var(--sp-color-accent, #667eea);
            background: #f0f4ff;
        }
        .sp-catalog-type-icon {
            font-size: 28px; display: block; margin-bottom: 8px; line-height: 1;
            color: var(--sp-color-primary, #1a1a2e);
        }
        .sp-catalog-type-name {
            font-size: 14px; font-weight: 600; display: block; margin-bottom: 4px;
            color: var(--sp-color-primary, #1a1a2e);
        }
        .sp-catalog-type-count {
            font-size: 13px; color: #888; display: block;
        }

        /* Subject tag cloud */
        .sp-catalog-subject-cloud { display: flex; flex-wrap: wrap; gap: 8px; }
        .sp-catalog-subject-tag {
            display: inline-block; padding: 6px 14px;
            background: #f0f0f0; border: 1px solid #e0e0e0; border-radius: 20px;
            font-size: 13px; color: #444; text-decoration: none;
            transition: all 0.15s ease;
        }
        .sp-catalog-subject-tag:hover {
            background: var(--sp-color-primary, #1a1a2e); color: #fff;
            border-color: var(--sp-color-primary, #1a1a2e);
        }
        .sp-catalog-subject-tag .sp-tag-count {
            font-size: 11px; color: #999; margin-left: 4px;
        }
        .sp-catalog-subject-tag:hover .sp-tag-count { color: rgba(255,255,255,0.7); }

        /* Divider between landing and results */
        .sp-catalog-divider {
            border: none; border-top: 1px solid #e5e7eb; margin: 28px 0;
        }

        /* ================================================================
           RESULTS — status bar, table, detail rows, pagination
           ================================================================ */

        /* Results count + active filters */
        .sp-catalog-status { display: flex; flex-wrap: wrap; align-items: center; gap: 8px; margin-bottom: 14px; color: #555; font-size: 14px; }
        .sp-catalog-active-filter { display: inline-flex; align-items: center; gap: 4px; background: var(--sp-color-accent, #667eea); color: #fff; padding: 3px 10px; border-radius: 12px; font-size: 12px; font-weight: 500; }
        .sp-catalog-active-filter a { color: #fff; text-decoration: none; font-weight: 700; margin-left: 2px; }
        .sp-catalog-active-filter a:hover { opacity: 0.8; }

        /* Table */
        .sp-catalog-table { width: 100%; border-collapse: collapse; }
        .sp-catalog-table thead th { padding: 10px 14px; text-align: left; border-bottom: 2px solid #d0d5dd; background: #f8f9fa; font-size: 13px; font-weight: 600; text-transform: uppercase; letter-spacing: 0.03em; color: #555; cursor: pointer; user-select: none; }
        .sp-catalog-table thead th:hover { color: var(--sp-color-primary, #1a1a2e); }
        .sp-catalog-table thead th.sorted { color: var(--sp-color-primary, #1a1a2e); }
        .sp-catalog-table thead th .sp-sort-arrow { font-size: 11px; margin-left: 4px; opacity: 0.4; }
        .sp-catalog-table thead th.sorted .sp-sort-arrow { opacity: 1; }
        .sp-catalog-table tbody td { padding: 10px 14px; border-bottom: 1px solid #eee; font-size: 14px; vertical-align: top; }
        .sp-catalog-table tbody tr:hover { background: #f8f9fa; }
        .sp-catalog-table .sp-item-title { color: var(--sp-color-primary, #2271b1); cursor: pointer; font-weight: 600; text-decoration: none; }
        .sp-catalog-table .sp-item-title:hover { text-decoration: underline; }
        .sp-catalog-table .sp-item-condition { font-size: 11px; font-weight: 500; }
        .sp-catalog-table .sp-item-media-type { font-size: 12px; color: #666; background: #f0f0f0; padding: 2px 8px; border-radius: 10px; display: inline-block; }

        /* Expandable detail row */
        .sp-catalog-detail-row td { padding: 0 !important; border-bottom: 2px solid var(--sp-color-accent, #667eea) !important; }
        .sp-catalog-detail { padding: 20px 24px; background: #fafbfc; animation: spDetailSlide 0.25s ease-out; }
        @keyframes spDetailSlide { from { opacity: 0; max-height: 0; } to { opacity: 1; max-height: 600px; } }
        .sp-catalog-detail-layout { display: flex; gap: 24px; }
        .sp-catalog-detail-cover { flex: 0 0 auto; }
        .sp-catalog-detail-cover img { max-width: 140px; max-height: 200px; border: 1px solid #ddd; border-radius: 4px; box-shadow: 0 2px 6px rgba(0,0,0,0.1); }
        .sp-catalog-detail-body { flex: 1; min-width: 0; }
        .sp-catalog-detail-grid { display: grid; grid-template-columns: 1fr 1fr; gap: 16px 32px; }
        .sp-catalog-detail-field { }
        .sp-catalog-detail-field dt { font-size: 11px; text-transform: uppercase; letter-spacing: 0.05em; color: #888; margin-bottom: 2px; font-weight: 600; }
        .sp-catalog-detail-field dd { margin: 0; font-size: 14px; color: #333; }
        .sp-catalog-detail-desc { grid-column: 1 / -1; margin-top: 8px; }
        .sp-catalog-detail-desc dt { font-size: 11px; text-transform: uppercase; letter-spacing: 0.05em; color: #888; margin-bottom: 4px; font-weight: 600; }
        .sp-catalog-detail-desc dd { margin: 0; font-size: 14px; color: #333; line-height: 1.6; }

        /* Subject / surname tags (in detail rows) */
        .sp-catalog-tag { display: inline-block; background: var(--sp-color-primary, #2271b1); color: #fff; padding: 2px 10px; border-radius: 12px; font-size: 12px; margin: 2px 3px 2px 0; text-decoration: none; cursor: pointer; }
        .sp-catalog-tag:hover { opacity: 0.85; color: #fff; }
        .sp-catalog-tag.sp-tag-surname { background: #6b7280; }

        /* Pagination */
        .sp-catalog-pagination { display: flex; justify-content: center; align-items: center; gap: 4px; margin-top: 20px; flex-wrap: wrap; }
        .sp-catalog-pagination a, .sp-catalog-pagination span { display: inline-block; padding: 6px 12px; border: 1px solid #d0d5dd; border-radius: 4px; font-size: 14px; text-decoration: none; color: #333; }
        .sp-catalog-pagination a:hover { background: #f0f0f0; }
        .sp-catalog-pagination .current { background: var(--sp-color-primary, #2271b1); color: #fff; border-color: var(--sp-color-primary, #2271b1); }
        .sp-catalog-pagination .dots { border: none; color: #999; }

        /* ================================================================
           RESPONSIVE — mobile-first adjustments
           ================================================================ */
        @media (max-width: 768px) {
            .sp-catalog-header h2 { font-size: 22px; }
            .sp-catalog-stats-bar { gap: 8px; }
            .sp-catalog-stat { padding: 10px 14px; min-width: 80px; }
            .sp-catalog-stat-number { font-size: 20px; }

            .sp-catalog-tabs { overflow-x: auto; -webkit-overflow-scrolling: touch; }
            .sp-catalog-tab { padding: 8px 12px; font-size: 13px; white-space: nowrap; }
            .sp-catalog-search-form { flex-direction: column; gap: 8px; }
            .sp-catalog-search-form input[type="text"] { border-radius: 6px; border-right: 1px solid #d0d5dd; }
            .sp-catalog-search-form button[type="submit"] { border-radius: 6px; }

            .sp-catalog-filter-row { flex-direction: column; }
            .sp-catalog-type-grid { grid-template-columns: repeat(auto-fill, minmax(120px, 1fr)); }

            .sp-catalog-table thead { display: none; }
            .sp-catalog-table tbody tr { display: block; padding: 12px 0; border-bottom: 1px solid #eee; }
            .sp-catalog-table tbody td { display: block; padding: 3px 0 !important; border-bottom: none !important; }
            .sp-catalog-table tbody td:before { content: attr(data-label); font-weight: 600; font-size: 11px; text-transform: uppercase; color: #888; display: block; }
            .sp-catalog-detail-grid { grid-template-columns: 1fr; }
            .sp-catalog-detail-layout { flex-direction: column; }
            .sp-catalog-detail-cover { text-align: center; }
            .sp-catalog-detail-cover img { max-width: 120px; }
        }
    </style>
    <?php

    // ================================================================
    // SECTION 1: COLLECTION HEADER — stats that show the depth of the library
    // ================================================================
    if ( $show_landing ) {
        echo '<div class="sp-catalog-header">';
        echo '<h2>' . esc_html__( 'Library Catalog', 'societypress' ) . '</h2>';
        echo '<p class="sp-catalog-subtitle">' . esc_html__( 'Search and browse our collection of books, periodicals, maps, and more. Click any title for full details.', 'societypress' ) . '</p>';

        echo '<div class="sp-catalog-stats-bar">';
        // Total items stat
        echo '<div class="sp-catalog-stat">';
        echo '<span class="sp-catalog-stat-number">' . number_format( $stats['total'] ) . '</span>';
        echo '<span class="sp-catalog-stat-label">' . esc_html__( 'Total Items', 'societypress' ) . '</span>';
        echo '</div>';

        // One stat card per media type
        foreach ( $stats['type_counts'] as $tc ) {
            echo '<div class="sp-catalog-stat">';
            echo '<span class="sp-catalog-stat-number">' . number_format( $tc->cnt ) . '</span>';
            echo '<span class="sp-catalog-stat-label">' . esc_html( $tc->media_type ) . '</span>';
            echo '</div>';
        }
        echo '</div>'; // close stats bar
        echo '</div>'; // close header
    }

    // ================================================================
    // SECTION 2: TABBED SEARCH — OPAC-style field-targeted search
    // ================================================================
    if ( $show_search ) {
        // Build base URL preserving non-catalog query params
        $base_params = [];
        foreach ( $_GET as $k => $v ) {
            if ( strpos( $k, 'sp_lib_' ) !== 0 ) {
                $base_params[ $k ] = $v;
            }
        }

        // WHY: Tabs let the researcher target their search. A genealogist looking
        //      for "Smith" as a surname doesn't want to also match books with
        //      "Goldsmith" in the title. Targeting = precision.
        $tab_labels = [
            'keyword'     => __( 'Keyword', 'societypress' ),
            'title'       => __( 'Title', 'societypress' ),
            'author'      => __( 'Author', 'societypress' ),
            'subject'     => __( 'Subject', 'societypress' ),
            'call_number' => __( 'Call Number', 'societypress' ),
        ];
        $tab_placeholders = [
            'keyword'     => __( 'Search titles, authors, subjects, surnames, descriptions...', 'societypress' ),
            'title'       => __( 'Search by title...', 'societypress' ),
            'author'      => __( 'Search by author or editor...', 'societypress' ),
            'subject'     => __( 'Search by subject...', 'societypress' ),
            'call_number' => __( 'Search by call number or shelf location...', 'societypress' ),
        ];

        echo '<div class="sp-catalog-search">';

        // Tabs
        echo '<div class="sp-catalog-tabs" role="tablist">';
        foreach ( $tab_labels as $field_key => $label ) {
            $active = ( $search_field === $field_key ) ? ' active' : '';
            echo '<button type="button" class="sp-catalog-tab' . $active . '" data-field="' . esc_attr( $field_key ) . '" role="tab">' . esc_html( $label ) . '</button>';
        }
        echo '</div>';

        // Search form
        echo '<form method="get" class="sp-catalog-search-form" id="' . esc_attr( $uid ) . '-form">';
        foreach ( $base_params as $k => $v ) {
            echo '<input type="hidden" name="' . esc_attr( $k ) . '" value="' . esc_attr( $v ) . '">';
        }
        echo '<input type="hidden" name="sp_lib_field" value="' . esc_attr( $search_field ) . '" id="' . esc_attr( $uid ) . '-field">';
        echo '<input type="text" name="sp_lib_search" value="' . esc_attr( $search ) . '" placeholder="' . esc_attr( $tab_placeholders[ $search_field ] ) . '" id="' . esc_attr( $uid ) . '-input">';
        echo '<button type="submit">' . esc_html__( 'Search', 'societypress' ) . '</button>';
        echo '</form>';

        // Additional filter dropdowns (media type, source, sort)
        echo '<form method="get" class="sp-catalog-filter-row" id="' . esc_attr( $uid ) . '-filters">';
        foreach ( $base_params as $k => $v ) {
            echo '<input type="hidden" name="' . esc_attr( $k ) . '" value="' . esc_attr( $v ) . '">';
        }
        // Carry search params forward when changing filters
        if ( $search ) {
            echo '<input type="hidden" name="sp_lib_search" value="' . esc_attr( $search ) . '">';
            echo '<input type="hidden" name="sp_lib_field" value="' . esc_attr( $search_field ) . '">';
        }

        // Media type filter
        echo '<select name="sp_lib_media" onchange="this.form.submit()">';
        echo '<option value="">' . esc_html__( 'All Types', 'societypress' ) . '</option>';
        foreach ( $media_types as $mt ) {
            $sel = ( $media_filter === $mt ) ? ' selected' : '';
            echo '<option value="' . esc_attr( $mt ) . '"' . $sel . '>' . esc_html( $mt ) . '</option>';
        }
        echo '</select>';

        // Acquisition code filter
        echo '<select name="sp_lib_acq" onchange="this.form.submit()">';
        echo '<option value="">' . esc_html__( 'All Sources', 'societypress' ) . '</option>';
        foreach ( $acq_codes as $ac ) {
            $sel = ( $acq_filter === $ac ) ? ' selected' : '';
            echo '<option value="' . esc_attr( $ac ) . '"' . $sel . '>' . esc_html( $ac ) . '</option>';
        }
        echo '</select>';

        // Sort
        echo '<select name="sp_lib_sort" onchange="this.form.submit()">';
        $sort_options = [
            'title'       => __( 'Sort: Title', 'societypress' ),
            'author'      => __( 'Sort: Author', 'societypress' ),
            'pub_year'    => __( 'Sort: Year Published', 'societypress' ),
            'call_number' => __( 'Sort: Call Number', 'societypress' ),
            'media_type'  => __( 'Sort: Media Type', 'societypress' ),
        ];
        foreach ( $sort_options as $val => $label ) {
            $sel = ( $sort_by === $val ) ? ' selected' : '';
            echo '<option value="' . esc_attr( $val ) . '"' . $sel . '>' . esc_html( $label ) . '</option>';
        }
        echo '</select>';
        echo '</form>';

        echo '</div>'; // close .sp-catalog-search
    }

    // ================================================================
    // SECTION 3: BROWSE — media type cards + popular subjects
    // WHY: Not every researcher comes with a specific search in mind. Some want
    //      to browse — "what maps do you have?" or "show me everything about
    //      cemeteries." These sections let people explore by collection type
    //      or subject area without typing anything. Once a filter is active
    //      these collapse so the results take center stage.
    // ================================================================
    if ( $show_landing && ! $has_active_filter ) {
        echo '<div class="sp-catalog-browse">';

        // ---- Browse by media type ----
        echo '<h3>' . esc_html__( 'Browse by Collection', 'societypress' ) . '</h3>';
        echo '<div class="sp-catalog-type-grid">';

        // WHY: Simple SVG icons give visual weight to the cards without adding
        //      external dependencies. Each icon is a single inline <svg> — no
        //      icon font, no image requests, no accessibility issues.
        $type_icons = [
            'Book'          => '<svg width="28" height="28" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.5"><path d="M4 19.5A2.5 2.5 0 0 1 6.5 17H20"/><path d="M6.5 2H20v20H6.5A2.5 2.5 0 0 1 4 19.5v-15A2.5 2.5 0 0 1 6.5 2z"/></svg>',
            'Periodicals'   => '<svg width="28" height="28" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.5"><path d="M4 4h16v16H4z"/><path d="M4 8h16"/><path d="M8 4v16"/></svg>',
            'Map'           => '<svg width="28" height="28" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.5"><polygon points="1 6 1 22 8 18 16 22 23 18 23 2 16 6 8 2 1 6"/><line x1="8" y1="2" x2="8" y2="18"/><line x1="16" y1="6" x2="16" y2="22"/></svg>',
            'Vertical File' => '<svg width="28" height="28" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.5"><path d="M22 19a2 2 0 0 1-2 2H4a2 2 0 0 1-2-2V5a2 2 0 0 1 2-2h5l2 3h9a2 2 0 0 1 2 2z"/></svg>',
            'eBook'         => '<svg width="28" height="28" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.5"><rect x="5" y="2" width="14" height="20" rx="2"/><line x1="9" y1="6" x2="15" y2="6"/><line x1="9" y1="10" x2="15" y2="10"/><line x1="9" y1="14" x2="12" y2="14"/></svg>',
            'Rare Books'    => '<svg width="28" height="28" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.5"><path d="M2 3h6a4 4 0 0 1 4 4v14a3 3 0 0 0-3-3H2z"/><path d="M22 3h-6a4 4 0 0 0-4 4v14a3 3 0 0 1 3-3h7z"/></svg>',
        ];

        $base_catalog_url = get_permalink();
        foreach ( $stats['type_counts'] as $tc ) {
            $filter_url = add_query_arg( 'sp_lib_media', $tc->media_type, $base_catalog_url );
            $icon = $type_icons[ $tc->media_type ] ?? $type_icons['Book'];
            $is_active = ( $media_filter === $tc->media_type ) ? ' active' : '';

            echo '<a href="' . esc_url( $filter_url ) . '" class="sp-catalog-type-card' . $is_active . '">';
            echo '<span class="sp-catalog-type-icon">' . $icon . '</span>';
            echo '<span class="sp-catalog-type-name">' . esc_html( $tc->media_type ) . '</span>';
            echo '<span class="sp-catalog-type-count">' . number_format( $tc->cnt ) . ' ' . esc_html__( 'items', 'societypress' ) . '</span>';
            echo '</a>';
        }
        echo '</div>'; // close type grid

        // ---- Browse by subject ----
        echo '<h3>' . esc_html__( 'Popular Subjects', 'societypress' ) . '</h3>';
        echo '<div class="sp-catalog-subject-cloud">';
        foreach ( $stats['subject_counts'] as $subj_name => $subj_cnt ) {
            $subj_url = add_query_arg( 'sp_lib_subject', $subj_name, $base_catalog_url );
            echo '<a href="' . esc_url( $subj_url ) . '" class="sp-catalog-subject-tag">';
            echo esc_html( $subj_name );
            echo ' <span class="sp-tag-count">(' . number_format( $subj_cnt ) . ')</span>';
            echo '</a>';
        }
        echo '</div>'; // close subject cloud

        echo '</div>'; // close .sp-catalog-browse

        echo '<hr class="sp-catalog-divider">';
    }

    // ================================================================
    // SECTION 4: RESULTS — status bar, table, pagination
    // ================================================================

    // ---- Active filter chips + result count ----
    echo '<div class="sp-catalog-status">';
    echo '<span>' . number_format( $total ) . ' ' . esc_html( _n( 'item', 'items', $total, 'societypress' ) ) . ' ' . esc_html__( 'found', 'societypress' ) . '</span>';

    $remove_base = remove_query_arg( [ 'sp_lib_pg' ] );
    if ( $search ) {
        $field_label = $tab_labels[ $search_field ] ?? __( 'Keyword', 'societypress' );
        $remove_url  = remove_query_arg( [ 'sp_lib_search', 'sp_lib_field' ], $remove_base );
        echo '<span class="sp-catalog-active-filter">' . esc_html( $field_label ) . ': ' . esc_html( $search ) . ' <a href="' . esc_url( $remove_url ) . '">&times;</a></span>';
    }
    if ( $media_filter ) {
        $remove_url = remove_query_arg( 'sp_lib_media', $remove_base );
        echo '<span class="sp-catalog-active-filter">' . esc_html__( 'Type', 'societypress' ) . ': ' . esc_html( $media_filter ) . ' <a href="' . esc_url( $remove_url ) . '">&times;</a></span>';
    }
    if ( $subj_filter ) {
        $remove_url = remove_query_arg( 'sp_lib_subject', $remove_base );
        echo '<span class="sp-catalog-active-filter">' . esc_html__( 'Subject', 'societypress' ) . ': ' . esc_html( $subj_filter ) . ' <a href="' . esc_url( $remove_url ) . '">&times;</a></span>';
    }
    if ( $acq_filter ) {
        $remove_url = remove_query_arg( 'sp_lib_acq', $remove_base );
        echo '<span class="sp-catalog-active-filter">' . esc_html__( 'Source', 'societypress' ) . ': ' . esc_html( $acq_filter ) . ' <a href="' . esc_url( $remove_url ) . '">&times;</a></span>';
    }
    if ( $has_active_filter ) {
        $clear_url = remove_query_arg( [ 'sp_lib_search', 'sp_lib_field', 'sp_lib_media', 'sp_lib_subject', 'sp_lib_acq', 'sp_lib_sort', 'sp_lib_pg' ] );
        echo '<a href="' . esc_url( $clear_url ) . '" style="font-size:13px; color:#b32d2e;">' . esc_html__( 'Clear all', 'societypress' ) . '</a>';
    }
    echo '</div>';

    // ---- Results table ----
    if ( empty( $items ) ) {
        echo '<p style="color:#666; font-style:italic; padding:20px 0;">' . esc_html__( 'No items match your search. Try broadening your filters.', 'societypress' ) . '</p>';
    } else {
        // WHY: Sortable column headers let the researcher reorder results without
        //      scrolling back up to the sort dropdown. The arrow indicator shows
        //      which column is active.
        $sort_url_base = remove_query_arg( [ 'sp_lib_sort', 'sp_lib_pg' ] );

        echo '<table class="sp-catalog-table">';
        echo '<thead><tr>';

        $columns = [
            'title'       => __( 'Title', 'societypress' ),
            'author'      => __( 'Author', 'societypress' ),
            'media_type'  => __( 'Type', 'societypress' ),
            'call_number' => __( 'Call #', 'societypress' ),
            'pub_year'    => __( 'Year', 'societypress' ),
        ];
        foreach ( $columns as $col_key => $col_label ) {
            $is_sorted = ( $sort_by === $col_key ) ? ' sorted' : '';
            $arrow     = ( $sort_by === $col_key ) ? ( $col_key === 'pub_year' ? '&#9660;' : '&#9650;' ) : '&#9650;';
            $col_url   = add_query_arg( 'sp_lib_sort', $col_key, $sort_url_base );
            echo '<th class="' . esc_attr( trim( $is_sorted ) ) . '">';
            echo '<a href="' . esc_url( $col_url ) . '" style="color:inherit; text-decoration:none;">';
            echo esc_html( $col_label ) . ' <span class="sp-sort-arrow">' . $arrow . '</span>';
            echo '</a></th>';
        }
        echo '<th style="text-align:center;">' . esc_html__( 'Status', 'societypress' ) . '</th>';
        echo '</tr></thead><tbody>';

        foreach ( $items as $item ) {
            $condition_colors = [
                'good'      => '#0a6b2e',
                'fair'      => '#92400e',
                'poor'      => '#b32d2e',
                'reference' => '#2271b1',
            ];
            $cond_color = $condition_colors[ $item->item_condition ] ?? '#666';

            echo '<tr class="sp-catalog-item-row" data-item-id="' . esc_attr( $item->id ) . '">';

            // Title cell — clickable to expand detail
            echo '<td data-label="' . esc_attr__( 'Title', 'societypress' ) . '">';
            echo '<a class="sp-item-title" data-item-id="' . esc_attr( $item->id ) . '">' . esc_html( $item->title ) . '</a>';
            if ( $item->item_condition ) {
                echo ' <span class="sp-item-condition" style="color:' . esc_attr( $cond_color ) . ';">(' . esc_html( ucfirst( $item->item_condition ) ) . ')</span>';
            }
            echo '</td>';

            echo '<td data-label="' . esc_attr__( 'Author', 'societypress' ) . '">' . esc_html( $item->author ?: '—' ) . '</td>';
            echo '<td data-label="' . esc_attr__( 'Type', 'societypress' ) . '">';
            if ( $item->media_type ) {
                echo '<span class="sp-item-media-type">' . esc_html( $item->media_type ) . '</span>';
            } else {
                echo '—';
            }
            echo '</td>';
            echo '<td data-label="' . esc_attr__( 'Call #', 'societypress' ) . '">' . esc_html( $item->call_number ?: '—' ) . '</td>';
            echo '<td data-label="' . esc_attr__( 'Year', 'societypress' ) . '">' . esc_html( $item->pub_year ?: '—' ) . '</td>';
            echo '<td data-label="' . esc_attr__( 'Status', 'societypress' ) . '" style="text-align:center;">';
            echo $item->available
                ? '<span style="color:#0a6b2e; font-weight:600;">' . esc_html__( 'Available', 'societypress' ) . '</span>'
                : '<span style="color:#b32d2e;">' . esc_html__( 'Checked Out', 'societypress' ) . '</span>';
            echo '</td>';
            echo '</tr>';
        }
        echo '</tbody></table>';

        // ---- Pagination ----
        if ( $total_pages > 1 ) {
            echo '<div class="sp-catalog-pagination">';
            $base_url = remove_query_arg( 'sp_lib_pg' );

            // Previous
            if ( $page_num > 1 ) {
                echo '<a href="' . esc_url( add_query_arg( 'sp_lib_pg', $page_num - 1, $base_url ) ) . '">&laquo; ' . esc_html__( 'Prev', 'societypress' ) . '</a>';
            }

            // Page numbers with smart truncation for large catalogs
            $range = 2;
            for ( $i = 1; $i <= $total_pages; $i++ ) {
                if ( $i === 1 || $i === $total_pages || abs( $i - $page_num ) <= $range ) {
                    if ( $i === $page_num ) {
                        echo '<span class="current">' . $i . '</span>';
                    } else {
                        echo '<a href="' . esc_url( add_query_arg( 'sp_lib_pg', $i, $base_url ) ) . '">' . $i . '</a>';
                    }
                } elseif ( $i === 2 && $page_num > $range + 2 ) {
                    echo '<span class="dots">&hellip;</span>';
                } elseif ( $i === $total_pages - 1 && $page_num < $total_pages - $range - 1 ) {
                    echo '<span class="dots">&hellip;</span>';
                }
            }

            // Next
            if ( $page_num < $total_pages ) {
                echo '<a href="' . esc_url( add_query_arg( 'sp_lib_pg', $page_num + 1, $base_url ) ) . '">' . esc_html__( 'Next', 'societypress' ) . ' &raquo;</a>';
            }
            echo '</div>';
        }
    }

    // ================================================================
    // JAVASCRIPT — tab switching, AJAX detail expansion
    // ================================================================
    ?>
    <script>
    (function() {
        var container = document.getElementById('<?php echo esc_js( $uid ); ?>');
        if ( ! container ) return;

        var ajaxUrl = '<?php echo esc_js( admin_url( "admin-ajax.php" ) ); ?>';
        var openRow = null;

        // ---- Tab switching ----
        // WHY: Clicking a tab doesn't submit the form — it just changes which
        //      field the search targets. The hidden input and placeholder update
        //      instantly so the researcher knows what they're searching.
        var tabs = container.querySelectorAll('.sp-catalog-tab');
        var fieldInput = document.getElementById('<?php echo esc_js( $uid ); ?>-field');
        var searchInput = document.getElementById('<?php echo esc_js( $uid ); ?>-input');
        var placeholders = <?php echo wp_json_encode( $tab_placeholders ); ?>;

        tabs.forEach(function(tab) {
            tab.addEventListener('click', function() {
                var field = this.getAttribute('data-field');

                // Update active tab styling
                tabs.forEach(function(t) { t.classList.remove('active'); });
                this.classList.add('active');

                // Update hidden field value and placeholder
                if ( fieldInput ) fieldInput.value = field;
                if ( searchInput ) searchInput.placeholder = placeholders[field] || '';
                if ( searchInput ) searchInput.focus();
            });
        });

        // ---- AJAX expand/collapse ----
        // WHY: Clicking a title row fetches full item details via AJAX and injects
        //      a detail panel below the row. Clicking again collapses it. No page
        //      reload — the researcher stays in context of their results.
        container.addEventListener('click', function(e) {
            var titleLink = e.target.closest('.sp-item-title');
            if ( ! titleLink ) return;
            e.preventDefault();

            var itemId = titleLink.getAttribute('data-item-id');
            var parentRow = titleLink.closest('tr');
            if ( ! parentRow ) return;

            // If this row's detail is already open, close it
            var existingDetail = parentRow.nextElementSibling;
            if ( existingDetail && existingDetail.classList.contains('sp-catalog-detail-row') ) {
                existingDetail.remove();
                openRow = null;
                return;
            }

            // Close any other open detail row
            if ( openRow ) {
                openRow.remove();
                openRow = null;
            }

            // Create placeholder row
            var detailRow = document.createElement('tr');
            detailRow.className = 'sp-catalog-detail-row';
            var detailCell = document.createElement('td');
            detailCell.setAttribute('colspan', '6');
            detailCell.innerHTML = '<div class="sp-catalog-detail" style="text-align:center; padding:30px;"><?php echo esc_js( __( 'Loading...', 'societypress' ) ); ?></div>';
            detailRow.appendChild(detailCell);
            parentRow.after(detailRow);
            openRow = detailRow;

            // Fetch item details
            fetch(ajaxUrl + '?action=sp_library_item_detail&item_id=' + itemId, { credentials: 'same-origin' })
                .then(function(r) { return r.json(); })
                .then(function(resp) {
                    if ( ! resp.success || ! resp.data ) {
                        detailCell.innerHTML = '<div class="sp-catalog-detail"><p><?php echo esc_js( __( 'Unable to load details.', 'societypress' ) ); ?></p></div>';
                        return;
                    }
                    var d = resp.data;

                    var html = '<div class="sp-catalog-detail">';
                    html += '<div class="sp-catalog-detail-layout">';

                    // Cover image — shown on the left if available
                    if ( d.cover_url ) {
                        html += '<div class="sp-catalog-detail-cover">';
                        html += '<img src="' + escAttr(d.cover_url) + '" alt="' + escAttr(d.title) + ' cover" loading="lazy">';
                        html += '</div>';
                    }

                    html += '<div class="sp-catalog-detail-body">';
                    html += '<div class="sp-catalog-detail-grid">';

                    function field(label, value) {
                        if ( ! value ) return '';
                        return '<dl class="sp-catalog-detail-field"><dt>' + label + '</dt><dd>' + escHtml(value) + '</dd></dl>';
                    }

                    html += field('<?php echo esc_js( __( 'Title', 'societypress' ) ); ?>', d.title);
                    html += field('<?php echo esc_js( __( 'Author', 'societypress' ) ); ?>', d.author);
                    html += field('<?php echo esc_js( __( 'Publisher', 'societypress' ) ); ?>', d.publisher);
                    html += field('<?php echo esc_js( __( 'Publisher Location', 'societypress' ) ); ?>', d.publisher_location);
                    html += field('<?php echo esc_js( __( 'Published', 'societypress' ) ); ?>', d.pub_date);
                    html += field('<?php echo esc_js( __( 'Media Type', 'societypress' ) ); ?>', d.media_type);
                    html += field('<?php echo esc_js( __( 'Category', 'societypress' ) ); ?>', d.category_name);
                    html += field('<?php echo esc_js( __( 'Call Number', 'societypress' ) ); ?>', d.call_number);
                    html += field('<?php echo esc_js( __( 'ISBN', 'societypress' ) ); ?>', d.isbn);
                    html += field('<?php echo esc_js( __( 'LCCN', 'societypress' ) ); ?>', d.lccn);
                    html += field('<?php echo esc_js( __( 'Shelf Location', 'societypress' ) ); ?>', d.shelf_location);
                    html += field('<?php echo esc_js( __( 'Geographic Coverage', 'societypress' ) ); ?>', d.geographic_location);
                    html += field('<?php echo esc_js( __( 'County', 'societypress' ) ); ?>', d.county);
                    html += field('<?php echo esc_js( __( 'State', 'societypress' ) ); ?>', d.state);
                    html += field('<?php echo esc_js( __( 'Condition', 'societypress' ) ); ?>', d.item_condition ? d.item_condition.charAt(0).toUpperCase() + d.item_condition.slice(1) : '');
                    html += field('<?php echo esc_js( __( 'Status', 'societypress' ) ); ?>', d.available ? '<?php echo esc_js( __( 'Available', 'societypress' ) ); ?>' : '<?php echo esc_js( __( 'Checked Out', 'societypress' ) ); ?>');
                    html += field('<?php echo esc_js( __( 'Acquisition', 'societypress' ) ); ?>', [d.acq_code, d.acq_date].filter(Boolean).join(' — '));
                    html += field('<?php echo esc_js( __( 'Donor', 'societypress' ) ); ?>', d.donor);
                    html += field('<?php echo esc_js( __( 'Value', 'societypress' ) ); ?>', d.item_value);
                    html += field('<?php echo esc_js( __( 'Acquisition #', 'societypress' ) ); ?>', d.acquisition_number);
                    html += field('<?php echo esc_js( __( 'System ID', 'societypress' ) ); ?>', d.system_id);

                    // Subject tags — clickable to filter
                    if ( d.subjects && d.subjects.length > 0 ) {
                        html += '<dl class="sp-catalog-detail-field"><dt><?php echo esc_js( __( 'Subjects', 'societypress' ) ); ?></dt><dd>';
                        d.subjects.forEach(function(s) {
                            var filterUrl = addOrReplaceParam(window.location.href, 'sp_lib_subject', s);
                            filterUrl = removeParam(filterUrl, 'sp_lib_pg');
                            html += '<a href="' + escAttr(filterUrl) + '" class="sp-catalog-tag">' + escHtml(s) + '</a>';
                        });
                        html += '</dd></dl>';
                    }

                    // Surname tags
                    if ( d.surnames && d.surnames.length > 0 ) {
                        html += '<dl class="sp-catalog-detail-field"><dt><?php echo esc_js( __( 'Surnames', 'societypress' ) ); ?></dt><dd>';
                        d.surnames.forEach(function(s) {
                            var filterUrl = addOrReplaceParam(window.location.href, 'sp_lib_search', s);
                            filterUrl = removeParam(filterUrl, 'sp_lib_pg');
                            html += '<a href="' + escAttr(filterUrl) + '" class="sp-catalog-tag sp-tag-surname">' + escHtml(s) + '</a>';
                        });
                        html += '</dd></dl>';
                    }

                    // Description — full width
                    if ( d.description ) {
                        html += '<div class="sp-catalog-detail-desc"><dt><?php echo esc_js( __( 'Description', 'societypress' ) ); ?></dt><dd>' + escHtml(d.description) + '</dd></div>';
                    }

                    html += '</div>'; // close grid
                    html += '</div>'; // close body
                    html += '</div>'; // close layout
                    html += '</div>'; // close detail

                    detailCell.innerHTML = html;
                })
                .catch(function() {
                    detailCell.innerHTML = '<div class="sp-catalog-detail"><p><?php echo esc_js( __( 'Unable to load details.', 'societypress' ) ); ?></p></div>';
                });
        });

        // Utility: escape HTML
        function escHtml(str) {
            var div = document.createElement('div');
            div.appendChild(document.createTextNode(str));
            return div.innerHTML;
        }
        function escAttr(str) {
            return str.replace(/&/g, '&amp;').replace(/"/g, '&quot;').replace(/'/g, '&#39;').replace(/</g, '&lt;').replace(/>/g, '&gt;');
        }
        function addOrReplaceParam(url, key, value) {
            var u = new URL(url);
            u.searchParams.set(key, value);
            return u.toString();
        }
        function removeParam(url, key) {
            var u = new URL(url);
            u.searchParams.delete(key);
            return u.toString();
        }
    })();
    </script>
    <?php
    echo '</div>'; // close .sp-widget-library-catalog
}

/**
 * Render: Hero Slider
 *
 * WHY: A full-width image slider is the centerpiece of many society homepages.
 *      This uses lightweight CSS transitions + vanilla JS for auto-advancing.
 *      No jQuery, no external libraries.
 */
function sp_render_builder_widget_hero_slider( array $s ): void {
    $slides   = $s['slides'] ?? [];
    $height   = (int) ( $s['height'] ?? 400 );
    $autoplay = (int) ( $s['autoplay'] ?? 1 );
    $interval = max( 2, (int) ( $s['interval'] ?? 5 ) ) * 1000;
    $overlay  = (int) ( $s['overlay'] ?? 1 );
    $uid      = 'sp-slider-' . wp_rand( 1000, 9999 );

    if ( empty( $slides ) ) {
        echo '<p style="text-align:center; padding:40px; color:#646970;">' . esc_html__( 'No slides configured.', 'societypress' ) . '</p>';
        return;
    }

    ?>
    <style>
        /* WHY the viewport-width trick: The slider sits inside nested content
           wrappers that cap the width. This breaks out to full viewport width
           regardless of how many max-width containers wrap it. */
        .sp-widget--hero_slider { width: 100vw; position: relative; left: 50%; right: 50%; margin-left: -50vw; margin-right: -50vw; margin-top: -130px; }
        .sp-hero-slider { position: relative; overflow: hidden; width: 100%; }
        .sp-hero-slider .sp-slide { position: absolute; top: 0; left: 0; width: 100%; height: 100%; opacity: 0; transition: opacity 0.8s ease; background-size: cover; background-position: center; display: flex; align-items: center; justify-content: center; }
        .sp-hero-slider .sp-slide.active { opacity: 1; position: relative; }
        .sp-hero-slider .sp-slide video.sp-slide-video { position: absolute; top: 50%; left: 50%; min-width: 100%; min-height: 100%; width: auto; height: auto; transform: translate(-50%, -50%); object-fit: cover; z-index: 0; }
        .sp-hero-slider .sp-slide-overlay { position: absolute; top: 0; left: 0; width: 100%; height: 100%; }
        .sp-hero-slider .sp-slide-content { position: relative; z-index: 2; text-align: center; color: #fff; padding: 20px; max-width: 900px; }
        /* WHY: Per-line styling is now inline on each .sp-slide-line element
           (font-size, font-weight, color). This rule just handles margin and
           text-shadow — the shared bits that don't vary per line. */
        .sp-hero-slider .sp-slide-content .sp-slide-line { margin: 0 0 6px; text-shadow: 0 2px 8px rgba(0,0,0,0.5); }
        .sp-hero-slider .sp-slide-btn { display: inline-block; padding: 12px 28px; background: var(--sp-color-accent, #667eea); color: #fff; text-decoration: none; border-radius: 4px; font-size: 16px; font-weight: 600; transition: background 0.2s; }
        .sp-hero-slider .sp-slide-btn:hover { background: var(--sp-color-primary, #2271b1); }
        .sp-slider-dots { display: none; }
        .sp-slider-arrows { display: none; }
        /* WHY: Mobile sizes are applied via a CSS class on each line element
           rather than inline styles, so the media query can override them.
           .sp-line-small = 16px, .sp-line-medium = 22px, .sp-line-large = 30px */
        @media (max-width: 768px) {
            .sp-hero-slider .sp-slide-content .sp-line-small  { font-size: 16px !important; }
            .sp-hero-slider .sp-slide-content .sp-line-medium { font-size: 22px !important; }
            .sp-hero-slider .sp-slide-content .sp-line-large  { font-size: 30px !important; }
        }
    </style>

    <div class="sp-hero-slider" id="<?php echo esc_attr( $uid ); ?>" style="height: <?php echo $height; ?>px;">
        <?php foreach ( $slides as $i => $slide ) :
            $media_url = esc_url( $slide['image'] ?? '' );
            // WHY: Detect video files so we can render a <video> element instead
            // of a CSS background-image. Videos need autoplay + muted + loop to
            // behave like a background — muted is required by browsers for
            // autoplay to work without user interaction.
            $is_video  = (bool) preg_match( '/\.(mp4|webm|ogg)(\?|$)/i', $media_url );
        ?>
            <div class="sp-slide <?php echo $i === 0 ? 'active' : ''; ?>"
                 <?php if ( ! $is_video && $media_url ) : ?>
                     style="background-image: url('<?php echo $media_url; ?>');"
                 <?php endif; ?>>
                <?php if ( $is_video && $media_url ) : ?>
                    <video class="sp-slide-video" autoplay muted loop playsinline>
                        <source src="<?php echo $media_url; ?>" type="video/<?php echo esc_attr( pathinfo( parse_url( $media_url, PHP_URL_PATH ), PATHINFO_EXTENSION ) ); ?>">
                    </video>
                <?php endif; ?>
                <?php if ( $overlay ) : ?>
                    <div class="sp-slide-overlay" style="background: rgba(0,0,0,0.35);"></div>
                <?php endif; ?>
                <div class="sp-slide-content">
                    <?php
                    // WHY: Per-line repeater data provides independent styling
                    // for each text line (size, weight, color). Falls back to
                    // legacy overlay_text format for slides saved before this
                    // change — auto-migrates on next save.
                    $slide_lines = $slide['lines'] ?? [];

                    // WHY: Legacy migration — if old overlay_text exists but no
                    // lines array, convert it. Line 1 → large/bold, line 2+ →
                    // medium/light, line 3+ → small/light. All white by default.
                    if ( empty( $slide_lines ) && ! empty( $slide['overlay_text'] ) ) {
                        $raw = array_filter( array_map( 'trim', explode( "\n", $slide['overlay_text'] ) ), 'strlen' );
                        $slide_lines = [];
                        foreach ( array_values( $raw ) as $li => $text ) {
                            if ( $li === 0 ) {
                                $slide_lines[] = [ 'text' => $text, 'size' => 'large',  'weight' => 'bold',  'color' => 'white' ];
                            } elseif ( $li === 1 ) {
                                $slide_lines[] = [ 'text' => $text, 'size' => 'medium', 'weight' => 'light', 'color' => 'white' ];
                            } else {
                                $slide_lines[] = [ 'text' => $text, 'size' => 'small',  'weight' => 'light', 'color' => 'white' ];
                            }
                        }
                    }

                    // WHY: Size/weight/color maps translate dropdown values to
                    // actual CSS values. Using a class for size so the media
                    // query can override it on mobile (inline styles beat MQs).
                    $size_map   = [ 'small' => '22px', 'medium' => '30px', 'large' => '44px' ];
                    $weight_map = [ 'light' => '300', 'bold' => '700' ];
                    $color_map  = [ 'white' => '#fff', 'dark' => '#1a1a1a', 'accent' => 'var(--sp-color-accent)' ];

                    foreach ( $slide_lines as $line ) {
                        $text   = esc_html( $line['text'] ?? '' );
                        if ( '' === $text ) continue;
                        $sz     = $size_map[ $line['size'] ?? 'medium' ] ?? '30px';
                        $wt     = $weight_map[ $line['weight'] ?? 'light' ] ?? '300';
                        $cl     = $color_map[ $line['color'] ?? 'white' ] ?? '#fff';
                        $szClass = 'sp-line-' . ( $line['size'] ?? 'medium' );
                        printf(
                            '<p class="sp-slide-line %s" style="font-size:%s; font-weight:%s; color:%s;">%s</p>',
                            esc_attr( $szClass ),
                            esc_attr( $sz ),
                            esc_attr( $wt ),
                            esc_attr( $cl ),
                            $text
                        );
                    }
                    ?>
                    <?php if ( ! empty( $slide['btn_text'] ) && ! empty( $slide['btn_url'] ) ) : ?>
                        <a href="<?php echo esc_url( $slide['btn_url'] ); ?>" class="sp-slide-btn"><?php echo esc_html( $slide['btn_text'] ); ?></a>
                    <?php endif; ?>
                </div>
            </div>
        <?php endforeach; ?>

        <?php if ( count( $slides ) > 1 ) : ?>
            <div class="sp-slider-arrows">
                <button type="button" class="sp-slider-arrow sp-slider-prev">&lsaquo;</button>
                <button type="button" class="sp-slider-arrow sp-slider-next">&rsaquo;</button>
            </div>
        <?php endif; ?>
    </div>

    <?php if ( count( $slides ) > 1 ) : ?>
        <div class="sp-slider-dots" data-slider="<?php echo esc_attr( $uid ); ?>">
            <?php for ( $i = 0; $i < count( $slides ); $i++ ) : ?>
                <button type="button" class="sp-slider-dot <?php echo $i === 0 ? 'active' : ''; ?>" data-index="<?php echo $i; ?>"></button>
            <?php endfor; ?>
        </div>

        <script>
        (function() {
            var slider   = document.getElementById('<?php echo esc_js( $uid ); ?>');
            var slides   = slider.querySelectorAll('.sp-slide');
            var dots     = document.querySelectorAll('[data-slider="<?php echo esc_js( $uid ); ?>"] .sp-slider-dot');
            var current  = 0;
            var total    = slides.length;
            var auto     = <?php echo $autoplay ? 'true' : 'false'; ?>;
            var interval = <?php echo $interval; ?>;
            var timer    = null;

            function goTo(idx) {
                slides[current].classList.remove('active');
                dots[current].classList.remove('active');
                current = (idx + total) % total;
                slides[current].classList.add('active');
                dots[current].classList.add('active');
            }

            function next() { goTo(current + 1); }
            function prev() { goTo(current - 1); }

            function startAuto() {
                if (auto && total > 1) {
                    timer = setInterval(next, interval);
                }
            }
            function stopAuto() {
                if (timer) { clearInterval(timer); timer = null; }
            }

            // Arrow buttons
            var prevBtn = slider.querySelector('.sp-slider-prev');
            var nextBtn = slider.querySelector('.sp-slider-next');
            if (prevBtn) prevBtn.addEventListener('click', function() { stopAuto(); prev(); startAuto(); });
            if (nextBtn) nextBtn.addEventListener('click', function() { stopAuto(); next(); startAuto(); });

            // Dot buttons
            dots.forEach(function(dot) {
                dot.addEventListener('click', function() {
                    stopAuto();
                    goTo(parseInt(this.getAttribute('data-index'), 10));
                    startAuto();
                });
            });

            // Pause on hover
            slider.addEventListener('mouseenter', stopAuto);
            slider.addEventListener('mouseleave', startAuto);

            startAuto();
        })();
        </script>
    <?php endif; ?>
    <?php
}


// ============================================================================
// SURNAME CONTACT — AJAX HANDLER
// ============================================================================
//
// WHY: Feature 2 — lets logged-in members contact a surname researcher without
//      exposing the researcher's email address. The sender's email goes in
//      Reply-To so the researcher can respond directly if they choose.

add_action( 'wp_ajax_sp_surname_contact', 'sp_handle_surname_contact' );

function sp_handle_surname_contact(): void {
    if ( ! check_ajax_referer( 'sp_surname_contact', 'sp_surname_contact_nonce', false ) ) {
        wp_send_json_error( __( 'Security check failed. Please refresh and try again.', 'societypress' ) );
    }
    if ( ! is_user_logged_in() ) {
        wp_send_json_error( __( 'You must be logged in to contact a researcher.', 'societypress' ) );
    }

    global $wpdb;
    $prefix = $wpdb->prefix . 'sp_';

    $researcher_id = absint( $_POST['researcher_id'] ?? 0 );
    $sender_name   = sanitize_text_field( $_POST['sender_name'] ?? '' );
    $sender_email  = sanitize_email( $_POST['sender_email'] ?? '' );
    $message       = sanitize_textarea_field( $_POST['message'] ?? '' );

    if ( ! $researcher_id || ! $sender_name || ! $sender_email || ! $message ) {
        wp_send_json_error( __( 'Please fill in all fields.', 'societypress' ) );
    }
    if ( ! is_email( $sender_email ) ) {
        wp_send_json_error( __( 'Please enter a valid email address.', 'societypress' ) );
    }

    // Look up the researcher's email from the contact table
    $researcher_email = $wpdb->get_var( $wpdb->prepare(
        "SELECT email FROM {$prefix}member_contact WHERE user_id = %d",
        $researcher_id
    ) );

    if ( ! $researcher_email || ! is_email( $researcher_email ) ) {
        wp_send_json_error( __( 'Unable to contact this researcher at this time.', 'societypress' ) );
    }

    // Check opt-out preference
    $opted_out = $wpdb->get_var( $wpdb->prepare(
        "SELECT meta_value FROM {$prefix}member_meta
         WHERE user_id = %d AND meta_key = 'pref_email_surnames'",
        $researcher_id
    ) );
    if ( $opted_out === '0' ) {
        wp_send_json_error( __( 'This researcher has opted out of contact messages.', 'societypress' ) );
    }

    // Build and send the email
    $site_name = get_bloginfo( 'name' );
    $body_html = '<p>' . esc_html( $sender_name ) . ' is researching a surname you have listed '
               . 'and would like to connect with you.</p>'
               . '<div style="background:#f6f7f7; border:1px solid #e0e0e0; border-radius:6px; padding:16px; margin:16px 0;">'
               . '<p style="margin:0; white-space:pre-wrap;">' . esc_html( $message ) . '</p>'
               . '</div>'
               . '<p style="color:#666; font-size:13px;">To reply, simply respond to this email. '
               . 'Your email address has not been shared with the sender.</p>';

    $html = sp_build_email_html( __( 'Surname Research Inquiry', 'societypress' ), $body_html );

    $headers = [
        'Content-Type: text/html; charset=UTF-8',
        sprintf( 'Reply-To: %s <%s>', $sender_name, $sender_email ),
    ];

    $sent = wp_mail(
        $researcher_email,
        sprintf( '[%s] Surname research inquiry from %s', $site_name, $sender_name ),
        $html,
        $headers
    );

    if ( $sent ) {
        wp_send_json_success( [ 'message' => __( 'Your message has been sent! The researcher can reply directly to your email.', 'societypress' ) ] );
    } else {
        wp_send_json_error( __( 'There was a problem sending your message. Please try again later.', 'societypress' ) );
    }
}


// ============================================================================
// PHOTO GALLERY — ADMIN PAGES
// ============================================================================
//
// WHY: Feature 5 — admin interface for managing photo albums. Albums group
//      WordPress media library attachments with captions and sort order.

/**
 * Render: Gallery Albums List Page
 *
 * WHY: Shows all albums in a card grid layout rather than a list table,
 *      because albums are visual by nature. Each card shows the cover image,
 *      title, photo count, and visibility status.
 */
function sp_render_gallery_page(): void {
    global $wpdb;
    $prefix = $wpdb->prefix . 'sp_';

    // Handle delete action
    if ( ( $_POST['action'] ?? '' ) === 'delete' && ! empty( $_POST['album_id'] ) ) {
        $album_id = absint( $_POST['album_id'] );
        check_admin_referer( 'sp_delete_album_' . $album_id );
        $wpdb->delete( $prefix . 'photo_album_items', [ 'album_id' => $album_id ] );
        $wpdb->delete( $prefix . 'photo_albums', [ 'id' => $album_id ] );
        echo '<div class="notice notice-success"><p>' . esc_html__( 'Album deleted.', 'societypress' ) . '</p></div>';
    }

    $albums = $wpdb->get_results(
        "SELECT a.*, (SELECT COUNT(*) FROM {$prefix}photo_album_items WHERE album_id = a.id) as photo_count
         FROM {$prefix}photo_albums a
         ORDER BY a.sort_order ASC, a.created_at DESC"
    );
    ?>
    <div class="wrap">
        <h1 class="wp-heading-inline"><?php esc_html_e( 'Photo Gallery', 'societypress' ); ?></h1>
        <a href="<?php echo esc_url( admin_url( 'admin.php?page=sp-album-edit' ) ); ?>" class="page-title-action">Add New Album</a>
        <hr class="wp-header-end">

        <?php if ( empty( $albums ) ) : ?>
            <p><?php esc_html_e( 'No albums yet.', 'societypress' ); ?> <a href="<?php echo esc_url( admin_url( 'admin.php?page=sp-album-edit' ) ); ?>"><?php esc_html_e( 'Create your first album', 'societypress' ); ?></a>.</p>
        <?php else : ?>
            <div style="display:flex; flex-wrap:wrap; gap:20px; margin-top:20px;">
                <?php foreach ( $albums as $album ) :
                    $cover_url = $album->cover_image_id
                        ? wp_get_attachment_image_url( $album->cover_image_id, 'medium' )
                        : '';
                    $edit_url   = admin_url( 'admin.php?page=sp-album-edit&album_id=' . $album->id );
                    // $delete_url removed — using POST form below
                ?>
                    <div style="width:220px; background:#fff; border:1px solid #ccd0d4; border-radius:8px; overflow:hidden;">
                        <a href="<?php echo esc_url( $edit_url ); ?>" style="display:block;">
                            <?php if ( $cover_url ) : ?>
                                <img src="<?php echo esc_url( $cover_url ); ?>" alt="" style="width:100%; height:160px; object-fit:cover;">
                            <?php else : ?>
                                <div style="width:100%; height:160px; background:#f0f0f0; display:flex; align-items:center; justify-content:center;">
                                    <span class="dashicons dashicons-format-gallery" style="font-size:48px; width:48px; height:48px; color:#ccc;"></span>
                                </div>
                            <?php endif; ?>
                        </a>
                        <div style="padding:12px;">
                            <h4 style="margin:0 0 4px;"><a href="<?php echo esc_url( $edit_url ); ?>" style="text-decoration:none; color:#1d2327;"><?php echo esc_html( $album->title ); ?></a></h4>
                            <span style="color:#666; font-size:12px;"><?php echo $album->photo_count; ?> photos</span>
                            <?php if ( $album->visibility === 'members_only' ) : ?>
                                <span style="background:#fef0c7; color:#92400e; font-size:10px; padding:2px 6px; border-radius:3px; margin-left:4px;"><?php esc_html_e( 'Members Only', 'societypress' ); ?></span>
                            <?php endif; ?>
                            <div style="margin-top:8px; font-size:12px;">
                                <a href="<?php echo esc_url( $edit_url ); ?>"><?php esc_html_e( 'Edit', 'societypress' ); ?></a> |
                                <form method="post" action="<?php echo esc_url( admin_url( 'admin.php?page=sp-gallery' ) ); ?>" style="display:inline;" onsubmit="return confirm('<?php echo esc_js( __( 'Delete this album and all its photos?', 'societypress' ) ); ?>');">
                                    <?php wp_nonce_field( 'sp_delete_album_' . $album->id ); ?>
                                    <input type="hidden" name="action" value="delete">
                                    <input type="hidden" name="album_id" value="<?php echo (int) $album->id; ?>">
                                    <button type="submit" class="sp-link-btn" style="background:none; border:none; color:#b32d2e; cursor:pointer; padding:0; font:inherit; text-decoration:underline;"><?php esc_html_e( 'Delete', 'societypress' ); ?></button>
                                </form>
                            </div>
                        </div>
                    </div>
                <?php endforeach; ?>
            </div>
        <?php endif; ?>
    </div>
    <?php
}

/**
 * Render: Album Edit Page
 *
 * WHY: Add/edit a photo album. Uses the WordPress media library picker so
 *      Harold can select existing images rather than re-uploading. Photos
 *      are sorted via drag-drop using native HTML5 drag events.
 */
function sp_render_album_edit_page(): void {
    global $wpdb;
    $prefix   = $wpdb->prefix . 'sp_';
    $album_id = absint( $_GET['album_id'] ?? 0 );

    // Handle save
    if ( isset( $_POST['sp_save_album'] ) && check_admin_referer( 'sp_album_save' ) ) {
        $data = [
            'title'          => sanitize_text_field( $_POST['title'] ?? '' ),
            'slug'           => sanitize_title( $_POST['title'] ?? '' ),
            'description'    => sanitize_textarea_field( $_POST['description'] ?? '' ),
            'cover_image_id' => absint( $_POST['cover_image_id'] ?? 0 ),
            'event_id'       => absint( $_POST['event_id'] ?? 0 ) ?: null,
            'visibility'     => sanitize_text_field( $_POST['visibility'] ?? 'public' ),
            'sort_order'     => absint( $_POST['sort_order'] ?? 0 ),
        ];

        if ( $album_id ) {
            $wpdb->update( $prefix . 'photo_albums', $data, [ 'id' => $album_id ] );
        } else {
            $wpdb->insert( $prefix . 'photo_albums', $data );
            $album_id = $wpdb->insert_id;
        }

        // Save photos — expects comma-separated attachment IDs
        $photo_ids = array_filter( array_map( 'absint', explode( ',', $_POST['photo_ids'] ?? '' ) ) );
        $captions  = (array) ( $_POST['photo_captions'] ?? [] );

        // Clear existing items and re-insert in order
        $wpdb->delete( $prefix . 'photo_album_items', [ 'album_id' => $album_id ] );
        foreach ( $photo_ids as $order => $attachment_id ) {
            $wpdb->insert( $prefix . 'photo_album_items', [
                'album_id'      => $album_id,
                'attachment_id' => $attachment_id,
                'caption'       => sanitize_text_field( $captions[ $attachment_id ] ?? '' ),
                'sort_order'    => $order,
            ] );
        }

        echo '<div class="notice notice-success"><p>' . esc_html__( 'Album saved.', 'societypress' ) . '</p></div>';
    }

    // Load album data
    $album = $album_id ? $wpdb->get_row( $wpdb->prepare(
        "SELECT * FROM {$prefix}photo_albums WHERE id = %d", $album_id
    ) ) : null;

    $photos = $album_id ? $wpdb->get_results( $wpdb->prepare(
        "SELECT * FROM {$prefix}photo_album_items WHERE album_id = %d ORDER BY sort_order ASC", $album_id
    ) ) : [];

    // WordPress media uploader needs this
    wp_enqueue_media();
    ?>
    <div class="wrap">
        <h1><?php echo $album ? esc_html__( 'Edit Album', 'societypress' ) : esc_html__( 'Add New Album', 'societypress' ); ?></h1>
        <a href="<?php echo esc_url( admin_url( 'admin.php?page=sp-gallery' ) ); ?>">&larr; Back to Gallery</a>

        <form method="post" style="margin-top:20px;">
            <?php wp_nonce_field( 'sp_album_save' ); ?>

            <table class="form-table">
                <tr>
                    <th><label for="title"><?php esc_html_e( 'Album Title', 'societypress' ); ?></label></th>
                    <td><input type="text" name="title" id="title" class="regular-text" value="<?php echo esc_attr( $album->title ?? '' ); ?>" required></td>
                </tr>
                <tr>
                    <th><label for="description"><?php esc_html_e( 'Description', 'societypress' ); ?></label></th>
                    <td><textarea name="description" id="description" rows="3" class="large-text"><?php echo esc_textarea( $album->description ?? '' ); ?></textarea></td>
                </tr>
                <tr>
                    <th>Cover Image</th>
                    <td>
                        <input type="hidden" name="cover_image_id" id="cover_image_id" value="<?php echo esc_attr( $album->cover_image_id ?? 0 ); ?>">
                        <div id="cover-preview" style="margin-bottom:8px;">
                            <?php if ( ! empty( $album->cover_image_id ) ) :
                                $img = wp_get_attachment_image_url( $album->cover_image_id, 'thumbnail' );
                                if ( $img ) echo '<img src="' . esc_url( $img ) . '" style="max-width:150px; border-radius:4px;">';
                            endif; ?>
                        </div>
                        <button type="button" class="button" id="select-cover-btn">Select Image</button>
                        <button type="button" class="button" id="remove-cover-btn" <?php if ( empty( $album->cover_image_id ) ) echo 'style="display:none;"'; ?>>Remove</button>
                    </td>
                </tr>
                <tr>
                    <th><label for="visibility"><?php esc_html_e( 'Visibility', 'societypress' ); ?></label></th>
                    <td>
                        <select name="visibility" id="visibility">
                            <option value="public" <?php selected( $album->visibility ?? 'public', 'public' ); ?>>Public</option>
                            <option value="members_only" <?php selected( $album->visibility ?? '', 'members_only' ); ?>>Members Only</option>
                        </select>
                    </td>
                </tr>
                <tr>
                    <th><label for="sort_order"><?php esc_html_e( 'Sort Order', 'societypress' ); ?></label></th>
                    <td><input type="number" name="sort_order" id="sort_order" value="<?php echo esc_attr( $album->sort_order ?? 0 ); ?>" min="0" style="width:80px;"></td>
                </tr>
            </table>

            <!-- Photos section -->
            <h3>Photos</h3>
            <input type="hidden" name="photo_ids" id="photo_ids" value="<?php echo esc_attr( implode( ',', array_column( $photos, 'attachment_id' ) ) ); ?>">

            <div id="album-photos" style="display:flex; flex-wrap:wrap; gap:12px; margin-bottom:16px; min-height:100px; background:#f9f9f9; border:2px dashed #ddd; border-radius:8px; padding:16px;">
                <?php foreach ( $photos as $photo ) :
                    $thumb = wp_get_attachment_image_url( $photo->attachment_id, 'thumbnail' );
                    if ( ! $thumb ) continue;
                ?>
                    <div class="sp-album-photo" data-id="<?php echo $photo->attachment_id; ?>" draggable="true" style="position:relative; width:120px; cursor:grab;">
                        <img src="<?php echo esc_url( $thumb ); ?>" style="width:120px; height:120px; object-fit:cover; border-radius:6px;">
                        <input type="text" name="photo_captions[<?php echo $photo->attachment_id; ?>]" value="<?php echo esc_attr( $photo->caption ); ?>" placeholder="Caption" style="width:120px; font-size:11px; margin-top:4px; padding:2px 4px; border:1px solid #ccc; border-radius:3px;">
                        <button type="button" class="sp-remove-photo" data-id="<?php echo $photo->attachment_id; ?>" style="position:absolute; top:-6px; right:-6px; background:#b32d2e; color:#fff; border:none; border-radius:50%; width:20px; height:20px; cursor:pointer; font-size:14px; line-height:18px;">&times;</button>
                    </div>
                <?php endforeach; ?>
            </div>
            <button type="button" class="button" id="add-photos-btn">Add Photos</button>

            <p class="submit">
                <input type="submit" name="sp_save_album" class="button button-primary" value="Save Album">
            </p>
        </form>
    </div>

    <script>
    jQuery(function($) {
        // Cover image picker
        $('#select-cover-btn').on('click', function() {
            var frame = wp.media({ title: 'Select Cover Image', button: { text: 'Set as Cover' }, multiple: false });
            frame.on('select', function() {
                var att = frame.state().get('selection').first().toJSON();
                $('#cover_image_id').val(att.id);
                $('#cover-preview').html('<img src="' + (att.sizes.thumbnail ? att.sizes.thumbnail.url : att.url) + '" style="max-width:150px; border-radius:4px;">');
                $('#remove-cover-btn').show();
            });
            frame.open();
        });
        $('#remove-cover-btn').on('click', function() {
            $('#cover_image_id').val(0);
            $('#cover-preview').empty();
            $(this).hide();
        });

        // Add photos
        $('#add-photos-btn').on('click', function() {
            var frame = wp.media({ title: 'Add Photos', button: { text: 'Add to Album' }, multiple: true });
            frame.on('select', function() {
                var attachments = frame.state().get('selection').toJSON();
                var currentIds = $('#photo_ids').val() ? $('#photo_ids').val().split(',').map(Number) : [];
                attachments.forEach(function(att) {
                    if (currentIds.indexOf(att.id) !== -1) return; // skip dupes
                    currentIds.push(att.id);
                    var thumb = att.sizes && att.sizes.thumbnail ? att.sizes.thumbnail.url : att.url;
                    var html = '<div class="sp-album-photo" data-id="' + att.id + '" draggable="true" style="position:relative; width:120px; cursor:grab;">'
                        + '<img src="' + thumb + '" style="width:120px; height:120px; object-fit:cover; border-radius:6px;">'
                        + '<input type="text" name="photo_captions[' + att.id + ']" placeholder="Caption" style="width:120px; font-size:11px; margin-top:4px; padding:2px 4px; border:1px solid #ccc; border-radius:3px;">'
                        + '<button type="button" class="sp-remove-photo" data-id="' + att.id + '" style="position:absolute; top:-6px; right:-6px; background:#b32d2e; color:#fff; border:none; border-radius:50%; width:20px; height:20px; cursor:pointer; font-size:14px; line-height:18px;">&times;</button>'
                        + '</div>';
                    $('#album-photos').append(html);
                });
                $('#photo_ids').val(currentIds.join(','));
            });
            frame.open();
        });

        // Remove photo
        $(document).on('click', '.sp-remove-photo', function() {
            var id = $(this).data('id');
            $(this).closest('.sp-album-photo').remove();
            var ids = $('#photo_ids').val().split(',').filter(function(v) { return v != id; });
            $('#photo_ids').val(ids.join(','));
        });

        // Drag-drop reorder
        var container = document.getElementById('album-photos');
        var dragSrc = null;
        container.addEventListener('dragstart', function(e) {
            dragSrc = e.target.closest('.sp-album-photo');
            if (dragSrc) e.dataTransfer.effectAllowed = 'move';
        });
        container.addEventListener('dragover', function(e) {
            e.preventDefault();
            e.dataTransfer.dropEffect = 'move';
        });
        container.addEventListener('drop', function(e) {
            e.preventDefault();
            var target = e.target.closest('.sp-album-photo');
            if (target && dragSrc && target !== dragSrc) {
                var items = Array.from(container.querySelectorAll('.sp-album-photo'));
                var srcIdx = items.indexOf(dragSrc);
                var tgtIdx = items.indexOf(target);
                if (srcIdx < tgtIdx) target.after(dragSrc);
                else target.before(dragSrc);
                // Update hidden field with new order
                var newIds = Array.from(container.querySelectorAll('.sp-album-photo')).map(function(el) { return el.dataset.id; });
                $('#photo_ids').val(newIds.join(','));
            }
        });
    });
    </script>
    <?php
}


