                                        <span><form method="post" action="<?php echo esc_url( admin_url( 'admin.php?page=sp-resource-categories' ) ); ?>" style="display:inline;" onsubmit="return confirm('<?php echo esc_js( __( 'Delete?', 'societypress' ) ); ?>');"><?php wp_nonce_field( 'sp_delete_resource_cat_' . $cat->id ); ?><input type="hidden" name="action" value="delete"><input type="hidden" name="cat_id" value="<?php echo (int) $cat->id; ?>"><button type="submit" class="sp-link-btn" style="background:none; border:none; color:#b32d2e; cursor:pointer; padding:0; font:inherit; text-decoration:underline;"><?php esc_html_e( 'Delete', 'societypress' ); ?></button></form></span>
                                    </div>
                                </td>
                                <td><?php echo esc_html( $cat->slug ); ?></td>
                                <td><?php echo $cat->sort_order; ?></td>
                                <td><?php echo $cat->active ? esc_html__( 'Yes', 'societypress' ) : esc_html__( 'No', 'societypress' ); ?></td>
                            </tr>
                        <?php endforeach; ?>
                    </tbody>
                </table>
            </div>
        </div>
    </div>
    <?php
}


// ============================================================================
// RESOURCE LINKS CSV IMPORT
// ============================================================================
// WHY: the society has 171 curated genealogy resource links exported from their old
//      EasyNetSites platform as CSV. This importer reads that format, creates
//      categories on the fly, and populates the sp_resources table so the admin
//      doesn't have to re-enter everything by hand.
// ============================================================================


/**
 * Process a resource links CSV import.
 *
 * WHY a dedicated function: Same pattern as sp_process_library_import() — the
 *     actual data crunching is separated from the UI rendering so it can be
 *     tested or called programmatically if ever needed.
 *
 * @param string $file_path      Absolute path to the temp CSV file.
 * @param array  $field_map      CSV column name => target field key.
 * @return array { imported: int, skipped: int, categories_created: int, errors: string[] }
 */
function sp_process_links_import( string $file_path, array $field_map ): array {
    global $wpdb;
    $prefix = $wpdb->prefix . 'sp_';

    $imported           = 0;
    $skipped            = 0;
    $categories_created = 0;
    $errors             = [];

    $handle = fopen( $file_path, 'r' );
    if ( ! $handle ) {
        return [ 'imported' => 0, 'skipped' => 0, 'categories_created' => 0, 'errors' => [ 'Could not open CSV file.' ] ];
    }

    // Read headers and strip BOM / whitespace
    $headers = fgetcsv( $handle );
    if ( ! $headers ) {
        fclose( $handle );
        return [ 'imported' => 0, 'skipped' => 0, 'categories_created' => 0, 'errors' => [ 'CSV file has no headers.' ] ];
    }
    $headers = array_map( function( $h ) {
        return trim( $h, "\xEF\xBB\xBF \t\n\r" );
    }, $headers );

    // Build a column-index-to-target lookup from the field map.
    // WHY: The field map uses CSV column names as keys, but we need to look up
    //      by column index as we iterate each row.
    $col_targets = [];
    foreach ( $headers as $idx => $header_name ) {
        if ( isset( $field_map[ $header_name ] ) && $field_map[ $header_name ] !== '' ) {
            $col_targets[ $idx ] = $field_map[ $header_name ];
        }
    }

    // Cache of category name → ID so we only query/create once per unique name
    $category_cache = [];

    // Pre-load existing categories
    $existing_cats = $wpdb->get_results( "SELECT id, name FROM {$prefix}resource_categories" );
    foreach ( $existing_cats as $cat ) {
        $category_cache[ strtolower( trim( $cat->name ) ) ] = (int) $cat->id;
    }

    // Pre-load existing resource URLs for duplicate detection
    $existing_urls = $wpdb->get_col( "SELECT url FROM {$prefix}resources" );
    $existing_url_set = array_flip( array_map( 'strtolower', $existing_urls ) );

    $row_num = 1; // 1-based (header is row 0)
    while ( ( $row = fgetcsv( $handle ) ) !== false ) {
        $row_num++;

        // Map this row's values into named fields
        $mapped = [];
        foreach ( $col_targets as $idx => $target ) {
            $mapped[ $target ] = isset( $row[ $idx ] ) ? trim( $row[ $idx ] ) : '';
        }

        // Title and URL are required
        $title = $mapped['title'] ?? '';
        $url   = $mapped['url'] ?? '';
        if ( empty( $title ) || empty( $url ) ) {
            $skipped++;
            continue;
        }

        // Duplicate detection — skip if this URL already exists
        if ( isset( $existing_url_set[ strtolower( $url ) ] ) ) {
            $skipped++;
            continue;
        }

        // Clean up description — the EasyNetSites export has HTML in description fields.
        // Convert <br> to newlines, <li> items to dash-prefixed lines, then strip remaining HTML.
        $description = $mapped['description'] ?? '';
        if ( ! empty( $description ) ) {
            $description = preg_replace( '/<br\s*\/?>/i', "\n", $description );
            $description = preg_replace( '/<li[^>]*>/i', "\n- ", $description );
            $description = wp_strip_all_tags( $description );
            $description = trim( $description );
        }

        // Sort order — default to 0 if not mapped or not numeric
        $sort_order = 0;
        if ( ! empty( $mapped['sort_order'] ) && is_numeric( $mapped['sort_order'] ) ) {
            $sort_order = absint( $mapped['sort_order'] );
        }

        // Updated date — parse MM/DD/YYYY format from EasyNetSites export
        $updated_at = current_time( 'mysql' );
        if ( ! empty( $mapped['updated_at'] ) ) {
            $parsed_date = DateTime::createFromFormat( 'm/d/Y', $mapped['updated_at'] );
            if ( $parsed_date ) {
                $updated_at = $parsed_date->format( 'Y-m-d H:i:s' );
            }
        }

        // Category — look up by name or create if it doesn't exist
        $category_id = null;
        if ( ! empty( $mapped['category'] ) ) {
            $cat_name = trim( $mapped['category'] );
            $cat_key  = strtolower( $cat_name );

            if ( isset( $category_cache[ $cat_key ] ) ) {
                $category_id = $category_cache[ $cat_key ];
            } else {
                // Create the category
                $cat_sort = 0;
                if ( ! empty( $mapped['category_sort_order'] ) && is_numeric( $mapped['category_sort_order'] ) ) {
                    $cat_sort = absint( $mapped['category_sort_order'] );
                }
                $wpdb->insert( $prefix . 'resource_categories', [
                    'name'       => sanitize_text_field( $cat_name ),
                    'slug'       => sanitize_title( $cat_name ),
                    'sort_order' => $cat_sort,
                    'active'     => 1,
                ] );
                $category_id = (int) $wpdb->insert_id;
                $category_cache[ $cat_key ] = $category_id;
                $categories_created++;
            }

            // Update category sort order if this row provides one and the
            // category was pre-existing — the CSV may have a better sort value
            // than whatever the default was.
            if ( ! empty( $mapped['category_sort_order'] ) && is_numeric( $mapped['category_sort_order'] ) ) {
                $wpdb->update(
                    $prefix . 'resource_categories',
                    [ 'sort_order' => absint( $mapped['category_sort_order'] ) ],
                    [ 'id' => $category_id ]
                );
            }
        }

        // Insert the resource
        $inserted = $wpdb->insert( $prefix . 'resources', [
            'title'       => sanitize_text_field( $title ),
            'url'         => esc_url_raw( $url ),
            'description' => sanitize_textarea_field( $description ),
            'category_id' => $category_id,
            'featured'    => 0,
            'active'      => 1,
            'sort_order'  => $sort_order,
            'updated_at'  => $updated_at,
        ] );

        if ( $inserted ) {
            $imported++;
            // Track the URL so duplicate detection works within the same import
            $existing_url_set[ strtolower( $url ) ] = true;
        } else {
            $errors[] = sprintf( 'Row %d: Database insert failed for "%s".', $row_num, $title );
        }
    }

    fclose( $handle );

    return [
        'imported'           => $imported,
        'skipped'            => $skipped,
        'categories_created' => $categories_created,
        'errors'             => $errors,
    ];
}


/**
 * Render: Resource Links Import Page
 *
 * WHY two-step: Same UX pattern as library import — upload first, preview the
 *     data and confirm field mapping, then run the actual import. This prevents
 *     accidental imports and lets the admin verify the CSV looks right before
 *     committing ~171 rows to the database.
 */
function sp_render_links_import_page(): void {
    global $wpdb;

    $results = null;
    $preview = null;

    // ------------------------------------------------------------------
    // STEP 2: Run the actual import from the temp file
    // ------------------------------------------------------------------
    if ( isset( $_POST['sp_import_action'] ) && $_POST['sp_import_action'] === 'run_import' ) {
        check_admin_referer( 'sp_import_links' );

        // Reconstruct full path from basename token — never trust full paths from HTML
        $token     = sanitize_file_name( $_POST['sp_import_temp_file'] ?? '' );
        $upload_dir = wp_upload_dir();
        $temp_dir   = $upload_dir['basedir'] . '/sp-import-temp/';
        $temp_file  = realpath( $temp_dir . $token );
        if ( ! $temp_file || strpos( $temp_file, realpath( $temp_dir ) ) !== 0 ) {
            $temp_file = '';
        }

        $raw_map = isset( $_POST['sp_field_map'] ) && is_array( $_POST['sp_field_map'] )
                 ? $_POST['sp_field_map']
                 : [];
        $import_field_map = [];
        foreach ( $raw_map as $csv_col => $target ) {
            $import_field_map[ sanitize_text_field( $csv_col ) ] = sanitize_text_field( $target );
        }

        if ( ! empty( $temp_file ) && file_exists( $temp_file ) ) {
            $results = sp_process_links_import( $temp_file, $import_field_map );
            wp_delete_file( $temp_file );
        } else {
            $results = [
                'imported' => 0, 'skipped' => 0, 'categories_created' => 0,
                'errors'   => [ __( 'The uploaded file has expired. Please upload again.', 'societypress' ) ],
            ];
        }
    }

    // ------------------------------------------------------------------
    // STEP 1: Upload CSV and show preview / field mapping
    // ------------------------------------------------------------------
    if ( isset( $_POST['sp_import_action'] ) && $_POST['sp_import_action'] === 'preview' ) {
        check_admin_referer( 'sp_import_links' );

        if ( ! empty( $_FILES['import_file']['tmp_name'] ) ) {
            $upload_dir = wp_upload_dir();
            $temp_dir   = $upload_dir['basedir'] . '/sp-import-temp';
            if ( ! is_dir( $temp_dir ) ) {
                wp_mkdir_p( $temp_dir );
                file_put_contents( $temp_dir . '/.htaccess', 'Deny from all' );
            }

            $temp_file = $temp_dir . '/links-import-' . wp_generate_password( 12, false ) . '.csv';
            move_uploaded_file( $_FILES['import_file']['tmp_name'], $temp_file );

            $handle  = fopen( $temp_file, 'r' );
            $headers = fgetcsv( $handle );

            if ( $headers ) {
                $headers = array_map( function( $h ) {
                    return trim( $h, "\xEF\xBB\xBF \t\n\r" );
                }, $headers );

                $row_count   = 0;
                $sample_rows = [];
                while ( ( $row = fgetcsv( $handle ) ) !== false ) {
                    $row_count++;
                    if ( count( $sample_rows ) < 5 ) {
                        $sample_rows[] = $row;
                    }
                }

                $preview = [
                    'headers'     => $headers,
                    'sample_rows' => $sample_rows,
                    'row_count'   => $row_count,
                    'temp_file'   => $temp_file,
                ];
            } else {
                wp_delete_file( $temp_file );
            }
            fclose( $handle );
        }
    }

    // ------------------------------------------------------------------
    // Target fields — the resource link columns available for mapping.
    // WHY fewer fields than library: Resource links are simpler — just a title,
    //     URL, description, category, and sort order. No ISBN, call number, etc.
    // ------------------------------------------------------------------
    $target_fields = [
        'title'               => 'Link Title',
        'url'                 => 'URL',
        'description'         => 'Description',
        'sort_order'          => 'Sort Order',
        'updated_at'          => 'Last Updated Date',
        'category'            => 'Category Name',
        'category_sort_order' => 'Category Sort Order',
    ];

    // ------------------------------------------------------------------
    // Auto-mapping — known column names from the EasyNetSites links export.
    // WHY: The the society export uses specific column names like "Link Title" and
    //      "Link Description". Auto-mapping these means the admin just clicks
    //      "Import" instead of mapping 9 columns by hand.
    // ------------------------------------------------------------------
    $auto_map = [
        'Link Title'          => 'title',
        'Link'                => 'url',
        'Link Description'    => 'description',
        'Link Sort Order'     => 'sort_order',
        'Last Updated'        => 'updated_at',
        'Link Category'       => 'category',
        'Category Sort Order' => 'category_sort_order',
    ];

    ?>
    <div class="wrap">
        <h1><?php esc_html_e( 'Import Resource Links', 'societypress' ); ?></h1>

        <?php if ( $results ) : ?>
            <!-- ============================================================
                 IMPORT RESULTS
                 Shows how many links were imported, skipped, and any errors.
                 ============================================================ -->
            <div class="notice notice-<?php echo $results['imported'] > 0 ? 'success' : 'warning'; ?>">
                <p>
                    <strong><?php esc_html_e( 'Import complete.', 'societypress' ); ?></strong>
                    <?php echo number_format( $results['imported'] ); ?> link<?php echo $results['imported'] !== 1 ? 's' : ''; ?> imported.
                    <?php if ( $results['categories_created'] > 0 ) : ?>
                        <?php echo number_format( $results['categories_created'] ); ?> new categor<?php echo $results['categories_created'] !== 1 ? 'ies' : 'y'; ?> created.
                    <?php endif; ?>
                    <?php if ( $results['skipped'] > 0 ) : ?>
                        <?php echo number_format( $results['skipped'] ); ?> skipped (duplicates or missing title/URL).
                    <?php endif; ?>
                </p>
            </div>
            <?php if ( ! empty( $results['errors'] ) ) : ?>
                <div class="notice notice-error">
                    <p><strong><?php esc_html_e( 'Errors:', 'societypress' ); ?></strong></p>
                    <ul style="margin-left:20px; list-style:disc;">
                        <?php foreach ( $results['errors'] as $err ) : ?>
                            <li><?php echo esc_html( $err ); ?></li>
                        <?php endforeach; ?>
                    </ul>
                </div>
            <?php endif; ?>

            <?php
            $total_links = (int) $wpdb->get_var( "SELECT COUNT(*) FROM {$wpdb->prefix}sp_resources" );
            ?>
            <p>
                <?php esc_html_e( 'You now have', 'societypress' ); ?> <strong><?php echo number_format( $total_links ); ?></strong> <?php esc_html_e( 'resource links.', 'societypress' ); ?>
                <a href="<?php echo esc_url( admin_url( 'admin.php?page=sp-library' ) ); ?>"><?php esc_html_e( 'View Resources →', 'societypress' ); ?></a>
            </p>
        <?php endif; ?>

        <?php if ( $preview ) : ?>
            <!-- ============================================================
                 STEP 2: FIELD MAPPING PREVIEW
                 Shows the detected CSV columns, sample data, and dropdowns
                 for mapping each column to a resource link field.
                 ============================================================ -->
            <div class="card" style="max-width:100%; padding:20px; margin-top:16px;">
                <h2 style="margin-top:0;"><?php esc_html_e( 'Map CSV Columns', 'societypress' ); ?></h2>
                <p class="description">
                    <?php
                    printf(
                        /* translators: %d is the number of data rows found */
                        esc_html__( 'Found %d data rows. Map each CSV column to a resource field, or leave as "— Skip —" to ignore it.', 'societypress' ),
                        $preview['row_count']
                    );
                    ?>
                </p>

                <form method="post">
                    <?php wp_nonce_field( 'sp_import_links' ); ?>
                    <input type="hidden" name="sp_import_action" value="run_import">
                    <input type="hidden" name="sp_import_temp_file" value="<?php echo esc_attr( basename( $preview['temp_file'] ) ); ?>">

                    <table class="widefat striped" style="margin-top:12px;">
                        <thead>
                            <tr>
                                <th><?php esc_html_e( 'CSV Column', 'societypress' ); ?></th>
                                <th><?php esc_html_e( 'Map To', 'societypress' ); ?></th>
                                <th><?php esc_html_e( 'Sample Data (first rows)', 'societypress' ); ?></th>
                            </tr>
                        </thead>
                        <tbody>
                            <?php foreach ( $preview['headers'] as $col_idx => $col_name ) :
                                // Check if auto-map has a suggestion for this column
                                $suggested = $auto_map[ $col_name ] ?? '';
                            ?>
                                <tr>
                                    <td><strong><?php echo esc_html( $col_name ); ?></strong></td>
                                    <td>
                                        <select name="sp_field_map[<?php echo esc_attr( $col_name ); ?>]">
                                            <option value=""><?php esc_html_e( '— Skip —', 'societypress' ); ?></option>
                                            <?php foreach ( $target_fields as $key => $label ) : ?>
                                                <option value="<?php echo esc_attr( $key ); ?>" <?php selected( $suggested, $key ); ?>><?php echo esc_html( $label ); ?></option>
                                            <?php endforeach; ?>
                                        </select>
                                    </td>
                                    <td style="font-size:12px; color:#666; max-width:400px; overflow:hidden; text-overflow:ellipsis; white-space:nowrap;">
                                        <?php
                                        // Show sample values from first few rows for this column
                                        $samples = [];
                                        foreach ( $preview['sample_rows'] as $sample_row ) {
                                            if ( isset( $sample_row[ $col_idx ] ) && trim( $sample_row[ $col_idx ] ) !== '' ) {
                                                $samples[] = esc_html( mb_substr( trim( $sample_row[ $col_idx ] ), 0, 60 ) );
                                            }
                                        }
                                        echo implode( ' | ', array_slice( $samples, 0, 3 ) );
                                        ?>
                                    </td>
                                </tr>
                            <?php endforeach; ?>
                        </tbody>
                    </table>

                    <p class="submit">
                        <input type="submit" class="button button-primary" value="<?php esc_attr_e( 'Run Import', 'societypress' ); ?>">
                        <a href="<?php echo esc_url( admin_url( 'admin.php?page=sp-import-links' ) ); ?>" class="button"><?php esc_html_e( 'Cancel', 'societypress' ); ?></a>
                    </p>
                </form>
            </div>

        <?php else : ?>
            <!-- ============================================================
                 STEP 1: UPLOAD FORM
                 Simple file upload — same pattern as the library import.
                 ============================================================ -->
            <?php if ( ! $results ) : ?>
                <div class="card" style="max-width:600px; padding:20px; margin-top:16px;">
                    <h2 style="margin-top:0;"><?php esc_html_e( 'Upload Links CSV', 'societypress' ); ?></h2>
                    <p class="description">
                        <?php esc_html_e( 'Upload a CSV file containing resource links. The importer will auto-detect columns from common export formats (EasyNetSites, etc.) and let you map them before importing.', 'societypress' ); ?>
                    </p>

                    <form method="post" enctype="multipart/form-data">
                        <?php wp_nonce_field( 'sp_import_links' ); ?>
                        <input type="hidden" name="sp_import_action" value="preview">

                        <table class="form-table">
                            <tr>
                                <th><label for="import_file"><?php esc_html_e( 'CSV File', 'societypress' ); ?></label></th>
                                <td>
                                    <input type="file" name="import_file" id="import_file" accept=".csv" required>
                                    <p class="description"><?php esc_html_e( 'Maximum file size: 2 MB. Must be a .csv file.', 'societypress' ); ?></p>
                                </td>
                            </tr>
                        </table>

                        <p class="submit">
                            <input type="submit" class="button button-primary" value="<?php esc_attr_e( 'Upload & Preview', 'societypress' ); ?>">
                        </p>
                    </form>
                </div>
            <?php endif; ?>
        <?php endif; ?>
    </div>
    <?php
}


// ============================================================================
// VOLUNTEER TRACKING — LIST TABLES & ADMIN PAGES
// ============================================================================
//
// WHY: Feature 4 — replaces the old Governance placeholder with a real
//      volunteer management system. Two WP_List_Table subclasses handle the
//      roster (standing roles) and hours log (activity tracking).

/**
 * Volunteer Roster List Table
 *
 * WHY: Shows active volunteer role assignments — who does what and for which
 *      committee. This is the "standing army" view of volunteer resources.
 */
class SP_Volunteers_List_Table extends WP_List_Table {

    public function __construct() {
        parent::__construct( [
            'singular' => 'volunteer',
            'plural'   => 'volunteers',
            'ajax'     => false,
        ] );
    }

    public function get_columns(): array {
        return [
            'cb'         => '<input type="checkbox" />',
            'name'       => __( 'Volunteer', 'societypress' ),
            'role_title' => __( 'Role', 'societypress' ),
            'committee'  => __( 'Committee', 'societypress' ),
            'start_date' => __( 'Start Date', 'societypress' ),
            'end_date'   => __( 'End Date', 'societypress' ),
            'status'     => __( 'Status', 'societypress' ),
        ];
    }

    public function get_sortable_columns(): array {
        return [
            'name'       => [ 'last_name', true ],
            'role_title' => [ 'role_title', false ],
            'start_date' => [ 'start_date', false ],
            'status'     => [ 'status', false ],
        ];
    }

    protected function get_bulk_actions(): array {
        return [ 'delete' => __( 'Delete', 'societypress' ) ];
    }

    protected function column_cb( $item ): string {
        return sprintf( '<input type="checkbox" name="volunteer_role[]" value="%d" />', $item->id );
    }

    protected function column_name( $item ): string {
        $name = esc_html( $item->first_name . ' ' . $item->last_name );
        $edit_url = admin_url( 'admin.php?page=sp-volunteer-roster&action=edit&role_id=' . $item->id );
        $actions = [
            'edit'   => sprintf( '<a href="%s">%s</a>', esc_url( $edit_url ), esc_html__( 'Edit', 'societypress' ) ),
            'delete' => '<a href="#" style="color:#b32d2e;" onclick="if(confirm(\'' . esc_js( __( 'Delete this role assignment?', 'societypress' ) ) . '\')){var f=document.createElement(\'form\');f.method=\'post\';f.action=\'' . esc_url( admin_url( 'admin.php?page=sp-volunteer-roster' ) ) . '\';var d=[[\'_wpnonce\',\'' . wp_create_nonce( 'sp_delete_volunteer_role_' . $item->id ) . '\'],[\'action\',\'delete\'],[\'role_id\',\'' . (int) $item->id . '\']];d.forEach(function(p){var i=document.createElement(\'input\');i.type=\'hidden\';i.name=p[0];i.value=p[1];f.appendChild(i);});document.body.appendChild(f);f.submit();}return false;">' . esc_html__( 'Delete', 'societypress' ) . '</a>',
        ];

        return '<strong><a href="' . esc_url( $edit_url ) . '">' . $name . '</a></strong>' . $this->row_actions( $actions );
    }

    protected function column_default( $item, $column_name ): string {
        switch ( $column_name ) {
            case 'role_title': return esc_html( $item->role_title ?: '—' );
            case 'committee':  return esc_html( $item->committee ?: '—' );
            case 'start_date': return $item->start_date ? esc_html( wp_date( 'M j, Y', strtotime( $item->start_date ) ) ) : '—';
            case 'end_date':   return $item->end_date ? esc_html( wp_date( 'M j, Y', strtotime( $item->end_date ) ) ) : esc_html__( 'Ongoing', 'societypress' );
            case 'status':
                $colors = [ 'active' => '#0a6b2e', 'inactive' => '#b32d2e' ];
                $color = $colors[ $item->status ] ?? '#666';
                return '<span style="color:' . $color . '; font-weight:600;">' . esc_html( ucfirst( $item->status ) ) . '</span>';
            default: return '';
        }
    }

    public function prepare_items(): void {
        global $wpdb;
        $prefix = $wpdb->prefix . 'sp_';

        $this->_column_headers = [ $this->get_columns(), [], $this->get_sortable_columns() ];

        // Handle bulk delete
        if ( 'delete' === ( $_REQUEST['action'] ?? '' ) && ! empty( $_REQUEST['volunteer_role'] ) ) {
            check_admin_referer( 'bulk-volunteers' );
            $ids = array_map( 'absint', (array) $_REQUEST['volunteer_role'] );
            $placeholders = implode( ',', array_fill( 0, count( $ids ), '%d' ) );
            $wpdb->query( $wpdb->prepare( "DELETE FROM {$prefix}volunteer_roles WHERE id IN ({$placeholders})", ...$ids ) );
        }

        // Handle single delete — POST-only
        if ( 'delete' === ( $_POST['action'] ?? '' ) && ! empty( $_POST['role_id'] ) ) {
            $role_id = absint( $_POST['role_id'] );
            check_admin_referer( 'sp_delete_volunteer_role_' . $role_id );
            $wpdb->delete( $prefix . 'volunteer_roles', [ 'id' => $role_id ] );
        }

        $orderby = sanitize_sql_orderby( $_GET['orderby'] ?? 'last_name' ) ?: 'last_name';
        $order   = strtoupper( $_GET['order'] ?? 'ASC' ) === 'DESC' ? 'DESC' : 'ASC';
        $search  = isset( $_GET['s'] ) ? sanitize_text_field( $_GET['s'] ) : '';

        // WHY: Filter to role_type = 'volunteer' (or empty/NULL for backwards compat).
        // Officers and committee members now live on the Leadership & Committees page;
        // this roster only shows day-to-day volunteer assignments.
        $where = " AND (vr.role_type = 'volunteer' OR vr.role_type = '' OR vr.role_type IS NULL)";
        if ( $search ) {
            $like = '%' . $wpdb->esc_like( $search ) . '%';
            $where .= $wpdb->prepare(
                " AND (m.first_name LIKE %s OR m.last_name LIKE %s OR vr.role_title LIKE %s OR vr.committee LIKE %s)",
                $like, $like, $like, $like
            );
        }

        $per_page = 20;
        $page_num = $this->get_pagenum();
        $offset   = ( $page_num - 1 ) * $per_page;

        $total = (int) $wpdb->get_var(
            "SELECT COUNT(*) FROM {$prefix}volunteer_roles vr
             INNER JOIN {$prefix}members m ON vr.user_id = m.user_id
             WHERE 1=1{$where}"
        );

        $this->items = $wpdb->get_results(
            "SELECT vr.*, m.first_name, m.last_name
             FROM {$prefix}volunteer_roles vr
             INNER JOIN {$prefix}members m ON vr.user_id = m.user_id
             WHERE 1=1{$where}
             ORDER BY {$orderby} {$order}
             LIMIT {$per_page} OFFSET {$offset}"
        );

        $this->set_pagination_args( [
            'total_items' => $total,
            'per_page'    => $per_page,
            'total_pages' => ceil( $total / $per_page ),
        ] );
    }
}

/**
 * Volunteer Hours List Table
 *
 * WHY: Shows the activity log — individual hours entries with dates, activities,
 *      and the volunteer who performed them. Used for reporting and recognition.
 */
class SP_VolunteerHours_List_Table extends WP_List_Table {

    public function __construct() {
        parent::__construct( [
            'singular' => 'volunteer_hour',
            'plural'   => 'volunteer_hours',
            'ajax'     => false,
        ] );
    }

    public function get_columns(): array {
        return [
            'cb'            => '<input type="checkbox" />',
            'name'          => __( 'Volunteer', 'societypress' ),
            'activity'      => __( 'Activity', 'societypress' ),
            'committee'     => __( 'Committee', 'societypress' ),
            'hours'         => __( 'Hours', 'societypress' ),
            'activity_date' => __( 'Date', 'societypress' ),
        ];
    }

    public function get_sortable_columns(): array {
        return [
            'name'          => [ 'last_name', false ],
            'activity_date' => [ 'activity_date', true ],
            'hours'         => [ 'hours', false ],
        ];
    }

    protected function get_bulk_actions(): array {
        return [ 'delete' => __( 'Delete', 'societypress' ) ];
    }

    protected function column_cb( $item ): string {
        return sprintf( '<input type="checkbox" name="hour_entry[]" value="%d" />', $item->id );
    }

    protected function column_name( $item ): string {
        $name = esc_html( $item->first_name . ' ' . $item->last_name );
        $actions = [
            'delete' => '<a href="#" style="color:#b32d2e;" onclick="if(confirm(\'' . esc_js( __( 'Delete this entry?', 'societypress' ) ) . '\')){var f=document.createElement(\'form\');f.method=\'post\';f.action=\'' . esc_url( admin_url( 'admin.php?page=sp-volunteer-hours' ) ) . '\';var d=[[\'_wpnonce\',\'' . wp_create_nonce( 'sp_delete_volunteer_hour_' . $item->id ) . '\'],[\'action\',\'delete\'],[\'hour_id\',\'' . (int) $item->id . '\']];d.forEach(function(p){var i=document.createElement(\'input\');i.type=\'hidden\';i.name=p[0];i.value=p[1];f.appendChild(i);});document.body.appendChild(f);f.submit();}return false;">' . esc_html__( 'Delete', 'societypress' ) . '</a>',
        ];
        return '<strong>' . $name . '</strong>' . $this->row_actions( $actions );
    }

    protected function column_default( $item, $column_name ): string {
        switch ( $column_name ) {
            case 'activity':      return esc_html( $item->activity ?: '—' );
            case 'committee':     return esc_html( $item->committee ?: '—' );
            case 'hours':         return esc_html( number_format( (float) $item->hours, 1 ) );
            case 'activity_date': return $item->activity_date ? esc_html( wp_date( 'M j, Y', strtotime( $item->activity_date ) ) ) : '—';
            default: return '';
        }
    }

    public function prepare_items(): void {
        global $wpdb;
        $prefix = $wpdb->prefix . 'sp_';

        $this->_column_headers = [ $this->get_columns(), [], $this->get_sortable_columns() ];

        // Handle bulk delete
        if ( 'delete' === ( $_REQUEST['action'] ?? '' ) && ! empty( $_REQUEST['hour_entry'] ) ) {
            check_admin_referer( 'bulk-volunteer_hours' );
            $ids = array_map( 'absint', (array) $_REQUEST['hour_entry'] );
            $placeholders = implode( ',', array_fill( 0, count( $ids ), '%d' ) );
            $wpdb->query( $wpdb->prepare( "DELETE FROM {$prefix}volunteer_hours WHERE id IN ({$placeholders})", ...$ids ) );
        }

        // Handle single delete — POST-only
        if ( 'delete' === ( $_POST['action'] ?? '' ) && ! empty( $_POST['hour_id'] ) ) {
            $hour_id = absint( $_POST['hour_id'] );
            check_admin_referer( 'sp_delete_volunteer_hour_' . $hour_id );
            $wpdb->delete( $prefix . 'volunteer_hours', [ 'id' => $hour_id ] );
        }

        $orderby = sanitize_sql_orderby( $_GET['orderby'] ?? 'activity_date' ) ?: 'activity_date';
        $order   = strtoupper( $_GET['order'] ?? 'DESC' ) === 'ASC' ? 'ASC' : 'DESC';

        $per_page = 20;
        $page_num = $this->get_pagenum();
        $offset   = ( $page_num - 1 ) * $per_page;

        $total = (int) $wpdb->get_var(
            "SELECT COUNT(*) FROM {$prefix}volunteer_hours"
        );

        $this->items = $wpdb->get_results(
            "SELECT vh.*, m.first_name, m.last_name
             FROM {$prefix}volunteer_hours vh
             INNER JOIN {$prefix}members m ON vh.user_id = m.user_id
             ORDER BY {$orderby} {$order}
             LIMIT {$per_page} OFFSET {$offset}"
        );

        $this->set_pagination_args( [
            'total_items' => $total,
            'per_page'    => $per_page,
            'total_pages' => ceil( $total / $per_page ),
        ] );
    }
}

/**
 * Render: Volunteers Page (Roster)
 *
 * WHY: Admin page showing all volunteer role assignments with an inline
 *      add/edit form at the top. Replaces the old Governance placeholder.
 */
// ============================================================================
// VOLUNTEER OPPORTUNITIES — CRUD + FRONTEND + AJAX
// ============================================================================
//
// WHY: Members need a way to find and sign up for volunteer work. Committee
//      chairs post needs ("We need 3 people for the book sale"), members
//      browse opportunities on the frontend and sign up. This is the full
//      cycle: admin creates opportunities, members sign up, admins track.
// ============================================================================

/**
 * Get the signup count for an opportunity.
 *
 * @param int $opp_id Opportunity ID.
 * @return int Number of confirmed signups.
 */
function sp_volunteer_opp_signup_count( int $opp_id ): int {
    global $wpdb;
    return (int) $wpdb->get_var( $wpdb->prepare(
        "SELECT COUNT(*) FROM {$wpdb->prefix}sp_volunteer_signups
         WHERE opportunity_id = %d AND status = 'confirmed'",
        $opp_id
    ) );
}

/**
 * Get remaining capacity for an opportunity.
 *
 * @param int $opp_id Opportunity ID.
 * @return int|null Remaining spots, or null if unlimited.
 */
function sp_volunteer_opp_remaining( int $opp_id ): ?int {
    global $wpdb;
    $opp = $wpdb->get_row( $wpdb->prepare(
        "SELECT capacity FROM {$wpdb->prefix}sp_volunteer_opportunities WHERE id = %d", $opp_id
    ) );
    if ( ! $opp || $opp->capacity === null ) {
        return null;
    }
    $count = sp_volunteer_opp_signup_count( $opp_id );
    return max( 0, (int) $opp->capacity - $count );
}

/**
 * Auto-promote from waitlist when a confirmed signup is cancelled.
 *
 * @param int $opp_id Opportunity ID.
 */
function sp_volunteer_promote_waitlist( int $opp_id ): void {
    global $wpdb;
    $table = $wpdb->prefix . 'sp_volunteer_signups';

    $remaining = sp_volunteer_opp_remaining( $opp_id );
    if ( $remaining !== null && $remaining <= 0 ) {
        return;
    }

    // If null capacity (unlimited), promote all waitlisted
    if ( $remaining === null ) {
        $wpdb->query( $wpdb->prepare(
            "UPDATE {$table} SET status = 'confirmed' WHERE opportunity_id = %d AND status = 'waitlisted'",
            $opp_id
        ) );
        return;
    }

    // Promote oldest waitlisted one at a time
    $waitlisted = $wpdb->get_results( $wpdb->prepare(
        "SELECT id FROM {$table} WHERE opportunity_id = %d AND status = 'waitlisted' ORDER BY signed_up_at ASC",
        $opp_id
    ) );

    $promoted = 0;
    foreach ( $waitlisted as $w ) {
        if ( $promoted >= $remaining ) break;
        $wpdb->update( $table, [ 'status' => 'confirmed' ], [ 'id' => $w->id ] );
        $promoted++;
    }
}

// ---- AJAX: Volunteer signup ----
add_action( 'wp_ajax_sp_volunteer_signup', function () {
    if ( ! wp_verify_nonce( $_POST['nonce'] ?? '', 'sp_volunteer_opp' ) ) {
        wp_send_json_error( __( 'Security check failed.', 'societypress' ) );
    }

    if ( ! is_user_logged_in() ) {
        wp_send_json_error( __( 'Please log in to volunteer.', 'societypress' ) );
    }

    global $wpdb;
    $opp_id  = (int) ( $_POST['opportunity_id'] ?? 0 );
    $user_id = get_current_user_id();

    // Check opportunity exists and is open
    $opp = $wpdb->get_row( $wpdb->prepare(
        "SELECT * FROM {$wpdb->prefix}sp_volunteer_opportunities WHERE id = %d", $opp_id
    ) );
    if ( ! $opp || ! in_array( $opp->status, [ 'open', 'filled' ], true ) ) {
        wp_send_json_error( __( 'This opportunity is not available.', 'societypress' ) );
    }

    // Check for existing signup (including cancelled — allow re-signup)
    $existing = $wpdb->get_row( $wpdb->prepare(
        "SELECT id, status FROM {$wpdb->prefix}sp_volunteer_signups
         WHERE opportunity_id = %d AND user_id = %d",
        $opp_id, $user_id
    ) );

    if ( $existing && in_array( $existing->status, [ 'confirmed', 'waitlisted' ], true ) ) {
        wp_send_json_error( __( 'You are already signed up for this opportunity.', 'societypress' ) );
    }

    // Determine status based on capacity
    $remaining = sp_volunteer_opp_remaining( $opp_id );
    $status = ( $remaining !== null && $remaining <= 0 ) ? 'waitlisted' : 'confirmed';

    if ( $existing ) {
        // Re-activate cancelled signup
        $wpdb->update(
            $wpdb->prefix . 'sp_volunteer_signups',
            [ 'status' => $status, 'signed_up_at' => current_time( 'mysql' ) ],
            [ 'id' => $existing->id ]
        );
        $signup_id = $existing->id;
    } else {
        $wpdb->insert( $wpdb->prefix . 'sp_volunteer_signups', [
            'opportunity_id' => $opp_id,
            'user_id'        => $user_id,
            'status'         => $status,
        ] );
        $signup_id = $wpdb->insert_id;
    }

    // Update opportunity status if now full
    if ( $remaining !== null && $remaining <= 1 && $status === 'confirmed' ) {
        $wpdb->update(
            $wpdb->prefix . 'sp_volunteer_opportunities',
            [ 'status' => 'filled' ],
            [ 'id' => $opp_id ]
        );
    }

    wp_send_json_success( [
        'signup_id' => $signup_id,
        'status'    => $status,
    ] );
} );

// ---- AJAX: Cancel volunteer signup ----
add_action( 'wp_ajax_sp_volunteer_cancel', function () {
    if ( ! is_user_logged_in() ) {
        wp_send_json_error( [ 'message' => __( 'You must be logged in.', 'societypress' ) ] );
    }

    if ( ! wp_verify_nonce( $_POST['nonce'] ?? '', 'sp_volunteer_opp' ) ) {
        wp_send_json_error( __( 'Security check failed.', 'societypress' ) );
    }

    global $wpdb;
    $signup_id = (int) ( $_POST['signup_id'] ?? 0 );
    $user_id   = get_current_user_id();

    // Verify ownership
    $signup = $wpdb->get_row( $wpdb->prepare(
        "SELECT * FROM {$wpdb->prefix}sp_volunteer_signups WHERE id = %d AND user_id = %d",
        $signup_id, $user_id
    ) );

    if ( ! $signup ) {
        wp_send_json_error( __( 'Signup not found.', 'societypress' ) );
    }

    $was_confirmed = $signup->status === 'confirmed';

    $wpdb->update(
        $wpdb->prefix . 'sp_volunteer_signups',
        [ 'status' => 'cancelled' ],
        [ 'id' => $signup_id ]
    );

    // If was confirmed, a spot opened — promote from waitlist
    if ( $was_confirmed ) {
        sp_volunteer_promote_waitlist( (int) $signup->opportunity_id );

        // Also re-open the opportunity if it was "filled"
        $wpdb->query( $wpdb->prepare(
            "UPDATE {$wpdb->prefix}sp_volunteer_opportunities SET status = 'open'
             WHERE id = %d AND status = 'filled'",
            $signup->opportunity_id
        ) );
    }

    wp_send_json_success( [ 'cancelled' => true ] );
} );

// ---- Frontend template: Volunteer Opportunities page ----
// WHY: Uses the same template_redirect pattern as events. When a page has the
//      SP "Volunteer" template, this renders the opportunities list.
add_action( 'init', function () {
    // WHY gated: If the governance module is disabled, the shortcode should
    // render nothing rather than showing volunteer content on a page where
    // the admin doesn't want it. The shortcode still gets registered (so WP
    // doesn't spit out the raw [tag]), but the callback returns early.
    if ( sp_module_enabled( 'governance' ) ) {
        add_shortcode( 'societypress_volunteers', 'sp_render_volunteer_opportunities_frontend' );
    } else {
        add_shortcode( 'societypress_volunteers', '__return_empty_string' );
    }
} );

/**
 * Render the volunteer opportunities frontend.
 *
 * WHY: Members see a card grid of open volunteer opportunities. Each card
 *      shows the title, when/where, capacity, and a sign-up button. The
 *      buttons change based on login state and signup status.
 *
 * @return string HTML output.
 */
function sp_render_volunteer_opportunities_frontend(): string {
    global $wpdb;
    $prefix = $wpdb->prefix . 'sp_';

    // Load open and filled opportunities, ordered by date then title
    $opportunities = $wpdb->get_results(
        "SELECT o.*, c.name AS committee_name,
                u.display_name AS contact_name
         FROM {$prefix}volunteer_opportunities o
         LEFT JOIN {$prefix}committees c ON o.committee_id = c.id
         LEFT JOIN {$wpdb->users} u ON o.contact_user_id = u.ID
         WHERE o.status IN ('open', 'filled')
         ORDER BY o.event_date ASC, o.sort_order ASC, o.title ASC"
    );

    // Get current user's signups for quick lookup
    $user_signups = [];
    if ( is_user_logged_in() ) {
        $user_id = get_current_user_id();
        $signups = $wpdb->get_results( $wpdb->prepare(
            "SELECT opportunity_id, id AS signup_id, status
             FROM {$prefix}volunteer_signups
             WHERE user_id = %d AND status IN ('confirmed', 'waitlisted')",
            $user_id
        ) );
        foreach ( $signups as $s ) {
            $user_signups[ (int) $s->opportunity_id ] = $s;
        }
    }

    // Get committees for filter dropdown
    $committees = $wpdb->get_results(
        "SELECT id, name FROM {$prefix}committees WHERE active = 1 ORDER BY name"
    );

    $nonce = wp_create_nonce( 'sp_volunteer_opp' );
    $type_labels = [ 'one_time' => __( 'One-Time', 'societypress' ), 'recurring' => __( 'Recurring', 'societypress' ), 'ongoing' => __( 'Ongoing', 'societypress' ) ];

    ob_start();
    ?>
    <div class="sp-volunteer-opps-wrap">
        <!-- Filters -->
        <?php if ( count( $committees ) > 1 || count( $opportunities ) > 3 ) : ?>
        <div class="sp-vol-filters" style="margin-bottom: 20px; display: flex; gap: 12px; flex-wrap: wrap;">
            <select id="sp-vol-filter-committee" style="min-width: 180px;">
                <option value=""><?php esc_html_e( 'All Committees', 'societypress' ); ?></option>
                <option value="society"><?php esc_html_e( 'Society-Wide', 'societypress' ); ?></option>
                <?php foreach ( $committees as $c ) : ?>
                    <option value="<?php echo esc_attr( $c->id ); ?>"><?php echo esc_html( $c->name ); ?></option>
                <?php endforeach; ?>
            </select>
            <select id="sp-vol-filter-type" style="min-width: 140px;">
                <option value=""><?php esc_html_e( 'All Types', 'societypress' ); ?></option>
                <option value="one_time"><?php esc_html_e( 'One-Time', 'societypress' ); ?></option>
                <option value="recurring"><?php esc_html_e( 'Recurring', 'societypress' ); ?></option>
                <option value="ongoing"><?php esc_html_e( 'Ongoing', 'societypress' ); ?></option>
            </select>
        </div>
        <?php endif; ?>

        <?php if ( empty( $opportunities ) ) : ?>
            <div class="sp-vol-empty" style="text-align: center; padding: 40px 20px; color: var(--sp-color-text-secondary, #6b7280);">
                <p style="font-size: 1.1em;"><?php esc_html_e( 'No volunteer opportunities available right now.', 'societypress' ); ?></p>
                <p><?php esc_html_e( 'Check back later or contact us to learn how you can help.', 'societypress' ); ?></p>
            </div>
        <?php else : ?>
            <div class="sp-vol-grid" style="display: grid; grid-template-columns: repeat(auto-fill, minmax(300px, 1fr)); gap: 20px;">
                <?php foreach ( $opportunities as $opp ) :
                    $signup_count = sp_volunteer_opp_signup_count( (int) $opp->id );
                    $remaining    = sp_volunteer_opp_remaining( (int) $opp->id );
                    $is_full      = $remaining !== null && $remaining <= 0;
                    $user_signup  = $user_signups[ (int) $opp->id ] ?? null;
                    $type_label   = $type_labels[ $opp->opportunity_type ] ?? $opp->opportunity_type;
                ?>
                <article class="sp-vol-card"
                         data-committee="<?php echo esc_attr( $opp->committee_id ?: 'society' ); ?>"
                         data-type="<?php echo esc_attr( $opp->opportunity_type ); ?>"
                         style="border: 1px solid var(--sp-color-border, #e5e7eb); border-radius: 8px; overflow: hidden; background: var(--sp-color-bg, #fff);">
                    <div style="padding: 16px;">
                        <div style="display: flex; justify-content: space-between; align-items: flex-start; margin-bottom: 8px;">
                            <h3 style="margin: 0; font-size: 1.15em;"><?php echo esc_html( $opp->title ); ?></h3>
                            <span style="display: inline-block; padding: 2px 8px; border-radius: 12px; font-size: 11px; font-weight: 600;
                                background: <?php echo $opp->opportunity_type === 'one_time' ? '#e8f0fe' : ( $opp->opportunity_type === 'recurring' ? '#fef3e0' : '#e8f5e9' ); ?>;
                                color: <?php echo $opp->opportunity_type === 'one_time' ? '#1a56db' : ( $opp->opportunity_type === 'recurring' ? '#b45309' : '#166534' ); ?>;">
                                <?php echo esc_html( $type_label ); ?>
                            </span>
                        </div>

                        <?php if ( $opp->committee_name ) : ?>
                            <p style="margin: 4px 0; font-size: 0.9em; color: var(--sp-color-text-secondary, #6b7280);">
                                <strong><?php esc_html_e( 'Committee:', 'societypress' ); ?></strong> <?php echo esc_html( $opp->committee_name ); ?>
                            </p>
                        <?php endif; ?>

                        <?php if ( $opp->event_date ) : ?>
                            <p style="margin: 4px 0; font-size: 0.9em;">
                                <strong><?php esc_html_e( 'When:', 'societypress' ); ?></strong> <?php echo esc_html( date_i18n( 'l, F j, Y', strtotime( $opp->event_date ) ) ); ?>
                                <?php if ( $opp->start_time ) : ?>
                                    <?php echo esc_html( wp_date( 'g:i A', strtotime( $opp->start_time ) ) ); ?>
                                    <?php if ( $opp->end_time ) echo '– ' . esc_html( wp_date( 'g:i A', strtotime( $opp->end_time ) ) ); ?>
                                <?php endif; ?>
                            </p>
                        <?php endif; ?>

                        <?php if ( $opp->location ) : ?>
                            <p style="margin: 4px 0; font-size: 0.9em;">
                                <strong><?php esc_html_e( 'Where:', 'societypress' ); ?></strong> <?php echo esc_html( $opp->location ); ?>
                            </p>
                        <?php endif; ?>

                        <?php if ( $opp->description ) : ?>
                            <div style="margin: 8px 0; font-size: 0.9em; color: var(--sp-color-text, #1a1a1a);">
                                <?php echo wp_kses_post( wpautop( $opp->description ) ); ?>
                            </div>
                        <?php endif; ?>

                        <?php if ( $opp->skills_needed ) : ?>
                            <p style="margin: 4px 0; font-size: 0.85em; color: var(--sp-color-text-secondary, #6b7280);">
                                <strong><?php esc_html_e( 'Skills/Requirements:', 'societypress' ); ?></strong> <?php echo esc_html( $opp->skills_needed ); ?>
                            </p>
                        <?php endif; ?>

                        <?php if ( $opp->capacity !== null ) : ?>
                            <p style="margin: 8px 0 4px; font-size: 0.85em; color: <?php echo $is_full ? '#d63638' : '#6b7280'; ?>;">
                                <?php if ( $is_full ) : ?>
                                    <strong><?php esc_html_e( 'Full', 'societypress' ); ?></strong> (<?php echo $signup_count; ?>/<?php echo $opp->capacity; ?>)
                                <?php else : ?>
                                    <?php /* translators: %1$d: number of spots taken, %2$d: total capacity */ ?>
                                    <?php printf( esc_html__( '%1$d/%2$d spots filled', 'societypress' ), $signup_count, $opp->capacity ); ?>
                                <?php endif; ?>
                            </p>
                        <?php elseif ( $signup_count > 0 ) : ?>
                            <p style="margin: 8px 0 4px; font-size: 0.85em; color: #6b7280;">
                                <?php /* translators: %d: number of volunteers signed up */ ?>
                                <?php printf( esc_html( _n( '%d volunteer signed up', '%d volunteers signed up', $signup_count, 'societypress' ) ), $signup_count ); ?>
                            </p>
                        <?php endif; ?>

                        <?php if ( $opp->contact_name ) : ?>
                            <p style="margin: 4px 0; font-size: 0.85em; color: var(--sp-color-text-secondary, #6b7280);">
