// Handle volunteer hours CSV export
add_action( 'admin_init', function() {
    if ( ( $_GET['page'] ?? '' ) !== 'sp-volunteer-hours' || ( $_GET['action'] ?? '' ) !== 'export_csv' ) return;
    if ( ! current_user_can( 'manage_options' ) ) return;
    check_admin_referer( 'sp_export_volunteer_hours' );

    global $wpdb;
    $prefix = $wpdb->prefix . 'sp_';

    $rows = $wpdb->get_results(
        "SELECT m.first_name, m.last_name, vh.activity, vh.committee, vh.hours, vh.activity_date
         FROM {$prefix}volunteer_hours vh
         INNER JOIN {$prefix}members m ON vh.user_id = m.user_id
         ORDER BY vh.activity_date DESC"
    );

    header( 'Content-Type: text/csv; charset=utf-8' );
    header( 'Content-Disposition: attachment; filename=volunteer-hours-' . date( 'Y-m-d' ) . '.csv' );
    $out = fopen( 'php://output', 'w' );
    fputcsv( $out, [ 'First Name', 'Last Name', 'Activity', 'Committee', 'Hours', 'Date' ] );
    foreach ( $rows as $row ) {
        fputcsv( $out, [ $row->first_name, $row->last_name, $row->activity, $row->committee, $row->hours, $row->activity_date ] );
    }
    fclose( $out );
    exit;
} );


// ============================================================================
// AUTOMATED RENEWAL REMINDERS — DAILY CRON
// ============================================================================
//
// WHY: Feature 3 — sends email reminders at 30, 15, and 7 days before a
//      member's expiration date. Each reminder is logged to sp_renewal_reminders
//      with a unique key (e.g., "30d_2026-03-20") so the same reminder is
//      never sent twice, even if cron runs multiple times.

// Schedule the cron event on plugin activation (done in register_activation_hook)
// and clear it on deactivation (done in register_deactivation_hook).

add_action( 'sp_renewal_reminder_cron', 'sp_process_renewal_reminders' );

function sp_process_renewal_reminders(): void {
    global $wpdb;
    $prefix   = $wpdb->prefix . 'sp_';
    $settings = get_option( 'societypress_settings', [] );

    // Prevent concurrent runs — if another cron instance is already processing,
    // bail out. The transient auto-expires after 5 minutes as a safety net.
    if ( get_transient( 'sp_notification_batch_running' ) ) {
        return;
    }
    set_transient( 'sp_notification_batch_running', true, 5 * MINUTE_IN_SECONDS );

    // Check which reminder intervals are enabled
    $intervals = [];
    if ( ! empty( $settings['renewal_reminder_30d'] ) ) $intervals[] = 30;
    if ( ! empty( $settings['renewal_reminder_15d'] ) ) $intervals[] = 15;
    if ( ! empty( $settings['renewal_reminder_7d'] ) )  $intervals[] = 7;

    $site_name        = get_bloginfo( 'name' );
    $subject_template = $settings['renewal_reminder_subject'] ?? 'Your membership expires soon';

    // ---- Send renewal reminders for each enabled interval ----
    foreach ( $intervals as $days ) {
        $target_date  = date( 'Y-m-d', strtotime( "+{$days} days" ) );
        $reminder_key = "{$days}d_{$target_date}";

        // WHY: Join wp_users to get the email address. The old code joined a
        //      member_contact table that doesn't exist. Members link to WP users
        //      via user_id, and the WP user record holds the email.
        $members = $wpdb->get_results( $wpdb->prepare(
            "SELECT m.user_id, m.first_name, m.last_name, m.expiration_date,
                    m.pref_email_notices, u.user_email
             FROM {$prefix}members m
             INNER JOIN {$wpdb->users} u ON m.user_id = u.ID
             LEFT JOIN {$prefix}renewal_reminders rr
                 ON rr.user_id = m.user_id AND rr.reminder_type = %s
             WHERE m.expiration_date = %s
               AND m.status = 'active'
               AND u.user_email IS NOT NULL AND u.user_email != ''
               AND rr.id IS NULL
             LIMIT 100",
            $reminder_key,
            $target_date
        ) );

        foreach ( $members as $member ) {
            if ( ! is_email( $member->user_email ) ) continue;

            // Respect communication preferences — if member opted out of notices, skip
            if ( isset( $member->pref_email_notices ) && (int) $member->pref_email_notices === 0 ) {
                continue;
            }

            // Use saved template if admin customized it, otherwise the default.
            // WHY settings fallback: The admin may never visit Email Templates,
            // so we always fall back to the built-in default.
            $template_body = $settings['email_template_renewal_reminder']
                             ?? sp_get_default_email_template( 'renewal_reminder' );
            $body_html = sp_replace_merge_tags(
                $template_body,
                $member,
                [ 'days_until_expiration' => $days ]
            );

            $subject = sp_replace_merge_tags( $subject_template, $member, [ 'days_until_expiration' => $days ] );
            $html    = sp_build_email_html( $subject, $body_html );

            wp_mail(
                $member->user_email,
                sprintf( '[%s] %s', $site_name, $subject ),
                $html,
                sp_get_email_headers()
            );

            // Log reminder to prevent re-sending
            $wpdb->insert( $prefix . 'renewal_reminders', [
                'user_id'       => $member->user_id,
                'reminder_type' => $reminder_key,
                'sent_at'       => current_time( 'mysql' ),
            ] );
        }
    }

    // ---- Send expired membership notices ----
    sp_process_expired_notices();

    delete_transient( 'sp_notification_batch_running' );
}

/**
 * Send expired membership notices to members whose membership lapsed yesterday.
 *
 * WHY: Members who just expired deserve a prompt, personalized nudge to renew.
 *      Sent once (day after expiration), tracked in renewal_reminders to prevent
 *      duplicate sends. Also updates member status to 'expired' so the admin
 *      list table reflects reality without manual intervention.
 */
function sp_process_expired_notices(): void {
    global $wpdb;
    $prefix   = $wpdb->prefix . 'sp_';
    $settings = get_option( 'societypress_settings', [] );

    // Only send if expired notices are enabled (default: off)
    if ( empty( $settings['expired_notice_enabled'] ) ) {
        return;
    }

    $yesterday    = date( 'Y-m-d', strtotime( '-1 day' ) );
    $reminder_key = 'expired_' . $yesterday;
    $site_name    = get_bloginfo( 'name' );
    $subject      = $settings['expired_notice_subject'] ?? 'Your {{organization_name}} membership has expired';

    $members = $wpdb->get_results( $wpdb->prepare(
        "SELECT m.user_id, m.first_name, m.last_name, m.expiration_date,
                m.pref_email_notices, u.user_email
         FROM {$prefix}members m
         INNER JOIN {$wpdb->users} u ON m.user_id = u.ID
         LEFT JOIN {$prefix}renewal_reminders rr
             ON rr.user_id = m.user_id AND rr.reminder_type = %s
         WHERE m.expiration_date = %s
           AND m.status = 'active'
           AND u.user_email IS NOT NULL AND u.user_email != ''
           AND rr.id IS NULL
         LIMIT 100",
        $reminder_key,
        $yesterday
    ) );

    foreach ( $members as $member ) {
        if ( ! is_email( $member->user_email ) ) continue;
        if ( isset( $member->pref_email_notices ) && (int) $member->pref_email_notices === 0 ) continue;

        $template_body = $settings['email_template_expired']
                         ?? sp_get_default_email_template( 'expired' );
        $body_html = sp_replace_merge_tags(
            $template_body,
            $member
        );

        $member_subject = sp_replace_merge_tags( $subject, $member );
        $html           = sp_build_email_html( $member_subject, $body_html );

        wp_mail(
            $member->user_email,
            sprintf( '[%s] %s', $site_name, $member_subject ),
            $html,
            sp_get_email_headers()
        );

        // Log to prevent re-sending
        $wpdb->insert( $prefix . 'renewal_reminders', [
            'user_id'       => $member->user_id,
            'reminder_type' => $reminder_key,
            'sent_at'       => current_time( 'mysql' ),
        ] );

        // Auto-update member status to expired
        $wpdb->update(
            $prefix . 'members',
            [ 'status' => 'expired', 'updated_at' => current_time( 'mysql' ) ],
            [ 'user_id' => $member->user_id ],
            [ '%s', '%s' ],
            [ '%d' ]
        );
    }
}

/**
 * Send a welcome email to a newly created member.
 *
 * WHY: Automated onboarding improves member experience and confirms that
 *      their information was received. Called when a new member record is
 *      created in the admin (or via future join form).
 *
 * @param int $user_id The WP user ID of the new member.
 */
function sp_send_welcome_email( int $user_id ): void {
    global $wpdb;
    $prefix   = $wpdb->prefix . 'sp_';
    $settings = get_option( 'societypress_settings', [] );

    // Only send if welcome emails are enabled
    if ( empty( $settings['welcome_email_enabled'] ) ) {
        return;
    }

    $member = $wpdb->get_row( $wpdb->prepare(
        "SELECT m.*, u.user_email
         FROM {$prefix}members m
         INNER JOIN {$wpdb->users} u ON m.user_id = u.ID
         WHERE m.user_id = %d",
        $user_id
    ) );
    // Decrypt contact fields — merge tags don't currently use them, but
    // future {{phone}} or {{address}} tags would break without this.
    $member = sp_member_decrypt_row( $member );

    if ( ! $member || ! is_email( $member->user_email ) ) {
        return;
    }

    // Don't send welcome emails to pending members — they haven't been
    // approved or paid yet. The welcome email fires when their status
    // changes to 'active' (see member save handler).
    if ( $member->status === 'pending' ) {
        return;
    }

    // Respect communication preference
    if ( isset( $member->pref_email_notices ) && (int) $member->pref_email_notices === 0 ) {
        return;
    }

    $site_name = get_bloginfo( 'name' );
    $subject   = $settings['welcome_email_subject'] ?? 'Welcome to {{organization_name}}!';
    $subject   = sp_replace_merge_tags( $subject, $member );

    $template_body = $settings['email_template_welcome']
                     ?? sp_get_default_email_template( 'welcome' );
    $body_html = sp_replace_merge_tags(
        $template_body,
        $member
    );

    $html = sp_build_email_html( $subject, $body_html );

    wp_mail(
        $member->user_email,
        sprintf( '[%s] %s', $site_name, $subject ),
        $html,
        sp_get_email_headers()
    );
}

/**
 * Replace merge tags in email content.
 *
 * WHY: Personalized emails improve engagement. Admins can customize email
 *      templates using simple {{tag}} syntax without knowing HTML or PHP.
 *      Tags are replaced with real member/organization data at send time.
 *
 * @param string      $content  Content with {{merge_tags}}.
 * @param object      $member   Member row (from sp_members JOIN wp_users).
 * @param array       $extra    Additional tag values (e.g., days_until_expiration).
 * @return string Content with tags replaced.
 */
function sp_replace_merge_tags( string $content, object $member, array $extra = [] ): string {
    $settings = get_option( 'societypress_settings', [] );

    // Calculate days until expiration if applicable
    $days_until = 0;
    if ( ! empty( $member->expiration_date ) ) {
        $days_until = max( 0, (int) ceil( ( strtotime( $member->expiration_date ) - time() ) / DAY_IN_SECONDS ) );
    }

    // Get tier name if tier_id is set
    $tier_name = '';
    if ( ! empty( $member->tier_id ) ) {
        global $wpdb;
        $tier_name = $wpdb->get_var( $wpdb->prepare(
            "SELECT name FROM {$wpdb->prefix}sp_membership_tiers WHERE id = %d",
            $member->tier_id
        ) ) ?: '';
    }

    // Build the tag map
    $tags = [
        '{{first_name}}'            => $member->first_name ?? '',
        '{{last_name}}'             => $member->last_name ?? '',
        '{{full_name}}'             => trim( ( $member->first_name ?? '' ) . ' ' . ( $member->last_name ?? '' ) ),
        '{{preferred_name}}'        => $member->preferred_name ?: ( $member->first_name ?? '' ),
        '{{email}}'                 => $member->user_email ?? '',
        '{{tier}}'                  => $tier_name,
        '{{status}}'                => ucfirst( $member->status ?? '' ),
        '{{join_date}}'             => ! empty( $member->join_date ) ? date_i18n( 'F j, Y', strtotime( $member->join_date ) ) : '',
        '{{expiration_date}}'       => ! empty( $member->expiration_date ) ? date_i18n( 'F j, Y', strtotime( $member->expiration_date ) ) : '',
        '{{days_until_expiration}}' => $extra['days_until_expiration'] ?? $days_until,
        '{{days}}'                  => $extra['days_until_expiration'] ?? $days_until,
        '{{organization_name}}'     => $settings['organization_name'] ?? get_bloginfo( 'name' ),
        '{{site_url}}'              => home_url(),
        '{{admin_email}}'           => $settings['organization_email'] ?? get_option( 'admin_email' ),
    ];

    return str_replace( array_keys( $tags ), array_values( $tags ), $content );
}

/**
 * Get default email template content by type.
 *
 * WHY: Admins need a starting point — staring at an empty textarea is paralyzing.
 *      These defaults use merge tags so they work for any society out of the box.
 *      Admins can customize them from the Email settings page.
 *
 * @param string $type Template type: welcome, renewal_reminder, expired.
 * @return string HTML template content.
 */
function sp_get_default_email_template( string $type ): string {
    switch ( $type ) {
        case 'welcome':
            return '<p>Dear {{preferred_name}},</p>
<p>Welcome to {{organization_name}}! We\'re glad to have you as a member.</p>
<p><strong>Your Membership Details:</strong></p>
<ul>
    <li>Membership Level: {{tier}}</li>
    <li>Joined: {{join_date}}</li>
    <li>Expires: {{expiration_date}}</li>
</ul>
<p>If you have any questions, feel free to reach out to us at {{admin_email}}.</p>
<p>We look forward to seeing you at our events!</p>
<p>Best regards,<br>{{organization_name}}</p>';

        case 'renewal_reminder':
            return '<p>Dear {{preferred_name}},</p>
<p>Your membership with {{organization_name}} expires on <strong>{{expiration_date}}</strong> — that\'s {{days_until_expiration}} days from now.</p>
<p>To continue enjoying your member benefits, please renew at your earliest convenience.</p>
<p><a href="{{site_url}}" style="display:inline-block; padding:12px 24px; background:#2271b1; color:#fff; text-decoration:none; border-radius:6px; font-weight:600;">Visit Our Website</a></p>
<p>Questions? Contact us at {{admin_email}}.</p>
<p>Thank you for being a valued member!</p>
<p>Best regards,<br>{{organization_name}}</p>';

        case 'expired':
            return '<p>Dear {{preferred_name}},</p>
<p>Your membership with {{organization_name}} expired on {{expiration_date}}.</p>
<p>We\'d love to have you back! Renewing is easy — just contact us at {{admin_email}} or visit our website.</p>
<p><a href="{{site_url}}" style="display:inline-block; padding:12px 24px; background:#2271b1; color:#fff; text-decoration:none; border-radius:6px; font-weight:600;">Visit Our Website</a></p>
<p>We hope to see you again soon!</p>
<p>Best regards,<br>{{organization_name}}</p>';

        case 'donation_acknowledgment':
            return '<p>Dear {{donor_name}},</p>
<p>Thank you for your generous donation of <strong>{{amount}}</strong> to {{organization_name}} on {{donation_date}}.</p>
<p>{{campaign}}</p>
<p>Your support helps {{organization_name}} continue its mission of preserving and sharing our community\'s history and heritage. Please keep this email for your tax records.</p>
<p>If you have any questions, please contact us at {{admin_email}}.</p>
<p>With gratitude,<br>{{organization_name}}</p>';

        default:
            return '';
    }
}

/**
 * Build email headers with configurable From and Reply-To.
 *
 * WHY: Societies need emails to come from their organization name and address,
 *      not "WordPress <wordpress@server>". The from_name, from_email, and
 *      reply_to are configurable in Settings > Email.
 *
 * @return array Email headers for wp_mail.
 */
function sp_get_email_headers(): array {
    $settings   = get_option( 'societypress_settings', [] );
    $from_name  = $settings['email_from_name']  ?? get_bloginfo( 'name' );
    $from_email = $settings['email_from_email'] ?? get_option( 'admin_email' );
    $reply_to   = $settings['email_reply_to']   ?? $from_email;

    return [
        'Content-Type: text/html; charset=UTF-8',
        'From: ' . $from_name . ' <' . $from_email . '>',
        'Reply-To: ' . $reply_to,
    ];
}

// Schedule daily notification cron if not already scheduled
add_action( 'init', function() {
    if ( ! wp_next_scheduled( 'sp_renewal_reminder_cron' ) ) {
        wp_schedule_event( time(), 'daily', 'sp_renewal_reminder_cron' );
    }
} );


// ============================================================================
// EMAIL TEMPLATES — ADMIN PAGE
// ============================================================================
//
// WHY: Admins need to customize the automated emails their society sends —
//      the welcome email, renewal reminder, and expiration notice. Rather
//      than forcing them to edit PHP code, this page provides a visual editor
//      (wp_editor / TinyMCE) for each template, a merge tag reference panel,
//      and a live preview. Templates are stored in the settings array and
//      used by the email senders, with sensible defaults if never customized.
// ============================================================================

/**
 * Render the Email Templates admin page.
 *
 * WHY: Three tabbed editors — one per automated email type — with a merge
 *      tag reference sidebar. Uses wp_editor() for rich text editing. The
 *      admin can see available merge tags at a glance and insert them into
 *      the template body or subject line.
 */
function sp_render_email_templates_page(): void {

    // --- Handle save ---
    if ( isset( $_POST['sp_email_template_nonce'] ) &&
         wp_verify_nonce( $_POST['sp_email_template_nonce'], 'sp_save_email_templates' ) ) {

        $settings = get_option( 'societypress_settings', [] );

        // Each template type has a subject (existing settings key) and body field.
        // WHY reuse existing subject keys: The Membership settings page already
        // has subject fields for renewal/expired emails, and welcome has its own.
        // We use the same keys so there's one source of truth — no conflicts.
        // WHY wp_kses_post for body: We allow the same HTML subset that WordPress
        // allows in post content — bold, links, lists, headings, etc. — but
        // strip any scripts or dangerous markup.
        $subject_keys = [
            'welcome'                  => 'welcome_email_subject',
            'renewal_reminder'         => 'renewal_reminder_subject',
            'expired'                  => 'expired_notice_subject',
            'donation_acknowledgment'  => 'donation_acknowledgment_subject',
        ];
        foreach ( $subject_keys as $type => $subj_key ) {
            $body_key = 'email_template_' . $type;
            if ( isset( $_POST[ $subj_key ] ) ) {
                $settings[ $subj_key ] = sanitize_text_field( wp_unslash( $_POST[ $subj_key ] ) );
            }
            if ( isset( $_POST[ $body_key ] ) ) {
                $settings[ $body_key ] = wp_kses_post( wp_unslash( $_POST[ $body_key ] ) );
            }
        }

        update_option( 'societypress_settings', $settings );

        echo '<div class="notice notice-success is-dismissible"><p>'
           . esc_html__( 'Email templates saved.', 'societypress' )
           . '</p></div>';
    }

    $settings = get_option( 'societypress_settings', [] );

    // Determine active tab — default to 'welcome'
    $active_tab = sanitize_key( $_GET['tab'] ?? 'welcome' );
    if ( ! in_array( $active_tab, [ 'welcome', 'renewal_reminder', 'expired', 'donation_acknowledgment' ], true ) ) {
        $active_tab = 'welcome';
    }

    // Tab labels, subject settings keys (reusing existing keys), and defaults.
    // WHY reuse: The Membership settings page already has subject fields for
    // renewal and expiration. The welcome email subject also has an existing key.
    // By sharing the same settings keys, admins can edit the subject from either
    // place without conflicts.
    $tabs = [
        'welcome'          => [
            'label'           => __( 'Welcome Email', 'societypress' ),
            'subject_key'     => 'welcome_email_subject',
            'default_subject' => __( 'Welcome to {{organization_name}}!', 'societypress' ),
            'description'     => __( 'Sent when a new member is approved or created with active status.', 'societypress' ),
        ],
        'renewal_reminder' => [
            'label'           => __( 'Renewal Reminder', 'societypress' ),
            'subject_key'     => 'renewal_reminder_subject',
            'default_subject' => __( 'Your membership expires soon', 'societypress' ),
            'description'     => __( 'Sent automatically at 30, 15, and 7 days before membership expiration (based on your settings).', 'societypress' ),
        ],
        'expired'          => [
            'label'           => __( 'Expiration Notice', 'societypress' ),
            'subject_key'     => 'expired_notice_subject',
            'default_subject' => __( 'Your membership has expired', 'societypress' ),
            'description'     => __( 'Sent after a membership expires and the member\'s status changes to expired.', 'societypress' ),
        ],
        'donation_acknowledgment' => [
            'label'           => __( 'Donation Acknowledgment', 'societypress' ),
            'subject_key'     => 'donation_acknowledgment_subject',
            'default_subject' => __( 'Thank You for Your Donation — {{organization_name}}', 'societypress' ),
            'description'     => __( 'Sent to donors when the treasurer clicks "Send Acknowledgment" on one or more donations. Supports donation-specific merge tags.', 'societypress' ),
        ],
    ];

    $tab_info = $tabs[ $active_tab ];
    $subj_key = $tab_info['subject_key'];
    $body_key = 'email_template_' . $active_tab;

    // Load saved values or defaults
    $subject = $settings[ $subj_key ] ?? $tab_info['default_subject'];
    $body    = $settings[ $body_key ] ?? sp_get_default_email_template( $active_tab );

    $page_url = admin_url( 'admin.php?page=sp-email-templates' );
    ?>
    <div class="wrap">
        <h1><?php esc_html_e( 'Email Templates', 'societypress' ); ?></h1>
        <p class="description"><?php esc_html_e( 'Customize the automated emails your site sends to members. Use merge tags to personalize each message.', 'societypress' ); ?></p>

        <!-- Tabs -->
        <nav class="nav-tab-wrapper" style="margin-bottom: 20px;">
            <?php foreach ( $tabs as $slug => $tab ) :
                $url   = add_query_arg( 'tab', $slug, $page_url );
                $class = ( $slug === $active_tab ) ? 'nav-tab nav-tab-active' : 'nav-tab';
            ?>
                <a href="<?php echo esc_url( $url ); ?>" class="<?php echo esc_attr( $class ); ?>">
                    <?php echo esc_html( $tab['label'] ); ?>
                </a>
            <?php endforeach; ?>
        </nav>

        <div style="display: flex; gap: 24px; align-items: flex-start;">

            <!-- Editor column -->
            <div style="flex: 1; min-width: 0;">
                <form method="post" action="<?php echo esc_url( add_query_arg( 'tab', $active_tab, $page_url ) ); ?>">
                    <?php wp_nonce_field( 'sp_save_email_templates', 'sp_email_template_nonce' ); ?>

                    <p class="description" style="margin-bottom: 16px;">
                        <?php echo esc_html( $tab_info['description'] ); ?>
                    </p>

                    <table class="form-table" role="presentation">
                        <tr>
                            <th scope="row">
                                <label for="<?php echo esc_attr( $subj_key ); ?>">
                                    <?php esc_html_e( 'Subject Line', 'societypress' ); ?>
                                </label>
                            </th>
                            <td>
                                <input type="text"
                                       id="<?php echo esc_attr( $subj_key ); ?>"
                                       name="<?php echo esc_attr( $subj_key ); ?>"
                                       value="<?php echo esc_attr( $subject ); ?>"
                                       class="large-text"
                                       style="max-width: 600px;">
                                <p class="description">
                                    <?php esc_html_e( 'Merge tags work here too — e.g. {{preferred_name}}, {{organization_name}}.', 'societypress' ); ?>
                                </p>
                            </td>
                        </tr>
                        <tr>
                            <th scope="row">
                                <label for="<?php echo esc_attr( $body_key ); ?>">
                                    <?php esc_html_e( 'Email Body', 'societypress' ); ?>
                                </label>
                            </th>
                            <td>
                                <?php
                                // WHY wp_editor: gives the admin a rich text editor
                                // with bold, links, lists — the same tools they use
                                // in WordPress posts. No HTML knowledge required.
                                wp_editor( $body, $body_key, [
                                    'textarea_name' => $body_key,
                                    'textarea_rows' => 18,
                                    'media_buttons' => false,
                                    'teeny'         => false,
                                    'quicktags'     => true,
                                ] );
                                ?>
                            </td>
                        </tr>
                    </table>

                    <p class="submit" style="display: flex; gap: 12px; align-items: center;">
                        <?php submit_button( __( 'Save Template', 'societypress' ), 'primary', 'submit', false ); ?>
                        <button type="button" class="button" id="sp-reset-template">
                            <?php esc_html_e( 'Reset to Default', 'societypress' ); ?>
                        </button>
                    </p>
                </form>
            </div>

            <!-- Merge tag reference sidebar -->
            <div style="width: 280px; flex-shrink: 0; background: #f6f7f7; border: 1px solid #c3c4c7; border-radius: 4px; padding: 16px;">
                <h3 style="margin-top: 0; font-size: 14px;">
                    <?php esc_html_e( 'Available Merge Tags', 'societypress' ); ?>
                </h3>
                <p class="description" style="margin-bottom: 12px;">
                    <?php esc_html_e( 'Click a tag to copy it, then paste into the subject or body.', 'societypress' ); ?>
                </p>
                <?php
                // WHY this list: These are the tags supported by sp_replace_merge_tags()
                // (for member-based emails) or sp_replace_donation_merge_tags() (for
                // donation acknowledgments). We show the appropriate set for each tab
                // so the admin knows what's available.
                if ( $active_tab === 'donation_acknowledgment' ) {
                    // Donation-specific merge tags — donors aren't always members,
                    // so we use a separate set tailored to donation data.
                    $merge_tags = [
                        '{{donor_name}}'        => __( 'Donor name', 'societypress' ),
                        '{{donor_email}}'       => __( 'Donor email', 'societypress' ),
                        '{{amount}}'            => __( 'Donation amount (formatted)', 'societypress' ),
                        '{{campaign}}'          => __( 'Campaign name', 'societypress' ),
                        '{{donation_date}}'     => __( 'Date of donation', 'societypress' ),
                        '{{donation_type}}'     => __( 'Donation type (cash, check, etc.)', 'societypress' ),
                        '{{in_kind_description}}' => __( 'In-kind item description', 'societypress' ),
                        '{{organization_name}}' => __( 'Organization name', 'societypress' ),
                        '{{site_url}}'          => __( 'Website URL', 'societypress' ),
                        '{{admin_email}}'       => __( 'Admin email address', 'societypress' ),
                    ];
                } else {
                    $merge_tags = [
                        '{{first_name}}'            => __( 'First name', 'societypress' ),
                        '{{last_name}}'             => __( 'Last name', 'societypress' ),
                        '{{full_name}}'             => __( 'Full name', 'societypress' ),
                        '{{preferred_name}}'        => __( 'Preferred name (or first name)', 'societypress' ),
                        '{{email}}'                 => __( 'Member email', 'societypress' ),
                        '{{tier}}'                  => __( 'Membership tier name', 'societypress' ),
                        '{{status}}'                => __( 'Membership status', 'societypress' ),
                        '{{join_date}}'             => __( 'Join date', 'societypress' ),
                        '{{expiration_date}}'       => __( 'Expiration date', 'societypress' ),
                        '{{days_until_expiration}}' => __( 'Days until expiration', 'societypress' ),
                        '{{days}}'                  => __( 'Days (shorthand)', 'societypress' ),
                        '{{organization_name}}'     => __( 'Organization name', 'societypress' ),
                        '{{site_url}}'              => __( 'Website URL', 'societypress' ),
                        '{{admin_email}}'           => __( 'Admin email address', 'societypress' ),
                    ];
                }
                foreach ( $merge_tags as $tag => $desc ) :
                ?>
                    <div style="margin-bottom: 6px; cursor: pointer;" class="sp-merge-tag-item"
                         data-tag="<?php echo esc_attr( $tag ); ?>"
                         title="<?php echo esc_attr( $desc ); ?>">
                        <code style="background: #fff; border: 1px solid #ddd; padding: 2px 6px; border-radius: 3px; font-size: 12px; display: inline-block;">
                            <?php echo esc_html( $tag ); ?>
                        </code>
                        <span style="font-size: 12px; color: #646970; margin-left: 4px;">
                            <?php echo esc_html( $desc ); ?>
                        </span>
                    </div>
                <?php endforeach; ?>
            </div>

        </div><!-- .flex wrapper -->
    </div><!-- .wrap -->

    <script>
    // WHY vanilla JS: Project policy — no jQuery. Two behaviors:
    // 1. Click-to-copy on merge tags so the admin can paste them into the editor.
    // 2. Reset button loads the default template via a hidden data attribute.
    (function() {
        // --- Click-to-copy merge tags ---
        document.querySelectorAll('.sp-merge-tag-item').forEach(function(el) {
            el.addEventListener('click', function() {
                var tag = this.getAttribute('data-tag');
                if (navigator.clipboard && navigator.clipboard.writeText) {
                    navigator.clipboard.writeText(tag).then(function() {
                        // Brief visual feedback
                        var code = el.querySelector('code');
                        var orig = code.style.background;
                        code.style.background = '#e0f0e0';
                        setTimeout(function() { code.style.background = orig; }, 600);
                    });
                } else {
                    // Fallback for older browsers
                    var ta = document.createElement('textarea');
                    ta.value = tag;
                    ta.style.position = 'fixed';
                    ta.style.left = '-9999px';
                    document.body.appendChild(ta);
                    ta.select();
                    document.execCommand('copy');
                    document.body.removeChild(ta);
                }
            });
        });

        // --- Reset to default ---
        var resetBtn = document.getElementById('sp-reset-template');
        if (resetBtn) {
            resetBtn.addEventListener('click', function() {
                if (!confirm(<?php echo wp_json_encode( __( 'Reset this template to the default? Your customizations will be lost.', 'societypress' ) ); ?>)) {
                    return;
                }
                // Fetch the default template via AJAX
                var formData = new FormData();
                formData.append('action', 'sp_get_default_template');
                formData.append('type', <?php echo wp_json_encode( $active_tab ); ?>);
                formData.append('_wpnonce', <?php echo wp_json_encode( wp_create_nonce( 'sp_default_template' ) ); ?>);

                fetch(ajaxurl, { method: 'POST', body: formData })
                    .then(function(r) { return r.json(); })
                    .then(function(data) {
                        if (data.success) {
                            // Update subject
                            var subjField = document.getElementById(<?php echo wp_json_encode( $subj_key ); ?>);
                            if (subjField) subjField.value = data.data.subject;

                            // Update TinyMCE editor or textarea
                            var editorId = <?php echo wp_json_encode( $body_key ); ?>;
                            if (typeof tinymce !== 'undefined' && tinymce.get(editorId)) {
                                tinymce.get(editorId).setContent(data.data.body);
                            } else {
                                var ta = document.getElementById(editorId);
                                if (ta) ta.value = data.data.body;
                            }
                        }
                    });
            });
        }
    })();
    </script>
    <?php
}

/**
 * AJAX handler: return default email template content for the reset button.
 *
 * WHY: The reset button needs to restore the factory default without a page
 *      reload. This endpoint returns the default subject and body for a
 *      given template type so JavaScript can inject them into the editor.
 */
add_action( 'wp_ajax_sp_get_default_template', function() {
    check_ajax_referer( 'sp_default_template' );

    if ( ! current_user_can( 'manage_options' ) ) {
        wp_send_json_error( __( 'Unauthorized', 'societypress' ), 403 );
    }

    $type = sanitize_key( $_POST['type'] ?? '' );

    $default_subjects = [
        'welcome'                 => __( 'Welcome to {{organization_name}}!', 'societypress' ),
        'renewal_reminder'        => __( 'Your membership expires soon', 'societypress' ),
        'expired'                 => __( 'Your membership has expired', 'societypress' ),
        'donation_acknowledgment' => __( 'Thank You for Your Donation — {{organization_name}}', 'societypress' ),
    ];

    if ( ! isset( $default_subjects[ $type ] ) ) {
        wp_send_json_error( __( 'Invalid type', 'societypress' ), 400 );
    }

    wp_send_json_success( [
        'subject' => $default_subjects[ $type ],
        'body'    => sp_get_default_email_template( $type ),
    ] );
} );


// ============================================================================
// EMAIL LOG — ADMIN PAGE
// ============================================================================
//
// WHY: Admins need to see what emails went out, whether they were delivered,
//      and what they contained. This page provides a searchable, filterable
//      list of all emails with status indicators and a detail view.
// ============================================================================

/**
 * Render the Email Log admin page.
 *
 * WHY: Provides the admin interface for reviewing all outgoing emails.
 *      Shows status (sent/blocked/failed), recipient, subject, date, and
 *      type. Supports filtering by status and type, search by recipient
 *      or subject, and pagination. Clicking a row shows the full email body.
 */
function sp_render_email_log_page(): void {
    global $wpdb;
    $table = $wpdb->prefix . 'sp_email_log';

    // Check if viewing a single email detail
    $view_id = isset( $_GET['view'] ) ? absint( $_GET['view'] ) : 0;

    if ( $view_id ) {
        sp_render_email_log_detail( $view_id );
        return;
    }

    // Gather filter parameters
    $current_status = sanitize_text_field( $_GET['status'] ?? '' );
    $current_type   = sanitize_text_field( $_GET['email_type'] ?? '' );
    $search         = sanitize_text_field( $_GET['s'] ?? '' );
    $paged          = max( 1, absint( $_GET['paged'] ?? 1 ) );
    $per_page       = 20;

    // Fetch results
    $result = sp_email_log_get_list( [
        'status'     => $current_status,
        'email_type' => $current_type,
        'search'     => $search,
        'per_page'   => $per_page,
        'page'       => $paged,
    ] );

    $items      = $result['items'];
    $total      = $result['total'];
    $total_pages = ceil( $total / $per_page );

    // Get stats for the summary cards
    $stats = sp_email_log_get_stats( 30 );

    // Get email types for the filter dropdown
    $email_types = sp_email_log_get_types();

    $base_url = admin_url( 'admin.php?page=sp-email-log' );

    ?>
    <div class="wrap">
        <h1><?php esc_html_e( 'Email Log', 'societypress' ); ?></h1>

        <!-- Stats cards -->
        <div style="display: flex; gap: 16px; margin: 20px 0;">
            <div style="background: #fff; border: 1px solid #c3c4c7; border-left: 4px solid #00a32a; padding: 12px 20px; min-width: 120px;">
                <div style="font-size: 24px; font-weight: 600; color: #00a32a;"><?php echo esc_html( $stats['sent'] ); ?></div>
                <div style="color: #50575e; font-size: 13px;">Sent (30d)</div>
            </div>
            <div style="background: #fff; border: 1px solid #c3c4c7; border-left: 4px solid #dba617; padding: 12px 20px; min-width: 120px;">
                <div style="font-size: 24px; font-weight: 600; color: #dba617;"><?php echo esc_html( $stats['blocked'] ); ?></div>
                <div style="color: #50575e; font-size: 13px;">Blocked (30d)</div>
            </div>
            <div style="background: #fff; border: 1px solid #c3c4c7; border-left: 4px solid #d63638; padding: 12px 20px; min-width: 120px;">
                <div style="font-size: 24px; font-weight: 600; color: #d63638;"><?php echo esc_html( $stats['failed'] ); ?></div>
                <div style="color: #50575e; font-size: 13px;">Failed (30d)</div>
            </div>
            <div style="background: #fff; border: 1px solid #c3c4c7; border-left: 4px solid #2271b1; padding: 12px 20px; min-width: 120px;">
                <div style="font-size: 24px; font-weight: 600; color: #2271b1;"><?php echo esc_html( $stats['total'] ); ?></div>
                <div style="color: #50575e; font-size: 13px;">Total (30d)</div>
            </div>
        </div>

