            <div class="tablenav top" style="display: flex; align-items: center; gap: 8px;">
                <select name="status">
                    <option value="">All Statuses</option>
                    <?php foreach ( [ 'sent', 'blocked', 'failed', 'pending' ] as $s ) : ?>
