                <div style="background:#eee; border-radius:6px; height:24px; overflow:hidden;">
                    <div id="sp-enrich-bar" style="background:#2271b1; height:100%; width:0%; transition:width 0.3s ease; border-radius:6px;"></div>
                </div>
                <div id="sp-enrich-status" style="margin-top:10px; font-size:14px; color:#555;"></div>
            </div>

            <!-- Results log -->
            <div id="sp-enrich-log" style="display:none; margin-top:20px; max-height:300px; overflow-y:auto; background:#f8f9fa; border:1px solid #ddd; border-radius:6px; padding:12px; font-size:13px; font-family:monospace; line-height:1.6;"></div>
        </div>
    </div>

    <script>
    (function() {
        var startBtn   = document.getElementById('sp-enrich-start');
        var stopBtn    = document.getElementById('sp-enrich-stop');
        var progressEl = document.getElementById('sp-enrich-progress');
        var barEl      = document.getElementById('sp-enrich-bar');
        var statusEl   = document.getElementById('sp-enrich-status');
        var logEl      = document.getElementById('sp-enrich-log');
        var running    = false;
        var stopped    = false;

        // Running totals for the session
        var processed  = 0;
        var found      = 0;
        var notFound   = 0;
        var errors     = 0;
        var totalToProcess = 0;
        var ajaxUrl    = '<?php echo esc_js( admin_url( 'admin-ajax.php' ) ); ?>';
        var nonce      = '<?php echo esc_js( wp_create_nonce( 'sp_library_enrich' ) ); ?>';

        startBtn.addEventListener('click', function() {
            if ( running ) return;
            running = true;
            stopped = false;
            processed = 0; found = 0; notFound = 0; errors = 0;

            startBtn.style.display = 'none';
            stopBtn.style.display = '';
            progressEl.style.display = 'block';
            logEl.style.display = 'block';
            logEl.innerHTML = '';
            barEl.style.width = '0%';

            log('Starting enrichment...');
            fetchBatch();
        });

        stopBtn.addEventListener('click', function() {
            stopped = true;
            stopBtn.style.display = 'none';
            log('Stopping after current batch completes...');
        });

        function fetchBatch() {
            if ( stopped ) {
                finish('Stopped by user.');
                return;
            }

            var lccnOnly = document.getElementById('sp-enrich-lccn-only').checked ? '1' : '0';
            var skipAttempted = document.getElementById('sp-enrich-skip-attempted').checked ? '1' : '0';

            var params = new URLSearchParams({
                action: 'sp_library_enrich_batch',
                _wpnonce: nonce,
                batch_size: '10',
                offset: processed.toString(),
                lccn_only: lccnOnly,
                skip_attempted: skipAttempted
            });

            fetch(ajaxUrl + '?' + params.toString(), { credentials: 'same-origin' })
                .then(function(r) { return r.json(); })
                .then(function(resp) {
                    if ( ! resp.success ) {
                        log('Error: ' + (resp.data || 'Unknown error'));
                        finish('Stopped due to error.');
                        return;
                    }

                    var d = resp.data;
                    totalToProcess = d.total_remaining + processed;

                    // Update counters with this batch's results
                    processed += d.processed;
                    found     += d.found;
                    notFound  += d.not_found;
                    errors    += d.errors;

                    // Log individual results
                    if ( d.results && d.results.length ) {
                        d.results.forEach(function(r) {
                            var icon = r.status === 'found' ? '✅' : (r.status === 'error' ? '❌' : '⬜');
                            log(icon + ' ' + r.title + (r.method ? ' [' + r.method + ']' : ''));
                        });
                    }

                    // Update progress
                    var pct = totalToProcess > 0 ? Math.round( (processed / totalToProcess) * 100 ) : 0;
                    barEl.style.width = pct + '%';
                    statusEl.textContent = 'Processed: ' + processed + ' / ' + totalToProcess +
                        ' | Covers found: ' + found + ' | Not found: ' + notFound + ' | Errors: ' + errors;

                    // If there are more items, continue after a brief delay
                    // WHY: Open Library rate-limits to ~100 requests/5min for unauthed clients.
                    //      A 2-second pause between batches of 10 keeps us well within limits.
                    if ( d.has_more && ! stopped ) {
                        setTimeout(fetchBatch, 2000);
                    } else {
                        finish(d.has_more ? 'Stopped.' : 'Complete!');
                    }
                })
                .catch(function(err) {
                    log('Network error: ' + err.message);
                    finish('Stopped due to network error.');
                });
        }

        function finish(msg) {
            running = false;
            startBtn.style.display = '';
            stopBtn.style.display = 'none';
            log(msg + ' Covers found: ' + found + ' of ' + processed + ' processed.');
            statusEl.textContent = msg + ' Processed: ' + processed +
                ' | Covers found: ' + found + ' | Not found: ' + notFound + ' | Errors: ' + errors;
        }

        function log(msg) {
            logEl.innerHTML += msg + '<br>';
            logEl.scrollTop = logEl.scrollHeight;
        }
    })();
    </script>
    <?php
}

/**
 * AJAX: Process one batch of library enrichment
 *
 * WHY: Runs server-side to query Open Library's API for each item in the batch.
 *      We do this in PHP (not client-side JS) because:
 *      1. We need to write results to the database immediately.
 *      2. Server-side HTTP is more reliable than browser CORS requests.
 *      3. We can control rate limiting and error handling centrally.
 *
 * STRATEGY:
 *   - Items with LCCNs: query by LCCN first (most specific match).
 *   - All items: fall back to title+author search.
 *   - For each match, grab the cover ID (if available) and any ISBN.
 *   - Cover URL pattern: https://covers.openlibrary.org/b/olid/{cover_edition_key}-M.jpg
 *   - We also mark items as "attempted" by setting cover_url to empty string
 *     (as opposed to NULL which means never tried), so we can skip them on re-runs.
 */
function sp_ajax_library_enrich_batch(): void {
    check_ajax_referer( 'sp_library_enrich' );

    if ( ! current_user_can( 'manage_options' ) ) {
        wp_send_json_error( __( 'Unauthorized.', 'societypress' ) );
    }

    global $wpdb;
    $prefix     = $wpdb->prefix . 'sp_';
    $batch_size = min( 20, max( 1, absint( $_GET['batch_size'] ?? 10 ) ) );
    $lccn_only  = ( $_GET['lccn_only'] ?? '0' ) === '1';
    $skip_attempted = ( $_GET['skip_attempted'] ?? '1' ) === '1';

    // Build WHERE clause for items needing enrichment
    // WHY: NULL cover_url = never attempted. Empty string = attempted, nothing found.
    //      If skip_attempted is on, we only process NULLs. Otherwise we retry everything
    //      without a cover (both NULL and empty).
    $where = [];
    if ( $skip_attempted ) {
        $where[] = 'cover_url IS NULL';
    } else {
        $where[] = "(cover_url IS NULL OR cover_url = '')";
    }
    if ( $lccn_only ) {
        $where[] = "lccn IS NOT NULL AND TRIM(lccn) != ''";
    }
    $where_sql = implode( ' AND ', $where );

    // Get total remaining for progress tracking
    // WHY prepare() with %d dummy: $where_sql is built entirely from hardcoded
    //      literals (no user input), but we run it through prepare() to match
    //      the companion query pattern below and satisfy static analysis tools.
    $total_remaining = (int) $wpdb->get_var( $wpdb->prepare(
        "SELECT COUNT(*) FROM {$prefix}library_items WHERE {$where_sql} AND 1 = %d",
        1
    ) );

    // Fetch the next batch — prioritize items with LCCNs (higher match rate)
    $items = $wpdb->get_results( $wpdb->prepare(
        "SELECT id, title, author, lccn, isbn
         FROM {$prefix}library_items
         WHERE {$where_sql}
         ORDER BY (lccn IS NOT NULL AND TRIM(lccn) != '') DESC, id ASC
         LIMIT %d",
        $batch_size
    ) );

    $results   = [];
    $found     = 0;
    $not_found = 0;
    $err_count = 0;

    foreach ( $items as $item ) {
        $cover_url = '';
        $isbn      = $item->isbn ?: '';
        $method    = '';

        // ------------------------------------------------------------------
        // Strategy 1: Try LCCN lookup (most specific)
        // ------------------------------------------------------------------
        if ( $item->lccn && trim( $item->lccn ) !== '' ) {
            // WHY strip dashes: the society LCCNs are stored as "85-082513" but Open Library
            // expects them without dashes (e.g. "85082513"). The dash format returns 0 results.
            $lccn_clean = str_replace( '-', '', trim( $item->lccn ) );
            $api_url = 'https://openlibrary.org/search.json?' . http_build_query( [
                'lccn'   => $lccn_clean,
                'limit'  => 1,
                'fields' => 'cover_edition_key,isbn,cover_i,edition_key',
            ] );

            $response = wp_remote_get( $api_url, [
                'timeout' => 15,
                'headers' => [ 'User-Agent' => 'SocietyPress/0.30 (WordPress plugin; library enrichment)' ],
            ] );

            if ( ! is_wp_error( $response ) && wp_remote_retrieve_response_code( $response ) === 200 ) {
                $body = json_decode( wp_remote_retrieve_body( $response ), true );
                if ( ! empty( $body['docs'][0] ) ) {
                    $doc = $body['docs'][0];
                    $cover_url = sp_extract_cover_url( $doc );
                    if ( empty( $isbn ) && ! empty( $doc['isbn'] ) ) {
                        $isbn = is_array( $doc['isbn'] ) ? $doc['isbn'][0] : $doc['isbn'];
                    }
                    if ( $cover_url ) {
                        $method = 'LCCN';
                    }
                }
            } else {
                $err_count++;
                $results[] = [
                    'title'  => mb_substr( $item->title, 0, 60 ),
                    'status' => 'error',
                    'method' => 'LCCN lookup failed',
                ];
                // Mark as attempted so we don't loop forever on network errors
                $wpdb->update( $prefix . 'library_items', [ 'cover_url' => '' ], [ 'id' => $item->id ] );
                continue;
            }
        }

        // ------------------------------------------------------------------
        // Strategy 2: Title + Author search (broader, lower precision)
        // ------------------------------------------------------------------
        if ( ! $cover_url && $item->title ) {
            $search_params = [
                'title'  => $item->title,
                'limit'  => 1,
                'fields' => 'cover_edition_key,isbn,cover_i,edition_key',
            ];
            if ( $item->author ) {
                $search_params['author'] = $item->author;
            }

            $api_url  = 'https://openlibrary.org/search.json?' . http_build_query( $search_params );
            $response = wp_remote_get( $api_url, [
                'timeout' => 15,
                'headers' => [ 'User-Agent' => 'SocietyPress/0.30 (WordPress plugin; library enrichment)' ],
            ] );

            if ( ! is_wp_error( $response ) && wp_remote_retrieve_response_code( $response ) === 200 ) {
                $body = json_decode( wp_remote_retrieve_body( $response ), true );
                if ( ! empty( $body['docs'][0] ) ) {
                    $doc = $body['docs'][0];
                    $url = sp_extract_cover_url( $doc );
                    if ( $url ) {
                        $cover_url = $url;
                        $method = 'title+author';
                    }
                    if ( empty( $isbn ) && ! empty( $doc['isbn'] ) ) {
                        $isbn = is_array( $doc['isbn'] ) ? $doc['isbn'][0] : $doc['isbn'];
                    }
                }
            }

            if ( ! $cover_url ) {
                $method = '';
            }
        }

        // ------------------------------------------------------------------
        // Store results
        // ------------------------------------------------------------------
        $update_data = [
            // Empty string = attempted but not found. Null = never attempted.
            'cover_url' => $cover_url ?: '',
        ];
        if ( $isbn && empty( $item->isbn ) ) {
            $update_data['isbn'] = mb_substr( $isbn, 0, 20 );
        }
        $wpdb->update( $prefix . 'library_items', $update_data, [ 'id' => $item->id ] );

        if ( $cover_url ) {
            $found++;
            $results[] = [
                'title'  => mb_substr( $item->title, 0, 60 ),
                'status' => 'found',
                'method' => $method,
            ];
        } else {
            $not_found++;
            $results[] = [
                'title'  => mb_substr( $item->title, 0, 60 ),
                'status' => 'not_found',
                'method' => '',
            ];
        }

        // Brief pause between API calls to be a respectful API consumer
        usleep( 200000 ); // 200ms
    }

    wp_send_json_success( [
        'processed'       => count( $items ),
        'found'           => $found,
        'not_found'       => $not_found,
        'errors'          => $err_count,
        'total_remaining' => $total_remaining,
        'has_more'        => $total_remaining > count( $items ),
        'results'         => $results,
    ] );
}

/**
 * Helper: Extract a cover image URL from an Open Library search result doc.
 *
 * WHY: Open Library has multiple ways to reference cover images:
 *      1. cover_i — a numeric cover ID → https://covers.openlibrary.org/b/id/{cover_i}-M.jpg
 *      2. cover_edition_key — an OLID → https://covers.openlibrary.org/b/olid/{key}-M.jpg
 *      3. edition_key array — can construct OLID-based URLs from any edition
 *      We try them in order of reliability. The -M suffix gives a medium-sized
 *      image (180px wide), which is perfect for catalog display.
 *
 * @param  array  $doc  A single document from Open Library's search API response.
 * @return string       Cover image URL, or empty string if none found.
 */
function sp_extract_cover_url( array $doc ): string {
    // Method 1: Direct cover ID (most reliable when present)
    if ( ! empty( $doc['cover_i'] ) ) {
        return 'https://covers.openlibrary.org/b/id/' . (int) $doc['cover_i'] . '-M.jpg';
    }

    // Method 2: Cover edition key (OLID)
    if ( ! empty( $doc['cover_edition_key'] ) ) {
        return 'https://covers.openlibrary.org/b/olid/' . sanitize_text_field( $doc['cover_edition_key'] ) . '-M.jpg';
    }

    // Method 3: First edition key as fallback
    if ( ! empty( $doc['edition_key'] ) && is_array( $doc['edition_key'] ) ) {
        return 'https://covers.openlibrary.org/b/olid/' . sanitize_text_field( $doc['edition_key'][0] ) . '-M.jpg';
    }

    return '';
}


// ============================================================================
// NEWSLETTER ARCHIVE
//
// WHY: Societies produce regular newsletters (monthly, quarterly, etc.) and
//      members expect to find an archive of past issues. Admins upload PDFs,
//      the system auto-generates a cover thumbnail from page 1, and members
//      can browse, preview in an inline viewer, and download. Non-members
//      can see the archive grid (for marketing value) but cannot open or
//      download the actual files.
// ============================================================================


/**
 * Render: Newsletter Archive Admin Page (Card Grid)
 *
 * WHY: Card grid matches the Gallery pattern — newsletters are visual items
 *      (cover thumbnails) so a card layout is more intuitive than a table.
 *      Shows cover image, title, date, volume/issue, visibility badge, and
 *      Edit/Delete action links. Sorted newest-first by publication date.
 */
function sp_render_newsletter_archive_page(): void {
    global $wpdb;
    $prefix = $wpdb->prefix . 'sp_';

    // ========== HANDLE DELETE ==========
    if ( ( $_POST['action'] ?? '' ) === 'delete' && ! empty( $_POST['newsletter_id'] ) ) {
        $newsletter_id = absint( $_POST['newsletter_id'] );
        check_admin_referer( 'sp_delete_newsletter_' . $newsletter_id );
        $wpdb->delete( $prefix . 'newsletters', [ 'id' => $newsletter_id ] );
        echo '<div class="notice notice-success"><p>' . esc_html__( 'Newsletter deleted.', 'societypress' ) . '</p></div>';
    }

    // ========== SEARCH FILTER ==========
    $search = sanitize_text_field( $_GET['s'] ?? '' );

    // ========== FETCH NEWSLETTERS ==========
    $sql = "SELECT * FROM {$prefix}newsletters";
    if ( $search ) {
        $sql .= $wpdb->prepare( " WHERE title LIKE %s", '%' . $wpdb->esc_like( $search ) . '%' );
    }
    $sql .= " ORDER BY pub_date DESC, created_at DESC";

    $newsletters = $wpdb->get_results( $sql );
    ?>
    <div class="wrap">
        <h1 class="wp-heading-inline"><?php esc_html_e( 'Newsletter Archive', 'societypress' ); ?></h1>
        <a href="<?php echo esc_url( admin_url( 'admin.php?page=sp-newsletter-edit' ) ); ?>" class="page-title-action">Add New</a>
        <hr class="wp-header-end">

        <!-- Search bar -->
        <form method="get" style="margin:16px 0;">
            <input type="hidden" name="page" value="sp-newsletter-archive">
            <p class="search-box">
                <input type="search" name="s" value="<?php echo esc_attr( $search ); ?>" placeholder="Search newsletters…">
                <input type="submit" class="button" value="Search">
                <?php if ( $search ) : ?>
                    <a href="<?php echo esc_url( admin_url( 'admin.php?page=sp-newsletter-archive' ) ); ?>" class="button"><?php esc_html_e( 'Clear', 'societypress' ); ?></a>
                <?php endif; ?>
            </p>
        </form>

        <?php if ( empty( $newsletters ) ) : ?>
            <p><?php esc_html_e( 'No newsletters yet.', 'societypress' ); ?> <a href="<?php echo esc_url( admin_url( 'admin.php?page=sp-newsletter-edit' ) ); ?>"><?php esc_html_e( 'Upload your first newsletter', 'societypress' ); ?></a>.</p>
        <?php else : ?>
            <div style="display:flex; flex-wrap:wrap; gap:20px; margin-top:20px;">
                <?php foreach ( $newsletters as $nl ) :
                    // Cover thumbnail — use auto-generated cover, fall back to placeholder
                    $cover_url = $nl->cover_image_id
                        ? wp_get_attachment_image_url( $nl->cover_image_id, 'medium' )
                        : '';

                    $edit_url   = admin_url( 'admin.php?page=sp-newsletter-edit&newsletter_id=' . $nl->id );
                    // delete via POST form below

                    // Format the volume/issue line (e.g. "Vol. 3, No. 2")
                    $vol_issue = '';
                    if ( $nl->volume )       $vol_issue .= 'Vol.&nbsp;' . $nl->volume;
                    if ( $nl->issue_number ) $vol_issue .= ( $vol_issue ? ', ' : '' ) . 'No.&nbsp;' . $nl->issue_number;

                    // Format the publication date
                    $date_display = $nl->pub_date ? wp_date( 'M j, Y', strtotime( $nl->pub_date ) ) : '';
                ?>
                    <div style="width:220px; background:#fff; border:1px solid #ccd0d4; border-radius:8px; overflow:hidden;">
                        <!-- Cover image area -->
                        <a href="<?php echo esc_url( $edit_url ); ?>" style="display:block;">
                            <?php if ( $cover_url ) : ?>
                                <img src="<?php echo esc_url( $cover_url ); ?>" alt="" style="width:100%; height:280px; object-fit:cover;">
                            <?php else : ?>
                                <div style="width:100%; height:280px; background:#f0f0f0; display:flex; align-items:center; justify-content:center;">
                                    <span class="dashicons dashicons-media-document" style="font-size:48px; width:48px; height:48px; color:#ccc;"></span>
                                </div>
                            <?php endif; ?>
                        </a>
                        <!-- Card body -->
                        <div style="padding:12px;">
                            <h4 style="margin:0 0 4px;">
                                <a href="<?php echo esc_url( $edit_url ); ?>" style="text-decoration:none; color:#1d2327;">
                                    <?php echo esc_html( $nl->title ); ?>
                                </a>
                            </h4>
                            <?php if ( $date_display ) : ?>
                                <span style="color:#666; font-size:12px;"><?php echo $date_display; ?></span><br>
                            <?php endif; ?>
                            <?php if ( $vol_issue ) : ?>
                                <span style="color:#666; font-size:12px;"><?php echo $vol_issue; ?></span>
                            <?php endif; ?>
                            <?php if ( $nl->visibility === 'members_only' ) : ?>
                                <span style="background:#fef0c7; color:#92400e; font-size:10px; padding:2px 6px; border-radius:3px; margin-left:4px;"><?php esc_html_e( 'Members Only', 'societypress' ); ?></span>
                            <?php endif; ?>
                            <?php if ( $nl->visibility === 'public' ) : ?>
                                <span style="background:#d1fae5; color:#065f46; font-size:10px; padding:2px 6px; border-radius:3px; margin-left:4px;">Public</span>
                            <?php endif; ?>
                            <div style="margin-top:8px; font-size:12px;">
                                <a href="<?php echo esc_url( $edit_url ); ?>"><?php esc_html_e( 'Edit', 'societypress' ); ?></a> |
                                <form method="post" action="<?php echo esc_url( admin_url( 'admin.php?page=sp-newsletter-archive' ) ); ?>" style="display:inline;" onsubmit="return confirm('<?php echo esc_js( __( 'Delete this newsletter?', 'societypress' ) ); ?>');">
                                    <?php wp_nonce_field( 'sp_delete_newsletter_' . $nl->id ); ?>
                                    <input type="hidden" name="action" value="delete">
                                    <input type="hidden" name="newsletter_id" value="<?php echo (int) $nl->id; ?>">
                                    <button type="submit" class="sp-link-btn" style="background:none; border:none; color:#b32d2e; cursor:pointer; padding:0; font:inherit; text-decoration:underline;"><?php esc_html_e( 'Delete', 'societypress' ); ?></button>
                                </form>
                            </div>
                        </div>
                    </div>
                <?php endforeach; ?>
            </div>
        <?php endif; ?>
    </div>
    <?php
}
// WHY: Newsletter save must happen on admin_init (before any output) because
// wp_redirect() requires headers not yet sent. The page render callback fires
// after admin_head has already output CSS, so redirect would silently fail.
add_action( 'admin_init', function () {
    // Only run on the newsletter edit page when the save button was clicked.
    if ( ! isset( $_POST['sp_save_newsletter'] ) ) return;
    if ( ( $_GET['page'] ?? '' ) !== 'sp-newsletter-edit' ) return;
    if ( ! current_user_can( 'manage_options' ) ) return;

    check_admin_referer( 'sp_newsletter_save' );

    global $wpdb;
    $prefix        = $wpdb->prefix . 'sp_';
    $newsletter_id = absint( $_GET['newsletter_id'] ?? 0 );

    $data = [
        'title'          => sanitize_text_field( $_POST['title'] ?? '' ),
        'slug'           => sanitize_title( $_POST['title'] ?? '' ),
        'description'    => sanitize_textarea_field( $_POST['description'] ?? '' ),
        'pub_date'       => sanitize_text_field( $_POST['pub_date'] ?? '' ) ?: null,
        'volume'         => absint( $_POST['volume'] ?? 0 ) ?: null,
        'issue_number'   => absint( $_POST['issue_number'] ?? 0 ) ?: null,
        'file_id'        => absint( $_POST['file_id'] ?? 0 ) ?: null,
        'cover_image_id' => absint( $_POST['cover_image_id'] ?? 0 ) ?: null,
        'visibility'     => sanitize_text_field( $_POST['visibility'] ?? 'members_only' ),
    ];

    if ( $newsletter_id ) {
        $wpdb->update( $prefix . 'newsletters', $data, [ 'id' => $newsletter_id ] );
    } else {
        $data['created_by'] = get_current_user_id();
        $wpdb->insert( $prefix . 'newsletters', $data );
    }

    wp_redirect( admin_url( 'admin.php?page=sp-newsletter-archive&sp_notice=newsletter_saved' ) );
    exit;
} );



/**
 * Render: Newsletter Edit Page (Add / Edit)
