                                    <input type="number" class="sp-store-qty" value="1" min="1" max="99" aria-label="<?php esc_attr_e( 'Quantity', 'societypress' ); ?>">
                                    <a href="#" class="sp-store-add-to-cart"><?php esc_html_e( 'Add to Cart', 'societypress' ); ?></a>
